INSERT INTO volumes (id, name, firstIssue, publisher, description, startYear, numIssues, image, characters_name, concepts_name, characters_id, concepts_id, numLikes) VALUES ('773', 'Superman', NULL, '10', '<p>This volume became <a href="https://comicvine.gamespot.com/adventures-of-superman/4050-3778/" data-ref-id="4050-3778">Adventures of Superman Volume 1</a> for issues #424-#649. The series title returned to Superman Volume 1 with issue #650. While titled <em>Adventures of Superman</em>, <a href="https://comicvine.gamespot.com/superman/4050-3816/" data-ref-id="4050-3816">Superman Volume 2</a> was published concurrently. Following the end of Volume 1, Continued in <a href="https://comicvine.gamespot.com/superman/4050-42986/" data-ref-id="4050-42986">Superman Volume 3</a>.</p><p><em>Superman</em> launched May 18, 1939 with its first issue (that doesn''t actually have a #1 on the cover) and although it was a seasonal book for its first five issues, with its sixth it began a bimonthly publishing rate and kept up with said rate until its eighty-fifth. With its eighty-sixth issue Superman began it''s mostly consistent monthly publishing rate which it continued using up until 1986 when the series ended at 423 issues, the last issue featuring <a href="/alan-moore/4040-40382/" data-ref-id="4040-40382">Alan Moore</a>''s acclaimed story "<a href="/whatever-happened-to-the-man-of-tomorrow/4045-56808/" data-ref-id="4045-56808"><em>Whatever Happened to the Man of Tomorrow?</em></a>" After that, the title''s numbering was continued through <em><a href="https://comicvine.gamespot.com/adventures-of-superman/4050-3778/" data-ref-id="4050-3778">Adventures of Superman</a></em> which lasted for several decades. It was in 2006 with #650 that the title returned to its original name, kicking off it''s new era with the <a href="/one-year-later/4045-40777/" data-ref-id="4045-40777">One Year Later</a> storyline co-written by <a href="/geoff-johns/4040-40439/" data-ref-id="4040-40439">Geoff Johns</a> and <a href="/kurt-busiek/4040-41741/" data-ref-id="4040-41741">Kurt Busiek</a>. After the arc, the series was written by Busiek from 654-675, with <a href="/james-robinson/4040-42389/" data-ref-id="4040-42389">James Robinson</a> taking the reigns in 677 and holding them tight until the milestone 700th issue where <a href="/j-michael-straczynski/4040-40683/" data-ref-id="4040-40683">JMS</a> took over with an arc entitled "<em><a href="/grounded/4045-56189/" data-ref-id="4045-56189">Grounded</a></em>" that would feature Superman walking across America. However, JMS left the book earlier then planned and new writer <a href="/chris-roberson/4040-19991/" data-ref-id="4040-19991">Chris Roberson</a> worked off of JMS'' original notes and plot-line. Unfortunately, Roberson never got to prove himself with his own story on the book as with the launch of The New 52 in September 2011, after 72 years and 714 issues (including <em>Adventures of Superman</em>) Superman Vol. 1 came to an end with the final chapter of the <em>Grounded</em> story arc serving as the final issue of the series. Superman will survive as an ongoing series at DC, with the month following the release of Superman #714 serving as the launching point of the third ongoing <a href="/superman/4050-42986/" data-ref-id="4050-42986">Superman</a> series in DC history with #1.</p><h2>Collected Editions</h2><ul><li><a href="/superman-archives-1-volume-1/4000-299490/" data-ref-id="4000-299490">Superman Archives Volume 1</a> (#1-4)</li><li><a href="/the-superman-chronicles-1-volume-1/4000-300176/" data-ref-id="4000-300176">The Superman Chronicles Volume 1</a> (#1)</li><li><a href="https://www.comicvine.com/superman-the-golden-age-omnibus-1-volume-1/4000-409195/" data-ref-id="4000-409195">Superman: The Golden Age Omnibus vol. 1</a> (#1-7)</li><li><a href="/superman-the-golden-age-1-volume-one/4000-520188/" data-ref-id="4000-520188">Superman: The Golden Age Volume One</a> (#1-4)</li><li><a href="/superman-in-the-forties-1-tpb/4000-299934/" data-ref-id="4000-299934">Superman in the Forties</a> (#1, 23, 40, 53, 58 &amp; 61)</li><li><a href="/superman-the-greatest-stories-ever-told-1-tpb/4000-308945/" data-ref-id="4000-308945">Superman: The Greatest Stories Ever Told Volume 1</a> (#1, 65, 156, 247 &amp; 400)</li><li><a href="/the-superman-chronicles-2-volume-2/4000-300177/" data-ref-id="4000-300177">The Superman Chronicles Volume 2</a> (#2-3)</li><li><a href="/the-superman-chronicles-3-volume-3/4000-300178/" data-ref-id="4000-300178">The Superman Chronicles Volume 3</a> (#4-5)</li><li><a href="/the-greatest-superman-stories-ever-told-1-hc/4000-441940/" data-ref-id="4000-441940">The Greatest Superman Stories Ever Told</a> (#4, 13, 30, 53, 123, 125, 129, 132, 145, 149, 162 &amp; 247)</li><li><a href="/superman-archives-2-volume-2/4000-299491/" data-ref-id="4000-299491">Superman Archives Volume 2</a> (#5-8)</li><li><a href="/superman-the-golden-age-2-volume-two/4000-562586/" data-ref-id="4000-562586">Superman: The Golden Age Volume Two</a> (#5-7)</li><li><a href="/the-superman-chronicles-4-volume-4/4000-300179/" data-ref-id="4000-300179">The Superman Chronicles Volume 4</a> (#6-7)</li><li><a href="/the-superman-chronicles-5-volume-5/4000-300180/" data-ref-id="4000-300180">The Superman Chronicles Volume 5</a> (#8-9)</li><li><a href="https://comicvine.gamespot.com/superman-the-golden-age-omnibus-2-volume-2/4000-539789/" data-ref-id="4000-539789">Superman: The Golden Age Omnibus vol. 2</a> (#8-15)</li><li><a href="https://comicvine.gamespot.com/superman-the-golden-age-3-volume-three/4000-603106/" data-ref-id="4000-603106">Superman: The Golden Age Volume Three</a> (#8-11)</li><li><a href="/superman-archives-3-volume-3/4000-299492/" data-ref-id="4000-299492">Superman Archives Volume 3</a> (#9-12)</li><li><a href="/the-superman-chronicles-6-volume-6/4000-300181/" data-ref-id="4000-300181">The Superman Chronicles Volume 6</a> (#10-11)</li><li><a href="/the-superman-chronicles-7-volume-