, {"id": 65261}, {"id": 65287}, {"id": 65288}, {"id": 65289}, {"id": 65290}, {"id": 66810}, {"id": 67172}, {"id": 67267}, {"id": 67377}, {"id": 67556}, {"id": 67904}, {"id": 68094}, {"id": 68786}, {"id": 70036}, {"id": 70043}, {"id": 70657}, {"id": 70669}, {"id": 70670}, {"id": 70674}, {"id": 74550}, {"id": 74611}, {"id": 75208}, {"id": 75896}, {"id": 76909}, {"id": 77368}, {"id": 77719}, {"id": 78150}, {"id": 78498}, {"id": 79256}, {"id": 79257}, {"id": 79258}, {"id": 80463}, {"id": 80843}, {"id": 81056}, {"id": 82165}, {"id": 82860}, {"id": 83522}, {"id": 85155}, {"id": 90329}, {"id": 90340}, {"id": 90341}, {"id": 90631}, {"id": 91875}, {"id": 93411}, {"id": 93564}, {"id": 96515}, {"id": 96516}, {"id": 96524}, {"id": 96525}, {"id": 96526}, {"id": 97325}, {"id": 97328}, {"id": 97355}, {"id": 97394}, {"id": 97395}, {"id": 97543}, {"id": 98492}, {"id": 98681}, {"id": 98682}, {"id": 98733}, {"id": 98746}, {"id": 98747}, {"id": 98851}, {"id": 105333}, {"id": 105334}, {"id": 107361}, {"id": 110171}, {"id": 110425}, {"id": 110426}, {"id": 110427}, {"id": 110428}, {"id": 110679}, {"id": 111690}, {"id": 116912}, {"id": 118757}, {"id": 119520}, {"id": 121202}, {"id": 123394}, {"id": 126211}, {"id": 128637}, {"id": 129144}, {"id": 134259}, {"id": 134614}, {"id": 135133}, {"id": 135644}, {"id": 143316}, {"id": 153459}, {"id": 155997}, {"id": 161271}, {"id": 161438}, {"id": 163070}, {"id": 173723}, {"id": 174071}, {"id": 175435}, {"id": 175436}, {"id": 175437}, {"id": 175438}, {"id": 175439}, {"id": 175440}, {"id": 175441}, {"id": 176383}, {"id": 180168}, {"id": 180398}, {"id": 180511}, {"id": 180598}, {"id": 180632}, {"id": 180637}, {"id": 180657}, {"id": 180658}, {"id": 181273}, {"id": 181612}, {"id": 182820}, {"id": 182821}, {"id": 183630}, {"id": 185419}, {"id": 185591}, {"id": 186283}, {"id": 190511}, {"id": 192523}, {"id": 194383}, {"id": 194941}]', '[{"id": 55712}, {"id": 43734}, {"id": 56090}, {"id": 41148}, {"id": 57596}, {"id": 57349}, {"id": 44795}, {"id": 58592}, {"id": 40617}, {"id": 56571}, {"id": 57350}, {"id": 56591}, {"id": 55803}, {"id": 55883}, {"id": 56363}, {"id": 58719}, {"id": 56321}, {"id": 56229}, {"id": 56163}, {"id": 56081}, {"id": 55776}, {"id": 45787}]', '0');
INSERT INTO volumes (id, name, firstIssue, publisher, description, startYear, numIssues, image, characters_name, concepts_name, characters_id, concepts_id, numLikes) VALUES ('796', 'Batman', 'The Legend of the Batman: Who He Is and How He Came To Be; The Joker', '10', '<p>Followed by <a href="https://comicvine.gamespot.com/batman/4050-42721/" data-ref-id="4050-42721">Batman Volume 2</a>.</p><p>The entire run of Batman still stands upon large controversies over who actually came up with some of the characters. <a href="/bob-kane/4040-19137/" data-ref-id="4040-19137">Bob Kane</a> supposedly came up with the idea for the hero, but it has been suggested that he only came up with a "Bird-man" and <a href="/bill-finger/4040-43591/" data-ref-id="4040-43591">Bill Finger</a> suggested he be a "Bat-man". Both creators, however, share credit for this character. As for the <a href="/joker/4005-1702/" data-ref-id="4005-1702">Joker</a>, the first concept sketch was drawn by <a href="/jerry-robinson/4040-9680/" data-ref-id="4040-9680">Jerry Robinson</a>, but Kane disputed that his input was "minimal" suggesting he and Bill came up with the idea. Kane also finagled many legal aspects of Batman related print and media ensuring he received sole credit. Prior to 2016, every movie and comic read "Batman created by Bob Kane", but following a campaign by the relatives of Bill Finger, all future credits have been changed to "Batman created by Bob Kane with Bill Finger". Robinson and Finger came up with the character, <a href="/dick-grayson/4005-1691/" data-ref-id="4005-1691">Robin</a> after "Robinhood". Bob Kane and Sheldon Moldoff co-created numerous bat-creations including <a href="/alfred/4005-5556/" data-ref-id="4005-5556">Alfred Pennyworth</a>, <a href="/poison-ivy/4005-1697/" data-ref-id="4005-1697">Poison Ivy,</a> <a href="/mr-freeze/4005-3715/" data-ref-id="4005-3715">Mr. Freeze</a>, <a href="/batwoman/4005-9052/" data-ref-id="4005-9052">Batwoman</a>, <a href="/batgirl/4050-7205/" data-ref-id="4050-7205">Batgirl</a> as well as <a href="/bat-mite/4005-23170/" data-ref-id="4005-23170">Bat-Mite</a> and <a href="/ace-the-bat-hound/4005-31302/" data-ref-id="4005-31302">Ace the Bat-Hound</a> just to name a few. <a href="/bill-finger/4040-43591/" data-ref-id="4040-43591">Bill Finger</a> also co-created <a href="/penguin/4005-4885/" data-ref-id="4005-4885">Penguin</a>, <a href="/riddler/4005-3718/" data-ref-id="4005-3718">Riddler</a>, and <a href="/catwoman/4005-1698/" data-ref-id="4005-1698">Catwoman</a>.</p><figure data-align="right" data-img-src="https://static.comicvine.com/uploads/original/6/64770/1681131-batman1ad.jpg" data-ref-id="1300-1681131" data-size="small" data-ratio="1.3854545454545" data-width="550" data-embed-type="image" style="width: 550px"><a class="fluid-height" style="padding-bottom:138.5%" href="https://static.comicvine.com/uploads/original/6/64770/1681131-batman1ad.jpg" data-ref-id="1300-1681131"><img alt="Ad for Batman #1" src="https://comicvine.gamespot.com/a/uploads/scale_small/6/64770/1681131-batman1ad.jpg" srcset="https://comicvine.gamespot.com/a/uploads/original/6/64770/1681131-batman1ad.jpg 550w, https://comicvine.gamespot.com/a/uploads/scale_medium/6/64770/1681131-batman1ad.jpg 480w, https://comicvine.gamespot.com/a/uploads/scale_small/6/64770/1681131-batman1ad.jpg 461w" sizes="(max-width: 461px) 100vw, 461px" data-width="461"></a><figcaption>Ad for Batman #1</figcaption></figure><p>One of DC''s longest running books showcasing the adventures of the Dark Knight, <a href="/batman/4005-1699/" data-ref-id="4005-1699">Batman</a>. Throughout the years, a majority of Batman''s marquee storylines have happened within the pages of this book including, but not limited to the death of the second Robin, <a href="/jason-todd/4005-6849/" data-ref-id="4005-6849">Jason Todd</a>, and <a href="/bane/4005-6129/" data-ref-id="4005-6129">Bane</a> breaking Batman''s back, leading to <a href="/jean-paul-valley/4005-12834/" data-ref-id="4005-12834">Jean-Paul Valley</a> to assume the role of Batman for a period of time in the 90s.</p><p>In 2006, superstar writer <a href="/grant-morrison/4040-40434/" data-ref-id="4040-40434">Grant Morrison</a> took over the book. Morrison wrote stories that introduced readers to Bruce''s son <a href="/damian-wayne/4005-42413/" data-ref-id="4005-42413">Damian Wayne</a> as well as putting Bruce through a series of near-fatal trials against <a href="/black-glove/4060-54825/" data-ref-id="4060-54825">The Black Glove</a> and <a href="/doctor-hurt/4005-54826/" data-ref-id="4005-54826">Doctor Hurt</a>, leading up to the epic 2008 storylines of <a href="/batman-rip/4045-55116/" data-ref-id="4045-55116">Batman RIP</a> and <a href="/final-crisis/4045-51642/" data-ref-id="4045-51642">Final Crisis</a> where Bruce Wayne had apparently died at the hands of the evil god <a href="/darkseid/4005-2349/" data-ref-id="4005-2349">Darkseid</a>.</p><p>After Bruce''s "death," and the <a href="/battle-for-the-cowl/4045-55808/" data-ref-id="4045-55808">Battle for the Cowl</a>, <a href="/dick-grayson/4005-1691/" data-ref-id="4005-1691">Dick Grayson</a>, the first Robin, took up the mantle of Batman, continuing to protect Gotham exactly as his mentor had. He even took in Damian as his own Robin. With the exception of two issues set prior to the events of <a href="/final-crisis/4045-51642/" data-ref-id="4045-51642">Final Crisis</a>, Dick Grayson has been the star of the book since issue #687.</p><p>When the superhero community learned that Bruce Wayne had never actually died, and was sent back in time by Darkseid, Dick Grayson eventually knew that his time as Batman would soon end. But with Bruce''s return, and formation of <a href="/batman-inc/4060-57839/" data-ref-id="4060-57839">Batman Incorporated</a>, Bruce deemed Dick Grayson the Batman of Gotham City, as he travelled the world, searching for more recruits for his new organization.</p><p><a href="/charles-paris/4040-38494/" data-ref-id="4040-38494">Charles Paris</a> has drawn the most issues of Batman thus far at 128. <a href="/dennis-oneil/4040-40861/" data-ref-id="4040-40861">Denny O''Neil</a> is a long time writer and editor at DC with 211 issues. He also contributed the location of <a href="/arkham-asylum/4020-31682/" data-ref-id="4020-31682">Arkham Asylum</a> as well as the characters <a href="/man-bat/4005-6131/" data-ref-id="4005-6131">Man-Bat</a>, <a href="/ras-al-ghul/4005-40816/" data-ref-id="4005-40816">Ra''s al Ghul</a> and <a href="/talia-al-ghul/4005-4917/" data-ref-id="4005-4917">Talia al Ghul</a>.</p><p>In September 2011, DC Comics relaunched their entire line in an event known as "<a href="/the-new-52/4015-56061/" data-ref-id="4015-56061">The New 52</a>" which would see the premiere of fifty-two new titles, thus the long-running Batman series ended with #713 during <a href="/tony-daniel/4040-4663/" data-ref-id="4040-4663">Tony S. Daniel</a>''s run on the title. In the new line, however, Tony Daniel will continue writing in the "Batman universe" but under the character''s other main title, <a href="/detective-comics/4050-18058/" data-ref-id="4050-18058">Detective Comics</a>. The new Batman series will be written instead by Scott Snyder (who was writing Detective Comics pre-relaunch).</p><h4>For Post <a href="/flashpoint/4045-56280/" data-ref-id="4045-56280">Flashpoint</a> volume 2, refer to <a href="/batman/4050-42721/" data-ref-id="4050-42721">Batman</a>.</h4><h4><b>Writers:</b></h4><p><b>Pre-Crisis</b></p><ul><li><a href="/bill-finger/4040-43591/" data-ref-id="4040-43591">Bill Finger</a> #1-13, 15, 18, 20, 22-23, 25, 28-36, 38-40, 42-45, 47-50, 52-53, 55-71, 74, 76-80, 82, 84-85, 87-90, 92-93, 95-105, 107-108, 110-116, 118-148, 150-160, 163, 167, 170, 176-177, 182, 185, 187, 193, 198, 200, 203, 208, 213, 218, 223, 228, 233, 236-237, 241-242, 254-259, 261</li><li><a href="/joseph-greene/4040-64596/" data-ref-id="4040-64596">Joseph Greene</a> #10, 17, 21, 26, 31, 261</li><li><a href="/jac