INSERT INTO volumes (id, name, firstIssue, publisher, description, startYear, numIssues, image, characters_name, concepts_name, characters_id, concepts_id, numLikes) VALUES ('832', 'The Human Torch', 'Introducing Toro; Sub-Mariner Crashes New York Again', '31', '<p>The Human Torch (<a href="/jim-hammond/4005-12605/" data-ref-id="4005-12605">Jim Hammond</a>) was one of the first characters created in the modern day "Marvel Universe" having first appeared in Marvel Comics #1, published by Timely. In 1940, he got his own ongoing series kicking off with "The Human Torch Comics #2", the elusive first issue actually being <a href="/red-raven-comics/4050-19964/" data-ref-id="4050-19964">Red Raven Comics</a> #1.</p><p>The first issue of the series was titled "Red Raven Comics", but issue #2, 3 &amp; 5 (June ''42) actually have NO numbers on the covers, but ONLY have the season of the year they were released.</p><p>#2 of the series says "FALL NUMBER" &lt;1941&gt;</p><p>#3 of the series says "WINTER NUMBER" &lt;1941&gt;</p><p>#4 of the series says "No. 3" &amp; "SPRING NUMBER" &lt;1942&gt;</p><p>#5 (June 1942) of the series says "SUMMER NUMBER" &lt;1942&gt;</p><p>#6 (Sept 1942) of the series says "No. 5" &amp; "FALL ISSUE" &lt;1942&gt;</p><p>Issue #4 of the series is actually 3rd issue of "The Human Torch Comics" title, and says "No. 3" on the cover and was the first attempt to renumber the series to the "The Human Torch Comics" title.</p><p>Issue #5 (June 1942) of the series, 4th issue of "The Human Torch Comics", has no number on the cover.</p><p>The 6th issue of the series (Sept 1942), on the cover it says "No.5" &amp; "FALL ISSUE" and is second, and permanent, effort to renumber the series to the "The Human Torch Comics" title. The numbering continues from here until the end of the series at issue "No. 38", thus giving the "The Human Torch Comics" title 38 issues, but 39 issues to the series. The renumbering effectively ignores the first issue if the series titled "Red Raven Comics".</p><p>The comic ended in 1954, but due to the fact that the first 29 issues were published at a quarterly rate, only 39 issues of the series (38 issues of "The Human Torch Comics") were printed from between 1941 to 1954.</p>', '1940', '38', '{''icon_url'': ''https://comicvine.gamespot.com/a/uploads/square_avatar/0/229/251258-832-119476-1-human-torch-the.jpg'', ''medium_url'': ''https://comicvine.gamespot.com/a/uploads/scale_medium/0/229/251258-832-119476-1-human-torch-the.jpg'', ''screen_url'': ''https://comicvine.gamespot.com/a/uploads/screen_medium/0/229/251258-832-119476-1-human-torch-the.jpg'', ''screen_large_url'': ''https://comicvine.gamespot.com/a/uploads/screen_kubrick/0/229/251258-832-119476-1-human-torch-the.jpg'', ''small_url'': ''https://comicvine.gamespot.com/a/uploads/scale_small/0/229/251258-832-119476-1-human-torch-the.jpg'', ''super_url'': ''https://comicvine.gamespot.com/a/uploads/scale_large/0/229/251258-832-119476-1-human-torch-the.jpg'', ''thumb_url'': ''https://comicvine.gamespot.com/a/uploads/scale_avatar/0/229/251258-832-119476-1-human-torch-the.jpg'', ''tiny_url'': ''https://comicvine.gamespot.com/a/uploads/square_mini/0/229/251258-832-119476-1-human-torch-the.jpg'', ''original_url'': ''https://comicvine.gamespot.com/a/uploads/original/0/229/251258-832-119476-1-human-torch-the.jpg'', ''image_tags'': ''All Images''}', '[{"id": "Jim Hammond"}, {"id": "Namor"}, {"id": "Toro"}, {"id": "Betty Dean"}, {"id": "Adolf Hitler"}, {"id": "Namora"}, {"id": "Sun Girl"}, {"id": "Franklin D. Roosevelt"}, {"id": "Jack Casey"}, {"id": "Patriot"}, {"id": "Hermann G\u00f6ring"}, {"id": "Josef Stalin"}, {"id": "Swoopy the Fearless"}, {"id": "Captain America"}, {"id": "Angel"}, {"id": "Folma"}, {"id": "Miss Patriot"}, {"id": "Benito Mussolini"}, {"id": "Fiery Mask"}, {"id": "Professor Horton"}, {"id": "Rathia"}, {"id": "Winston Churchill"}, {"id": "Jimmy Everett"}, {"id": "Harold Schmidt"}, {"id": "Mantor the Magician"}, {"id": "Nora Raymond"}, {"id": "Fred Raymond"}, {"id": "Python"}, {"id": "Max the Magician"}, {"id": "Ka-Zar (Rand)"}, {"id": "Jimmy Jupiter"}, {"id": "Pre-History"}, {"id": "Falcon (Burgess)"}, {"id": "Princess Fen"}, {"id": "Joseph Goebbels"}, {"id": "Hyena"}, {"id": "Asbestos Lady"}, {"id": "Peter Matson"}, {"id": "Dolores"}, {"id": "Rod"}, {"id": "Captain Fred Jory"}, {"id": "Prof. Marko"}, {"id": "Tha-Korr"}, {"id": "Ares"}, {"id": "Dorma"}, {"id": "Death"}, {"id": "Napoleon Bonaparte"}]', 'NaN', '[{"id": 12605}, {"id": 1476}, {"id": 11835}, {"id": 36300}, {"id": 9671}, {"id": 2177}, {"id": 36454}, {"id": 31595}, {"id": 134997}, {"id": 44588}, {"id": 31684}, {"id": 28624}, {"id": 158570}, {"id": 1442}, {"id": 36389}, {"id": 23292}, {"id": 7313}, {"id": 9672}, {"id": 46444}, {"id": 7228}, {"id": 138158}, {"id": 31245}, {"id": 133394}, {"id": 133393}, {"id": 133392}, {"id": 133391}, {"id": 133390}, {"id": 109751}, {"id": 89881}, {"id": 79647}, {"id": 79023}, {"id": 62571}, {"id": 50581}, {"id": 32130}, {"id": 31685}, {"id": 43995}, {"id": 43702}, {"id": 40217}, {"id": 40188}, {"id": 40187}, {"id": 40164}, {"id": 40162}, {"id": 40137}, {"id": 11940}, {"id": 12601}, {"id": 12620}, {"id": 35568}]', 'NaN', '0');
INSERT INTO volumes (id, name, firstIssue, publisher, description, startYear, numIssues, image, characters_name, concepts_name, characters_id, concepts_id, numLikes) VALUES ('921', 'Boy Commandos', NULL, '10', '<p>Boy Commandos was a Golden Age anthology title published by DC Comics in the 1940''s, each issue containing a few stories of the titular group as well as the occasional filler or short story. Created by Jack Kirby and Joe Simon, Boy Commandos became the third best-selling title at DC with over a million copies a month. Originally the book featured the boys and their adult leader, Rip Carter fighting in World War II but following the end of the war the series continued but no longer as a war comic. Near the end of its run the line-up of the team began to change and finally the series ended in 1949 after a run of thirty-six issues.</p><h4>Collected Editions</h4><ul><li><a href="/boy-commandos-by-joe-simon-and-jack-kirby-1-volume/4000-302186/" data-ref-id="4000-302186">Boy Commandos by Joe Simon and Jack Kirby Volume One</a> (#1-2)</li><li><a href="https://comicvine.gamespot.com/dc-goes-to-war/4050-127614/">DC Goes To War</a> (#1)</li><li><a href="/boy-commandos-by-joe-simon-and-jack-kirby-2-volume/4000-507146/" data-ref-id="4000-507146">Boy Commandos by Joe Simon and Jack Kirby Volume Two</a> (#3-5)</li></ul>', '1942', '36', '{''icon_url'': ''https://comicvine.gamespot.com/a/uploads/square_avatar/0/4/45206-921-52350-1-boy-commandos.jpg'', ''medium_url'': ''https://comicvine.gamespot.com/a/uploads/scale_medium/0/4/45206-921-52350-1-boy-commandos.jpg'', ''screen_url'': ''https://comicvine.gamespot.com/a/uploads/screen_medium/0/4/45206-921-52350-1-boy-commandos.jpg'', ''screen_large_url'': ''https://comicvine.gamespot.com/a/uploads/screen_kubrick/0/4/45206-921-52350-1-boy-commandos.jpg'', ''small_url'': ''https://comicvine.gamespot.com/a/uploads/scale_small/0/4/45206-921-52350-1-boy-commandos.jpg'', ''super_url'': ''https://comicvine.gamespot.com/a/uploads/scale_large/0/4/45206-921-52350-1-boy-commandos.jpg'', ''thumb_url'': ''https://comicvine.gamespot.com/a/uploads/scale_avatar/0/4/45206-921-52350-1-boy-commandos.jpg'', ''tiny_url'': ''https://comicvine.gamespot.com/a/uploads/square_mini/0/4/45206-921-52350-1-boy-commandos.jpg'', ''original_url'': ''https://comicvine.gamespot.com/a/uploads/original/0/4/45206-921-52350-1-boy-commandos.jpg'', ''image_tags'': ''All Images''}', '[{"id": "Andre Chavard"}, {"id": "Dan Turpin"}, {"id": "Rip Carter"}, {"id": "Alfy Twidgetts"}, {"id": "Jan Haasan"}, {"id": "Tex"}, {"id": "Crazy Quilt (Dekker)"}, {"id": "Captain Tootsie"}, {"id": "Dr. Narsty"}, {"id": "Private Pete"}, {"id": "Rollo"}, {"id": "Rickey Cannon "}, {"id": "Agent Axis"}, {"id": "Libby Lawrence"}, {"id": "Adolf Hitler"}, {"id": "Bob Feller"}, {"id": "Shorty"}, {"id": "Percy Clearweather  "}, {"id": "Helen of Troy"}, {"id": "Patrick MacGuire"}, {"id": "Anthony Rodriguez"}, {"id": "Johnny Gabrielli"}, {"id": "Tommy Tompkins"}, {"id": "Jerry the Jitterbug"}, {"id": "Joe Simon"}, {"id": "Peg"}, {"id": "Robin Hood"}, {"id": "Paris of Troy"}, {"id": "Jack Kirby"}, {"id": "Menelaus"}, {"id": "Hank the Yank"}, {"id": "Wesley Dodds"}, {"id": "Dale Evans"}]', '[{"id": "Fourth Wall"}]', '[{"id": 73230}, {"id": 9605}, {"id": 18136}, {"id": 73232}, {"id": 73231}, {"id": 115961}, {"id": 18141}, {"id": 16890}, {"id": 177932}, {"id": 38858}, {"id": 160345}, {"id": 141930}, {"id": 18144}, {"id": 32525}, {"id": 9671}, {"id": 73253}, {"id": 90520}, {"id": 142684}, {"id": 34422}, {"id": 69764}, {"id": 69762}, {"id": 69761}, {"id": 69760}, {"id": 47403}, {"id": 4070}, {"id": 18142}, {"id": 14335}, {"id": 11766}, {"id": 11432}, {"id": 11119}, {"id": 10397}, {"id": 9299}, {"id": 4537}]', '[{"id": 44795}]', '0');
INSERT INTO volumes (id, name, firstIssue, publisher, description, startYear, numIssues, image, characters_name, concepts_name, characters_id, concepts_id, numLikes) VALUES ('1313', 'Topolino', 'Eta Beta l''uomo del 2000 (p.1)', '2350', '<p>Topolino means Mickey Mouse, and is the primary Italian Disney publication. Beginning in 1949, it was originally published at a monthly rate, then twice a month, but within a few years it became a weekly comic (which it still is to this day) thus making it one of the longest-running comic book publications in history.</p><p> </p><h4><strong>Publishers:</strong></h4><p>Mondadori: 1-1701</p><p>Disney Italia: 1702-3018</p><p>Panini Comics: 3019-current</p><p> </p><p><b>General Notes</b></p><p>The following three issues don''t actually exist:</p><ul><li>Topolino #480 (February 7, 1965) was never printed due to a strike and as such the series numbering goes straight from 479 to 481.</li><li>Topolino #1370 (February 28, 1982) was also never printed due to a strike thus the series skips from 1369 to 1371.</li><li>Topolino #1531 (March 31, 1985) is the most recent Topolino issue to have not been printed due to a strike so the series jumps from 1530 to 1532.</li></ul><p>With #2009, the release date for the comic changed from Sunday to Wednesday.</p>', '1949', '3661', '{''icon_url'': ''https://comicvine.gamespot.com/a/uploads/square_avatar/0/77/567240-00001.jpg'', ''medium_url'': ''https://comicvine.gamespot.com/a/uploads/scale_medium/0/77/567240-00001.jpg'', ''screen_url'': ''https://comicvine.gamespot.com/a/uploads/screen_medium/0/77/567240-00001.jpg'', ''screen_large_url'': ''https://comicvine.gamespot.com/a/uploads/screen_kubrick/0/77/567240-00001.jpg'', ''small_url'': ''https://comicvine.gamespot.com/a/uploads/scale_small/0/77/567240-00001.jpg'', ''super_url'': ''https://comicvine.gamespot.com/a/uploads/scale_large/0/77/567240-00001.jpg'', ''thumb_url'': ''https://comicvine.gamespot.com/a/uploads/scale_avatar/0/77/567240-00001.jpg'', 