INSERT INTO volumes (id, name, firstIssue, publisher, description, startYear, numIssues, image, characters_name, concepts_name, characters_id, concepts_id, numLikes) VALUES ('1368', 'Young Men', NULL, '31', '<p>Young Men started as a romance-based title named <a href="/cowboy-romances/4050-1262/" data-ref-id="4050-1262"> Cowboy Romances</a> for issue 1, 2 and 3. It then became a war-based title named Young Men with issue 4 (even adding the words "<a href="https://comicvine.gamespot.com/young-men-on-the-battlefield/4050-75286/" data-ref-id="4050-75286">on the Battlefield</a>" to its title for several issues) until issue 24, when it became a revived super-hero title. The changes reflected the changing moods of this particular era''s comic readers. With issue #24, Publisher Martin Goodman and writer Stan Lee tried to revive successful heroes from the Golden Age - Human Torch &amp; Toro, Captain America &amp; Sub-Mariner. Although initially greeted with enthusiasm, this mini revival was short lived. Within 12 months of Young Men #24, Torch &amp; Cap''s own titles would be revived (and canceled again) - followed soon after by the cancellation of Sub-Mariner.</p><h4>Non-U.S. Collected Editions</h4><ul><li><a href="https://comicvine.gamespot.com/80-jahre-marvel-2-die-1950er-helden-in-zeiten-des-/4000-710061/">80 Jahre Marvel - Die 1950er: Helden in Zeiten des Kalten Krieges</a> (#24-28) (German)</li></ul>', '1950', '17', '{''icon_url'': ''https://comicvine.gamespot.com/a/uploads/square_avatar/0/4/58009-1368-91004-1-young-men.jpg'', ''medium_url'': ''https://comicvine.gamespot.com/a/uploads/scale_medium/0/4/58009-1368-91004-1-young-men.jpg'', ''screen_url'': ''https://comicvine.gamespot.com/a/uploads/screen_medium/0/4/58009-1368-91004-1-young-men.jpg'', ''screen_large_url'': ''https://comicvine.gamespot.com/a/uploads/screen_kubrick/0/4/58009-1368-91004-1-young-men.jpg'', ''small_url'': ''https://comicvine.gamespot.com/a/uploads/scale_small/0/4/58009-1368-91004-1-young-men.jpg'', ''super_url'': ''https://comicvine.gamespot.com/a/uploads/scale_large/0/4/58009-1368-91004-1-young-men.jpg'', ''thumb_url'': ''https://comicvine.gamespot.com/a/uploads/scale_avatar/0/4/58009-1368-91004-1-young-men.jpg'', ''tiny_url'': ''https://comicvine.gamespot.com/a/uploads/square_mini/0/4/58009-1368-91004-1-young-men.jpg'', ''original_url'': ''https://comicvine.gamespot.com/a/uploads/original/0/4/58009-1368-91004-1-young-men.jpg'', ''image_tags'': ''All Images''}', '[{"id": "Namor"}, {"id": "Jack Monroe"}, {"id": "Toro"}, {"id": "Jim Hammond"}, {"id": "Grand Director"}, {"id": "Betty Dean"}, {"id": "Rocky Jorden"}, {"id": "Red Skull (Malik)"}, {"id": "Namora"}, {"id": "Adolf Hitler"}, {"id": "Dorma"}, {"id": "Tha-Korr"}, {"id": "Vulture (Scarlotti)"}]', 'NaN', '[{"id": 1476}, {"id": 7618}, {"id": 11835}, {"id": 12605}, {"id": 14492}, {"id": 36300}, {"id": 178182}, {"id": 77248}, {"id": 2177}, {"id": 9671}, {"id": 12601}, {"id": 40137}, {"id": 77249}]', 'NaN', '0');
INSERT INTO volumes (id, name, firstIssue, publisher, description, startYear, numIssues, image, characters_name, concepts_name, characters_id, concepts_id, numLikes) VALUES ('1497', 'Journey into Mystery', 'One Foot In The Grave!', '31', '<p><b>Journey into Mystery volume 1</b> Continues into <a href="/thor/4050-2294/" data-ref-id="4050-2294"> Thor vol. 1</a> with issue 126.</p><p>Journey into Mystery volume 1 was a comic that began publication in 1952 by <a href="/atlas/4010-75/" data-ref-id="4010-75"> Atlas</a>, and although it wasn''t until the eighty-third issue that <a href="../../thor/29-2268/" rel="nofollow "> Thor</a> even appeared in comics, let alone the title, it is most often linked to his character. This is why after releasing the one hundred and twenty-fifth issue of the series in 1966 that the series changed its name to become the first volume entitled <a href="../../thor/49-2294/" rel="nofollow "> Thor volume 1</a>. For more than three hundred issues the title remained as Thor, but in 1996 after the five hundred and second issue of the series, they decided to change the name back to <a href="../49-7168/" rel="nofollow "> Journey into Mystery (vol.3)</a> which is what it was called up until its end in 1998 with the five hundred and twenty-first issue. Although these later Journey into Mystery issues (503-521) spin out of Thor vol.1, they are not counted in the collective Thor series.</p><p>Back in 1998, Thor''s adventures restarted in the first issue of <a href="../../thor/49-6226/" rel="nofollow "> Thor volume 2</a> and there they were contained until issue eighty-five when the series concluded because of Avengers: Disassembled in 2004. After that event Thor disappeared for a couple years until he returned in 2007 for his newest volume, <a href="../../thor/49-18831/" rel="nofollow "> Thor volume 3</a>, which only lasted for twelve issues with its restarted numbering. After that Marvel realized it had now published 599 comics in the collectively-grouped "Thor" series (even though eighty-two issues had nothing to do with him) and therefore reverted the numbering back to its original formation and thus, the 600th issue and the succeeding issues were born.</p><h4>Collected Editions</h4><ul><li><a href="https://comicvine.gamespot.com/marvel-august-1961-omnibus/4050-138275/">Marvel: August 1961 Omnibus</a> (#73-74)</li><li><a href="/marvel-masterworks-the-mighty-thor-1-volume-1/4000-232352/" data-ref-id="4000-232352">Marvel Masterworks: Mighty Thor Vol. 1</a> (#83-100)</li><li><a href="/thor-epic-collection-the-god-of-thunder/4050-77662/" data-ref-id="4050-77662">Thor Epic Collection: The God Of Thunder</a> (#83-109)</li><li><a href="https://comicvine.gamespot.com/kirby-is-mighty-king-size/4050-120010/">Kirby Is... Mighty! King-Size</a> (#83 &amp; 125)</li><li><a href="/marvel-masterworks-the-mighty-thor-2-volume-2/4000-232379/" data-ref-id="4000-232379">Marvel Masterworks: Mighty Thor Vol. 2</a> (#101-110)</li><li><a href="https://comicvine.gamespot.com/thor-epic-collection-when-titans-clash/4050-95441/" data-ref-id="4050-95441">Thor Epic Collection: When Titans Clash</a> (#110-125)</li><li><a href="/marvel-masterworks-the-mighty-thor-3-volume-3/4000-232238/" data-ref-id="4000-232238">Marvel Masterworks: Mighty Thor Vol. 3</a> (#111-120)</li><li><a href="https://comicvine.gamespot.com/loki-omnibus/4050-138891/">Loki Omnibus</a> (#111, 113 &amp; 115-123)</li><li><a href="https://comicvine.gamespot.com/incredible-hulk-hulk-vs-the-marvel-universe/4050-31010/">Incredible Hulk: Hulk vs the Marvel Universe</a> (#112)</li><li><a href="/marvel-masterworks-the-mighty-thor-4-volume-4/4000-232239/" data-ref-id="4000-232239">Marvel Masterworks: Mighty Thor Vol. 4</a> (#121-125)</li></ul>', '1952', '125', '{''icon_url'': ''https://comicvine.gamespot.com/a/uploads/square_avatar/5/58993/2642135-jim1cgc4.5.jpg'', ''medium_url'': ''https://comicvine.gamespot.com/a/uploads/scale_medium/5/58993/2642135-jim1cgc4.5.jpg'', ''screen_url'': ''https://comicvine.gamespot.com/a/uploads/screen_medium/5/58993/2642135-jim1cgc4.5.jpg'', ''screen_large_url'': ''https://comicvine.gamespot.com/a/uploads/screen_kubrick/5/58993/2642135-jim1cgc4.5.jpg'', ''small_url'': ''https://comicvine.gamespot.com/a/uploads/scale_small/5/58993/2642135-jim1cgc4.5.jpg'', ''super_url'': ''https://comicvine.gamespot.com/a/uploads/scale_large/5/58993/2642135-jim1cgc4.5.jpg'', ''thumb_url'': ''https://comicvine.gamespot.com/a/uploads/scale_avatar/5/58993/2642135-jim1cgc4.5.jpg'', ''tiny_url'': ''https://comicvine.gamespot.com/a/uploads/square_mini/5/58993/2642135-jim1cgc4.5.jpg'', ''original_url'': ''https://comicvine.gamespot.com/a/uploads/original/5/58993/2642135-jim1cgc4.5.jpg'', ''image_tags'': ''All Images''}', '[{"id": "Thor"}, {"id": "Odin"}, {"id": "Jane Foster"}, {"id": "Loki"}, {"id": "Balder"}, {"id": "Heimdall"}, {"id": "Mr. Hyde"}, {"id": "Absorbing Man"}, {"id": "Volstagg"}, {"id": "Harris Hobbs"}, {"id": "Iron Man"}, {"id": "Wasp"}, {"id": "Hank Pym"}, {"id": "King Cobra"}, {"id": "Magrat"}, {"id": "Kroda"}, {"id": "Hogun"}, {"id": "Fandral"}, {"id": "Executioner"}, {"id": "Enchantress"}, {"id": "Zarrko the Tomorrow Man"}, {"id": "Karnilla"}, {"id": "Ymir"}, {"id": "Surtur"}, {"id": "Ularic"}, {"id": "The Demon"}, {"id": "Captain America"}, {"id": "Scarlet Witch"}, {"id": "Quicksilver"}, {"id": "Hercules"}, {"id": "Gorr"}, {"id": "Grey Gargoyle"}, {"id": "Destroyer"}, {"id": "Margus"}, {"id": "Medusa"}, {"id": "Xemnu"}, {"id": "Tyr"}, {"id": "Queen Ula"}, {"id": "Sindri"}, {"id": "Korg"}, {"id": "Zetora the Martian"}, {"id": "Zadixx"}, {"id": "Honir"}, {"id": "Dustan Blake"}, {"id": "Magneto"}, {"id": "Doctor Strange"}, {"id": "Toad"}, {"id": "Hawkeye"}, {"id": "Namor"}, {"id": "Rick Jones"}, {"id": "Hulk"}, {"id": "Sigurd"}, {"id": "Wizard"}, {"id": "Sandman"}, {"id": "Brimer"}, {"id": "Queen Knorda"}, {"id": "Medusa"}, {"id": "Trapster"}, {"id": "Hela"}, {"id": "Radioactive Man"}, {"id": "Gudrun"}, {"id": "Frigga"}