INSERT INTO volumes (id, name, firstIssue, publisher, description, startYear, numIssues, image, characters_name, concepts_name, characters_id, concepts_id, numLikes) VALUES ('1642', 'Sub-Mariner', NULL, '31', '<p><b>Continued Sub-Mariner Volume 1</b> <br/> <br/>Sub-Mariner is the continuation of <a href="../../sub-mariner-comics/49-18548/" rel="nofollow ">   Sub-Mariner Comics</a>, witch had been on hiatus since 1949. This volume picked up the numbering with issue 33 in 1954.  <br/>Although It''s revival was short-lived, the series lasted longer then the also revived <a data-ref-id="4050-1628" href="/captain-america-comics/4050-1628/" slug="captain-america-comics">  Captain America Comics</a> series and <a data-ref-id="4050-1368" href="/young-men/4050-1368/" slug="young-men">  Young Men</a> series. This was most likely because publisher <a data-ref-id="4040-43801" href="/martin-goodman/4040-43801/" slug="martin-goodman">  Martin Goodman</a> had developed plans with a TV network-company to have Sub-mariner appear in his own live-action tv show. Plans for the show however never materialized and thus the series was cancelled as well. <br/></p>', '1954', '10', '{''icon_url'': ''https://comicvine.gamespot.com/a/uploads/square_avatar/0/4/999-1642-1064-1-sub-mariner-comics.jpg'', ''medium_url'': ''https://comicvine.gamespot.com/a/uploads/scale_medium/0/4/999-1642-1064-1-sub-mariner-comics.jpg'', ''screen_url'': ''https://comicvine.gamespot.com/a/uploads/screen_medium/0/4/999-1642-1064-1-sub-mariner-comics.jpg'', ''screen_large_url'': ''https://comicvine.gamespot.com/a/uploads/screen_kubrick/0/4/999-1642-1064-1-sub-mariner-comics.jpg'', ''small_url'': ''https://comicvine.gamespot.com/a/uploads/scale_small/0/4/999-1642-1064-1-sub-mariner-comics.jpg'', ''super_url'': ''https://comicvine.gamespot.com/a/uploads/scale_large/0/4/999-1642-1064-1-sub-mariner-comics.jpg'', ''thumb_url'': ''https://comicvine.gamespot.com/a/uploads/scale_avatar/0/4/999-1642-1064-1-sub-mariner-comics.jpg'', ''tiny_url'': ''https://comicvine.gamespot.com/a/uploads/square_mini/0/4/999-1642-1064-1-sub-mariner-comics.jpg'', ''original_url'': ''https://comicvine.gamespot.com/a/uploads/original/0/4/999-1642-1064-1-sub-mariner-comics.jpg'', ''image_tags'': ''All Images''}', '[{"id": "Namor"}, {"id": "Namora"}, {"id": "Princess Fen"}, {"id": "Byrrah"}, {"id": "Betty Dean"}, {"id": "Tha-Korr"}, {"id": "Toro"}, {"id": "Jim Hammond"}, {"id": "U-Man"}, {"id": "Leonard McKenzie"}, {"id": "Professor Zunbar"}, {"id": "Elmer"}, {"id": "Ice King"}]', 'NaN', '[{"id": 1476}, {"id": 2177}, {"id": 32130}, {"id": 2179}, {"id": 36300}, {"id": 40137}, {"id": 11835}, {"id": 12605}, {"id": 29530}, {"id": 37545}, {"id": 91549}, {"id": 91550}, {"id": 92285}]', 'NaN', '0');
INSERT INTO volumes (id, name, firstIssue, publisher, description, startYear, numIssues, image, characters_name, concepts_name, characters_id, concepts_id, numLikes) VALUES ('1683', 'The Brave and the Bold', 'The Thunder of the Chariots!; Battle for the Dragon Ship!; Duel in Forest Perilous', '10', '<p><em>Brave and the Bold</em> was started in 1955 and was canceled in 1983, lasting 200 Issues. <em>Brave and the Bold</em> was followed up with two miniseries in 1991 and 1999. The magazine was revived in 2007 as an ongoing title. Whilst it started out as a triple-feature for <a href="/silent-knight/4005-29505/" data-ref-id="4005-29505">The Silent Knight</a>, <a href="/viking-prince/4005-12832/" data-ref-id="4005-12832">The Viking Prince</a> and <a href="/robin-hood/4005-14335/" data-ref-id="4005-14335">Robin Hood</a>, the most consistent theme for the series was team ups by two heroes from the DC Universe with the majority being <a href="/batman/4005-1699/" data-ref-id="4005-1699">Batman</a> team-ups.</p><h4>Collected Editions</h4><ul><li><a href="/justice-league-of-america-archives-1-volume-1/4000-140329/" data-ref-id="4000-140329">Justice League of America Archives Vol. 1</a> (#28-30)</li><li><a href="https://www.comicvine.com/justice-league-of-america-omnibus-1-volume-1/4000-450546/" data-ref-id="4000-450546">Justice League of America Omnibus Vol. 1</a> (#28-30)</li><li><a href="/justice-league-of-america-the-silver-age-1-volume-/4000-514413/" data-ref-id="4000-514413">Justice League of America: The Silver Age Volume One</a> (#28-30)</li><li><a href="https://comicvine.gamespot.com/justice-league-of-america-a-celebration-of-60-year/4050-126262/">Justice League of America: A Celebration of 60 Years</a> (#28)</li><li><a href="/the-hawkman-archives-1-volume-1/4000-300198/" data-ref-id="4000-300198">Hawkman Archives Vol. 1</a> (#34-36, 42-44)</li><li><a href="/showcase-presents-green-arrow/4050-38845/" data-ref-id="4050-38845">Showcase Presents: Green Arrow</a> (#50, 71, 85)</li><li><a href="https://comicvine.gamespot.com/teen-titans-the-silver-age-omnibus-1-vol-1/4000-556462/" data-ref-id="4000-556462">Teen Titans: The Silver Age Omnibus Vol. 1</a> (#54, 60 &amp; 83)</li><li><a href="/showcase-presents-brave-and-the-bold-batman-team-u/4000-260043/" data-ref-id="4000-260043">Showcase Presents: Brave and the Bold: Batman Team-ups Vol. 1</a> (#59, 64, 67-71, 74-87)</li><li><a href="https://comicvine.gamespot.com/wonder-girl-adventures-of-a-teen-titan-1-volume-1/4000-617809/" data-ref-id="4000-617809">Wonder Girl: Adventures of A Teen Titan Volume 1</a> (#60)</li><li><a href="https://comicvine.gamespot.com/doom-patrol-the-silver-age-2-volume-2/4000-743299/" data-ref-id="4000-743299">Doom Patrol: The Silver Age Volume 2</a> (#65)</li><li><a href="https://comicvine.gamespot.com/batman-the-brave-and-the-bold-the-bronze-age-omnib/4000-649693/" data-ref-id="4000-649693">Batman In The Brave &amp; The Bold: The Bronze Age Omnibus Vol. 1</a> (#74-109)</li><li><a href="https://www.comicvine.com/deadman-2-book-two/4000-316132/">Deadman #2 - Book Two</a> (#79 and 86)</li><li><a href="/batman-by-neal-adams-1-book-one/4000-662055/" data-ref-id="4000-662055">Batman by Neal Adams Book One</a> (#79-85)</li><li><a href="https://comicvine.gamespot.com/deadman-omnibus/4050-132454/">Deadman Omnibus</a> (#79, 86, 104 &amp; 133)</li><li><a href="https://comicvine.gamespot.com/teen-titans-the-silver-age-2-volume-two/4000-693449/" data-ref-id="4000-693449">Teen Titans: The Silver Age Vol. 2</a> (#83)</li><li><a href="/batman-by-neal-adams-2-book-two/4000-696326/" data-ref-id="4000-696326">Batman by Neal Adams Book Two</a> (#86 &amp; 93)</li><li><a href="https://comicvine.gamespot.com/batman-the-brave-and-the-bold-the-bronze-age-omnib/4000-649693/" data-ref-id="4000-649693">Batman: The Brave and the Bold: The Bronze Age Omnibus Volume 1</a> (#87-122)</li><li><a href="https://comicvine.gamespot.com/wonder-woman-diana-prince-the-50th-anniversary-omn/4050-116063/">Wonder Woman: Diana Prince: The 50th Anniversary Omnibus</a> (#87 &amp; 105)</li><li><a href="/showcase-presents-brave-and-the-bold-batman-team-u/4000-260044/" data-ref-id="4000-260044">Showcase Presents: Brave and the Bold: Batman Team-Ups Vol. 2</a> (#88-108)</li><li><a href="https://comicvine.gamespot.com/batman-wildcat/4050-101598/" data-ref-id="4050-101598">Batman/Wildcat</a> (#88, 97, 110, 118 &amp; 127)</li><li><a href="/batman-the-brave-and-the-bold-the-bronze-age-omnib/4000-698579/" data-ref-id="4000-698579">Batman: The Brave and the Bold: The Bronze Age Omnibus Volume Two</a> (#91-109)</li><li><a href="https://comicvine.gamespot.com/teen-titans-the-bronze-age-omnibus/4050-102137/" data-ref-id="4050-102137">Teen Titans: The Bronze Age Omnibus</a> (#94, 102 &amp; 149)</li><li><a href="https://www.comicvine.com/legends-of-the-dark-knight-jim-aparo-1-volume-1/4000-327788/" data-ref-id="4000-327788">Legends of The Dark Knight: Jim Aparo vol. 1</a> (#98, 100-102 and 104-122)</li><li><a href="/showcase-presents-brave-and-the-bold-batman-team-u/4000-260045/" data-ref-id="4000-260045">Showcase Presents: Brave and the Bold: Batman Team-Ups Vol. 3</a> (#109-134)</li><li><a href="/batman-in-the-brave-and-the-bold-the-bronze-age-om/4000-682634/" data-ref-id="4000-682634">Batman In The Brave &amp; The Bold: The Bronze Age Omnibus Vol. 2</a> (#110-156)</li><li><a href="https://comicvine.gamespot.com/the-joker-the-bronze-age-omnibus/4050-120647/">The Joker: The Bronze Age Omnibus</a> (#111, 118, 129-130, 141&amp; 191)</li><li><a href="https://comicvine.gamespot.com/mister-miracle-by-steve-englehart-and-steve-gerber/4050-125642/">Mister Miracle by Steve Englehart and Steve Gerber</a> (#112, 128 &amp; 138)</li><li><a href="https://comicvine.gamespot.com/swamp-thing-the-bronze-age-2-volume-two/4000-732690/" data-ref-id="4000-732690">Swamp Thing: The Bronze Age Volume Two</a> (#122 &amp; 176)</li><li><a href="https://www.comicvine.com/legends-of-the-dark-knight-jim-aparo-2-volume-2/4000-427157/" data-ref-id="4000-427157">Legends of The Dark Knight: Jim Aparo vol. 2</a> (#123-145 and 147-151)</li><li><a href="https://comicvine.gamespot.com/richard-dragon-kung-fu-fighter-coming-of-the-drago/4050-133796/">Richard Dragon, Kung-Fu Fighter: Coming of the Dragon!</a> (#132)</li><li><a href="https://www.comicvine.com/deadman-3-book-three/4000-386290/">Deadman Book Three</a> (#133)</li><li><a href="/batman-in-the-brave-and-the-bold-the-bronze-age-om/4000-883419/" data-ref-id="4000-883419">Batman In The Brave &amp; The Bold: The Bronze Age Omnibus Vol. 3</a> (#157-200)</li><li><a href="https://comicvine.gamespot.com/tales-of-the-batman-gerry-conway-1-volume-1/4000-608194/" data-ref-id="4000-608194">Tales of the Batman: Gerry Conway Volume 1</a> (#158, 161 &amp; 171-174)</li><li><a href="https://comicvine.gamespot.com/batman-arkham-ras-al-ghul/4050-117730/">Batman Arkham: Ra''s Al Ghul</a> (#159)</li><li><a href="https://comicvine.gamespot.com/tales-of-the-batman-marv-wolfman-1-volume-1/4000-743303/" data-ref-id="4000-743303">Tales of the Batman: Marv Wolfman Volume 1</a> (#167)</li><li><a href="/batman-arkham-the-riddler/4050-81959/" data-ref-id="4050-81959">Batman: Arkham - The Riddler</a> (#183)</li><li><a href="https://comicvine.gamespot.com/dc-through-the-80s-the-end-of-eras/4050-132564/">DC Through the ''80s: The End of Eras</a> (#200)</li></ul><h4>Non-U.S. Collected Editions</h4><ul><li><a href="https://comicvine.gamespot.com/batman-collection-jim-aparo-1-volumen-1/4000-414552/">Batman Collection: Jim Aparo - Volumen 1</a> (#98. #100-102 &amp; #104-110) (German)</li><li><a href="https://comicvine.gamespot.com/batman-collection-jim-aparo-2-volumen-2/4000-696407/">Batman Collection: Jim Aparo - Volumen 2</a> (#111-122) (German)</li><li><a href="https://comicvine.gamespot.com/batman-collection-jim-aparo-3-volumen-3/4000-696408/">Batman Collection: Jim Aparo - Volumen 3</a> (#123-136) (German)</li><li><a href="https://comicvine.gamespot.com