INSERT INTO volumes (id, name, firstIssue, publisher, description, startYear, numIssues, image, characters_name, concepts_name, characters_id, concepts_id, numLikes) VALUES ('1687', 'My Greatest Adventure', 'My Cargo Was Death', '10', '<p>Starring: <a href="/robotman/4005-4079/" data-ref-id="4005-4079">Robotman</a>, <a href="/elasti-girl/4005-4088/" data-ref-id="4005-4088">Elasti-Girl</a>, <a href="/negative-man/4005-4087/" data-ref-id="4005-4087">Negative Man</a>, and the <a href="/the-chief/4005-35126/" data-ref-id="4005-35126">Chief</a>.</p><p>Continued in: <a href="/doom-patrol-1964/4050-2177/" data-ref-id="4050-2177">Doom Patrol (Volume 1)</a></p><p>The anthology series "My Greatest Adventure" debuted in 1954 as it began an 85 issue run with the stories, "I was King of Dagger Island," "I hunted a flying saucer," and "My cargo was death." The series would become most notable for introducing misfit band of maybe - super heroes, the Doom Patrol, in issue# 80. As of #86, the series changed its name to Doom Patrol and retained the same numbering until in ended with #121 in October 1968.</p><h4>Collected Editions</h4><ul><li><a href="https://comicvine.gamespot.com/doom-patrol-the-silver-age-omnibus/4050-102255/" data-ref-id="4050-102255">Doom Patrol: The Silver Age Omnibus</a> (#80-85)</li><li><a href="/doom-patrol-the-silver-age-1-volume-one/4000-677945/" data-ref-id="4000-677945">Doom Patrol: The Silver Age Volume One</a> (#80-85)</li></ul>', '1955', '85', '{''icon_url'': ''https://comicvine.gamespot.com/a/uploads/square_avatar/0/4/1458-1687-1566-1-my-greatest-adventur.jpg'', ''medium_url'': ''https://comicvine.gamespot.com/a/uploads/scale_medium/0/4/1458-1687-1566-1-my-greatest-adventur.jpg'', ''screen_url'': ''https://comicvine.gamespot.com/a/uploads/screen_medium/0/4/1458-1687-1566-1-my-greatest-adventur.jpg'', ''screen_large_url'': ''https://comicvine.gamespot.com/a/uploads/screen_kubrick/0/4/1458-1687-1566-1-my-greatest-adventur.jpg'', ''small_url'': ''https:/