INSERT INTO volumes (id, name, firstIssue, publisher, description, startYear, numIssues, image, characters_name, concepts_name, characters_id, concepts_id, numLikes) VALUES ('1770', 'Showcase', 'The School For Smoke-Eaters / Fire Under The Big Top / Fourth Alarm', '10', '<p><em>Showcase</em> was a flagship title of DC''s during the Golden and Silver Ages. It was here that many heroes had their origins told, including the Flash, Green Lantern, Adam Strange, The Atom, Metal Men and the Sea Devils, before going on to star in their own titles. Showcase #4 is widely regarded as being the first Silver Age Comic.</p><p>However, not all characters that starred in <em>Showcase</em> were completely new; Lois Lane, Aquaman and Tommy Tomorrow were all cover stars for this title. <em>Showcase</em> also had licensed characters, such as G.I. Joe and James Bond.</p><p>Although canceled for a time in the early 1970s, it was revived a few years later as part of the marketing campaign for DC Comics known as the <a href="/dc-explosion-and-implosion/4015-56163/" data-ref-id="4015-56163">DC Explosion</a>. It was subsequently cancelled in a wave of cancellations by DC which came to be known as the DC Implosion. Issues 105 and 106 were later published elsewhere.</p><h4>Collected Editions</h4><ul><li><a href="/showcase-presents-showcase-1-vol-1/4000-344983/" data-ref-id="4000-344983">Showcase Presents: Showcase</a> (#1-21)</li><li><a href="/the-flash-archives-volume-1/4000-225812/" data-ref-id="4000-225812">Flash Archives Vol. 1</a> (#4, 8, 13 &amp; 14)</li><li><a href="/the-flash-omnibus-1-volume-one/4000-466310/" data-ref-id="4000-466310">Flash Omnibus Volume One</a> (#4, 8, 13 &amp; 14)</li><li><a href="https://comicvine.gamespot.com/flash-the-silver-age-1-volume-one/4000-535333/" data-ref-id="4000-535333">Flash: The Silver Age Volume One</a> (#4, 8 &amp; 14)</li><li><a href="/challengers-of-the-unknown-archives-volume-1/4000-300886/" data-ref-id="4000-300886">Challengers of the Unknown Vol. 1</a> (#6-7 &amp; 11-12)</li><li><a href="https://comicvine.gamespot.com/flash-rogues-captain-cold/4050-112951/">Flash Rogues: Captain Cold</a> (#8)</li><li><a href="/adam-strange-archives-volume-one/4000-140340/" data-ref-id="4000-140340">Adam Strange Archives Vol. 1</a> (#17-19)</li><li><a href="https://comicvine.gamespot.com/adam-strange-the-silver-age-omnibus/4050-102880/" data-ref-id="4050-102880">Adam Strange: The Silver Age Omnibus</a> (#17-19 &amp; 101-103)</li><li><a href="/green-lantern-archives-/4000-214818/" data-ref-id="4000-214818">Green Lantern Archives Vol. 1</a> (#22-24)</li><li><a href="https://comicvine.gamespot.com/green-lantern-the-silver-age-omnibus-1-volume-1/4000-582499/" data-ref-id="4000-582499">Green Lantern: The Silver Age Omnibus Volume 1</a> (#22-24)</li><li><a href="https://comicvine.gamespot.com/green-lantern-the-silver-age-1-volume-one/4000-552137/" data-ref-id="4000-552137">Green Lantern: The Silver Age Volume One</a> (#22-24)</li><li><a href="/showcase-presents-the-sea-devils-vol-1/4000-336875/" data-ref-id="4000-336875">Showcase Presents: The Sea Devils Vol. 1</a> (#27-29)</li><li><a href="/aquaman-archives-volume-1/4000-140370/" data-ref-id="4000-140370">Aquaman Archives Vol. 1</a> (#30-31)</li><li><a href="/showcase-presents-aquaman-1-vol-1/4000-236348/" data-ref-id="4000-236348">Showcase Presents: Aquaman Vol. 1</a> (#30-33)</li><li><a href="/legends-of-tomorrow-the-atom/4050-108741/" data-ref-id="4050-108741">Legends of Tomorrow: The Atom</a> (#34)</li><li><a href="/the-enemy-ace-archives-volume-1/4000-301027/" data-ref-id="4000-301027">The Enemy Ace Archives Vol. 1</a> (#57-58)</li><li><a href="https://comicvine.gamespot.com/dc-goes-to-war/4050-127614/">DC Goes To War</a> (#57)</li><li><a href="https://comicvine.gamespot.com/teen-titans-the-silver-age-omnibus-1-vol-1/4000-556462/" data-ref-id="4000-556462">Teen Titans: The Silver Age Omnibus Vol. 1</a> (#59)</li><li><a href="/the-hawk-and-the-dove-the-silver-age/4050-109