INSERT INTO volumes (id, name, firstIssue, publisher, description, startYear, numIssues, image, characters_name, concepts_name, characters_id, concepts_id, numLikes) VALUES ('1866', 'Challengers of the Unknown', 'The Human Pets!', '10', '<p>Paranormal explorers the Challengers of the Unknown got their own title following their test run which began in Showcase# 6 (February 1957). Following the adventures of Rocky, Red, Ace and Prof, the series ran for 87 issues. The first issue features cover and interior artwork by Jack Kirby and the "King" also wrote both stories, "The Man Who Tampered With Infinity" and " The Human Pets." The first issue set the tone for the 86 that were to follow. In the Challenger''s adventures, the non super hero adventure comic reached its peak. Many see in Kirby''s interpretation of the team the inspiration for and even prototype of the Fantastic Four. The team would later re-appear in three new self - titled series, which varied widely in tone and interpretation of the team.</p><h4>Collected Editions</h4><ul><li><a href="/challengers-of-the-unknown-archives-volume-1/4000-300886/" data-ref-id="4000-300886">Challengers of the Unknown Archives vol. 1</a> (#1-2)</li><li><a href="/challengers-of-the-unknown-archives-volume-2/4000-300887/" data-ref-id="4000-300887">Challengers of the Unknown Archives vol. 2</a> (#3-8)</li><li><a href="https://comicvine.gamespot.com/challengers-of-the-unknown-by-jack-kirby/4050-69015/">Challengers of the Unknown by Jack Kirby</a> (#1-8)</li><li><a href="https://comicvine.gamespot.com/doom-patrol-the-silver-age-2-volume-2/4000-743299/" data-ref-id="4000-743299">Doom Patrol: The Silver Age Volume 2</a> (#48)</li><li><a href="https://comicvine.gamespot.com/deadman-omnibus/4050-132454/">Deadman Omnibus</a> (#74 &amp; 84-87)</li><li><a href="https://comicvine.gamespot.com/swamp-thing-the-bronze-age-2-volume-two/4000-732690/" data-ref-id="4000-732690">Swamp Thing: The Bronze Age Volume Two</a> (#81-87)</li><li><a href="https://www.comicvine.com/deadman-5-book-five/4000-451072/" data-ref-id="4000-451072">Deadman Book Five</a> (#85-87)</li></ul>', '1958', '87', '{''icon_url'': ''https://comicvine.gamespot.com/a/uploads/square_avatar/0/4/3412-1866-3766-1-challengers-of-the-u.jpg'', ''medium_url'': ''https://comicvine.gamespot.com/a/uploads/scale_medium/0/4/3412-1866-3766-1-challengers-of-the-u.jpg'', ''screen_url'': ''https://comicvine.gamespot.com/a/uploads/screen_medium/0/4/3412-1866-3766-1-challengers-of-the-u.jpg'', ''screen_large_url'': ''https://comicvine.gamespot.com/a/uploads/screen_kubrick/0/4/3412-1866-3766-1-challengers-of-the-u.jpg'', ''small_url'': ''https://comicvine.gamespot.com/a/uploads/scale_small/0/4/3412-1866-3766-1-challengers-of-the-u.jpg'', ''super_url'': ''https://comicvine.gamespot.com/a/uploads/scale_large/0/4/3412-1866-3766-1-challengers-of-the-u.jpg'', ''thumb_url'': ''https://comicvine.gamespot.com/a/uploads/scale_avatar/0/4/3412-1866-3766-1-challengers-of-the-u.jpg'', ''tiny_url'': ''https://comicvine.gamespot.com/a/uploads/square_mini/0/4/3412-1866-3766-1-challengers-of-the-u.jpg'', ''original_url'': ''https://comicvine.gamespot.com/a/uploads/original/0/4/3412-1866-3766-1-challengers-of-the-u.jpg'', ''image_tags'': ''All Images''}', '[{"id": "Ace Morgan"}, {"id": "Rocky Davis"}, {"id": "Red Ryan"}, {"id": "Prof Haley"}, {"id": "June Robbins"}, {"id": "Multi-Man"}, {"id": "Tino Manarry"}, {"id": "Volcano Man"}, {"id": "Corinna Stark"}, {"id": "Kra"}, {"id": "Swamp Thing"}, {"id": "Deadman"}, {"id": "F. Gaylord Clayburn III"}, {"id": "Villo"}, {"id": "Brainex"}, {"id": "Drabny"}, {"id": "Cosmo"}, {"id": "Rip Hunter"}, {"id": "Count Karnak"}, {"id": "Madoga"}, {"id": "Hordred"}, {"id": "Tukamenon"}, {"id": "Multi-Woman"}, {"id": "M''Nagalah"}, {"id": "Lucas Lawspeaker"}, {"id": "Heathcliff Monroe"}, {"id": "Chu"}, {"id": "Algernon Stark"}, {"id": "Sponge Man"}, {"id": "Madame Zaddum"}, {"id": "Paul Haley"}, {"id": "Dr. Hascomb"}, {"id": "Abner Jenkins"}, {"