INSERT INTO volumes (id, name, firstIssue, publisher, description, startYear, numIssues, image, characters_name, concepts_name, characters_id, concepts_id, numLikes) VALUES ('2007', 'Tales of Suspense', 'The Strangers From Space!', '31', '<p>Tales of Suspense was one of several horror-like anthology series that <a href="/marvel/4010-31/" data-ref-id="4010-31">Marvel</a> was publishing in the early 1960''s. The series mainly consisted of one-shot stories about monsters or other horror-like creatures. However, with issue 39 a new road was taken with the debut of a superhero, the <a href="/iron-man/4005-1455/" data-ref-id="4005-1455">Invincible Iron Man</a>. He already soon became the main star of the magazine. With issue 58, <a href="/captain-america/4005-1442/" data-ref-id="4005-1442">Captain America</a> also got a starring role in the series after which the two heroes each had their own 11 page story within Tales of Suspense. In 1968 after ninety-nine issues, the series was renamed and became <a href="/captain-america-vol-1/4050-2400/" data-ref-id="4050-2400">Captain America Vol.1</a> with its hundredth issue. The adventure of the original star of Tales of Suspense, Iron Man, continued in a one-shot alongside Namor the Submariner named <a href="/iron-man-and-sub-mariner/4050-18547/" data-ref-id="4050-18547">Iron Man And Sub-Mariner</a> before he received his own series called <a href="/iron-man-vol-1/4050-2407/" data-ref-id="4050-2407">Iron Man Vol. 1</a> which continued for 332 issues.</p><h4>Collected Editions</h4><ul><li><a href="/marvel-masterworks-atlas-era-tales-of-suspense-1-v/4000-394428/" data-ref-id="4000-394428">Marvel Masterworks: Atlas Era Tales of Suspense Vol. 1</a> (#1-10)</li><li><a href="/marvel-masterworks-atlas-era-tales-of-suspense-2-v/4000-394442/" data-ref-id="4000-394442">Marvel Masterworks: Atlas Era Tales of Suspense Vol. 2</a> (#11-#20)</li><li><a href="/marvel-masterworks-atlas-era-tales-of-suspense-3-v/4000-394444/" data-ref-id="4000-394444">Marvel Masterworks: Atlas Era Tales of Suspense Vol. 3</a> (#21-#31)</li><li><a href="https://comicvine.gamespot.com/marvel-august-1961-omnibus/4050-138275/">Marvel: August 1961 Omnibus</a> (#23)</li><li><a href="/iron-man-epic-collection-the-golden-avenger/4050-77896/" data-ref-id="4050-77896">Iron Man Epic Collection: The Golden Avenger</a> (#39-72)</li><li><a href="https://comicvine.gamespot.com/black-widow-the-sting-of-the-widow/4050-28946/">Black Widow: The Sting of the Widow</a> (#52)</li><li><a href="/marvel-masterworks-captain-america-1-volume-1/4000-233674/" data-ref-id="4000-233674">Marvel Masterworks: Captain America Vol. 1</a> (#59-81)</li><li><a href="/marvel-masterworks-captain-america-2-volume-2/4000-336526/" data-ref-id="4000-336526">Marvel Masterworks: Captain America Vol. 2</a> (#82-99)</li><li><a href="/marvel-masterworks-the-invincible-iron-man-1-volum/4000-232085/" data-ref-id="4000-232085">Marvel Masterworks: Iron Man Vol. 1</a> (#39-50)</li><li><a href="/marvel-masterworks-the-invincible-iron-man-2-volum/4000-232088/" data-ref-id="4000-232088">Marvel Masterworks: Iron Man Vol. 2</a> (#51-65)</li><li><a href="https://comicvine.gamespot.com/iron-mancaptain-america/4050-34683/">Iron Man/Captain America</a> (#58)</li><li><a href="https://comicvine.gamespot.com/captain-america-omnibus-1-volume-1/4000-274607/" data-ref-id="4000-274607">Captain America Omnibus Volume 1</a> (#59-99)</li><li><a href="/kingsize-kirby/4050-83141/" data-ref-id="4050-83141">King-Size Kirby</a> (#59)</li><li><a href="/marvel-masterworks-the-invincible-iron-man-3-volum/4000-232095/" data-ref-id="4000-232095">Marvel Masterworks: Iron Man Vol. 3</a> (#66-83)</li><li><a href="https://comicvine.gamespot.com/iron-man-epic-collection-by-force-of-arms/4050-98341/" data-ref-id="4050-98341">Iron Man Epic Collection: By Force of Arms</a> (#73-99)</li><li><a href="/shield-by-lee-kirby-the-complete-collection/4050-85052/" data-ref-id="4050-85052">S.H.I.E.L.D. by Lee &amp; Kirby: The Complete Collection</a> (#78)</li><li><a href="/shield-the-complete-collection/4050-85133/" data-ref-id="4050-85133">S.H.I.E.L.D.: The Complete Collection</a> (#78)</li><li><a href="/marvel-masterworks-the-invincible-iron-man-4-volum/4000-232096/" data-ref-id="4000-232096">Marvel Masterworks: Iron Man Vol. 4</a> (#84-99)</li><li><a href="https://comicvine.gamespot.com/captain-america-epic-collection-the-coming-of-the-/4050-94262/" data-ref-id="4050-94262">Captain America Epic Collection: The Coming of... The Falcon</a> (#97-99)</li></ul><h4>Non-U.S. Collected Editions</h4><ul><li><a href="https://comicvine.gamespot.com/visionarios-marvel-stan-lee/4050-95780/" data-ref-id="4050-95780">Visionarios Marvel: Stan Lee</a> (#29) (Spanish)</li><li><a href="https://comicvine.gamespot.com/coleccionable-marvel-heroes-22-viuda-negra-red-de-/4000-612227/">Coleccionable Marvel Héroes: Viuda Negra: Red de intrigas</a> (#52) (Spanish)</li><li><a href="https://comicvine.gamespot.com/marvel-gold-capitan-america-1-la-leyenda-viviente/4000-631292/">Marvel Gold. Capitán América - La leyenda viviente</a> (#58-99) (Spanish)</li><li><a href="https://comicvine.gamespot.com/kingsize-kirby/4050-104017/" data-ref-id="4050-104017">King-Size Kirby</a> (#59) (Spanish)</li><li><a href="https://comicvine.gamespot.com/die-captain-america-anthologie/4050-120108/">Die Captain America-Anthologie </a>(#63) (German)</li></ul><p>Issues <a href="https://comicvine.gamespot.com/biblioteca-marvel-iron-man/4050-41951/" data-ref-id="4050-41951">#39-99</a> have been translated into Spanish.</p>', '1959', '99', '{''icon_url'': ''https://comicvine.gamespot.com/a/uploads/square_avatar/11/117763/2678712-talesofsuspense01.jpg'', ''medium_url'': ''https://comicvine.gamespot.com/a/uploads/scale_medium/11/117763/2678712-talesofsuspense01.jpg'', ''screen_url'': ''https://comicvine.gamespot.com/a/uploads/screen_medium/11/117763/2678712-talesofsuspense01.jpg'', ''screen_large_url'': ''https://comicvine.gamespot.com/a/upl