INSERT INTO volumes (id, name, firstIssue, publisher, description, startYear, numIssues, image, characters_name, concepts_name, characters_id, concepts_id, numLikes) VALUES ('2008', 'Tales to Astonish', 'We Found The Ninth Wonder Of The World', '31', '<p>Tales to Astonish was originally one of several anthology comics published by Marvel in the early 1960''s that mainly featured monster and horror stories. In issue 27 of the series, <a href="/hank-pym/4005-2247/" data-ref-id="4005-2247">Hank Pym</a> made his debut as "The Man in the Ant-Hill", what seemed to be just another one-shot horror story. However, soon Hank Pym would star in the series once more as <a href="/hank-pym/4005-2247/" data-ref-id="4005-2247">Ant-Man</a>, debuting as such in issue 35.</p><p>Later <a href="/hulk/4005-2267/" data-ref-id="4005-2267">The Incredible Hulk</a> joined the book with Ant-Man in issue 59, a year after his own series <a href="/the-incredible-hulk/4050-2077/" data-ref-id="4050-2077">The Incredible Hulk Vol.1</a> was cancelled. With issue 70, the <a href="/namor/4005-1476/" data-ref-id="4005-1476">Sub-Mariner</a> took over Ant-Man/Giant-Man''s place in the book. Hulk however remained a main-stay in the series and that is why, after 101 issues, the series changed its name to <a href="/the-incredible-hulk/4050-2406/" data-ref-id="4050-2406">The Incredible Hulk Vol.2</a> with issue 102. Namor''s adventure continued in a one-shot alongside Iron Man named <a href="/iron-man-and-sub-mariner/4050-18547/" data-ref-id="4050-18547">Iron Man And Sub-Mariner</a> before he received his own series called <a href="/sub-mariner/4050-2413/" data-ref-id="4050-2413">Sub-Mariner Vol.1</a>.</p><h4>Collected Editions</h4><ul><li><a href="/annihilation-classic/4050-30933/" data-ref-id="4050-30933">Annihilation Classic</a> (#13)</li><li><a href="https://comicvine.gamespot.com/marvel-august-1961-omnibus/4050-138275/">Marvel: August 1961 Omnibus</a> (#25)</li><li><a href="/marvel-masterworks-ant-mangiant-man-1-volume-1/4000-394299/" data-ref-id="4000-394299">Marvel Masterworks: Ant-Man/Giant Man</a> Vol. 1 (#27 &amp; 35-52)</li><li><a href="/ant-man-ant-iversary/4050-148658/" data-ref-id="4050-148658">Ant-Man: Ant-Iversary</a> (#37 &amp; 43)</li><li><a href="/marvel-masterworks-ant-mangiant-man-2-volume-2/4000-394301/" data-ref-id="4000-394301">Marvel Masterworks: Ant-Man/Giant Man</a> Vol. 2 (#53-69)</li><li><a href="/marvel-masterworks-the-incredible-hulk-volume-two/4000-233677/" data-ref-id="4000-233677">Marvel Masterworks: Incredible Hulk Vol. 2</a> (#60-79)</li><li><a href="/marvel-masterworks-the-sub-mariner-volume-one/4000-232261/" data-ref-id="4000-232261">Marvel Masterworks: Sub-Mariner Vol. 1</a> (#70-87)</li><li><a href="https://comicvine.gamespot.com/namor-the-sub-mariner-epic-collection-enter-the-su/4050-135436/">Namor, The Sub-Mariner Epic Collection: Enter The Sub-Mariner</a> (#70-76)</li><li><a href="/marvel-masterworks-the-incredible-hulk-volume-three/4000-391871/" data-ref-id="4000-391871">Marvel Masterworks: Incredible Hulk Vol. 3</a> (#80-101)</li><li><a href="/marvel-masterworks-the-sub-mariner-volume-two/4000-232081/" data-ref-id="4000-232081">Marvel Masterworks: Sub-Mariner Vol. 2</a> (#88-101)</li><li><a href="https://comicvine.gamespot.com/incredible-hulk-hulk-vs-the-marvel-universe/4050-31010/">Incredible Hulk: Hulk vs the Marvel Universe</a> (#92-93)</li></ul><h4>Non-U.S. Collected Editions</h4><ul><li><a href="https://comicvine.gamespot.com/los-vengadores-el-hombre-hormiga-y-la-avispa/4050-103955/">Los Vengadores: El Hombre Hormiga y La Avispa</a> (#27, #35 &amp; #44) (Spanish)</li><li><a href="https://comicvine.gamespot.com/80-jahre-marvel-3-die-1960er-aufbruch-in-eine-neue/4000-713394/">80 Jahre Marvel - Die 1960er: Aufbruch in eine neue Zeit </a>(#57) (German)</li><li><a href="https://comicvine.gamespot.com/visionarios-marvel-stan-lee/4050-95780/" data-ref-id="4050-95780">Marvel Gold. El Increíble Hulk</a> (#59-101) (Hulk stories) (Spanish)</li><li><a href="https://comicvine.gamespot.com/visionarios-marvel-stan-lee/4050-95780/" data-ref-id="4050-95780">Visionarios Marvel: Stan Lee</a> (#92-93) (Spanish)</li></ul><p>Issues <a href="https://comicvine.gamespot.com/biblioteca-marvel-namor/4050-41964/" data-ref-id="4050-41964">#70-101</a> have been translated into Spanish.</p>', '1959', '101', '{''icon_url'': ''https://comicvine.gamespot.com/a/uploads/square_avatar/11/117763/2615591-talestoastonish001.jpg'', ''medium_url'': ''https://comicvine.gamespot.com/a/uploads/scale_medium/11/117763/2615591-talestoastonish001.jpg'', ''screen_url'': ''https://comicvine.gamespot.com/a/uploads/screen_medium/11/117763/2615591-talestoastonish001.jpg'', ''screen_large_url'': ''https://comicvine.gamespot.com/a/uploads/screen_kubrick/11/117763/2615591-talestoastonish001.jpg'', ''small_url'': ''https://comicvine.gamespot.com/a/uploads/scale_small/11/117763/2615591-talestoastonish001.jpg'', ''super_url'': ''https://comicvine.gamespot.com/a/uploads/scale_large/11/117763/2615591-talestoastonish001.jpg'', ''thumb_url'': ''https://comicvine.gamespot.com/a/uploads/scale_avatar/11/117763/2615591-talestoastonish001.jpg'', ''tiny_url'': ''https://comicvine.gamespot.com/a/uploads/square_mini/11/117763/2615591-talestoastonish001.jpg'', ''original_url'': ''https://comicvine.gamespot.com/a/uploads/original/11/117763/2615591-talestoastonish001.jpg'', ''image_tags'': ''All Images''}', '[{"id": "Hulk"}, {"id": "Hank Pym"}, {"id": "Glenn Talbot"}, {"id": "Namor"}, {"id": "Thunderbolt Ross"}, {"id": "Wasp"}, {"id": "Betty Ross"}, {"id": "Dorma"}, {"id": "Rick Jones"}, {"id": "Vashti"}, {"id": "Krang"}, {"id": "Leader"}, {"id": "Boomerang"}, {"id": "Chameleon"}, {"id": "Whirlwind"}, {"id": "Parnival Plunder"}, {"id": "Egghead"}, {"id": "Puppet Master"}, {"id": "Neptune"}, {"id": "Attuma"}, {"id": "Number One"}, {"id": "Captain America"}, {"id": "Iron Man"}, {"id": "Tyrannus"}, {"id": "Abomination"}, {"id": "Watcher"}, {"id": "Stranger"}, 