INSERT INTO volumes (id, name, firstIssue, publisher, description, startYear, numIssues, image, characters_name, concepts_name, characters_id, concepts_id, numLikes) VALUES ('2113', 'Metal Men', 'Rain of the Missile Men!', '10', '<p>The Metal Men were created by Dr Will Magnus in order to help fight evil. This series records the adventures of Gold, Iron, Lead, Mercury, Platinum and Tin as they seek to do just that. </p><p><em>The original </em>Metal Men <em>series which ran for 41 issues from 1963-1970, returned three years later in 1973 with three experimental reprint issues and continued the numbering with #42-#45</em>.</p><p><em>After being quickly cancelled yet again after the reprint issues</em>, another three years passed and the series returned with new stories and art with issues 45-56 from 1976-1978 untii the DC Implosion of 1978 cancelled this run of the the Metal Men for the final time.</p><p> </p>', '1963', '56', '{''icon_url'': ''https://comicvine.gamespot.com/a/uploads/square_avatar/0/4/5888-2113-6443-1-metal-men.jpg'', ''medium_url'': ''https://comicvine.gamespot.com/a/uploads/scale_medium/0/4/5888-2113-6443-1-metal-men.jpg'', ''screen_url'': ''https://comicvine.gamespot.com/a/uploads/screen_medium/0/4/5888-2113-6443-1-metal-men.jpg'', ''screen_large_url'': ''https://comicvine.gamespot.com/a/uploads/screen_kubrick/0/4/5888-2113-6443-1-metal-men.jpg'', ''small_url'': ''https://comicvine.gamespot.com/a/uploads/scale_small/0/4/5888-2113-6443-1-metal-men.jpg'', ''super_url'': ''https://comicvine.gamespot.com/a/uploads/scale_large/0/4/5888-2113-6443-1-metal-men.jpg'', ''thumb_url'': ''https://comicvine.gamespot.com/a/uploads/scale_avatar/0/4/5888-2113-6443-1-metal-men.jpg'', ''tiny_url'': ''https://comicvine.gamespot.com/a/uploads/square_mini/0/4/5888-2113-6443-1-metal-men.jpg'', ''original_url'': ''https://comicvine.gamespot.com/a/uploads/original/0/4/5888-2113-6443-1-metal-men.jpg'', ''image_tags'': ''All Images''}', '[{"id": "Iron"}, {"id": "Lead"}, {"id": "Mercury"}, {"id": "Gold"}, {"id": "Tin"}, {"id": "Platinum"}, {"id": "Will Magnus"}, {"id": "Nameless"}, {"id": "Chemo"}, {"id": "The Sizzler"}, {"id": "King of the Missle Men"}, {"id": "Plutonium Man"}, {"id": "Chloroform"}, {"id": "Helium"}, {"id": "Oxygen"}, {"id": "Carbon Dioxide"}, {"id": "Carbon Monoxide"}, {"id": "Inheritor"}, {"id": "Timmy"}, {"id": "Professor Snakelocks"}, {"id": "Cap"}, {"id": "Mona Bennett"}, {"id": "Hal Jordan"}, {"id": "Bruce Gordon"}, {"id": "Eclipso"}, {"id": "Wonder Woman"}, {"id": "Colonel Henry Caspar"}, {"id": "Fferka"}, {"id": "Alloy"}, {"id": "Copper"}, {"id": "Chaselon"}, {"id": "Robot Doc Magnus"}, {"id": "Dr. Ramsey Norton"}, {"id": "Balloonatic"}, {"id": "Giant Robot Queen"}, {"id": "Professor Bravo"}, {"id": "Solar Brain"}, {"id": "Skyscraper Robot"}, {"id": "Iron Girl"}, {"id": "King Dymond"}, {"id": "Dick Grayson"}, {"id": "Mercury Girl"}, {"id": "Batman"}, {"id": "Steve Trevor"}, {"id": "Barry Allen"}, {"id": "Poseidon"}, {"id": "Baroness Paula Von Gunther"}, {"id": "Floating Fury"}, {"id": "Platinum Man"}, {"id": "Gold Girl"}, {"id": "Plutonium"}, {"id": "Lead Girl"}, {"id": "The Lizard"}, {"id": "Tin Amazon"}, {"id": "Barium"}, {"id": "Aluminum"}, {"id": "Calcium"}, {"id": "Zirconium"}, {"id": "Sodium"}]', '[{"id": "DC Explosion and Implosion"}]', '[{"id": 10017}, {"id": 12702}, {"id": 13682}, {"id": 13683}, {"id": 13684}, {"id": 13685}, {"id": 9536}, {"id": 37305}, {"id": 10004}, {"id": 38577}, {"id": 81405}, {"id": 68910}, {"id": 34938}, {"id": 35378}, {"id": 35379}, {"id": 35380}, {"id": 35381}, {"id": 135278}, {"id": 39110}, {"id": 38576}, {"id": 38830}, {"id": 12934}, {"id": 11202}, {"id": 3764}, {"id": 3763}, {"id": 2048}, {"id": 39400}, {"id": 67255}, {"id": 57846}, {"id": 55922}, {"id": 46423}, {"id": 82065}, {"id": 39426}, {"id": 67362}, {"id": 82063}, {"id": 195725}, {"id": 82080}, {"id": 82082}, {"id": 94832}, {"id": 174070}, {"id": 1691}, {"id": 32803}, {"id": 1699}, {"id": 15789}, {"id": 22804}, {"id": 23356}, {"id": 23778}, {"id": 32798}, {"id": 32800}, {"id": 32802}, {"id": 39284}, {"id": 32804}, {"id": 38578}, {"id": 39207}, {"id": 39279}, {"id": 39280}, {"id": 39281}, {"id": 39282}, {"id": 39283}]', '[{"id": 56163}]', '0');
INSERT INTO volumes (id, name, firstIssue, publisher, description, startYear, numIssues, image, characters_name, concepts_name, characters_id, concepts_id, numLikes) VALUES ('2127', 'The Amazing Spider-Man', 'Spider-Man; Spider-Man Vs. The Chameleon', '31', '<figure data-align="right" data-size="small" data-ref-id="1300-78670" data-img-src="https://static.comicvine.com/uploads/original/0/394/78670-5533-105342-1-amazing-fantasy.jpg" data-ratio="1.5075" data-width="400" data-embed-type="image" style="width: 400px"><a class="fluid-height" style="padding-bottom:150.8%" href="https://static.comicvine.com/uploads/original/0/394/78670-5533-105342-1-amazing-fantasy.jpg" data-ref-id="1300-78670"><img alt="No Caption Provided" src="https://comicvine.gamespot.com/a/uploads/original/0/394/78670-5533-105342-1-amazing-fantasy.jpg" srcset="https://comicvine.gamespot.com/a/uploads/original/0/394/78670-5533-105342-1-amazing-fantasy.jpg 400w" sizes="(max-width: 424px) 100vw, 424px" data-width="424"></a></figure><p>After the success of <a href="/amazing-fantasy/4050-5533/" data-ref-id="4050-5533">Amazing Fantasy #15</a> (Aug. 1962) a few months later the same creative team came back to start an ongoing series focusing on the character the two of them created.</p><p>The series continued until <a href="/the-amazing-spider-man-441-the-final-chapter-part-/4000-64477/" data-ref-id="4000-64477">#441</a> (Nov. 1998) when Marvel relaunched the title as <a href="https://www.comicvine.com/the-amazing-spiderman/4050-78701/" data-ref-id="4050-78701">Amazing Spider-Man Volume 2</a> with a new #1 in January 1999, but after issue <a href="/the-amazing-spider-man-30-transformations-literal-/4000-113461/" data-ref-id="4000-113461">#30</a> <em>(#471)</em> Marvel began to use a dual numbering system. And then on the 40th anniversary the numbering was returned again from issue <a href="/the-amazing-spider-man-58-happy-birthday-part-2/4000-113489/" data-ref-id="4000-113489">#58</a> to <a href="/the-amazing-spider-man-500-happy-birthday-part-3/4000-107505/" data-ref-id="4000-107505">#500</a> (Dec. 2003) as Amazing Spider-Man Volume 1.</p><p>This volume ends with <a href="/the-amazing-spider-man-700-dying-wish-suicide-run-/4000-373805/" data-ref-id="4000-373805">#700</a> and is picked up by the <a href="/marvel-now/4015-56129/" data-ref-id="4015-56129">Marvel Now!</a> revolution volume <a href="/superior-spider-man/4050-55552/" data-ref-id="4050-55552">Superior Spider-Man</a>.</p><h2>Writers</h2><ul><li><strong><a href="/stan-lee/4040-40467/" data-ref-id="4040-40467">Stan Lee</a></strong>: #1-110, 200, 365, 400, 600, 634-644, 700 <strong>(TOT 125)</strong></li><li><strong><a href="/gerry-conway/4040-40871/" data-ref-id="4040-40871">Gerry Conway</a></strong>: #111-149 <strong>(TOT 39)</strong></li><li><a href="/archie-goodwin/4040-42923/" data-ref-id="4040-42923">Archie Goodwin</a>: #150, 181</li><li><strong><a href="/len-wein/4040-41457/" data-ref-id="4040-41457">Len Wein</a></strong>: #151-180 <strong>(TOT 30)</strong></li><li><a href="/marv-wolfman/4040-41478/" data-ref-id="4040-41478"><strong>Marv Wolfman</strong></a>: #182-204 <strong>(TOT 23)</strong></li><li><a href="/david-michelinie/4040-40650/" data-ref-id="4040-40650"><strong>David Michelinie</strong></a>: #205, 290-292, 296-352, 359-388 <strong>(TOT 90)</strong></li><li><strong><a href="https://comicvine.gamespot.com/roger-stern/4040-41502/" data-ref-id="4040-41502">Roger Stern</a></strong>: #206, 224-227, 229-252, 580, 627-629 <strong>(TOT 29)</strong></li><li><a href="/dennis-oneil/4040-40861/" data-ref-id="4040-40861">Dennis O''Neil</a>: #207-219, 221-223</li><li><a href="/tom-defalco/4040-41037/" data-ref-id="4040-41037"><strong>Tom DeFalco</strong></a>: #-1, 251-261, 263, 265, 268-269, 271-273, 276-285, 365, 375, 407-439 <strong>(TOT 64)</strong></li><li><a href="/christopher-priest/4040-41500/" data-ref-id="4040-41500">Christopher Priest</a>: #284-288</li><li><a href="https://comicvine.gamespot.com/peter-david/4040-40682/" data-ref-id="4040-40682">Peter David</a>: #266-267, 278, 289, 525</li><li><a href="/ann-nocenti/4040-42297/" data-ref-id="4040-42297">Ann Nocenti</a>: #295</li><li><strong><a href="https://comicvine.gamespot.com/jm-dematteis/4040-41043/" data-ref-id="4040-41043">J. M. DeMatteis</a></strong>: #223, 293-294, 368-370, 373, 389-406, 634-637, 700 <strong>(TOT 25)</strong></li><li><a href="/john-byrne/4040-1770/" data-ref-id="4040-1770">John Byrne</a>: #440-441</li><li><strong><a href="https://comicvine.gamespot.com/j-michael-straczynski/4040-40683/" data-ref-id="4040-40683">J. Michael Straczynski</a></strong>: #571-545 <strong>(TOT 73)</strong></li><li><a href="https://comicvine.gamespot.com/reginald-hudlin/4040-41772/" data-ref-id="4040-41772">Reginald Hudlin</a>: #526</li><li><strong><a href="https://comicvine.gamespot.com/dan-slott/4040-41786/" data-ref-id="4040-41786">Dan Slott</a></strong>: #546-548, 559-561, 564, 568-573, 581-582, 590-591, 600, 618-621, 647-660, 662-700 <strong>(TOT 77)</strong></li><li><strong><a href="https://comicvine.gamespot.com/marc-guggenheim/4040-42339/" data-ref-id="4040-42339">Marc Guggenheim</a></strong>: #549-551, 564-567, 574, 584-588, 600, 608-610, 647 <strong>(TOT 19)</strong></li><li><a href="https://comicvine.gamespot.com/bob-gale/4040-48783/" data-ref-id="4040-48783">Bob Gale</a>: #552-554, 558, 562-564, 600, 647</li><li><a href="https://comicvine.gamespot.com/zeb-wells/4040-43083/" data-ref-id="4040-43083">Zeb Wells</a>: #555-557, 577, 583, 600, 629-633, 647</li><li><strong><a href="https://comicvine.gamespot.com/mark-waid/4040-40724/" data-ref-id="4040-40724">Mark Waid</a></strong>: #568, 573, 578-579, 583, 592-601, 612-614, 623-624, 628, 642-647, 677 <strong>(TOT 23)</strong></li><li><strong><a href="https://comicvine.gamespot.com/joe-kelly/4040-40982/" data-ref-id="4040-40982">Joe Kelly</a></strong>: #575-577, 595-600, 606-607, 611-612, 617, 625, 634-636 <strong>(TOT 20)</strong></li><li><a href="https://comicvine.gamespot.com/fred-van-lente/4040-44637/" data-ref-id="4040-44637">Fred Van Lente</a>: #589, 602-605, 615-616, 622, 626, 647, 652-654, 659, 560, 692</li><li><a href="/brian-reed/4040-41608/" data-ref-id="4040-41608">Brian Reed</a>: #605, #700.5</li><li><a href="https://comicvine.gamespot.com/greg-weisman/4040-55699/" data-ref-id="4040-55699">Greg Weisman</a>: #622</li><li><a href="https://comicvine.gamespot.com/paul-tobin/4040-44634/" data-ref-id="4040-44634">Paul Tobin</a>: #647</li><li><a href="https://comicvine.gamespot.com/christos-n-gage/4040-41687/" data-ref-id="4040-41687">Christos Gage</a>: #661-662, 664, 695-697</li><li><a href="https://comicvine.gamespot.com/christopher-yost/4040-40897/" data-ref-id="4040-40897">Christopher Yost</a>: #680-681, 679.1</li><li><a href="/david-morrell/4040-46548/" data-ref-id="4040-46548">David Morrell</a>: #700.1-700.2</li><li><a href="/joe-casey/4040-41023/" data-ref-id="4040-41023">Joe Casey</a>: #700.3-700.4</li></ul><h2>Collected Editions</h2><h4><strong>Marvel Masterworks:</strong></h4><ul><li><a href="https://comicvine.gamespot.com/marvel-masterworks-the-amazing-spider-man-volume-one/4000-140400/" data-ref-id="4000-140400">Vol. 1</a> (#1-10)</li><li><a href="https://comicvine.gamespot.com/marvel-masterworks-the-amazing-spider-man-volume-two/4000-140399/" data-ref-id="4000-140399">Vol. 2</a> (#11-19)</li><li><a href="https://comicvine.gamespot.com/marvel-masterworks-the-amazing-spider-man-volume-three/4000-140398/" data-ref-id="4000-140398">Vol. 3</a> (#20-30)</li><li><a href="https://comicvine.gamespot.com/marvel-masterworks-the-amazing-spider-man-volume-four/4000-140397/" data-ref-id="4000-140397">Vol. 4</a> (#31-40)</li><li><a href="https://comicvine.gamespot.com/marvel-masterworks-the-amazing-spider-man-volume-five/4000-140396/" data-ref-id="4000-140396">Vol. 5</a> (#41-50)</li><li><a href="https://comicvine.gamespot.com/marvel-masterworks-the-amazing-spider-man-volume-six/4000-140391/" data-ref-id="4000-140391">Vol. 6</a> (#51-61)</li><li><a href="https://comicvine.gamespot.com/marvel-masterworks-the-amazing-spider-man-volume-seven/4000-140392/" data-ref-id="4000-140392">Vol. 7</a> (#62-67)</li><li><a href="https://comicvine.gamespot.com/marvel-masterworks-the-amazing-spider-man-volume-eight/4000-140393/" data-ref-id="4000-140393">Vol. 8</a> (#68-77)</li><li><a href="https://comicvine.gamespot.com/marvel-masterworks-the-amazing-spider-man-volume-nine/4000-140394/" data-ref-id="4000-140394">Vol. 9</a> (#78-87)</li><li><a href="https://comicvine.gamespot.com/marvel-masterworks-the-amazing-spider-man-volume-ten/4000-140395/" data-ref-id="4000-140395">Vol. 10</a> (#88-99)</li><li><a href="https://comicvine.gamespot.com/marvel-masterworks-the-amazing-spider-man-volume-eleven/4000-232118/" data-ref-id="4000-232118">Vol. 11</a> (#100-109)</li><li><a href="https://comicvine.gamespot.com/marvel-masterworks-the-amazing-spider-man-volume-twelve/4000-264613/" data-ref-id="4000-264613">Vol. 12</a> (#110-120)</li><li><a href="https://comicvine.gamespot.com/marvel-masterworks-the-amazing-spider-man-volume-thirteen/4000-264614/" data-ref-id="4000-264614">Vol. 13</a> (#121-131)</li><li><a href="https://www.comicvine.com/marvel-masterworks-the-amazing-spider-man-14-volum/4000-395033/" data-ref-id="4000-395033">Vol. 14</a> (#132-142)</li><li><a href="https://www.comicvine.com/marvel-masterworks-the-amazing-spider-man-15-volum/4000-395034/" data-ref-id="4000-395034">Vol. 15</a> (#143-155)</li><li><a href="https://www.comicvine.com/marvel-masterworks-the-amazing-spider-man-16-volum/4000-451339/" data-ref-id="4000-451339">Vol. 16</a> (#156-168)</li><li><a href="https://comicvine.gamespot.com/marvel-masterworks-the-amazing-spider-man-17-volum/4000-508624/" data-ref-id="4000-508624">Vol. 17</a> (#169-180)</li><li><a href="https://comicvine.gamespot.com/marvel-masterworks-the-amazing-spider-man-18-volum/4000-566715/" data-ref-id="4000-566715">Vol. 18</a> (#181-192</li><li><a href="https://co