INSERT INTO volumes (id, name, firstIssue, publisher, description, startYear, numIssues, image, characters_name, concepts_name, characters_id, concepts_id, numLikes) VALUES ('2128', 'The Avengers', 'The Coming of the Avengers', '31', '<p>The first Avengers ongoing series, the one that started the Earth''s Mightiest Heroes'' campaign for justice and freedom. They will save the world, and if they can''t, they will avenge it. And there came a day, a day unlike any other when Earth''s mightiest heroes joined forces to face the threats no single superhero could withstand! The Avengers were born!</p><p>The first volume of the Avengers lasted from 1963 until 1996 and ran for 402 issues. This ended during the <a href="/onslaught/4045-43814/" data-ref-id="4045-43814">Onslaught</a> storyline and was continued in <a href="/avengers/4050-6742/" data-ref-id="4050-6742">Avengers Volume 2</a>.</p><h4>Collected Editions</h4><p><a href="/marvel-masterworks-avengers/4050-23401/" data-ref-id="4050-23401">Marvel Masterworks: Avengers</a></p><ul><li><a href="https://www.comicvine.com/marvel-masterworks-avengers-1-volume-one/4000-140582/" data-ref-id="4000-140582">Vol. 1</a> (#1-10)</li><li><a href="https://www.comicvine.com/marvel-masterworks-avengers-2-volume-two/4000-140583/" data-ref-id="4000-140583">Vol. 2</a> (#11-20)</li><li><a href="https://www.comicvine.com/marvel-masterworks-avengers-3-volume-three/4000-140584/" data-ref-id="4000-140584">Vol. 3</a> (#21-30)</li><li><a href="https://www.comicvine.com/marvel-masterworks-avengers-4-volume-four/4000-140387/" data-ref-id="4000-140387">Vol. 4</a> (#31-40)</li><li><a href="https://www.comicvine.com/marvel-masterworks-avengers-5-volume-five/4000-140388/" data-ref-id="4000-140388">Vol. 5</a> (#41-50, King-Size Special #1)</li><li><a href="https://www.comicvine.com/marvel-masterworks-avengers-6-volume-six/4000-140389/" data-ref-id="4000-140389">Vol. 6</a> (#51-58, King-Size Special #2)</li><li><a href="https://www.comicvine.com/marvel-ma