INSERT INTO volumes (id, name, firstIssue, publisher, description, startYear, numIssues, image, characters_name, concepts_name, characters_id, concepts_id, numLikes) VALUES ('2129', 'Fantastic Four Annual', 'Sub-Mariner Versus the Human Race!; The Fabulous Fantastic Four Meet Spider-Man!; The Fantastic Four', '31', '<p>Annual for <a href="https://comicvine.gamespot.com/fantastic-four/4050-2045/" data-ref-id="4050-2045">Fantastic Four</a>.</p><p>The series ran from 1963-1994 for twenty-seven issues. From 1995 til 1997 there was no annual for this series. From 1998 til 2001 the FF annual''s had unique indicia titles;</p><ul><li><a href="//www.comicvine.com/fantastic-four-fantastic-4-98/4050-60493/" data-ref-id="4050-60493">Fantastic Four / Fantastic 4 ''98</a></li><li><a href="//www.comicvine.com/fantastic-four-1999/4050-60494/" data-ref-id="4050-60494">Fantastic Four 1999</a></li><li><a href="//www.comicvine.com/fantastic-four-2000/4050-60495/" data-ref-id="4050-60495">Fantastic Four 2000</a></li><li><a href="//www.comicvine.com/fantastic-four-2001/4050-60496/" data-ref-id="4050-60496">Fantastic Four 2001</a></li></ul><p>The series resumed in 2010 with issue #32. A new <a href="https://www.comicvine.com/fantastic-four-annual/4050-77247/">Fantastic Four Annual </a>series started in 2014 with a new number 1.</p><h4>Collected Editions</h4><ul><li><a href="/marvel-masterworks-the-fantastic-four-2-volume-two/4000-232241/" data-ref-id="4000-232241">Marvel Masterworks: Fantastic Four Vol. 2</a> (#1)</li><li><a href="https://comicvine.gamespot.com/namor-the-sub-mariner-epic-collection-enter-the-su/4050-135436/">Namor, The Sub-Mariner Epic Collection: Enter The Sub-Mariner</a> (#1)</li><li><a href="https://comicvine.gamespot.com/fantastic-four-epic-collection-the-master-plan-of-/4050-102458/" data-ref-id="4050-102458">Fantastic Four Epic Collection: The Master Plan of Doctor Doom</a> (#1-2)</li><li><a href="/marvel-masterworks-the-fantastic-four-4-volume-fou/4000-232243/" data-ref-id="4000-232243">Marvel Masterworks: Fantastic Four, Vol. 4</a> (#2)</li><li><a href="/marvel-masterworks-the-fantastic-four-5-volume-fiv/4000-232244/" data-ref-id="4000-232244">Marvel Masterworks: Fantastic Four, Vol. 5</a> (#3)</li><li><a href="https://comicvine.gamespot.com/fantastic-four-epic-collection-the-coming-of-galac/4050-112582/">Fantastic Four Epic Collection: The Coming of Galactus</a> (#3)</li><li><a href="https://comicvine.gamespot.com/marvel-weddings/4050-137619/">Marvel Weddings</a> (#3)</li><li><a href="/marvel-masterworks-the-fantastic-four-6-volume-six/4000-232080/" data-ref-id="4000-232080">Marvel Masterworks: Fantastic Four, Vol. 6</a> (#4)</li><li><a href="https://comicvine.gamespot.com/fantastic-four-epic-collection-the-mystery-of-the-/4050-120815/">Fantastic Four Epic Collection: The Mystery of the Black Panther</a> (#4-5)</li><li><a href="/marvel-masterworks-the-fantastic-four-7-volume-sev/4000-232245/" data-ref-id="4000-232245">Marvel Masterworks: Fantastic Four, Vol. 7</a> (#5)</li><li><a href="/kingsize-kirby/4050-83141/" data-ref-id="4050-83141">King-Size Kirby </a>(#5)</li><li><a href="https://www.comicvine.com/fantastic-four-omnibus-3-volume-three/4000-487393/" data-ref-id="4000-487393">Fantastic Four Omnibus Vol. 3</a> (#5-7)</li><li><a href="https://comicvine.gamespot.com/kirby-is-fantastic/4050-119384/">Kirby Is... Fantastic!</a> (#6)</li><li><a href="https://comicvine.gamespot.com/fantastic-four-epic-collection-the-name-is-doom/4050-126609/">Fantastic Four Epic Collection: The Name Is Doom</a> (#6)</li><li><a href="https://comicvine.gamespot.com/fantastic-four-epic-collection-at-war-with-atlanti/4050-131537/">Fantastic Four Epic Collection: At War With Atlantis</a> (#7)</li><li><a href="https://comicvine.gamespot.com/marvel-masterworks-marvel-two-in-one-2-volume-2/4000-621669/" data-ref-id="4000-621669">Marvel Masterworks: Marvel Two-In-One vol. 2</a> (#11)</li><li><a href="https://comicvine.gamespot.com/marvel-masterworks-the-fantastic-four-18-volume-18/4000-549517/" data-ref-id="4000-549517">Marvel Masterworks: Fantastic Four, Vol. 18</a> (#12-13)</li><li><a href="/avengers-the-legacy-of-thanos/4050-74816/" data-ref-id="4050-74816">Avengers: The Legacy of Thanos</a> (#19)</li><li><a href="https://comicvine.gamespot.com/secret-invasion-rise-of-the-skrulls/4050-112466/">Secret Invasion: Rise of the Skrulls</a> (#19)</li><li><a href="https://comicvine.gamespot.com/avengers-vs-fantastic-four/4050-123278/">Avengers vs. Fantastic Four</a> (#19)</li><li><a href="//www.comicvine.com/fantastic-four-epic-collection-all-in-the-family/4050-70951/" data-ref-id="4050-70951">Fantastic Four Epic Collection: All In the Family</a> (#20)</li><li><a href="https://comicvine.gamespot.com/fantastic-four-epic-collection-the-more-things-cha/4050-119753/">Fantastic Four Epic Collection: The More Things Change...</a> (#21)</li><li><a href="https://comicvine.gamespot.com/fantastic-four-epic-collection-into-the-time-strea/4050-76010/" data-ref-id="4050-76010">Fantastic Four Epic Collection: Into the Time Stream</a> (#23)</li><li><a href="//www.comicvine.com/guardians-of-the-galaxy-by-jim-valentino-1-volume-/4000-441868/" data-ref-id="4000-441868">Guardians of the Galaxy By Jim Valentino vol. 1</a> (#24)</li><li><a href="https://comicvine.gamespot.com/fantastic-four-epic-collection-the-new-fantastic-f/4050-111826/">Fantastic Four Epic Collection: The New Fantastic Four</a> (#24)</li><li><a href="https://comicvine.gamespot.com/fantastic-four-epic-collection-this-flame-this-fur/4050-139958/">Fantastic Four Epic Collection: This Flame, This Fury</a> (#25-26)</li><li><a href="https://comicvine.gamespot.com/marvel-tales-by-alan-davis/4050-106204/" data-ref-id="4050-106204">Marvel Tales by Alan Davis</a> (#33)</li><li><a href="https://comicvine.gamespot.com/clandestine-family-ties/4050-113696/">ClanDestine: Family Ties</a> (#33)</li></ul><h4>Non-U.S. Collected Editions</h4><ul><li><a href="https://comicvine.gamespot.co