INSERT INTO volumes (id, name, firstIssue, publisher, description, startYear, numIssues, image, characters_name, concepts_name, characters_id, concepts_id, numLikes) VALUES ('2133', 'The X-Men', 'X-Men', '31', '<p>The comic that started it all for the X-Men. For the first 66 issues, the series starred the team of Cyclops, Marvel Girl, Angel, Beast, Iceman and Professor Xavier, with Havok and Polaris joining near the end of the run.</p><p>Unfortunately, due to falling sales and lack of interest for the comic, the series started publishing reprints from earlier adventures with issue #67. This kept on up to issue #93. With X-Men issue #94, the New X-Men team was brought into the comic after they had starred in their first adventure in <a href="//www.comicvine.com/giant-size-x-men-1-deadly-genesis/4000-14890/" data-ref-id="4000-14890"> Giant-Size X-Men</a> issue #1. Beginning with issue #114 the descriptive "Uncanny" was added to the cover treatment but it wasn''t until issue #142 that the volume''s official name was permanently changed, via the indicia, to Uncanny X-Men. The series continues in <a href="/uncanny-x-men/4050-3092/" data-ref-id="4050-3092"><strong><em>The Uncanny X-Men</em></strong></a> with issue #142.</p><h4>Collected Editions</h4><ul><li><a href="https://comicvine.gamespot.com/x-men-omnibus-1-volume-one/4000-167612/" data-ref-id="4000-167612">X-Men Omnibus Volume 1</a>#1-31</li><li><a href="/marvel-masterworks-the-x-men/4050-35213/" data-ref-id="4050-35213">Marvel Masterworks: X-Men</a> Vol. 1 (#1-10)</li><li><a href="/xmen-epic-collection-children-of-the-atom/4050-79108/" data-ref-id="4050-79108">X-Men Epic Collection: Children of the Atom</a> (#1-23)</li><li><a href="https://comicvine.gamespot.com/x-men-adventures/4050-112834/">X-Men Adventures</a> (#1 &amp; 19)</li><li><a href="https://comicvine.gamespot.com/x-men-we-are-the-x-men/4050-35334/">X-Men: We Are the X-Men</a> (#1 &amp; 129)</li><li><a href="/mighty-marvel-masterworks-the-x-men-1-the-stranges/4000-881496/" data-ref-id="4000-881496">Mighty Marvel Masterworks: The X-Men: The Strangest Super-Heroes of All</a> (#1-10)</li><li><a href="https://comicvine.gamespot.com/namor-the-sub-mariner-epic-collection-enter-the-su/4050-135436/">Namor, The Sub-Mariner Epic Collection: Enter The Sub-Mariner</a> (#6)</li><li><a href="/kingsize-kirby/4050-83141/" data-ref-id="4050-83141">King-Size Kirby</a> (#9)</li><li>Marvel Masterworks: X-Men, Vol. 2 (#11-21)</li><li>Marvel Masterworks: X-Men, Vol. 3 (#22-31)</li><li><a href="https://comicvine.gamespot.com/xmen-epic-collection-lonely-are-the-hunted/4050-96317/" data-ref-id="4050-96317">X-Men Epic Collection: Lonely Are The Hunted</a> (#24-45)</li><li><a href="https://comicvine.gamespot.com/x-men-omnibus-2-volume-two/4000-273105/" data-ref-id="4000-273105">X-Men Omnibus Volume 2</a> #32-66</li><li>Marvel Masterworks: X-Men, Vol. 4 (#32-42)</li><li><a href="https://comicvine.gamespot.com/decades-marvel-in-the-60s-spider-man-meets-the-mar/4050-117580/">Decades: Marvel In the ''60s: Spider-Man Meets the Marvel Universe</a> (#35)</li><li>Marvel Masterworks: X-Men, Vol. 5 (#43-53)</li><li><a href="/avengers-omnibus-2-volume-two/4000-482859/" data-ref-id="4000-482859">Avengers Omnibus Volume 2</a> (#45)</li><li><a href="https://comicvine.gamespot.com/avengers-epic-collection-masters-of-evil/4050-100962/" data-ref-id="4050-100962">Avengers Epic Collection: The Masters of Evil</a> (#45)</li><li><a href="https://comicvine.gamespot.com/x-men-epic-collection-the-sentinels-live/4050-115289/">X-Men Epic Collection: The Sentinels Live</a> (#46-66)</li><li>Marvel Masterworks: X-Men, Vol. 6 (#54-66)</li><li><a href="https://comicvine.gamespot.com/x-men-by-roy-thomas-and-neal-adams-gallery-edition/4050-121265/">X-Men by Roy Thomas &amp; Neal Adams Gallery Edition</a> (#56-57 (A Stories), 58-63 &amp; 65)</li><li><a href="https://comicvine.gamespot.com/uncanny-x-men-omnibus-1-volume-1/4000-167686/" data-ref-id="4000-167686">The Uncanny X-Men Volume 1</a> #94-131</li><li><a href="/marvel-masterworks-the-uncanny-x-men/4050-30807/" data-ref-id="4050-30807">Marvel Masterworks: Uncanny X-Men</a>, Vol. 1 (#94-100)</li><li><a href="https://comicvine.gamespot.com/xmen-epic-collection-second-genesis/4050-100394/" data-ref-id="4050-100394">X-Men Epic Collection: Second Genesis</a> (#94-110)</li><li><a href="https://comicvine.gamespot.com/x-men-the-dark-phoenix-saga-omnibus/4050-112607/">X-Men: The Dark Phoenix Saga Omnibus</a> (#97-105, 107-108 &amp; 125-138)</li><li>Marvel Masterworks: Uncanny X-Men, Vol. 2 (#101-110)</li><li><a href="https://comicvine.gamespot.com/x-men-starjammers-by-dave-cockrum/4050-122501/">X-Men: Starjammers by Dave Cockrum</a> (#107-108)</li><li><a href="https://comicvine.gamespot.com/alpha-flight-by-john-byrne-omnibus/4050-98560/" data-ref-id="4050-98560">Alpha Flight By John Byrne Omnibus</a> (#109, 120-121 &amp; 139-140)</li><li>Marvel Masterworks: Uncanny X-Men, Vol. 3 (#111-121)</li><li><a href="https://comicvine.gamespot.com/x-men-epic-collection-proteus/4050-129905/">X-Men Epic Collection: Proteus</a> (#111-128)</li><li>Marvel Masterworks: Uncanny X-Men, Vol. 4 (#122-131)</li><li><a href="/marvel-masterworks-dazzler-1-volume-1/4000-742426/" data-ref-id="4000-742426">Marvel Masterworks: Dazzler Volume 1</a> (#130-131)</li><li><a href="https://comicvine.gamespot.com/uncanny-x-men-omnibus-2-volume-2/4000-450781/" data-ref-id="4000-450781">The Uncanny X-Men Volume 2</a> #132-141</li><li>Marvel Masterworks: Uncanny X-Men, Vol. 5 (#132-140)</li><li><a href="https://comicvine.gamespot.com/marvel-horror-lives-again-omnibus/4050-131205/">Marvel Horror Lives Again! Omnibus</a> (#13-140)</li><li>Marvel Masterworks: Uncanny X-Men, Vol. 6 (#141-150)</li><li><a href="/x-men-proteus/4050-28480/" data-ref-id="4050-28480">X:Men: Proteus</a> (#125-128)</li><li><a href="/x-men-the-dark-phoenix-saga/4050-30096/" data-ref-id="4050-30096">X-Men: The Dark Phoenix Saga</a> (#129-137)</li><li><a href="h