INSERT INTO volumes (id, name, firstIssue, publisher, description, startYear, numIssues, image, characters_name, concepts_name, characters_id, concepts_id, numLikes) VALUES ('2177', 'Doom Patrol', 'The Trail of the Terrible Titan, A Medal For ''Go-Buggy 3''!', '10', '<p>This series began at #86, with the numbering Continued from: <a href="/my-greatest-adventure/4050-1687/" data-ref-id="4050-1687">My Greatest Adventure</a>. The Doom Patrol consisted of the members, <a href="/robotman/4005-4079/" data-ref-id="4005-4079">Robotman</a>, <a href="/negative-man/4005-4087/" data-ref-id="4005-4087">Negative Man</a>, <a href="/elasti-girl/4005-4088/" data-ref-id="4005-4088">Elasti-Girl</a>, <a href="/mento/4005-14647/" data-ref-id="4005-14647">Mento</a>, <a href="/beast-boy/4005-3586/" data-ref-id="4005-3586">Beast Boy</a>, and the <a href="/the-chief/4005-35126/" data-ref-id="4005-35126">Chief</a>.</p><p>Series was cancelled at #121, (Oct. 1968). A brief three issue reprint revival was published a little over four years later (Feb. 1973) with issues #122-#124.</p><h4>Collected Editions</h4><ul><li><a href="https://comicvine.gamespot.com/doom-patrol-the-silver-age-omnibus/4050-102255/" data-ref-id="4050-102255">Doom Patrol: The Silver Age Omnibus</a> (#86-124)</li><li><a href="/doom-patrol-the-silver-age-1-volume-one/4000-677945/" data-ref-id="4000-677945">Doom Patrol: The Silver Age Volume One</a> (#86-95)</li><li><a href="/doom-patrol-the-silver-age-2-volume-2/4000-743299/" data-ref-id="4000-743299">Doom Patrol: The Silver Age Volume 2</a> (#96-107)</li></ul>', '1964', '39', '{''icon_url'': ''https://comicvine.gamespot.com/a/uploads/square_avatar/0/4/6405-2177-7001-1-doom-patrol-the.jpg'', ''medium_url'': ''https://comicvine.gamespot.com/a/uploads/scale_medium/0/4/6405-2177-7001-1-doom-patrol-the.jpg'', ''screen_url'': ''https://comicvine.gamespot.com/a/uploads/screen_medium/0/4/6405-2177-7001-1-doom-patrol-the.jpg'', ''screen_large_url'': ''https://comicvine.gamespot.com/a