INSERT INTO volumes (id, name, firstIssue, publisher, description, startYear, numIssues, image, characters_name, concepts_name, characters_id, concepts_id, numLikes) VALUES ('2189', 'The Amazing Spider-Man Annual', 'The Sinister Six!;A Gallery of Spider-Man''s Most Famous Foes!;The Secrets of Spider-Man!;Supporting Cast Pin-Ups;How Stan Lee and Steve Ditko Create Spider-Man!', '31', '<p>Annual volume for <a href="https://comicvine.gamespot.com/the-amazing-spider-man/4050-2127/" data-ref-id="4050-2127">The Amazing Spider-Man Volume 1</a>.</p><p>The original annuals ran for 28 issues before being renamed with unique titles. The series continued numbering with #<strong>1 </strong><em>or </em>35 in 2008.</p><p>In 1995 they did not release an annual, but instead the <a href="../../amazing-spider-man-super-special/49-18772/" rel="nofollow ">Amazing Spider-Man Super Special</a>.</p><p>From 1996-2001 Marvel used a year format with unique titles:</p><ul><li><a href="//www.comicvine.com/the-amazing-spider-man-annual-96/4050-60436/" data-ref-id="4050-60436">The Amazing Spider-Man ''96</a></li><li><a href="//www.comicvine.com/the-amazing-spider-man-annual-97/4050-60438/" data-ref-id="4050-60438">The Amazing Spider-Man ''97</a></li><li><a href="//www.comicvine.com/the-amazing-spider-man-annual-98/4050-60439/" data-ref-id="4050-60439">Spider-Man ''98</a></li><li><a href="//www.comicvine.com/the-amazing-spider-man-annual-99/4050-60440/" data-ref-id="4050-60440">The Amazing Spider-Man 1999</a></li><li><a href="//www.comicvine.com/the-amazing-spider-man-annual-2000/4050-60441/" data-ref-id="4050-60441">The Amazing Spider-Man 2000</a></li><li><a href="//www.comicvine.com/the-amazing-spider-man-annual-2001/4050-60442/" data-ref-id="4050-60442">The Amazing Spider-Man 2001</a></li></ul><h4>Collected Editions</h4><ul><li><a href="/the-amazing-spiderman-epic-collection-great-power/4050-77149/" data-ref-id="4050-77149">Amazing Spider-Man Epic Collection: Great Power</a> (#1)</li><li><a href="https://comicvine.gamespot.com/marvel-masterworks-the-amazing-spider-man-2-volume/4000-140399/" data-ref-id="4000-140399">Marvel Masterworks: The Amazing Spider-Man Vol. 2</a> (#1)</li><li><a href="https://comicvine.gamespot.com/ditko-is-amazing/4050-123281/">Ditko Is... Amazing!</a> (#1-2)</li><li><a href="https://comicvine.gamespot.com/amazing-spiderman-epic-collection-great-responsibi/4050-97134/" data-ref-id="4050-97134">Amazing Spider-Man Epic Collection: Great Responsibility</a> (#2)</li><li><a href="https://comicvine.gamespot.com/marvel-masterworks-the-amazing-spider-man-3-volume/4000-140398/" data-ref-id="4000-140398">Marvel Masterworks: The Amazing Spider-Man Vol. 3</a> (#2)</li><li><a href="https://comicvine.gamespot.com/spidermandoctor-strange-the-way-to-dusty-death/4050-102278/" data-ref-id="4050-102278">Spider-Man/Doctor Strange: The Way To Dusty Death</a> (#2 &amp; 14)</li><li><a href="https://comicvine.gamespot.com/decades-marvel-in-the-60s-spider-man-meets-the-mar/4050-117580/">Decades: Marvel In the ''60s: Spider-Man Meets the Marvel Universe</a> (#2-3)</li><li><a href="https://comicvine.gamespot.com/marvel-masterworks-the-amazing-spider-man-5-volume/4000-140396/" data-ref-id="4000-140396">Marvel Masterworks: The Amazing Spider-Man Vol. 5</a> (#3)</li><li><a href="https://comicvine.gamespot.com/amazing-spider-man-epic-collection-spider-man-no-m/4050-110903/">Amazing Spider-Man Epic Collection: Spider-Man No More</a> (#3-4)</li><li><a href="https://comicvine.gamespot.com/marvel-masterworks-the-amazing-spider-man-6-volume/4000-140391/" data-ref-id="4000-140391">Marvel Masterworks: The Amazing Spider-Man Vol. 6</a> (#4)</li><li><a href="https://comicvine.gamespot.com/marvel-masterworks-the-amazing-spider-man-7-volume/4000-140392/" data-ref-id="4000-140392">Marvel Masterworks: The Amazing Spider-Man Vol. 7</a> (#5)</li><li><a href="https://comicvine.gamespot.com/amazing-spider-man-epic-collection-the-secret-of-t/4050-124993/">Amazing Spider-Man Epic 