INSERT INTO volumes (id, name, firstIssue, publisher, description, startYear, numIssues, image, characters_name, concepts_name, characters_id, concepts_id, numLikes) VALUES ('2190', 'Daredevil', 'The Origin of Daredevil', '31', '<p><em>He dwells in eternal night, but the blackness is filled with sounds and scents other men cannot perceive. Though attorney Matt Murdock is blind, his other senses function with superhuman sharpness; his radar sense guides him over every obstacle! He stalks the streets by night, a red-garbed foe of evil! Stan Lee presents... Daredevil, The Man Without Fear!</em></p><p>Unlike many <a href="/marvel/4010-31/" data-ref-id="4010-31">Marvel</a> heroes launched during the <a href="/silver-age-of-comics/4015-55821/" data-ref-id="4015-55821"> Silver Age of Comics</a>, Daredevil debuted in his own series without first being test launched in another title, as such, <em>Daredevil, The Man Without Fear</em> introduced readers to Matt Murdock in the first issue. The series started in 1964 and lasted 380 issues until being canceled in 1998. The title was selected to be part of the <a href="/marvel-knights/4015-58406/" data-ref-id="4015-58406">Marvel Knights</a> imprint and relaunched the series and character with <a href="/daredevil/4050-6209/" data-ref-id="4050-6209">Daredevil Vol. 2</a>.</p><h4>Additional Volumes</h4><ul><li>Daredevil Vol. 1</li><li><a href="https://comicvine.gamespot.com/daredevil/4050-6209/" data-ref-id="4050-6209">Daredevil Vol. 2</a></li><li><a href="https://comicvine.gamespot.com/daredevil/4050-41410/" data-ref-id="4050-41410">Daredevil Vol. 3</a></li><li><a href="https://comicvine.gamespot.com/daredevil/4050-72417/" data-ref-id="4050-72417">Daredevil Vol. 4</a></li><li><a href="https://comicvine.gamespot.com/daredevil/4050-86343/" data-ref-id="4050-86343">Daredevil Vol. 5</a></li><li><a href="https://comicvine.gamespot.com/daredevil/4050-116964/" data-ref-id="4050-116964">Daredevil Vol. 6</a></li><li><a href="https://comicvine