INSERT INTO volumes (id, name, firstIssue, publisher, description, startYear, numIssues, image, characters_name, concepts_name, characters_id, concepts_id, numLikes) VALUES ('2279', 'Teen Titans', 'The Beast-God of Xochatan', '10', '<p><i>The <a href="/teen-titans/4060-19081/" data-ref-id="4060-19081">Teen Titans</a> in their very own series! The sidekicks to the greatest heroes of the DC Universe unite as the Teen Titans--superheroes in their own right out to save the world from threats large and small. Featuring Robin, Kid Flash, Wonder Girl and more!</i></p><p>Starting members: <a href="/dick-grayson/4005-1691/" data-ref-id="4005-1691">Robin</a>, <a href="/wally-west/4005-23879/" data-ref-id="4005-23879">Kid Flash</a>, <a href="/tempest/4005-2382/" data-ref-id="4005-2382">Aqualad</a>, <a href="/donna-troy/4005-4913/" data-ref-id="4005-4913">Wonder Girl</a>. Later constant members: <a href="/roy-harper/4005-3404/" data-ref-id="4005-3404">Speedy</a>, <a href="/lilith-clay/4005-12525/" data-ref-id="4005-12525">Lilith Clay</a>, <a href="/vox/4005-35124/" data-ref-id="4005-35124">Mal Duncan</a>, <a href="/duela-dent/4005-5939/" data-ref-id="4005-5939">Harlequin</a> (Duela Dent).</p><p>Relaunched in <a href="/the-new-teen-titans/4050-3036/" data-ref-id="4050-3036">The New Teen Titans</a> in 1980.</p><h2>Collected Editions</h2><h3>Actual collections:</h3><table data-max-width="true"><thead><tr><th scope="col">Omnibuses</th><th scope="col">Issues</th></tr></thead><tbody><tr><td><a href="/teen-titans-the-silver-age-omnibus-1-vol-1/4000-556462/" data-ref-id="4000-556462">The Silver Age</a></td><td>1-24</td></tr><tr><td><a href="/teen-titans-the-bronze-age-omnibus-1-volume-1/4000-601777/" data-ref-id="4000-601777">The Bronze Age</a></td><td>25-53</td></tr></tbody></table><table data-max-width="true"><thead><tr><th scope="col">TPBs</th><th scope="col">Issues</th></tr></thead><tbody><tr><td><a href="/teen-titans-the-silver-age-1-volume-one/4000-647927/" data-ref-id="4000-647927">The Silver Age, Volume One</a></td><td>1-11</td></tr><tr><td><a href="/teen-titans-the-silver-age-2-volume-two/4000-693449/" data-ref-id="4000-693449">The Silver Age, Volume Two</a></td><td>12-24</td></tr></tbody></table><p>The Bronze Age isn''t collected in TPBs yet. </p><h3>Old collection:</h3><ul><li><a href="/showcase-presents-teen-titans/4050-38657/" data-ref-id="4050-38657">Showcase Presents: Teen Titans, Vol. 1</a> (#1-18)</li><li><a href="/showcase-presents-teen-titans/4050-38657/" data-ref-id="4050-38657">Showcase Presents: Teen Titans, Vol. 2</a> (#19-36)</li></ul><p>Also in <a href="/the-hawk-and-the-dove-the-silver-age/4050-109450/" data-ref-id="4050-109450">The Hawk and the Dove: The Silver Age</a> (#21). </p>', '1966', '53', '{''icon_url'': ''https://comicvine.gamespot.com/a/uploads/square_avatar/0/4/7520-2279-8295-1-teen-titans.jpg'', ''medium_url'': ''https://comicvine.gamespot.com/a/uploads/scale_medium/0/4/7520-2279-8295-1-teen-titans.jpg'', ''screen_url'': ''https://comicvine.gamespot.com/a/uploads/screen_medium/0/4/7520-2279-8295-1-teen-titans.jpg'', ''screen_large_url'': ''https://comicvine.gamespot.com/a/uploads/screen_kubrick/0/4/7520-2279-8295-1-teen-titans.jpg'', ''small_url'': ''https://comicvine.gamespot.com/a/uploads/scale_small/0/4/7520-2279-8295-1-teen-titans.jpg'', ''super_url'': ''https://comicvine.gamespot.com/a/uploads/scale_large/0/4/7520-2279-8295-1-teen-titans.jpg'', ''thumb_url'': ''https://comicvine.gamespot.com/a/uploads/scale_avatar/0/4/7520-2279-8295-1-teen-titans.jpg'', ''tiny_url'': ''https://comicvine.gamespot.com/a/uploads/square_mini/0/4/7520-2279-8295-1-teen-titans.jpg'', ''original_url'': ''https://comicvine.gamespot.com/a/uploads/original/0/4/7520-2279-8295-1-teen-titans.jpg'', ''image_tags'': ''All Images''}', '[{"id": "Donna Troy"}, {"id": "Wally West"}, {"id": "Dick Grayson"}, {"id": "Roy Harper"}, {"id": "Tempest"}, {"id": "Herald"}, {"id": "Lilith Clay"}, {"id": "Don Hall"}, {"id": "Hank Hall"}, {"id": "Lore