INSERT INTO volumes (id, name, firstIssue, publisher, description, startYear, numIssues, image, characters_name, concepts_name, characters_id, concepts_id, numLikes) VALUES ('2290', 'Fantasy Masterpieces', NULL, '31', '<p>Fantasy Masterpieces reprinted stories Golden Age stories. Originally the books included stories from anthology titles, but with the inclusion of a Captain America reprint in Issue 3 there was an increasing focus on Golden Age super-hero stories. The series continues as <a data-ref-id="4050-2353" href="/marvel-super-heroes-vol-1/4050-2353/" slug="marvel-super-heroes-vol-1">Marvel Super-Heroes Vol.1</a></p>', '1966', '11', '{''icon_url'': ''https://comicvine.gamespot.com/a/uploads/square_avatar/0/4/7588-2290-8368-1-fantasy-masterpieces.jpg'', ''medium_url'': ''https://comicvine.gamespot.com/a/uploads/scale_medium/0/4/7588-2290-8368-1-fantasy-masterpieces.jpg'', ''screen_url'': ''https://comicvine.gamespot.com/a/uploads/screen_medium/0/4/7588-2290-8368-1-fantasy-masterpieces.jpg'', ''screen_large_url'': ''https://comicvine.gamespot.com/a/uploads/screen_kubrick/0/4/7588-2290-8368-1-fantasy-masterpieces.jpg'', ''small_url'': ''https://comicvine.gamespot.com/a/uploads/scale_small/0/4/7588-2290-8368-1-fantasy-masterpieces.jpg'', ''super_url'': ''https://comicvine.gamespot.com/a/uploads/scale_large/0/4/7588-2290-8368-1-fantasy-masterpieces.jpg'', ''thumb_url'': ''https://comicvine.gamespot.com/a/uploads/scale_avatar/0/4/7588-2290-8368-1-fantasy-masterpieces.jpg'', ''tiny_url'': ''https://comicvine.gamespot.com/a/uploads/square_mini/0/4/7588-2290-8368-1-fantasy-masterpieces.jpg'', ''original_url'': ''https://comicvine.gamespot.com/a/uploads/original/0/4/7588-2290-8368-1-fantasy-masterpieces.jpg'', ''image_tags'': ''All Images''}', '[{"id": "Captain America"}, {"id": "Sgt. Duffy"}, {"id": "Bucky Barnes"}, {"id": "Namor"}, {"id": "Jim Hammond"}, {"id": "Betty Dean"}, {"id": "Golden Girl"}, {"id": "Toro"}, {"id": "Black Toad"}, {"id": "Albert Carstairs"}, {"i