INSERT INTO volumes (id, name, firstIssue, publisher, description, startYear, numIssues, image, characters_name, concepts_name, characters_id, concepts_id, numLikes) VALUES ('2293', 'Marvel Tales', NULL, '31', '<p>The first volume of "Marvel Tales" to be published by Marvel Comics. Numbering continues from <a href="https://comicvine.gamespot.com/marvel-tales-annual-2/4000-119631/" data-ref-id="4000-119631">Marvel Tales Annual #2</a>. The original <a href="/marvel-tales/4050-1283/" data-ref-id="4050-1283">Marvel Tales</a> was published from 1949-1957 by <a href="https://www.comicvine.com/atlas/4010-75/" data-ref-id="4010-75">Atlas</a>.</p><p>This series started out as <a href="https://comicvine.gamespot.com/marvel-tales-annual/4050-131835/" data-ref-id="4050-131835">Marvel Tales Annual</a> in the years 1964 and 1965 before it became a monthly reprint series. Most issues only had reprints in them, but some had additional new stories, such as "Spider-Ham" in 33 issues of the series and "the Freaks" in issue 256.</p><p>The volume''s cover title changed to <em><a href="/marvel-tales-starring-spider-man/4050-138122/" data-ref-id="4050-138122">Marvel Tales Starring Spider-Man</a></em> with issue 122 but the indicia didn''t reflect until issue 223. The title changed again with issue 223 to <a href="/marvel-tales-featuring-spider-man/4050-137722/" data-ref-id="4050-137722"><em>Marvel Tales Featuring Spider-Man</em></a> but the indicia didn''t reflect until issue 239.</p><h4>Collected Editions</h4><ul><li><a href="https://comicvine.gamespot.com/the-marvel-universe-according-to-hembeck/4050-94809/" data-ref-id="4050-94809">The Marvel Universe According To Hembeck</a> (#216-217, 224-226, 235, 248 &amp; 250-252)</li></ul>', '1966', '120', '{''icon_url'': ''https://comicvine.gamespot.com/a/uploads/square_avatar/0/4/7853-2293-8668-1-marvel-tales.jpg'', ''medium_url'': ''https://comicvine.gamespot.com/a/uploads/scale_medium/0/4/7853-2293-8668-1-marvel-tales.jpg'', ''screen_url'': '