INSERT INTO volumes (id, name, firstIssue, publisher, description, startYear, numIssues, image, characters_name, concepts_name, characters_id, concepts_id, numLikes) VALUES ('2295', 'Thor Annual', 'If Asgard Falls...', '31', '<p>Continued from <a href="../../journey-into-mystery-annual/49-19069/" rel="nofollow ">Journey Into Mystery Annual</a>. Continues as <a href="/the-mighty-thor-annual/4050-79259/" data-ref-id="4050-79259">The Mighty Thor Annual</a> with issue 14. In 1998 three more annuals and a team-up with <a href="/silver-surfer/4005-2502/" data-ref-id="4005-2502">Silver Surfer</a> were released, with unique indicia titles;</p><ul><li><a href="/silver-surfer-thor-annual-98/4050-39906/" data-ref-id="4050-39906">Silver Surfer / Thor ''98</a> (<a href="/silver-surfer-annual/4050-4069/" data-ref-id="4050-4069">Silver Surfer Annual</a>)</li><li><a href="//www.comicvine.com/thor-annual-99/4050-60447/" data-ref-id="4050-60447">Thor 1999</a></li><li><a href="//www.comicvine.com/thor-annual-2000/4050-60449/" data-ref-id="4050-60449">Thor 2000</a></li><li><a href="//www.comicvine.com/thor-annual-2001/4050-60450/" data-ref-id="4050-60450">Thor 2001</a></li></ul><h4>Collected Editions</h4><ul><li><a href="/marvel-masterworks-the-mighty-thor-5-volume-five/4000-232946/" data-ref-id="4000-232946">Marvel Masterworks: The Mighty Thor Volume 5</a> (#2)</li><li><a href="https://comicvine.gamespot.com/thor-epic-collection-the-wrath-of-odin/4050-104642/" data-ref-id="4050-104642">Thor Epic Collection: The Wrath of Odin</a> (#2)</li><li><a href="https://comicvine.gamespot.com/loki-omnibus/4050-138891/">Loki Omnibus</a> (#2)</li><li><a href="https://comicvine.gamespot.com/marvel-masterworks-the-mighty-thor-15-volume-15/4000-520206/" data-ref-id="4000-520206">Marvel Masterworks: The Mighty Thor Volume 15</a> (#5)</li><li><a href="https://comicvine.gamespot.com/thor-vs-hercules/4050-36372/">Thor vs. Hercules</a> (#5)</li><li><a href="https://www.comicvine.com/essential-thor-7-volume