INSERT INTO volumes (id, name, firstIssue, publisher, description, startYear, numIssues, image, characters_name, concepts_name, characters_id, concepts_id, numLikes) VALUES ('2330', 'Blue Beetle', 'Bugs the Squids; Who is the Question?', '125', '<p>Starring: <a href="/ted-kord/4005-2054/" data-ref-id="4005-2054">Ted Kord</a> as Blue Beetle (II)</p><p>The opening issues of this short lived series from Charlton Comics featured both Blue Beetle and the Question - two heroes who would leave an indelible impression on the DC Universe for years to come. Eight months after Ted Kord assumed the scarab as Blue Beetle in a back up feature of "Captain Atom" # 83, writer / artist Steve Ditko launched the Beetle into his own series.</p><p>This Beetle didn''t possess super powers. Instead, Kord was a brilliant inventor whose gadgets - chief among them a bug shaped aircraft and a gun that fired blinding light and compressed air blasts - powered his war against crime. In his inaugural issue, the Blue Beetle dispatched the Squids, a costumed gang equipped with suctioning devices that enabled them to climb walls. In the same issue, Ditko introduced Vic Sage, a hard hitting TV reporter for World Wide Broadcasting Company, and his faceless alter ego, the Question, to Hub City''s criminal underground. Using a chemical gas to apply and remove a special skin mask created by his mentor, Aristotle Rodor, Sage was able to conceal his features completely while operating outside of the law.</p><p>As the Question he made his first mark by apprehending gambling ringleader Lou Dicer and his accomplice, WWB executive Jim Lark - on whom Sage blew the whistle during his next broadcast.</p><h4><strong>Notes</strong></h4><ul><li>Fourth Charlton publication; 5th volume overall.</li><li>Unpublished #6 appeared in <a href="https://comicvine.gamespot.com/charlton-portfolio/4050-135701/">Charlton Portfolio</a>.</li></ul><h4>Collected Editions</h4><ul><li><a href="https://comicvine.gamespot.com/gwandanaland-comics-2030-charlton-heroes-of-the-19/4000-680814/">Charlton Heroes of the 1960s: Volume 2</a> (Question stories from #1-5)</li><li><a href="https://comicvine.gamespot.com/gwandanaland-comics-20252030-charlton-heroes-of-th/4000-683139/">Charlton Heroes of the 1960''s: Volumes 1 &amp; 2</a> (Question stories from #1-5)</li><li><a href="https://comicvine.gamespot.com/gwandanaland-comics-1296-the-complete-question/4000-681014/">The Complete Question</a> (Question stories from #1-5)</li></ul>', '1967', '5', '{''icon_url'': ''https://comicvine.gamespot.com/a/uploads/square_avatar/0/4/8496-2330-9383-1-blue-beetle.jpg'', ''medium_url'': ''https://comicvine.gamespot.com/a/uploads/scale_medium/0/4/8496-2330-9383-1-blue-beetle.jpg'', ''screen_url'': ''https://comicvine.gamespot.com/a/uploads/screen_medium/0/4/8496-2330-9383-1-blue-beetle.jpg'', ''screen_large_url'': ''https://comicvine.gamespot.com/a/uploads/screen_kubrick/0/4/8496-2330-9383-1-blue-beetle.jpg'', ''small_url'': ''https://comicvine.gamespot.com/a/uploads/scale_small/0/4/8496-2330-9383-1-blue-beetle.jpg'', ''super_url'': ''https://comicvine.gamespot.com/a/uploads/scale_large/0/4/8496-2330-9383-1-blue-beetle.jpg'', ''thumb_url'': ''https://comicvine.gamespot.com/a/uploads/scale_avatar/0/4/8496-2330-9383-1-blue-beetle.jpg'', ''tiny_url'': ''https://comicvine.gamespot.com/a/uploads/square_mini/0/4/8496-2330-9383-1-blue-beetle.jpg'', ''original_url'': ''https://comicvine.gamespot.com/a/uploads/original/0/4/8496-2330-9383-1-blue-beetle.jpg'', ''image_tags'': ''All Images''}', '[{"id": "Question (Sage)"}, {"id": "Nora Lace"}, {"id": "Ted Kord"}, {"id": "Tracey"}, {"id": "Syd Starr"}, {"id": "Maxwell Fisher"}, {"id": "Aristotle Rodor"}, {"id": "Al Kert"}, {"id": "Fred Pine"}, {"id": "Ceila Starr"}, {"id": "Jarvis Kord"}, {"id": "Banshee"}, {"id": "Dan Greer"}, {"id": "Bob Hasel"}, {"id": "Dan Garret"}, {"id": "Our Man"}, {"id": "Boris Ebar"}, {"id": "Nat Kat"}, {"id": "Sam Starr"}, {"id": "Captain Lash"}, {"id": "Lou Dicer"}, {"id": "Todd Van III"}, {"id": "Farley Fleeter"}, {"id": "Jim Lark"}]', 'NaN', '[{"id": 3211}, {"id": 183129}, {"id": 2054}, {"id": 190177}, {"id": 183183}, {"id": 48558}, {"id": 19343}, {"id": 70023}, {"id": 183130}, {"id": 183131}, {"id": 48494}, {"id": 183133}, {"id": 183257}, {"id": 183132}, {"id": 18745}, {"id": 183326}, {"id": 183325}, {"id": 183258}, {"id": 183184}, {"id": 32182}, {"id": 38479}, {"id": 183128}, {"id": 49880}, {"id": 38480}]', 'NaN', '0');
