INSERT INTO volumes (id, name, firstIssue, publisher, description, startYear, numIssues, image, characters_name, concepts_name, characters_id, concepts_id, numLikes) VALUES ('2351', 'Daredevil Annual', 'Electro and The Emissaries of Evil; Inside Daredevil; At the Stroke of Midnight!', '31', '<p>This series accompanies <a href="/daredevil/4050-2190/" data-ref-id="4050-2190">Daredevil vol. 1</a> and was released sporadically between 1967 and 1994. The stories are mainly one-off adventures that are unrelated to <a href="/daredevil/4005-24694/" data-ref-id="4005-24694">Daredevil''s</a> main story-lines. Issue 5 is mis-numbered as issue 4. In 1997 Daredevil teamed up with <a href="/deadpool/4005-7606/" data-ref-id="4005-7606">Deadpool</a> in <a href="/daredevildeadpool-annual-97/4050-26448/" data-ref-id="4050-26448">Daredevil / Deadpool ''97</a>. Since then the series has been published under two more #1s <a href="/daredevil-annual/4050-19415/" data-ref-id="4050-19415">Daredevil Annual</a> in 2007, and <a href="/daredevil-annual/4050-51109/" data-ref-id="4050-51109">Daredevil Annual</a> in 2012.</p><h4>Collected Editions</h4><ul><li><a href="https://comicvine.gamespot.com/daredevil-omnibus-1-volume-1/4000-580744/" data-ref-id="4000-580744">Daredevil Omnibus Volume 1</a> (#1)</li><li><a href="/daredevil-epic-collection-mike-murdock-must-die/4050-108731/" data-ref-id="4050-108731">Daredevil Epic Collection: Mike Murdock Must Die!</a> (#1)</li><li><a href="https://comicvine.gamespot.com/daredevil-epic-collection-heart-of-darkness/4050-104463/" data-ref-id="4050-104463">Daredevil Epic Collection: Heart of Darkness</a> (#5-6)</li><li><a href="https://comicvine.gamespot.com/hulk-lifeform/4050-126604/">Hulk: Lifeform</a> (#6 (Main Story))</li><li><a href="https://comicvine.gamespot.com/daredevil-epic-collection-last-rites/4050-132134/">Daredevil Epic Collection: Last Rites</a> (#7)</li><li><a href="/daredevil-epic-collection-fall-from-grace/4050-73013/" data-ref-id="4050-73013">Daredevil Epic Collection: Fall From Grace</a> (#10)</li><li><a href="https://comicvine.gamespot.com/black-widow-epic-collection-the-coldest-war/4050-130989/">Black Widow Epic Collection: The Coldest War</a> (#10)</li></ul><h4>Non-U.S. Collected Editions</h4><ul><li><a href="https://comicvine.gamespot.com/visionarios-marvel-stan-lee/4050-95780/" data-ref-id="4050-95780">Visionarios Marvel: Stan Lee</a> (#1) (Spanish)</li><li><a href="https://comicvine.gamespot.com/coleccionable-marvel-heroes-55-daredevil-el-ocaso-/4000-612263/">Coleccionable Marvel Héroes - Daredevil: El ocaso de los ídolos</a> (#4) (Spanish)</li></ul>', '1967', '10', '{''icon_url'': ''https://comicvine.gamespot.com/a/uploads/square_avatar/0/4/8707-2351-9614-1-daredevil-annual.jpg'', ''medium_url'': ''https://comicvine.gamespot.com/a/uploads/scale_medium/0/4/8707-2351-9614-1-daredevil-annual.jpg'', ''screen_url'': ''https://comicvine.gamespot.com/a/uploads/screen_medium/0/4/8707-2351-9614-1-daredevil-annual.jpg'', ''screen_large_url'': ''https://comicvine.gamespot.com/a/uploads/screen_kubrick/0/4/8707-2351-9614-1-daredevil-annual.jpg'', ''small_url'': ''https://comicvine.gamespot.com/a/uploads/scale_small/0/4/8707-2351-9614-1-daredevil-annual.jpg'', ''super_url'': ''https://comicvine.gamespot.com/a/uploads/scale_large/0/4/8707-2351-9614-1-daredevil-annual.jpg'', ''thumb_url'': ''https://comicvine.gamespot.com/a/uploads/scale_avatar/0/4/8707-2351-9614-1-daredevil-annual.jpg'', ''tiny_url'': ''https://comicvine.gamespot.com/a/uploads/square_mini/0/4/8707-2351-9614-1-daredevil-annual.jpg'', ''original_url'': ''https://comicvine.gamespot.com/a/uploads/original/0/4/8707-2351-9614-1-daredevil-annual.jpg'', ''image_tags'': ''All Images''}', '[{"id": "Daredevil"}, {"id": "Foggy Nelson"}, {"id": "Eight-Ball"}, {"id": "Spit"}, {"id": "Ben Urich"}, {"id": "Karen Page"}, {"id": "Darla"}, {"id": "Jet"}, {"id": "Typhoid Mary"}, {"id": "J. Jonah Jameson"}, {"id": "Elektra"}, {"id": "Stilt-Man"}, {"id": "Spider-Ma