INSERT INTO volumes (id, name, firstIssue, publisher, description, startYear, numIssues, image, characters_name, concepts_name, characters_id, concepts_id, numLikes) VALUES ('2353', 'Marvel Super-Heroes', 'The Coming of Captain Marvel', '31', '<p>Continues numbering from <a href="/fantasy-masterpieces/4050-2290/" data-ref-id="4050-2290">Fantasy Masterpieces </a>#11. It features original stories up to issue 20, after which it becomes a reprint series. The series is mostly known for the debut of <a href="/captain-marvel/4005-1472/" data-ref-id="4005-1472">Captain Mar-Vell</a> in issue 12. This led to <a href="/marvel/4010-31/" data-ref-id="4010-31">Marvel</a> attaining the rights to the "Captain Marvel" name and forcing <a href="/dc-comics/4010-10/" data-ref-id="4010-10">DC</a> to rename their Captain Marvel series to <a href="/shazam/4050-2622/" data-ref-id="4050-2622">Shazam!</a> Issue 13 of the series features the first appearance of <a href="//www.comicvine.com/ms-marvel/4005-21561/" data-ref-id="4005-21561">Carol Danvers</a>.</p><p>Issue 18 of the series features the first appearance of <a href="/guardians-of-the-galaxy/4060-25956/" data-ref-id="4060-25956">The Guardians of the Galaxy</a>.</p><h4>Collected Editions</h4><ul><li><a href="https://comicvine.gamespot.com/marvels-captain-marvel-prelude/4050-116977/">Marvel''s Captain Marvel Prelude</a> (#13)</li><li><a href="https://comicvine.gamespot.com/captain-marvel-the-many-lives-of-carol-danvers/4050-129471/">Captain Marvel: The Many Lives of Carol Danvers</a> (#13)</li><li><a href="https://comicvine.gamespot.com/amazing-spider-man-epic-collection-the-goblin-live/4050-119744/">Amazing Spider-Man Epic Collection: The Goblin Lives</a> (#14)</li><li><a href="/amazing-spider-man-omnibus-4-volume-four/4000-883304/" data-ref-id="4000-883304">Amazing Spider-Man Omnibus Volume Four</a> (#14)</li><li><a href="https://comicvine.gamespot.com/inhumans-beware-the-inhumans/4050-107505/" data-ref-id="4050-107505">Inhumans: Beware the Inhumans</a> (#15)</li><li><a href="/marvel-masterworks-ka-zar-1-volume-1/4000-380710/" data-ref-id="4000-380710">Marvel Masterworks: Ka-Zar Volume 1</a> (#16)</li><li><a href="https://comicvine.gamespot.com/incredible-hulk-epic-collection-in-the-hands-of-hy/4050-121575/">Incredible Hulk Epic Collection: In the Hands of Hydra</a> (#16)</li><li><a href="/avengers-epic-collection-behold-the-vision/4050-81657/" data-ref-id="4050-81657">Avengers Epic Collection: Behold... The Vision</a> (#17)</li><li><a href="/avengers-omnibus-3-volume-three/4000-663568/" data-ref-id="4000-663568">Avengers Omnibus Volume 3</a> (#17)</li><li><a href="/guardians-of-the-galaxy-by-jim-valentino-3-volume-/4000-504337/" data-ref-id="4000-504337">Guardians of the Galaxy By Jim Valentino Volume 3</a> (#18)</li><li><a href="https://comicvine.gamespot.com/guardians-of-the-galaxy-by-jim-valentino-omnibus-1/4000-583938/" data-ref-id="4000-583938">Guardians of the Galaxy by Jim Valentino Omnibus Volume 1</a> (#18)</li><li><a href="/guardians-of-the-galaxy-earth-shall-overcome/4050-30359/" data-ref-id="4050-30359">Guardians of the Galaxy: Earth Shall Overcome</a> (#18)</li><li><a href="https://comicvine.gamespot.com/guardians-of-the-galaxy-tomorrows-heroes-omnibus/4050-116248/">Guardians of the Galaxy: Tomorrow''s Heroes Omnibus</a> (#18)</li></ul>', '1967', '94', '{''icon_url'': ''https://comicvine.gamespot.com/a/uploads/square_avatar/11/117763/2481693-marvelsuper_heroes12.jpg'', ''medium_url'': ''https://comicvine.gamespot.com/a/uploads/scale_medium/11/117763/2481693-marvelsuper_heroes12.jpg'', ''screen_url'': ''https://comicvine.gamespot.com/a/uploads/screen_medium/11/117763/2481693-marvelsuper_heroes12.jpg'', ''screen_large_url'': ''https://comicvine.gamespot.com/a/uploads/screen_kubrick/11/117763/2481693-marvelsuper_heroes12.jpg'', ''small_url'': ''https://comicvine.gamespot.com/a/uploads/scale_small/11/117763/2481693-marvelsuper_heroes12.jpg'', ''super_url'': ''https://comicvine.gamespot