INSERT INTO volumes (id, name, firstIssue, publisher, description, startYear, numIssues, image, characters_name, concepts_name, characters_id, concepts_id, numLikes) VALUES ('2354', 'Not Brand Echh', 'The Silver Burper!; The Fastest Gums in the West!; The Human Scorch Versus the Sunk-Mariner!; A Day of Blunder!', '31', '<p>Marvel''s very first novelty comic-series. Some 6 years after the Marvel Age of Comics started in 1961, Marvel came up with the idea to make fun of their own characters. What came of it was this series, mostly hosted by <a href="https://comicvine.gamespot.com/forbush-man/4005-6808/">Forbush Man</a>. In 2018, a <a href="https://comicvine.gamespot.com/not-brand-echh/4050-106134/">Not Brand Echh</a> one-shot was published as number 14 of this series.</p><h4>Collected Editions</h4><ul><li><a href="https://comicvine.gamespot.com/kingsize-kirby/4050-83141/">King-Size Kirby</a> (#1)</li><li><a href="https://comicvine.gamespot.com/marvel-masterworks-not-brand-echh/4050-82434/">Marvel Masterworks: Not Brand Echh</a></li><li><a href="https://comicvine.gamespot.com/not-brand-echh-the-complete-collection/4050-119863/">Not Brand Echh: The Complete Collection</a> (#1-13)</li><li><a href="https://comicvine.gamespot.com/captain-america-omnibus-1-volume-1/4000-274607/">Captain America Omnibus Volume 1</a> (#3)</li></ul><h4>Non-U.S. Collected Editions</h4><ul><li><a href="https://comicvine.gamespot.com/kingsize-kirby/4050-104017/">King-Size Kirby</a> (#1) (Spanish)</li><li><a href="https://comicvine.gamespot.com/marvel-gold-capitan-america-3-el-quinto-durmiente/4000-631306/">Marvel Gold. Capitán América Volume 3: ¡El quinto durmiente!</a> (#3) (Spanish)</li><li><a href="https://comicvine.gamespot.com/visionarios-marvel-stan-lee/4050-95780/">Visionarios Marvel: Stan Lee</a> (#1-2 &amp; #7)</li></ul>', '1967', '13', '{''icon_url'': ''https://comicvine.gamespot.com/a/uploads/square_avatar/0/4/8655-2354-9557-1-not-brand-echh.jpg'', ''medium_url'': ''https://comicvine.g