INSERT INTO volumes (id, name, firstIssue, publisher, description, startYear, numIssues, image, characters_name, concepts_name, characters_id, concepts_id, numLikes) VALUES ('2387', 'The Atom & Hawkman', '"Vengeance of the Silver Vulture"', '10', '<p>When sales of both Atom &amp; Hawkman were on the slide, the two comics combined, continuing number wise where the Atom left off. Running for 7 issues, the comic sometimes featured our heroes in a team up and at other times they were in separate adventures. Continues from <a href="/the-atom/4050-2051/" data-ref-id="4050-2051">The Atom</a></p><p>In 2010, DC resurrected the series for a single issue tied in to the Blackest Night event, #46.</p><h4>Collected Editions</h4><ul><li><a href="https://comicvine.gamespot.com/blackest-night-10th-anniversary-omnibus/4050-119521/">Blackest Night 10th Anniversary Omnibus</a> (#46)</li></ul>', '1968', '8', '{''icon_url'': ''https://comicvine.gamespot.com/a/uploads/square_avatar/0/9116/1106682-39.jpg'', ''medium_url'': ''https://comicvine.gamespot.com/a/uploads/scale_medium/0/9116/1106682-39.jpg'', ''screen_url'': ''https://comicvine.gamespot.com/a/uploads/screen_medium/0/9116/1106682-39.jpg'', ''screen_large_url'': ''https://comicvine.gamespot.com/a/uploads/screen_kubrick/0/9116/1106682-39.jpg'', ''small_url'': ''https://comicvine.gamespot.com/a/uploads/scale_small/0/9116/1106682-39.jpg'', ''super_url'': ''https://comicvine.gamespot.com/a/uploads/scale_large/0/9116/1106682-39.jpg'', ''thumb_url'': ''https://comicvine.gamespot.com/a/uploads/scale_avatar/0/9116/1106682-39.jpg'', ''tiny_url'': ''https://comicvine.gamespot.com/a/uploads/square_mini/0/9116/1106682-39.jpg'', ''original_url'': ''https://comicvine.gamespot.com/a/uploads/original/0/9116/1106682-39.jpg'', ''image_tags'': ''All Images''}', '[{"id": "Ray Palmer"}, {"id": "Katar Hol"}, {"id": "Jean Loring"}, {"id": "Hawkwoman"}, {"id": "Gentleman Ghost"}, {"id": "Khufu"}, {"id": "Guy Gardner"}, {"id": "Laethwen"}, {"id": "Chay-Ara"}, {"id": "Munk"}, {"id": "Iroque"}, {"id": "Slushh"}, {"id": "Karu-Sil"}, {"id": "Arkillo"}, {"id": "Soranik Natu"}, {"id": "Kyle Rayner"}, {"id": "Commissioner Emmett"}, {"id": "Spectre"}, {"id": "Elongated Man"}, {"id": "Shiva"}, {"id": "Sue Dibny"}, {"id": "Chronos"}, {"id": "Vishnu"}, {"id": "Brahma"}, {"id": "Brain Wave"}, {"id": "Hawkman"}, {"id": "Hawkgirl"}, {"id": "Crispus Allen"}, {"id": "Damage"}]', 'NaN', '[{"id": 34685}, {"id": 81180}, {"id": 22036}, {"id": 5693}, {"id": 18358}, {"id": 32724}, {"id": 1791}, {"id": 72457}, {"id": 68315}, {"id": 67350}, {"id": 60712}, {"id": 54063}, {"id": 45575}, {"id": 45081}, {"id": 42284}, {"id": 40431}, {"id": 39383}, {"id": 2361}, {"id": 4437}, {"id": 30262}, {"id": 1790}, {"id": 21245}, {"id": 15392}, {"id": 15389}, {"id": 9338}, {"id": 8337}, {"id": 6903}, {"id": 6882}, {"id": 3582}]', 'NaN', '0');
