INSERT INTO volumes (id, name, firstIssue, publisher, description, startYear, numIssues, image, characters_name, concepts_name, characters_id, concepts_id, numLikes) VALUES ('2400', 'Captain America', 'This Monster Unmasked', '31', '<p>Captain America is on his own at last, in the comic that started it all, the Super Soldier''s story begins.</p><p>Continued from <a href="/tales-of-suspense/4050-2007/" data-ref-id="4050-2007">Tales of Suspense</a> issue 99. Tales of Suspense was one of several horror-like anthologies that Marvel was publishing in the early 1960''s, but just like its counterpart <a href="../../tales-to-astonish/49-2008/" rel="nofollow ">Tales To Astonish</a>, after nearly one hundred issues the series changed its name, after it already went a completely new route featuring characters such as <a href="/iron-man/4005-1455/" data-ref-id="4005-1455">Iron Man</a> and Captain America instead of horror stories. So it was that in 1968, the series became <a href="/captain-america/4050-2400/" data-ref-id="4050-2400">Captain America Volume 1</a> with its hundredth issue. Captain America ran on for three more decades much like its <a href="/the-incredible-hulk/4050-2406/" data-ref-id="4050-2406">Incredible Hulk</a> counterpart. The series concluded with issue 454, when the series was relaunched as <a href="/captain-america/4050-5776/" data-ref-id="4050-5776">Captain America vol. 2</a>. After issue number 50 of <a href="/captain-america/4050-11499/" data-ref-id="4050-11499">Captain America vol. 5</a>, that series returned to its original numbering started here in Volume 1, celebrating it''s 600th issue.</p><p>This is the first solo Captain America series published by <a href="/marvel/4010-31/" data-ref-id="4010-31">Marvel Comics</a>, the previous series, <a href="/captain-america-comics/4050-1628/" data-ref-id="4050-1628">Captain America Comics</a>, had been published by Marvel’s predecessors <a href="/atlas/4010-75/" data-ref-id="4010-75">Atlas</a> and <a href="/timely/4010-21/" data-ref-id="4010-21">Timely</a> respectively.</p><h4>Collected Editions</h4><ul><li><a href="https://www.comicvine.com/marvel-masterworks-captain-america-2-vol-2/4000-336526/" data-ref-id="4000-336526">Marvel Masterworks: Captain America Vol. 2</a> (#100)</li><li><a href="https://comicvine.gamespot.com/marvel-verse-captain-america/4050-129192/">Marvel-Verse: Captain America</a> (#100 &amp; 255)</li><li><a href="https://comicvine.gamespot.com/captain-america-omnibus-1-volume-1/4000-274607/" data-ref-id="4000-274607">Captain America Omnibus Volume 1</a> (#100-113)</li><li><a href="https://comicvine.gamespot.com/captain-america-epic-collection-the-coming-of-the-/4050-94262/" data-ref-id="4050-94262">Captain America Epic Collection: The Coming of... The Falcon</a> (#100-119)</li><li><a href="https://www.comicvine.com/marvel-masterworks-captain-america-3-vol-3/4000-233672/" data-ref-id="4000-233672">Marvel Masterworks: Captain America Vol. 3</a> (#101-113)</li><li><a href="https://www.comicvine.com/marvel-masterworks-captain-america-4-vol-4/4000-233673/" data-ref-id="4000-233673">Marvel Masterworks: Captain America Vol. 4</a> (#114-124)</li><li><a href="https://comicvine.gamespot.com/captain-america-omnibus-2-volume-2/4000-520197/" data-ref-id="4000-520197">Captain America Omnibus Volume 2</a> (#114-148)</li><li><a href="/marvels-captain-america-the-winter-soldier-prelude/4050-72369/" data-ref-id="4050-72369">Marvel''s Captain America: The Winter Soldier Prelude</a> (#117)</li><li><a href="https://comicvine.gamespot.com/captain-america-epic-collection-bucky-reborn/4050-102578/" data-ref-id="4050-102578">Captain America Epic Collection: Bucky Reborn</a> (#120-138)</li><li><a href="https://www.comicvine.com/marvel-masterworks-captain-america-5-vol-5/4000-233675/" data-ref-id="4000-233675">Marvel Masterworks: Captain America Vol. 5</a> (#125-136)</li><li><a href="https://comicvine.gamespot.com/modok-head-trips/4050-123130/">M.O.D.O.K.: Head Trips</a> (#133