INSERT INTO volumes (id, name, firstIssue, publisher, description, startYear, numIssues, image, characters_name, concepts_name, characters_id, concepts_id, numLikes) VALUES ('2401', 'Captain Marvel', 'Out Of The Holocaust-- A Hero!', '31', '<figure data-align="right" data-img-src="https://static.comicvine.com/uploads/original/11/117930/2298787-marvel_super_heroes.jpg" data-ref-id="1300-2298787" data-size="small" data-ratio="1.52" data-width="400" data-embed-type="image" style="width: 400px"><a class="fluid-height" style="padding-bottom:152.0%" href="https://static.comicvine.com/uploads/original/11/117930/2298787-marvel_super_heroes.jpg" data-ref-id="1300-2298787"><img alt="No Caption Provided" src="https://comicvine.gamespot.com/a/uploads/original/11/117930/2298787-marvel_super_heroes.jpg" srcset="https://comicvine.gamespot.com/a/uploads/original/11/117930/2298787-marvel_super_heroes.jpg 400w" sizes="(max-width: 421px) 100vw, 421px" data-width="421"></a></figure><p>A <a href="/marvel/4010-31/" data-ref-id="4010-31"> Marvel</a> series featuring <a href="/captain-marvel/4005-1472/" data-ref-id="4005-1472"> Mar-Vell</a>, a former <a href="/kree/4060-7588/" data-ref-id="4060-7588"> Kree</a> soldier turned The Protector of the Universe. Captain Marvel Vol. 1 is Mar-Vell''s only long running solo series. The series was launched following the success of Captain Marvel''s debut in <a href="/marvel-super-heroes/4050-2353/" data-ref-id="4050-2353"> Marvel Super-Heroes</a> #12 and picks up the story arc from Marvel Super-Heroes #13. The series started in 1968 and lasted until 1979. However due to low sales figures, it was put on hiatus after issue #19 (December 1969). The volume resumed in 1970 for 2 further issues (June and August) but another break ensued until September 1972 when the series returned with a bi-monthly release.</p><p>The creation of the Captain Marvel character led to Marvel attaining the rights to the "Captain Marvel" name and forcing <a href="/dc-comics/4010-10/" data-ref-id="4010-10"> DC</a> to rename their Captain Marvel series to "<a href="/shazam/4050-2622/" data-ref-id="4050-2622">Shazam!</a>". To retain their trademark, Marvel has published a Captain Marvel title every few years since, leading to a number of ongoing and mini series'' as well as one-shots featuring a number of different characters using the Captain Marvel identity.</p><p>Created by writer/editor <a href="/stan-lee/4040-40467/" data-ref-id="4040-40467"> Stan Lee</a> and artist <a href="/gene-colan/4040-3792/" data-ref-id="4040-3792"> Gene Colan</a>, Captain Marvel Vol. 1 also saw the introduction of <a href="/ms-marvel/4005-21561/" data-ref-id="4005-21561"> Carol Danvers</a> a.k.a. Ms. Marvel, who would eventually go on to take the title of Captain Marvel.</p><h4>Collected Editions</h4><ul><li><a href="/marvel-masterworks-captain-marvel-1-volume-one/4000-228342/" data-ref-id="4000-228342">Marvel Masterworks: Captain Marvel Vol. 1</a> (Marvel Super-Heroes #12-13 and Captain Marvel #1-9)</li><li><a href="/marvel-masterworks-captain-marvel-2-volume-two/4000-228345/" data-ref-id="4000-228345">Marvel Masterworks: Captain Marvel Vol. 2</a> (Captain Marvel #10-21)</li><li><a href="/marvel-masterworks-captain-marvel-3-volume-three/4000-228347/" data-ref-id="4000-228347">Marvel Masterworks: Captain Marvel Vol. 3</a> (Captain Marvel #22-33 and Iron Man #55)</li><li><a href="/marvel-masterworks-captain-marvel-4-volume-4/4000-343519/" data-ref-id="4000-343519">Marvel Masterworks: Captain Marvel Vol. 4</a> (Captain Marvel #34-46)</li><li><a href="/marvel-masterworks-captain-marvel-5-volume-5/4000-456212/" data-ref-id="4000-456212">Marvel Masterworks: Captain Marvel Vol. 5</a> (Captain Marvel #47-57, Avengers Annual #7 and Marvel Two-in-One Annual #2)</li><li><a href="https://comicvine.gamespot.com/marvel-masterworks-captain-marvel-6-volume-6/4000-529659/" data-ref-id="4000-529659">Marvel Masterworks: Captain Marvel Vol. 6</a> (Captain Marvel #58-62, Marvel Spotlight #1-4, 8; Marvel Super-Heroes #3, and Marvel Graphic Novel #1)</li></ul><ul><li><a href="https://comicvine.gamespot.com/captain-marvel-by-jim-starlin-the-complete-collect/4050-95814/" data-ref-id="4050-95814">Captain Marvel by Jim Starlin: The Complete Collection</a> (#25-34)</li></ul><ul><li><a href="/avengers-avengers-vs-thanos/4050-57667/" data-ref-id="4050-57667">Avengers vs. Thanos</a> (#25-33)</li><li><a href="https://comicvine.gamespot.com/the-thanos-wars-infinity-origin/4050-118000/">The Thanos Wars: Infinity Origin</a> (#25-34)</li><li><a href="/guardians-of-the-galaxy-solo-classic-omnibus/4050-85759/" data-ref-id="4050-85759">Guardians of the Galaxy Solo Classic Omnibus</a> (#27-33, 43-44 &amp; 58-62)</li><li><a href="https://comicvine.gamespot.com/drax-guardian-of-the-galaxy/4050-93657/" data-ref-id="4050-93657">Drax: Guardian of the Galaxy</a> (#27-33, 43-44 &amp; 58-62)</li><li><a href="https://comicvine.gamespot.com/avengers-the-complete-celestial-madonna-saga/4050-100682/" data-ref-id="4050-100682">Avengers: The Complete Celestial Madonna Saga</a> (#33)</li><li><a href="https://comicvine.gamespot.com/avengers-epic-collection-the-avengersdefenders-war/4050-109747/">Avengers Epic Collection: The Avengers/Defenders War</a> (#33)</li><li><a href="https://comicvine.gamespot.com/marvel-verse-thanos/4050-122491/">Marvel-Verse: Thanos</a> (#33)</li><li><a href="/captain-marvel-the-death-of-captain-marvel/4050-34102/" data-ref-id="4050-34102">Captain Marvel: The Death of Captain Marvel</a> (#34)</li><li><a href="https://comicvine.gamespot.com/captain-marvel-starforce/4050-119136/">Captain Marvel: Starforce</a> (#52)</li></ul>', '1968', '62', '{''icon_url'': ''https://comicvine.gamespot.com/a/uploads/square_avatar/11/117763/2481699-captainmarvel001.jpg'', ''medium_url'': ''https://comicvine.gamespot.com/a/uploads/scale_medium/11/117763/2481699-captainmarvel001.jpg'', ''screen_url'': ''https://comicvine.gamespot.com/a/uploads/screen_medium/11/117763/248169