INSERT INTO volumes (id, name, firstIssue, publisher, description, startYear, numIssues, image, characters_name, concepts_name, characters_id, concepts_id, numLikes) VALUES ('2402', 'Captain Savage', 'The Last Banzai!', '31', '<p><b>Captain Savage Volume 1</b></p><p> </p><p>A comic-book series featuring another team of colorful soldiers during World War Two, much like Nick Fury''s Howling Commandos. The series ran from 1968 till 1970 with a total of 19 issues. The title''s under scribe was changed from "Leatherneck Raiders" to "Battlefield Raiders" with issue 9. The indica remained the same however.</p>', '1968', '19', '{''icon_url'': ''https://comicvine.gamespot.com/a/uploads/square_avatar/6/67663/2172646-01.jpg'', ''medium_url'': ''https://comicvine.gamespot.com/a/uploads/scale_medium/6/67663/2172646-01.jpg'', ''screen_url'': ''https://comicvine.gamespot.com/a/uploads/screen_medium/6/67663/2172646-01.jpg'', ''screen_large_url'': ''https://comicvine.gamespot.com/a/uploads/screen_kubrick/6/67663/2172646-01.jpg'', ''small_url'': ''https://comicvine.gamespot.com/a/uploads/scale_small/6/67663/2172646-01.jpg'', ''super_url'': ''https://comicvine.gamespot.com/a/uploads/scale_large/6/67663/2172646-01.jpg'', ''thumb_url'': ''https://comicvine.gamespot.com/a/uploads/scale_avatar/6/67663/2172646-01.jpg'', ''tiny_url'': ''https://comicvine.gamespot.com/a/uploads/square_mini/6/67663/2172646-01.jpg'', ''original_url'': ''https://comicvine.gamespot.com/a/uploads/original/6/67663/2172646-01.jpg'', ''image_tags'': ''All Images''}', '[{"id": "Roy Stone"}, {"id": "Jacques LaRocque"}, {"id": "Sam Yates"}, {"id": "Captain Savage"}, {"id": "Jay Little Bear"}, {"id": "Lee Baker"}, {"id": "Izzy Cohen"}, {"id": "Nick Fury"}, {"id": "Gweny Lee"}, {"id": "Dino Manelli"}, {"id": "Percy Pinkerton"}, {"id": "Rebel Ralston"}, {"id": "Baron von Strucker"}, {"id": "Eric Koenig"}, {"id": "Gabriel Jones"}, {"id": "Dum Dum Dugan"}, {"id": "Rolfe Harrison"}, {"id": "Happy Sam Sawyer"}, {"id": "John F. Kennedy"}, {"id": "Erikson"}, {"id": "General Ten Per Cent"}, {"id": "Father Thompson"}, {"id": "Thing"}, {"id": "Michelle Fisher"}]', 'NaN', '[{"id": 61950}, {"id": 38284}, {"id": 38283}, {"id": 38282}, {"id": 37194}, {"id": 38285}, {"id": 14198}, {"id": 3202}, {"id": 38007}, {"id": 14199}, {"id": 14197}, {"id": 14196}, {"id": 4662}, {"id": 13837}, {"id": 13836}, {"id": 3526}, {"id": 61949}, {"id": 32606}, {"id": 33077}, {"id": 38104}, {"id": 38124}, {"id": 60588}, {"id": 2114}, {"id": 92365}]', 'NaN', '0');
INSERT INTO volumes (id, name, firstIssue, publisher, description, startYear, numIssues, image, characters_name, concepts_name, characters_id, concepts_id, numLikes) VALUES ('2406', 'The Incredible Hulk', '--This World Not His Own!', '31', '<p>Continued from <a href="/tales-to-astonish/4050-2008/" data-ref-id="4050-2008">Tales to Astonish Vol.1</a> which was originally one of several anthology comics published by <a href="/marvel/4010-31/" data-ref-id="4010-31">Marvel</a> in the 1960''s featuring one-shot monsters in their own tales. Over the years the series began to focus more upon some of the anti-heroes still famous to this day such as the <a href="/namor/4005-1476/" data-ref-id="4005-1476">Sub-Mariner</a> and <a href="/hulk/4005-2267/" data-ref-id="4005-2267">The Incredible Hulk</a>. That is why, after 101 issues, that series changed its name to The Incredible Hulk with issue #102. Under this new name the series lasted thirty more years until it finally concluded with issue #474. The series was then revamped with a new number one and a new title, simply called <a href="/hulk/4050-6779/" data-ref-id="4050-6779"> Hulk (1998)</a>.</p><p>Although it started out as Tales to Astonish, this is actually the second volume to be entitled "The Incredible Hulk", the first, <a href="/the-incredible-hulk/4050-2077/" data-ref-id="4050-2077"> The Incredible Hulk</a> (1962), having begun publication six years earlier, although it only lasted six issues.</p><h4>Collected Editions</h4><ul><li><a href="https://comicvine.gamespot.com/incredible-hulk-epic-collection-the-leader-lives/4050-114890/">Incredible Hulk Epic Collection: The Leader Lives</a> (#102-117)</li><li><a href="https://comicvine.gamespot.com/incredible-hulk-epic-collection-in-the-hands-of-hy/4050-121575/">Incredible Hulk Epic Collection: In the Hands of Hydra</a> (#118-137)</li><li><a href="https://comicvine.gamespot.com/doctor-strange-epic-collection-a-separate-reality/4050-95006/" data-ref-id="4050-95006">Doctor Strange Epic Collection: A Separate Reality</a> (#126)</li><li><a href="https://comicvine.gamespot.com/avengers-kang-time-and-time-again/4050-30427/" data-ref-id="4050-30427">Avengers: Kang: Time and Time Again</a> (#135)</li><li><a href="/spider-man-saga-of-the-sandman/4050-27204/" data-ref-id="4050-27204">Spider-Man: Saga of the Sandman</a> (#138)</li><li><a href="https://comicvine.gamespot.com/incredible-hulk-epic-collection-who-will-judge-the/4050-133098/">Incredible Hulk Epic Collection: Who Will Judge The Hulk?</a> (#138-156)</li><li><a href="https://comicvine.gamespot.com/hulk-heart-of-the-atom/4050-50267/" data-ref-id="4050-50267">Hulk: Heart of the Atom</a> (#140, 148, 156, 202-203, 205-207 and 246-248)</li><li><a href="/avengers-omnibus-3-volume-three/4000-663568/" data-ref-id="4000-663568">Avengers Omnibus Volume 3</a> (#140)</li><li><a href="https://comicvine.gamespot.com/avengers-epic-collection-this-beachhead-earth/4050-129190/">Avengers Epic Collection: This Beachhead Earth</a> (#140)</li><li><a href="https://comicvine.gamespot.com/x-men-epic-collection-its-always-darkest-before-th/4050-120262/">X-Men Epic Collection: It''s Always Darkest Before the Dawn</a> (#150, 161, 172 &amp; 180-182)</li><li><a href="https://comicvine.gamespot.com/incredible-hulk-epic-collection-crisis-on-counter-/4050-139161/">Incredible Hulk Epic Collection: Crisis On Counter-Earth</a> (#157-178)</li><li><a href="https://comicvine.gamespot.com/marvel-horror-lives-again-omnibus/4050-131205/">Marvel Horror Lives Again! Omnibus</a> (#162, 180-181 &amp; 272)</li><li><a href="/marvel-masterworks-the-incredible-hulk-15-volume-1/4000-851634/" data-ref-id="4000-851634">Marvel Masterworks: The Incredible Hulk Volume 15</a> (#234-244)</li><li><a href="https://comicvine.gamespot.com/machine-man-by-kirby-ditko-the-complete-collection/4050-92563/" data-ref-id="4050-92563">Machine Man by Kirby &amp; Ditko: The Complete Collection</a> (#235-237)</li><li><a href="https://comicvine.gamespot.com/marvel-horror-omnibus/4050-121088/">Marvel Horror Omnibus</a> (#244)</li><li><a href="https://comicvine.gamespot.com/thor-vs-hulk/4050-104825/" data-ref-id="4050-104825">Thor vs. Hulk</a> (#255 &amp; 440)</li><li><a href="https://comicvine.gamespot.com/marvels-guardians-of-the-galaxy-prelude-1-tpb/4000-458964/" data-ref-id="4000-458964">Marvel''s Guardians of the Galaxy Prelude Volume 1</a> (#271)</li><li><a href="/guardians-of-the-galaxy-cosmic-teamup/4050-75814/" data-ref-id="4050-75814">Guardians of the Galaxy: Cosmic Team-Up</a> (#271)</li><li><a href="/guardians-of-the-galaxy-solo-classic-omnibus/4050-85759/" data-ref-id="4050-85759">Guardians of the Galaxy Solo Classic Omnibus</a> (#271)</li><li><a href="https://comicvine.gamespot.com/rocket-raccoon-guardian-of-the-keystone-quadrant/4050-42935/">Rocket Raccoon: Guardian of the Keystone Quadrant</a> (#271)</li><li><a href="https://comicvine.gamespot.com/alpha-flight-by-john-byrne-omnibus/4050-98560/" data-ref-id="4050-98560">Alpha Flight By John Byrne Omnibus</a> (#272 &amp; 313)</li><li><a href="/incredible-hulk-regression/4050-51322/" data-ref-id="4050-51322">Incredible Hulk: Regression</a> (#286-300)</li><li><a href="https://comicvine.gamespot.com/modok-head-trips/4050-123130/">M.O.D.O.K.: Head Trips</a> (#287-290)</li><li><a href="https://comicvine.gamespot.com/incredible-hulk-hulk-vs-the-marvel-universe/4050-31010/">Incredible Hulk: Hulk vs the Marvel Universe</a> (#300 &amp; 340)</li><li><a href="//www.comicvine.com/the-incredible-hulk-crossroads/4050-61401/" data-ref-id="4050-61401">The Incredible Hulk: Crossroads</a> (#301-313)</li><li><a href="https://comicvine.gamespot.com/alpha-flight-classic-3-volume-3/4000-550693/" data-ref-id="4000-550693">Alpha Flight Classic Volume Three</a> (#313)</li><li><a href="/marvel-universe-by-john-byrne-omnibus-1-hc/4000-523259/" data-ref-id="4000-523259">Marvel Universe by John Byrne Omnibus Volume 1</a> (#314-319)</li><li><a href="https://comicvine.gamespot.com/incredi