INSERT INTO volumes (id, name, firstIssue, publisher, description, startYear, numIssues, image, characters_name, concepts_name, characters_id, concepts_id, numLikes) VALUES ('2407', 'Iron Man', 'Alone Against A.I.M.!: The Origin of Iron Man', '31', '<p>A new hero has arrived, Iron Man, but who is he and what is he. This is the comic that started it all, written by Stan Lee, Larry Lieber and drawn by Jack Kirby and Don Heck.</p><figure data-align="right" data-img-src="https://static.comicvine.com/uploads/original/11/117930/2295526-iron_man_debut.jpg" data-ref-id="1300-2295526" data-size="small" data-ratio="1.4925" data-width="400" data-embed-type="image" style="width: 400px"><a class="fluid-height" style="padding-bottom:149.3%" href="https://static.comicvine.com/uploads/original/11/117930/2295526-iron_man_debut.jpg" data-ref-id="1300-2295526"><img alt="No Caption Provided" src="https://comicvine.gamespot.com/a/uploads/original/11/117930/2295526-iron_man_debut.jpg" srcset="https://comicvine.gamespot.com/a/uploads/original/11/117930/2295526-iron_man_debut.jpg 400w" sizes="(max-width: 428px) 100vw, 428px" data-width="428"></a></figure><p>Iron Man Vol. 1 is Iron Man''s first ongoing solo series. The series was launched following the success of the Iron Man stories in <a href="/tales-of-suspense/4050-2007/" data-ref-id="4050-2007">Tales of Suspense</a> and continues from the one shot <a href="/iron-man-and-sub-mariner/4050-18547/" data-ref-id="4050-18547">Iron Man and Sub-Mariner</a> which picks up the story arc from Tales of Suspense #99. Many of the classic story lines and characters that are part of comic history today originate from this volume. The series started in 1968 and lasted all the way to 1996. Continues in <a href="/iron-man-vol-2/4050-18800/" data-ref-id="4050-18800">Iron Man Vol.2</a>.</p><p>Created by writers <a href="/stan-lee/4040-40467/" data-ref-id="4040-40467">Stan Lee</a> and <a href="/larry-lieber/4040-4068/" data-ref-id="4040-4068">Larry Lieber</a> and artists <a href="/don-heck/4040-6609/" data-ref-id="4040-6609">Don Heck</a> and <a href="/jack-kirby/4040-5614/" data-ref-id="4040-5614">Jack Kirby</a>, Iron Man''s first appearance was in Tales of Suspense #39.</p><h4>Collected Editions</h4><ul><li><a href="https://www.comicvine.com/essential-iron-man-2-volume-2/4000-150311/" data-ref-id="4000-150311">Essential Iron Man Vol. 2</a> (#1-11)</li><li><a href="https://comicvine.gamespot.com/iron-man-epic-collection-by-force-of-arms/4050-98341/" data-ref-id="4050-98341">Iron Man Epic Collection: By Force of Arms</a> (#1)</li><li><a href="https://www.comicvine.com/marvel-masterworks-the-invincible-iron-man-5-volum/4000-232215/" data-ref-id="4000-232215">Marvel Masterworks Vol. 5</a> (#2-13)</li><li><a href="https://comicvine.gamespot.com/iron-man-epic-collection-the-man-who-killed-tony-s/4050-118382/">Iron Man Epic Collection: The Man Who Killed Tony Stark</a> (#2-24)</li><li><a href="https://www.comicvine.com/essential-iron-man-3-volume-3/4000-150312/" data-ref-id="4000-150312">Essential Iron Man Vol. 3</a> (#12-38)</li><li><a href="https://www.comicvine.com/marvel-masterworks-the-invincible-iron-man-6-volum/4000-232217/" data-ref-id="4000-232217">Marvel Masterworks Vol. 6</a> (#14-25)</li><li><a href="https://comicvine.gamespot.com/iron-man-epic-collection-the-fury-of-the-firebrand/4050-129903/">Iron Man Epic Collection: The Fury of the Firebrand</a> (#25-46)</li><li><a href="https://www.comicvine.com/marvel-masterworks-the-invincible-iron-man-7-volum/4000-394391/" data-ref-id="4000-394391">Marvel Masterworks Vol. 7</a> (#26-38)</li><li><a href="https://comicvine.gamespot.com/daredevil-epic-collection-a-woman-called-widow/4050-122193/">Daredevil Epic Collection: A Woman Called Widow</a> (#35-36)</li><li><a href="https://www.comicvine.com/marvel-masterworks-the-invincible-iron-man-8-volum/4000-402613/" data-ref-id="4000-402613">Marvel Masterworks Vol. 8</a> (#39-53)</li><li><a href="https://www.comicvine.com/essential-iron-man-4-volume-4/4000-308911/" data-ref-id="4000-308911">Essential Iron Man Vol. 4</a> (#39-61)</li><li><a href="https://comicvine.gamespot.com/iron-man-many-armors-of-iron-man/4050-115823/">Iron Man: Many Armors of Iron Man</a> (#47, 142-144, 152-153, 200 &amp; 218)</li><li><a href="https://www.comicvine.com/marvel-masterworks-the-invincible-iron-man-9-volum/4000-482892/" data-ref-id="4000-482892">Marvel Masterworks: The Invincible Iron Man Volume 9</a> (#54-67)</li><li><a href="https://comicvine.gamespot.com/marvels-guardians-of-the-galaxy-prelude-1-tpb/4000-458964/" data-ref-id="4000-458964">Marvel''s Guardians of the Galaxy Prelude Volume 1</a> (#55)</li><li><a href="https://comicvine.gamespot.com/drax-guardian-of-the-galaxy/4050-93657/" data-ref-id="4050-93657">Drax: Guardian of the Galaxy</a> (#55)</li><li><a href="/guardians-of-the-galaxy-solo-classic-omnibus/4050-85759/" data-ref-id="4050-85759">Guardians of the Galaxy Solo Classic Omnibus</a> (#55)</li><li><a href="https://comicvine.gamespot.com/captain-marvel-by-jim-starlin-the-complete-collect/4050-95814/" data-ref-id="4050-95814">Captain Marvel By Jim Starlin: The Complete Collection</a> (#55)</li><li><a href="https://comicvine.gamespot.com/the-thanos-wars-infinity-origin/4050-118000/">The Thanos Wars: Infinity Origin</a> (#55)</li><li><a href="https://comicvine.gamespot.com/marvel-verse-thanos/4050-122491/">Marvel-Verse: Thanos</a> (#55)</li><li><a href="https://www.comicvine.com/essential-iron-man-5-volume-5/4000-396602/" data-ref-id="4000-396602">Essential Iron Man Vol. 5</a> (#62-75 &amp; 77-87)</li><li><a href="https://comicvine.gamespot.com/marvel-masterworks-the-invincible-iron-man-10-volu/4000-575872/" data-ref-id="4000-575872">Marvel Masterworks: The Invincible Iron Man Vol. 10</a> (#68-81)</li><li><a href="/marvel-masterworks-the-invincible-iron-man-11-volu/4000-688320/" data-ref-id="4000-688320">Marvel Masterworks: The Invincible Iron Man Vol. 11</a> (#82-94)</li><li><a href="/marvel-ma