INSERT INTO volumes (id, name, firstIssue, publisher, description, startYear, numIssues, image, characters_name, concepts_name, characters_id, concepts_id, numLikes) VALUES ('2410', 'Nick Fury, Agent of SHIELD', 'Who Is Scorpio?', '31', '<p>Nick Fury, the super-spy takes center stage in his own ongoing series with beautiful art-work by Jim Steranko. The series spun-off from <a href="../../strange-tales/49-18066/" rel="nofollow ">Strange Tales</a> #168. The series lasted for 15 issues. After that, the series was cancelled, with the story continuing into <em> <a href="https://comicvine.gamespot.com/the-avengers-72-did-you-hear-the-one-about-scorpio/4000-10617/">The Avengers issue 72</a>. </em>One year later, the series returned as a reprint series for issue 16,17 and 18.</p><p>A year and a half later, the series was sort of revived for a few issues with a new number one in <a href="https://www.comicvine.com/nick-fury-and-his-agents-of-shield/4050-2642/">Nick Fury and His Agents of SHIELD</a>.</p><h4>Collected Editions</h4><ul><li><a href="/shield-the-complete-collection/4050-85133/" data-ref-id="4050-85133">S.H.I.E.L.D.: The Complete Collection</a> (#1-15)</li><li>Marvel Masterworks: Nick Fury, Agent of S.H.I.E.L.D. Vol. 2 (#1-3)</li><li><a href="https://www.comicvine.com/shield-by-steranko-the-complete-collection/4050-67342/" data-ref-id="4050-67342">Shield By Steranko: The Complete Collection</a> (#1-3)</li><li><a href="https://comicvine.gamespot.com/steranko-is-revolutionary/4050-129904/">Steranko Is… Revolutionary!</a> (#1-3 &amp; 5)</li></ul><h4>Non-U.S. Collected Editions</h4><ul><li><a href="https://comicvine.gamespot.com/coleccionable-marvel-heroes-10-nick-furia-agente-d/4000-612215/">Coleccionable Marvel Héroes: Nick Furia: Agente de SHIELD</a> (#1-3) (Spanish)</li></ul>', '1968', '18', '{''icon_url'': ''https://comicvine.gamespot.com/a/uploads/square_avatar/11/117930/2694258-nick_fury_aos__1.jpg'', ''medium_url'': ''https://comicvine.gamespot.com/a/uploads/scale_medium/11/117930/2694258-nick_fury_aos__1.jpg'', ''screen_url'': ''https://comicvine.gamespot.com/a/uploads/screen_medium/11/117930/2694258-nick_fury_aos__1.jpg'', ''screen_large_url'': ''https://comicvine.gamespot.com/a/uploads/screen_kubrick/11/117930/2694258-nick_fury_aos__1.jpg'', ''small_url'': ''https://comicvine.gamespot.com/a/uploads/scale_small/11/117930/2694258-nick_fury_aos__1.jpg'', ''super_url'': ''https://comicvine.gamespot.com/a/uploads/scale_large/11/117930/2694258-nick_fury_aos__1.jpg'', ''thumb_url'': ''https://comicvine.gamespot.com/a/uploads/scale_avatar/11/117930/2694258-nick_fury_aos__1.jpg'', ''tiny_url'': ''https://comicvine.gamespot.com/a/uploads/square_mini/11/117930/2694258-nick_fury_aos__1.jpg'', ''original_url'': ''https://comicvine.gamespot.com/a/uploads/original/11/117930/2694258-nick_fury_aos__1.jpg'', ''image_tags'': ''All Images''}', '[{"id": "Nick Fury"}, {"id": "Dum Dum Dugan"}, {"id": "Gabriel Jones"}, {"id": "Laura Brown"}, {"id": "Jimmy Woo"}, {"id": "Valentina de Fontaine"}, {"id": "Iron Man"}, {"id": "Jasper Sitwell"}, {"id": "Hate-Monger"}, {"id": "Arnold Brown"}, {"id": "Mentallo"}, {"id": "Number 72"}, {"id": "Robert Rickard"}, {"id": "Centurius"}, {"id": "Super-Patriot"}, {"id": "Fixer"}, {"id": "Jake Fury"}, {"id": "Brad Carter"}, {"id": "Rachel MacGregor"}, {"id": "Dredmund Druid"}, {"id": "Lyndon Johnson"}, {"id": "Bull''s Eye"}, {"id": "Half-Man"}, {"id": "Supremus"}, {"id": "Ed Sullivan"}, {"id": "Supreme Hydra"}, {"id": "Karl Kraus"}, {"id": "Yellow Claw"}, {"id": "Dino Manelli"}, {"id": "Sidney Levine"}, {"id": "Eric Koenig"}, {"id": "Clay Quartermain"}, {"id": "Baron von Strucker"}]', '[{"id": "Homage Covers"}]', '[{"id": 3202}, {"id": 3526}, {"id": 13836}, {"id": 13838}, {"id": 7530}, {"id": 23797}, {"id": 1455}, {"id": 7529}, {"id": 12064}, {"id": 14565}, {"id": 13922}, {"id": 14569}, {"id": 14567}, {"id": 50738}, {"id": 79818}, {"id": 3282}, {"id": 5076}, {"id": 64546}, {"id": 166949}, {"id": 47170}, {"id": 38601}, {"id": 86376}, {"id": 37061}, {"id": 37013}, {"id": 20177}, {"id": 16040}, {"id": 14568}, {"id": 14525}, {"id": 14199}, {"id": 13840}, {"id": 13837}, {"id": 7524}, {"id": 4662}]', '[{"id": 43734}]', '0');
INSERT INTO volumes (id, name, firstIssue, publisher, description, startYear, numIssues, image, characters_name, concepts_name, characters_id, concepts_id, numLikes) VALUES ('2411', 'The Silver Surfer', 'The Origin of the Silver Surfer', '31', '<p><a href="/stan-lee/4040-40467/" data-ref-id="4040-40467">Stan Lee</a> launched the solo title The Silver Surfer. <a href="/john-buscema/4040-3800/" data-ref-id="4040-3800">John Buscema</a> was penciller for the first 17 issues of the series, with <a href="/jack-kirby/4040-5614/" data-ref-id="4040-5614">Jack Kirby</a> returning for the 18th and final issue. The first seven issues, which included anthological "Tales of the Watcher" backup stories, were 72-page (with advertising), 25-cent "giants", as opposed to the typical 36-page, 12-cent comics of the time. Thematically, the stories dealt with The Silver Surfer''s exile on <a href="/earth/4020-57183/" data-ref-id="4020-57183">Earth</a> and the inhumanity of man as observed by this noble yet fallen hero. Though short-lived, the series became known as one of Lee''s most thoughtful and introspective works.</p><p>Following this series'' cancellation, <a href="/silver-surfer/4005-2502/" data-ref-id="4005-2502">Silver Surfer</a> made sporadic appearances as a guest star or antagonist in such comic books as <a href="/thor/4050-2294/" data-ref-id="4050-2294">Thor</a>, <a href="/the-defenders/4050-2569/" data-ref-id="4050-2569">The Defenders</a>, and <a href="/fantastic-four/4050-2045/" data-ref-id="4050-2045">Fantastic Four</a>. Lee remained partial to the Surfer, and with Kirby collaborated on a seminal 1978 <a href="/the-silver-surfer-the-ultimate-cosmic-experience/4050-20444/" data-ref-id="4050-20444">graphic novel</a> starring the character.</p><h3>Collections</h3><ul><li><a href="/marvel-masterworks-15-volume-15-the-silver-surfer/4000-32227/" data-ref-id="4000-32227">Marvel Masterworks Vol. 15</a> (#1-5)</li><li><a href="/fantasy-masterpieces/4050-3003/" data-ref-id="4050-3003">Fantasy Masterpieces Vol. 2</a> (#1-14, individual issues)</li><li><a href="/essential-silver-surfer-1-volume-1/4000-157715/" data-ref-id="4000-157715">Essential Silver Surfer Vol. 1</a> (#1-18)</li><li><a href="/marvel-masterworks-19-volume-19-the-silver-surfer-/4000-33695/" data-ref-id="4000-33695">Marvel Masterworks Vol. 19</a> (#6-18)</li><li><a href="/spiderman-silver-surfer/4050-87462/" data-ref-id="4050-87462">Spider-Man: Silver Surfer</a> (#14)</li><li><a href="/marvel-masterworks-the-silver-surfer-1-volume-one/4000-228379/" data-ref-id="4000-228379">Marvel Masterworks: Silver Surfer Vol. 1</a> (#1-6)</li><li><a href="/marvel-masterworks-the-silver-surfer-2-volume-two/4000-228380/" data-ref-id="4000-228380">Marvel Masterworks: Silver Surfer Vol. 2</a> (#7-18)</li></ul>', '1968', '18', '{''icon_url'': ''https://comicvine.gamespot.com/a/uploads/square_avatar/11/117763/2403460-ss1.png'', ''medium_url'': ''https://comicvine.gamespot.com/a/uploads/scale_medium/11/117763/2403460-ss1.png'', ''screen_url'': ''https://comicvine.gamespot.com/a/uploads/screen_medium/11/117763/2403460-ss1.png'', ''screen_large_url'': ''https://comicvine.gamespot.com/a/uploads/screen_kubrick/11/117763/2403460-ss1.png'', ''small_url'': ''https://comicvine.gamespot.com/a/uploads/scale_small/11/117763/2403460-ss1.png'', ''super_url'': ''https://comicvine.gamespot.com/a/uploads/scale_large/11/117763/2403460-ss1.png'', ''thumb_url'': ''https://comicvine.gamespot.com/a/uploads/scale_avatar/11/117763/2403460-ss1.png'', ''tiny_url'': ''https://comicvine.gamespot.com/a/uploads/square_mini/11/117763/2403460-ss1.png'', ''original_url'': ''https://comicvine.gamespot.com/a/uploads/original/11/117763/2403460-ss1.png'', ''image_tags'': ''All Images''}', '[{"id": "Silver Surfer"}, {"id": "Shalla Bal"}, {"id": "Watcher"}, {"id": "Mephisto"}, {"id": "Thing"}, {"id": "Mr. Fantastic"}, {"id": "Hulk"}, {"id": "Yarro Gort"}, {"id": "Stranger"}, {"id": "Galactus"}, {"id": "Human Torch"}, {"id": "Nick Fury"}, {"id": "Invisible Woman"}, {"id": "Overlord"}, {"id": "Dum Dum Dugan"}, {"id": "Donna Maria Perez"}, {"id": "Spider-Man"}, {"id": "Flying Dutchman"}, {"id": "Zeus"}, {"id": "Triton"}, {"id": "Karnak"}, {"id": "Borgo"}, {"id": "Mastermind"}, {"id": "Balder"}, {"id": "Sif"}, {"id": "John Jameson"}, {"id": "Gorgon"}, {"id": "Frankenstein"}, {"id": "Doomsday Man"}, {"id": "Brother Royal"}, {"id": "Frankensurfer"}, {"id": "Pedro"}, {"id": "Igron The Invincible"}, {"id": "Ludwig Frankenstein"}, {"id": "Tomazooma"}, {"id": "Tim Boo Ba"}, {"id": "Emnu"}, {"id": "Ikor"}, {"id": "Monster of Badoon"}, {"id": "Al Harper"}, {"id": "Magneto"}, {"id": "Stallior"}, {"id": "Captain America"}, {"id": "Iron Man"}, {"id": "Beast"}, {"id": "Iceman"}, {"id": "Scarlet Witch"}, {"id": "Quicksilver"}, {"id": "Doctor Doom"}, {"id": "Toad"}, {"id": "Angel"}, {"id": "Skybreaker"}, {"id": "Thor"}, {"id": "Hercules"}, {"id": "Betty Ross"}, {"id": "Maximus"}, {"id": "Black Bolt"}, {"id": "Leonus"}, {"id": "Timberius"}, {"id": "Thunderbolt Ross"}, {"id": "Abomination"}, {"id": "Odin"}, {"id": "Heimdall"}, {"id": "Hogun"}, {"id": "Fandral"}, {"id": "Volstagg"}, {"id": "Lockjaw"}, {"id": "Manuel"}, {"id": "Loki"}, {"id": "Medusa"}]', '[{"id": "Comics Code Authority"}, {"id": "Comic Books In Media"}, {"id": "Homage Covers"}, {"id": "Time Travel"}]', '[{"id": 2502}, {"id": 7125}, {"id": 7120}, {"id": 2635}, {"id": 2114}, {"id": 2151}, {"id": 2267}, {"id": 14620}, {"id": 13332}, {"id": 2149}, {"id": 2120}, {"id": 3202}, {"id": 2190}, {"id": 37998}, {"id": 3526}, {"id": 14621}, {"id": 1443}, {"id": 14624}, {"id": 10226}, {"id": 11428}, {"id": 10975}, {"id": 27845}, {"id": 8306}, {"id": 7201}, {"id": 7200}, {"id": 4456}, {"id": 4330}, {"id": 16075}, {"id": 19948}, {"id": 22908}, {"id": 84299}, {"id": 28508}, {"id": 36691}, {"id": 37059}, {"id": 38178}, {"id": 44845}, {"id": 46959}, {"id": 46977}, {"id": 59376}, {"id": 62834}, {"id": 1441}, {"id": 3449}, {"id": 1442}, {"id": 1455}, {"id": 1462}, {"id": 1464}, {"id": 1466}, {"id": 1467}, {"id": 1468}, {"id": 1470}, {"id": 2112}, {"id": 2133}, {"id": 2268}, {"id": 2503}, {"id": 3445}, {"id": 3447}, {"id": 4329}, {"id": 3450}, {"id": 3451}, {"id": 3457}, {"id": 3489}, {"id": 3507}, {"id": 3508}, {"id": 3511}, {"id": 3512}, {"id": 3513}, {"id": 3534}, {"id": 4075}, {"id": 4324}, {"id": 4327}]', '[{"id": 42382}, {"id": 57596}, {"id": 43734}, {"id": 55712}]', '0');
INSERT INTO volumes (id, name, firstIssue, publisher, description, startYear, numIssues, image, characters_name, concepts_name, characters_id, concepts_id, numLikes) VALUES ('2413', 'Sub-Mariner', 'Years Of Glory, Day Of Doom', '31', '<p>The series was launched following the Sub-Mariner stories from <a href="/tales-to-astonish/4050-2008/" data-ref-id="4050-2008">Tales To Astonish</a>. The series is a continuation from the one-shot <a href="/iron-man-and-sub-mariner/4050-18547/" data-ref-id="4050-18547">Iron Man and Sub-Mariner</a> comic which picks up the story arc from <a href="/tales-to-astonish-where-walk-the-immortalsand-evil-shall-beckon/4000-108670/" data-ref-id="4000-108670">Tales To Astonish #101</a>. The series started in 1968 and lasted until 1974 for a total of 72 issues. The series also had a <a href="https://comicvine.gamespot.com/sub-mariner-annual/4050-2521/">Sub-Mariner Annual </a>companion series.</p><p>This is the first solo <a href="/namor/4005-1476/" data-ref-id="4005-1476">Sub-Mariner</a> series published by <a href="/marvel/4010-31/" data-ref-id="4010-31">Marvel Comics</a>, the previous “<a href="/sub-mariner/4050-1642/" data-ref-id="4050-1642">Sub-Mariner</a>" and “<a href="/sub-mariner-comics/4050-18548/" data-ref-id="4050-18548">Sub-Mariner Comics</a>” having been published by Marvel’s predecessors <a href="/atlas/4010-75/" data-ref-id="4010-75">Atlas</a> and <a href="/timely/4010-21/" data-ref-id="4010-21">Timely</a> respectively.</p><h3>Writers</h3><ul><li><a href="/roy-thomas/4040-42067/" data-ref-id="4040-42067">Roy Thomas</a> #1-40</li><li><a href="/gerry-conway/4040-40871/" data-ref-id="4040-40871">Gerry Conway</a> #41-49</li><li><a href="/bill-everett/4040-6103/" data-ref-id="4040-6103">Bill Everett</a> #45(reprint) 50, 52-55, 57-61, 63</li><li><a href="/mike-friedrich/4040-51799/" data-ref-id="4040-51799">Mike Friedrich</a> #51-52, 54, 56</li><li><a href="/dan-adkins/4040-11274/" data-ref-id="4040-11274">Dan Adkins</a> #56</li><li><a href="/steve-gerber/4040-41456/" data-ref-id="4040-41456">Steve Gerber</a> #58-69</li><li><a href="/howard-chaykin/4040-2424/" data-ref-id="4040-2424">Howard Chaykin</a> #62, 63-64</li><li><a href="/marv-wolfman/4040-41478/" data-ref-id="4040-41478">Marv Wolfman</a> #70-71</li><li><a href="/steve-skeates/4040-44731/" data-ref-id="4040-44731">Steve Skeates</a> #72</li></ul><h4>Collected Editions</h4><ul><li><a href="https://www.comicvine.com/marvel-masterworks-the-sub-mariner-2-volume-two/4000-232081/" data-ref-id="4000-232081">Marvel Masterworks: Sub-Mariner, Vol. 2</a> (#1)</li><li><a href="https://www.comicvine.com/marvel-masterworks-the-sub-mariner-3-volume-three/4000-232082/" data-ref-id="4000-232082">Marvel Masterworks: Sub-Mariner, Vol. 3</a> (#2-13)</li><li><a href="https://www.comicvine.com/marvel-masterworks-the-sub-mariner-4-volume-four/4000-265711/" data-ref-id="4000-265711">Marvel Masterworks: Sub-Mariner, Vol. 4</a> (#14-25)</li><li><a href="https://comicvine.gamespot.com/doctor-strange-epic-collection-a-separate-reality/4050-95006/" data-ref-id="4050-95006">Doctor Strange Epic Collection: A Separate Reality</a> (#22)</li><li><a href="https://www.comicvine.com/marvel-masterworks-the-sub-mariner-5-volume-5/4000-442428/" data-ref-id="4000-442428">Marvel Masterworks: Sub-Mariner, Vol. 5</a> (#26-38)</li><li><a href="/the-defenders-omnibus-1-volume-1/4000-842243/" data-ref-id="4000-842243">The Defenders Omnibus Volume 1</a> (#34-35)</li><li><a href="https://comicvine.gamespot.com/thor-vs-hulk/4050-104825/" data-ref-id="4050-104825">Thor vs. Hulk</a> (#35)</li><li><a href="/marvel-masterworks-the-sub-mariner-6-volume-6/4000-479396/" data-ref-id="4000-479396">Marvel Masterworks: Sub-Mariner, Vol. 6</a> (#39-49)</li><li><a href="/marvel-masterworks-the-sub-mariner-7-volume-7/4000-510946/" data-ref-id="4000-510946">Marvel Masterworks: Sub-Mariner, Vol. 7</a> (#50-60)</li><li><a href="/marvel-masterworks-the-sub-mariner/4050-35188/" data-ref-id="4050-35188">Marvel Masterworks: Sub-Mariner, Vol. 8</a> (#61-72)</li></ul><p>Issues <a href="https://comicvine.gamespot.com/biblioteca-marvel-namor-1/4000-285570/" data-ref-id="4000-285570">#62-66</a> have been translated into Spanish.</p>', '1968', '72', '{''icon_url'': ''https://comicvine.gamespot.com/a/uploads/square_avatar/11/117763/2803744-submariner01.jpg'', ''medium_url'': ''https://comicvine.gamespot.com/a/uploads/scale_medium/11/117763/2803744-submariner01.jpg'', ''screen_url'': ''https://comicvine.gamespot.com/a/uploads/screen_medium/11/117763/2803744-submariner01.jpg'', ''screen_large_url'': ''https://comicvine.gamespot.com/a/uploads/screen_kubrick/11/117763/2803744-submariner01.jpg'', ''small_url'': ''https://comicvine.gamespot.com/a/uploads/scale_small/11/117763/2803744-submariner01.jpg'', ''super_url'': ''https://comicvine.gamespot.com/a/uploads/scale_large/11/117763/2803744-submariner01.jpg'', ''thumb_url'': ''https://comicvine.gamespot.com/a/uploads/scale_avatar/11/117763/2803744-submariner01.jpg'', ''tiny_url'': ''https://comicvine.gamespot.com/a/uploads/square_mini/11/117763/2803744-submariner01.jpg'', ''original_url'': ''https://comicvine.gamespot.com/a/uploads/original/11/117763/2803744-submariner01.jpg'', ''image_tags'': ''All Images''}', '[{"id": "Namor"}, {"id": "Dorma"}, {"id": "Vashti"}, {"id": "Diane Newell"}, {"id": "Namorita"}, {"id": "Stingray"}, {"id": "Llyra"}, {"id": "Tamara Rahn"}, {"id": "Tiger Shark"}, {"id": "Ikthon"}, {"id": "Betty Dean"}, {"id": "Thing"}, {"id": "Triton"}, {"id": "Human Torch"}, {"id": "Warlord Seth"}, {"id": "Karthon"}, {"id": "Invisible Woman"}, {"id": "Dr. Dorcas"}, {"id": "Leonard McKenzie"}, {"id": "Mr. Fantastic"}, {"id": "Byrrah"}, {"id": "Orka"}, {"id": "Attuma"}, {"id": "Naga"}, {"id": "King Kamuu"}, {"id": "Spider-Man"}, {"id": "Doctor Doom"}, {"id": "Namora"}, {"id": "Force"}, {"id": "Princess Fen"}, {"id": "Stephen Tuval"}, {"id": "Virago"}, {"id": "Dr. Hydro"}, {"id": "Destiny"}, {"id": "Cindy Jones "}, {"id": "Do