INSERT INTO volumes (id, name, firstIssue, publisher, description, startYear, numIssues, image, characters_name, concepts_name, characters_id, concepts_id, numLikes) VALUES ('2469', 'Amazing Adventures', 'Beware the Inhumans!; Then Came the Black Widdow', '31', '<p>Amazing Adventures began life as another of Marvel''s tried and tested "double feature" comics - in the mould of <a href="/tales-of-suspense/4050-2007/" data-ref-id="4050-2007">Tales of Suspense</a> / <a href="/tales-to-astonish/4050-2008/" data-ref-id="4050-2008">Tales to Astonish</a>. Its original features were the <a href="/inhumans/4060-11427/" data-ref-id="4060-11427">Inhumans</a> and <a href="/black-widow/4005-3200/" data-ref-id="4005-3200">Black Widow</a>. However, this dual feature lasted only 8 issues, before the headline feature became "<a href="/black-bolt/4005-4329/" data-ref-id="4005-4329">Black Bolt</a> and the Inhumans" for a further 2 issues. Then, from the pages of the <a href="/x-men/4060-3173/" data-ref-id="4060-3173">X-Men</a> (who at this time did not have their own book) came "<a href="/beast/4005-1462/" data-ref-id="4005-1462">The Beast</a>", who took centre stage for the next 7 issues before super heroes gave way to space fantasy with "War of the Worlds", where the hero <a href="/killraven/4005-7233/" data-ref-id="4005-7233">Killraven</a>, Warrior of the Worlds, made his debut. His series filled in the remaining 22 issues of the title.</p><h4>Collected Editions</h4><ul><li><a href="/kingsize-kirby/4050-83141/" data-ref-id="4050-83141">King-Size Kirby</a> (#1-2)</li><li><a href="https://comicvine.gamespot.com/civil-war-ii-xmen/4050-95724/" data-ref-id="4050-95724">Civil War II: X-Men</a> (#9)</li><li><a href="https://comicvine.gamespot.com/x-men-epic-collection-its-always-darkest-before-th/4050-120262/">X-Men Epic Collection: It''s Always Darkest Before the Dawn</a> (#11-17)</li><li><a href="https://comicvine.gamespot.com/killraven-epic-collection-warrior-of-the-worlds/4050-139434/">Killraven Epic Collection: Warrior of the Worlds</a> (#18-39) (Killraven Stories)</li><li><a href="/marvel-masterworks-killraven-1-volume-1/4000-685850/" data-ref-id="4000-685850">Marvel Masterworks: Killraven Volume 1</a> (#18-39) (Killraven Stories)</li></ul><h4>Non-U.S. Collected Editions</h4><ul><li><a href="https://comicvine.gamespot.com/kingsize-kirby/4050-104017/" data-ref-id="4050-104017">King-Size Kirby</a> (#1-2) (Spanish)</li><li><a href="https://comicvine.gamespot.com/coleccionable-marvel-heroes-22-viuda-negra-red-de-/4000-612227/">Coleccionable Marvel Héroes: Viuda Negra: Red de intrigas</a> (#1-8) (Spanish)</li></ul>', '1970', '39', '{''icon_url'': ''https://comicvine.gamespot.com/a/uploads/square_avatar/0/4/9942-2469-10946-1-amazing-adventures.jpg'', ''medium_url'': ''https://comicvine.gamespot.com/a/uploads/scale_medium/0/4/9942-2469-10946-1-amazing-adventures.jpg'', ''screen_url'': ''https://comicvine.gamespot.com/a/uploads/screen_medium/0/4/9942-2469-10946-1-amazing-adventures.jpg'', ''screen_large_url'': ''https://comicvine.gamespot.com/a/uploads/screen_kubrick/0/4/9942-2469-10946-1-amazing-adventures.jpg'', ''small_url'': ''https://comicvine.gamespot.com/a/uploads/scale_small/0/4/9942-2469-10946-1-amazing-adventures.jpg'', ''super_url'': ''https://comicvine.gamespot.com/a/uploads/scale_large/0/4/9942-2469-10946-1-amazing-adventures.jpg'', ''thumb_url'': ''https://comicvine.gamespot.com/a/uploads/scale_avatar/0/4/9942-2469-10946-1-amazing-adventures.jpg'', ''tiny_url'': ''https://comicvine.gamespot.com/a/uploads/square_mini/0/4/9942-2469-10946-1-amazing-adventures.jpg'', ''original_url'': ''https://comicvine.gamespot.com/a/uploads/original/0/4/9942-2469-10946-1-amazing-adventures.jpg'', ''image_tags'': ''All Images''}', '[{"id": "Killraven"}, {"id": "M''Shulla"}, {"id": "Old Skull"}, {"id": "Carmilla Frost"}, {"id": "Grok"}, {"id": "Hawk"}, {"id": "Medusa"}, {"id": "Black Bolt"}, {"id": "Gorgon"}, {"id": "Karnak"}, {"id": "Black Widow"}, {"id": "