INSERT INTO volumes (id, name, firstIssue, publisher, description, startYear, numIssues, image, characters_name, concepts_name, characters_id, concepts_id, numLikes) VALUES ('2470', 'Astonishing Tales', 'Unto you is Born the Doomsman; The Power of Ka-zar', '31', '<p>The line up of features in Astonishing Tales changed several times. It first featured Ka-Zar and Doctor Doom. The double feature lasted only 8 issues, before Ka-Zar took over the book completely upto issue 20, when his adventures continued in <a href="https://comicvine.gamespot.com/ka-zar/4050-2692/">Ka-Zar Volume 2</a>. Following 4 issues of IT - the Living Collosus, the remaining issues featured the debut and continuing adventures of Deathlok the Demolisher (apart from #29, which was a reprint comic starring the Guardians of the Galaxy).</p><h4>Collected Editions</h4><ul><li><a href="/marvel-masterworks-ka-zar-1-volume-1/4000-380710/" data-ref-id="4000-380710">Marvel Masterworks: Ka-Zar Volume 1</a> (#1-16)</li><li><a href="https://comicvine.gamespot.com/mockingbird-bobbi-morse-agent-of-shield/4050-92762/" data-ref-id="4050-92762">Mockingbird: Bobbi Morse, Agent of S.H.I.E.L.D.</a> (#10, 13-13 &amp; 15-20)</li><li><a href="/man-thing-by-steve-gerber-the-complete-collection-/4000-502866/" data-ref-id="4000-502866">Man-Thing by Steve Gerber: The Complete Collection Vol. 1</a> (#12-13)</li><li><a href="/marvel-masterworks-ka-zar-2-volume-2/4000-663576/" data-ref-id="4000-663576">Marvel Masterworks: Ka-Zar Volume 2</a> (#17-20)</li><li><a href="https://comicvine.gamespot.com/marvel-horror-omnibus/4050-121088/">Marvel Horror Omnibus</a> (#21-24)</li><li><a href="/deathlok-the-demolisher-the-complete-collection/4050-77316/" data-ref-id="4050-77316">Deathlok The Demolisher: The Complete Collection</a> (#25-28 &amp; 30-36)</li></ul>', '1970', '36', '{''icon_url'': ''https://comicvine.gamespot.com/a/uploads/square_avatar/0/4/9944-2470-10948-1-astonishing-tales.jpg'', ''medium_url'': ''https://comicvine.gamespot