INSERT INTO volumes (id, name, firstIssue, publisher, description, startYear, numIssues, image, characters_name, concepts_name, characters_id, concepts_id, numLikes) VALUES ('2471', 'Conan the Barbarian', 'The Coming of Conan!', '31', '<p>The series lasted for 275 issues, after that Marvel revamped the series into <a href="../../conan-the-adventurer/49-5288/" rel="nofollow ">Conan the Adventurer</a> with a new number 1. This second series was however short lived and after that Marvel published many mini-series up until 1998, when they lost the rights to publish Conan.</p><h4>Collected Editions</h4><ul><li><a href="/chronicles-of-conan-tower-of-the-elephant-other-stories/4000-150363/" data-ref-id="4000-150363">The Chronicles of Conan vol. 1</a> (#1-8)</li><li><a href="/conan-the-barbarian-the-original-marvel-years-omni/4000-714448/" data-ref-id="4000-714448">Conan the Barbarian: The Original Marvel Years Omnibus Volume 1</a> (#1-26)</li><li><a href="https://comicvine.gamespot.com/conan-the-barbarian-epic-collection-the-original-m/4050-129254/">Conan the Barbarian Epic Collection: The Original Marvel Years: The Coming of Conan</a> (#1-13)</li><li><a href="/chronicles-of-conan-rogues-in-the-house-other-stories/4000-150370/" data-ref-id="4000-150370">The Chronicles of Conan vol. 2</a> (#9-13 &amp; 16)</li><li><a href="/chronicles-of-conan-the-monster-of-the-monoliths-and-other-stories/4000-150371/" data-ref-id="4000-150371">The Chronicles of Conan vol. 3</a> (#14, 15, 17-22)</li><li><a href="https://comicvine.gamespot.com/conan-the-barbarian-epic-collection-the-original-m/4050-134428/">Conan the Barbarian Epic Collection: The Original Marvel Years: Hawks From the Sea</a> (#14-26)</li><li><a href="/chronicles-of-conan-the-song-of-red-sonja-and-other-stories/4000-150372/" data-ref-id="4000-150372">The Chronicles of Conan vol. 4</a> (#23-26)</li><li><a href="/chronicles-of-conan-the-shadow-in-the-tomb-and-other-stories/4000-150373/" data-ref-id="4000-150373">The Chronicles of Conan vol. 5</a> (#27-34)</li><li><a href="/conan-the-barbarian-the-original-marvel-years-omni/4000-714442/" data-ref-id="4000-714442">Conan the Barbarian: The Original Marvel Years Omnibus Volume 2</a> (#27-51)</li><li><a href="https://comicvine.gamespot.com/conan-the-barbarian-epic-collection-the-original-m/4050-137983/">Conan the Barbarian Epic Collection: The Original Marvel Years: The Curse of the Golden Skull</a> (#27-42)</li><li><a href="/chronicles-of-conan-the-curse-of-the-golden-skull-and-other-stories/4000-150374/" data-ref-id="4000-150374">The Chronicles of Conan vol. 6</a> (#35-42)</li><li><a href="/chronicles-of-conan-the-dweller-in-the-pool-and-other-stories/4000-150375/" data-ref-id="4000-150375">The Chronicles of Conan vol. 7</a> (#43-51)</li><li><a href="/conan-the-barbarian-epic-collection-the-original-m/4050-141052/" data-ref-id="4050-141052">Conan the Barbarian Epic Collection: The Original Marvel Years: Queen of the Black Coast</a> (#43-59)</li><li><a href="/chronicles-of-conan-brothers-of-the-blade-and-other-stories/4000-218361/" data-ref-id="4000-218361">The Chronicles of Conan vol. 8</a> (#52-59)</li><li><a href="/conan-the-barbarian-the-original-marvel-years-omni/4000-733874/" data-ref-id="4000-733874">Conan the Barbarian: The Original Marvel Years Omnibus Volume 3</a> (#52-83)</li><li><a href="/chronicles-of-conan-riders-of-the-river-dragons-and-other-stories/4000-150376/" data-ref-id="4000-150376">The Chronicles of Conan vol. 9</a> (#60-63, 65, 69-71)</li><li><a href="/chronicles-of-conan-when-giants-walk-the-earth-and-other-stories/4000-150377/" data-ref-id="4000-150377">The Chronicles of Conan vol. 10</a> (#72-77 &amp; 79-81)</li><li><a href="/chronicles-of-conan-the-dance-of-the-skull-and-other-stories/4000-172450/" data-ref-id="4000-172450">The Chronicles of Conan vol. 11</a> (#82-90)</li><li><a href="/conan-the-barbarian-the-original-marvel-years-omni/4000-803673/" data-ref-id="4000-803673">Conan the Barbarian: The Original Marve