INSERT INTO volumes (id, name, firstIssue, publisher, description, startYear, numIssues, image, characters_name, concepts_name, characters_id, concepts_id, numLikes) VALUES ('2510', 'Captain America Annual', 'The Origin of Captain America', '31', '<p>Annuals to the Captain America series. It ran from 1971 until 1994. There were no annuals published from 1995-1997. Starring In 1998 four more annuals and a team-up with <a href="/iron-man/4005-1455/" data-ref-id="4005-1455">Iron Man</a> were released, with unique titles;</p><ul><li><a href="//www.comicvine.com/captain-america-annual-98/4050-60452/" data-ref-id="4050-60452">Captain America / Citizen V ''98</a></li><li><a href="/iron-man-captain-america-annual-98/4050-30391/" data-ref-id="4050-30391">Iron Man / Captain America ''98</a> (<a href="//www.comicvine.com/iron-man-annual/4050-2905/" data-ref-id="4050-2905">Iron Man Annual</a>)</li><li><a href="//www.comicvine.com/captain-america-annual-99/4050-60453/" data-ref-id="4050-60453">Captain America 1999</a></li><li><a href="//www.comicvine.com/captain-america-annual-2000/4050-60454/" data-ref-id="4050-60454">Captain America 2000</a></li><li><a href="//www.comicvine.com/captain-america-annual-2001/4050-60455/" data-ref-id="4050-60455">Captain America 2001</a></li></ul><h4>Collected Editions</h4><ul><li><a href="/marvel-masterworks-captain-america-10-volume-10/4000-676702/" data-ref-id="4000-676702">Marvel Masterworks: Captain America Volume 10</a> (#3)</li><li><a href="https://comicvine.gamespot.com/captain-america-and-the-falcon-the-swine/4050-27520/">Captain America and the Falcon: The Swine</a> (#3-4)</li><li><a href="/marvel-masterworks-captain-america-11-volume-11/4000-713508/" data-ref-id="4000-713508">Marvel Masterworks: Captain America Volume 11</a> (#4)</li><li><a href="/captain-america-epic-collection-dawns-early-light/4050-71799/" data-ref-id="4050-71799">Captain America Epic Collection: Dawn''s Early Light</a> (#5)</li><li><a href="https://comicvine.gamespo