INSERT INTO volumes (id, name, firstIssue, publisher, description, startYear, numIssues, image, characters_name, concepts_name, characters_id, concepts_id, numLikes) VALUES ('2512', 'Creatures on the Loose', 'The Skull of Silence; Trull the Unhuman!', '31', '<p>Continued from <a href="/tower-of-shadows/4050-2448/" data-ref-id="4050-2448"> Tower of Shadows</a> issue 9. The series started out as a comic with reprint stories of horror and monster comics, but from issue 16 and on became the home for Marvel stars such as Gullivar Jones, Thongor and John Jameson, aka the Man-Wolf!. It lasted until issue 37.</p><h4>Collected Editions</h4><ul><li><a href="https://comicvine.gamespot.com/kull-the-destroyer-the-original-marvel-years-omnib/4050-139959/">Kull the Destroyer: The Original Marvel Years Omnibus</a> (#10)</li><li><a href="https://comicvine.gamespot.com/man-wolf-the-complete-collection/4050-121739/">Man-Wolf: The Complete Collection</a> (#30-37)</li></ul>', '1971', '28', '{''icon_url'': ''https://comicvine.gamespot.com/a/uploads/square_avatar/6/67663/8117036-9077662688-96029.jpg'', ''medium_url'': ''https://comicvine.gamespot.com/a/uploads/scale_medium/6/67663/8117036-9077662688-96029.jpg'', ''screen_url'': ''https://comicvine.gamespot.com/a/uploads/screen_medium/6/67663/8117036-9077662688-96029.jpg'', ''screen_large_url'': ''https://comicvine.gamespot.com/a/uploads/screen_kubrick/6/67663/8117036-9077662688-96029.jpg'', ''small_url'': ''https://comicvine.gamespot.com/a/uploads/scale_small/6/67663/8117036-9077662688-96029.jpg'', ''super_url'': ''https://comicvine.gamespot.com/a/uploads/scale_large/6/67663/8117036-9077662688-96029.jpg'', ''thumb_url'': ''https://comicvine.gamespot.com/a/uploads/scale_avatar/6/67663/8117036-9077662688-96029.jpg'', ''tiny_url'': ''https://comicvine.gamespot.com/a/uploads/square_mini/6/67663/8117036-9077662688-96029.jpg'', ''original_url'': ''https://comicvine.gamespot.com/a/uploads/original/6/67663/8117036-9077662688-96029.jpg'', ''image_