INSERT INTO volumes (id, name, firstIssue, publisher, description, startYear, numIssues, image, characters_name, concepts_name, characters_id, concepts_id, numLikes) VALUES ('2515', 'Marvel Feature', 'The Day of the Defenders!; The Sub-Mariner and the Icebergs; The Return', '31', '<p>A small series with a large legacy; It features the formation and first appearance of the Defenders. This series is somewhat continued in <a href="../../marvel-two-in-one/49-2696/" rel="nofollow ">Marvel Two-In-One</a>. That series started two months after this series was cancelled and continues the Thing''s story that started here in the last two issues of Marvel Feature.</p><h4>Collected Editions</h4><ul><li><a href="https://comicvine.gamespot.com/doctor-strange-epic-collection-a-separate-reality/4050-95006/" data-ref-id="4050-95006">Doctor Strange Epic Collection: A Separate Reality</a> (#1)</li><li><a href="/marvel-masterworks-defenders-1-volume-1/4000-231493/" data-ref-id="4000-231493">Marvel Masterworks: The Defenders Volume 1</a> (#1-3)</li><li><a href="https://comicvine.gamespot.com/the-defenders-omnibus-1-volume-1/4000-842243/" data-ref-id="4000-842243">The Defenders Omnibus Volume 1</a> (#1-3)</li><li><a href="/marvel-masterworks-ant-mangiant-man-3-volume-3/4000-673021/" data-ref-id="4000-673021">Marvel Masterworks: Ant-Man/Giant-Man Volume 3</a> (#4-10)</li><li><a href="https://www.comicvine.com/marvel-masterworks-marvel-two-in-one-1-volume-1/4000-433434/" data-ref-id="4000-433434">Marvel Masterworks: Marvel Two-In-One vol. 1</a> (#11-12)</li><li><a href="https://comicvine.gamespot.com/marvel-two-in-one-epic-collection-cry-monster/4050-112694/">Marvel Two-In-One Epic Collection: Cry Monster</a> (#11-12)</li><li><a href="https://comicvine.gamespot.com/captain-marvel-by-jim-starlin-the-complete-collect/4050-95814/" data-ref-id="4050-95814">Captain Marvel By Jim Starlin: The Complete Collection</a> (#12)</li><li><a href="https://comicvine.gamespot.com/the-thanos-wars-infinity-or