INSERT INTO volumes (id, name, firstIssue, publisher, description, startYear, numIssues, image, characters_name, concepts_name, characters_id, concepts_id, numLikes) VALUES ('2516', 'Marvel Spotlight', 'Red Wolf', '31', '<p>The first volume of Marvel Spotlight from the 1970''s. This series introduced some mayor Marvel Characters, such as Ghost Rider, Werewolf by Night, the Spider-woman and Devil Slayer. It also gave some heroes such as Son of Satan and Moon Knight their first solo adventures.</p><h4>Collected Editions</h4><ul><li><a href="/werewold-by-night-omnibus/4050-85148/" data-ref-id="4050-85148">Werewolf By Night Omnibus</a> (#2-4)</li><li><a href="https://comicvine.gamespot.com/werewolf-by-night-the-complete-collection-1-volume/4000-626305/" data-ref-id="4000-626305">Werewolf By Night: The Complete Collection Volume 1</a> (#2-4)</li><li><a href="https://comicvine.gamespot.com/avengersdoctor-strange-rise-of-the-darkhold/4050-114044/">Avengers/Doctor Strange: Rise of the Darkhold</a> (#3-4)</li><li><a href="/marvel-masterworks-ghost-rider-1-volume-1/4000-721798/" data-ref-id="4000-721798">Marvel Masterworks: Ghost Rider Volume 1</a> (#5-12)</li><li><a href="https://comicvine.gamespot.com/marvel-universe-by-frank-miller-omnibus/4050-116073/">Marvel Universe by Frank Miller Omnibus</a> (#8)</li><li><a href="https://comicvine.gamespot.com/the-son-of-satan-classic/4050-95033/" data-ref-id="4050-95033">The Son of Satan Classic</a> (#12-24)</li><li><a href="https://comicvine.gamespot.com/hellstrom-evil-origins/4050-129473/">Hellstrom: Evil Origins</a> (#12-13 &amp; 24)</li><li><a href="https://comicvine.gamespot.com/marvel-horror-lives-again-omnibus/4050-131205/">Marvel Horror Lives Again! Omnibus</a> (#24)</li><li><a href="https://comicvine.gamespot.com/doctor-strange-lords-of-fear/4050-107359/" data-ref-id="4050-107359">Doctor Strange: Lords of Fear</a> (#26)</li><li><a href="https://comicvine.gamespot.com/marvel-horror-omnibus/4050-121088/">Marvel Horror Omnibus<