INSERT INTO volumes (id, name, firstIssue, publisher, description, startYear, numIssues, image, characters_name, concepts_name, characters_id, concepts_id, numLikes) VALUES ('2569', 'The Defenders', 'I Slay by the Stars!', '31', '<p>The first ongoing Defenders series. It starred a variety of superheroes such as Doctor Strange, Namor, Hulk, Nighthawk, Hellcat, Valkyrie, Silver Surfer and many others. With issue 125, the series was duped "the New Defenders" and starred an almost entirely different cast. It ended with issue 152 after half the team seemingly died, and the rest of the team (Beast, Angel and Iceman) joined <a href="https://comicvine.gamespot.com/x-factor/4050-3657/">X-Factor</a>.</p><h4>Collected Editions</h4><ul><li><a href="/marvel-masterworks-defenders-1-volume-1/4000-231493/" data-ref-id="4000-231493">Marvel Masterworks: Defenders Volume 1</a> (#1-6)</li><li><a href="https://comicvine.gamespot.com/the-defenders-omnibus-1-volume-1/4000-842243/" data-ref-id="4000-842243">The Defenders Omnibus Volume 1</a> (#1-19)</li><li><a href="/marvel-masterworks-defenders-2-volume-2/4000-307503/" data-ref-id="4000-307503">Marvel Masterworks: Defenders Volume 2</a> (#7-16)</li><li><a href="/avengersdefenders-war/4050-30226/" data-ref-id="4050-30226">Avengers/Defenders War</a> (#8-11)</li><li><a href="https://comicvine.gamespot.com/avengers-epic-collection-the-avengersdefenders-war/4050-109747/">Avengers Epic Collection: The Avengers/Defenders War</a> (#8-11)</li><li><a href="/avengers-omnibus-4-volume-four/4000-703935/" data-ref-id="4000-703935">Avengers Omnibus Volume 4</a> (#8-11)</li><li><a href="https://comicvine.gamespot.com/thor-vs-hulk/4050-104825/" data-ref-id="4050-104825">Thor vs. Hulk</a> (#10)</li><li><a href="https://comicvine.gamespot.com/x-men-epic-collection-its-always-darkest-before-th/4050-120262/">X-Men Epic Collection: It''s Always Darkest Before the Dawn</a> (#15-16)</li><li><a href="/marvel-masterworks-defenders-3-volume-3/4000-445309/" data-ref-id="4000-445309">Marvel Masterworks: Defenders Volume 3</a> (#17-21)</li><li><a href="/marvel-masterworks-defenders-4-volume-4/4000-445310/" data-ref-id="4000-445310">Marvel Masterworks: Defenders Volume 4</a> (#22-30)</li><li><a href="/guardians-of-the-galaxy-earth-shall-overcome/4050-30359/" data-ref-id="4050-30359">Guardians of the Galaxy: Earth Shall Overcome</a> (#26-29)</li><li><a href="https://comicvine.gamespot.com/guardians-of-the-galaxy-tomorrows-heroes-omnibus/4050-116248/">Guardians of the Galaxy: Tomorrow''s Heroes Omnibus</a> (#26-29)</li><li><a href="/marvel-masterworks-defenders-5-volume-5/4000-502867/" data-ref-id="4000-502867">Marvel Masterworks: Defenders Volume 5</a> (#31-41)</li><li><a href="/marvel-masterworks-defenders-6-volume-6/4000-670117/" data-ref-id="4000-670117">Marvel Masterworks: Defenders Volume 6</a> (#42-57)</li><li><a href="/moon-knight-epic-collection-bad-moon-rising/4050-77333/" data-ref-id="4050-77333">Moon Knight Epic Collection: Bad Moon Rising</a> (#47-50)</li><li><a href="https://comicvine.gamespot.com/moon-knight-omnibus-1-volume-1/4000-824088/" data-ref-id="4000-824088">Moon Knight Omnibus Volume 1</a> (#47-50)</li><li><a href="https://comicvine.gamespot.com/ms-marvel-epic-collection-this-woman-this-warrior/4050-116378/">Ms. Marvel Epic Collection: This Woman, This Warrior</a> (#57)</li><li><a href="https://comicvine.gamespot.com/captain-marvel-ms-marvel-a-hero-is-born/4050-117049/">Captain Marvel: Ms. Marvel: A Hero Is Born</a> (#57)</li><li><a href="/marvel-masterworks-defenders-7-volume-7/4000-814972/" data-ref-id="4000-814972">Marvel Masterworks: Defenders Volume 7</a> (#58-75)</li><li><a href="https://comicvine.gamespot.com/defenders-epic-collection-the-sixfingered-hand-sag/4050-93423/" data-ref-id="4050-93423">Defenders Epic Collection: The Six-Fingered Hand Saga</a> (#92-109)</li><li><a href="https://comicvine.gamespot.com/hellstrom-evil-origins/4050-129473/">Hellstrom: Evil Origins</a> (#92 &amp; 120-121)</li><li><a href="https://comicvine.gamespot.com/captain-america-epic-collection-monsters-and-men/4050-131207/">Captain America Epic Collection: Monsters and Men</a> (#106)</li><li><a href="https://comicvine.gamespot.com/defenders-epic-collection-ashes-ashes/4050-103812/" data-ref-id="4050-103812">Defenders Epic Collection: Ashes, Ashes...</a> (#110-125)</li><li><a href="https://comicvine.gamespot.com/squadron-supreme-classic-omnibus/4050-90892/" data-ref-id="4050-90892">Squadron Supreme Classic Omnibus</a> (#112-114)</li><li><a href="/the-new-defenders-1-volume-one/4000-312125/" data-ref-id="4000-312125">The New Defenders Volume One</a> (#122-131)</li><li><a href="https://comicvine.gamespot.com/defenders-epic-collection-the-new-defenders/4050-112801/">Defenders Epic Collection: The New Defenders</a> (#126-137)</li><li><a href="https://comicvine.gamespot.com/defenders-epic-collection-the-end-of-all-songs/4050-123717/">Defenders Epic Collection: The End of All Songs</a> (#138-152)</li></ul><h4>Non-U.S. Collected Editions</h4><ul><li><a href="https://comicvine.gamespot.com/coleccionable-marvel-heroes-53-secret-wars-ii-quie/4000-612261/">Coleccionable Marvel Héroes - Secret Wars II: ¿Quién es el Todopoderoso?</a> (#152) (Spanish)</li></ul><p>Issue <a href="https://comicvine.gamespot.com/biblioteca-marvel-la-cosa-1/4000-285468/" data-ref-id="4000-285468">#20</a> has been translated into Spanish.</p>', '1972', '152', '{''icon_url'': ''https://comicvine.gamespot.com/a/uploads/square_avatar/11/117763/2618111-defenders001.jpg'', ''medium_url'': ''https://comicvine.gamespot.com/a/uploads/scale_medium/11/117763/2618111-defenders001.jpg'', ''screen_url'': ''https://comicvine.gamespot.com/a/uploads/screen_medium/11/117763/2618111-defenders001.jpg'', ''screen_large_url'': ''https://comicvine.gamespot.com/a/uploads/screen_kubrick/11/117763/2618111-defenders001.jpg'', ''small_url'': ''https://comicvine.gamespot.com/a/uploads/scale_small/11/117763/2618111-defenders001.jpg'', ''super_url'':