INSERT INTO volumes (id, name, firstIssue, publisher, description, startYear, numIssues, image, characters_name, concepts_name, characters_id, concepts_id, numLikes) VALUES ('2572', 'Hero for Hire', 'Out of Hell - A Hero!', '31', '<p>Introducing Luke Cage, Hero for Hire! This volume follows the first adventures of Luke Cage, whom was wrongly convicted of a crime and, under the alias of Luke Cage, fights for the little people as a Hero for Hire! The series was continued as <a href="/power-man/4050-2700/" data-ref-id="4050-2700"> Power Man</a> with issue #17.</p><h4>Collected Editions</h4><ul><li><a href="https://comicvine.gamespot.com/luke-cage-epic-collection-retribution/4050-133628/">Luke Cage Epic Collection: Retribution</a></li><li><a href="/marvel-masterworks-luke-cage-hero-for-hire/4050-83964/" data-ref-id="4050-83964">Marvel Masterworks: Luke Cage, Hero For Hire</a></li><li><a href="/luke-cage-omnibus/4050-148451/" data-ref-id="4050-148451">Luke Cage Omnibus</a></li></ul><h4>Non-U.S. Collected Editions</h4><ul><li><a href="https://comicvine.gamespot.com/los-nuevos-vengadores-luke-cage/4050-103867/">Los Nuevos Vengadores: Luke Cage</a> (#1) (Spanish)</li></ul>', '1972', '16', '{''icon_url'': ''https://comicvine.gamespot.com/a/uploads/square_avatar/6/67663/6606937-4179961455-STL093571'', ''medium_url'': ''https://comicvine.gamespot.com/a/uploads/scale_medium/6/67663/6606937-4179961455-STL093571'', ''screen_url'': ''https://comicvine.gamespot.com/a/uploads/screen_medium/6/67663/6606937-4179961455-STL093571'', ''screen_large_url'': ''https://comicvine.gamespot.com/a/uploads/screen_kubrick/6/67663/6606937-4179961455-STL093571'', ''small_url'': ''https://comicvine.gamespot.com/a/uploads/scale_small/6/67663/6606937-4179961455-STL093571'', ''super_url'': ''https://comicvine.gamespot.com/a/uploads/scale_large/6/67663/6606937-4179961455-STL093571'', ''thumb_url'': ''https://comicvine.gamespot.com/a/uploads/scale_avatar/6/67663/6606937-4179961455-STL093571'', ''tiny_url'