INSERT INTO volumes (id, name, firstIssue, publisher, description, startYear, numIssues, image, characters_name, concepts_name, characters_id, concepts_id, numLikes) VALUES ('2574', 'Jungle Action', 'The Trail of Sudden Death', '31', '<p>It started as a series for the "Tarzan-like" hero known as <a href="/tharn/4005-37003/" data-ref-id="4005-37003"> Tharn</a>, whom was the star of the <a href="/jungle-action/4050-20835/" data-ref-id="4050-20835"> first Jungle Action</a> series, but became a series starring the Black Panther with issue 5. The series lasted until issue 24 and was continued one month later in Black Panther''s very own <a href="/black-panther/4050-2896/" data-ref-id="4050-2896"> ongoing series</a>.</p><h4>Collected Editions</h4><ul><li><a href="https://comicvine.gamespot.com/black-panther-epic-collection-panthers-rage/4050-94409/" data-ref-id="4050-94409">Black Panther Epic Collection: Panther''s Rage</a> (#6-24)</li><li><a href="https://comicvine.gamespot.com/marvels-black-panther-prelude/4050-107660/" data-ref-id="4050-107660">Marvel''s Black Panther Prelude</a> (#6-7)</li></ul>', '1972', '24', '{''icon_url'': ''https://comicvine.gamespot.com/a/uploads/square_avatar/8/84205/3668184-%24%28kgrhqf%2C%21pce9enm3fpbbpz7szmpmq~~60_3.jpg'', ''medium_url'': ''https://comicvine.gamespot.com/a/uploads/scale_medium/8/84205/3668184-%24%28kgrhqf%2C%21pce9enm3fpbbpz7szmpmq~~60_3.jpg'', ''screen_url'': ''https://comicvine.gamespot.com/a/uploads/screen_medium/8/84205/3668184-%24%28kgrhqf%2C%21pce9enm3fpbbpz7szmpmq~~60_3.jpg'', ''screen_large_url'': ''https://comicvine.gamespot.com/a/uploads/screen_kubrick/8/84205/3668184-%24%28kgrhqf%2C%21pce9enm3fpbbpz7szmpmq~~60_3.jpg'', ''small_url'': ''https://comicvine.gamespot.com/a/uploads/scale_small/8/84205/3668184-%24%28kgrhqf%2C%21pce9enm3fpbbpz7szmpmq~~60_3.jpg'', ''super_url'': ''https://comicvine.gamespot.com/a/uploads/scale_large/8/84205/3668184-%24%28kgrhqf%2C%21pce9enm3fpbbpz7szmpmq~~60_3.jpg'', ''thumb_url'': ''http