INSERT INTO volumes (id, name, firstIssue, publisher, description, startYear, numIssues, image, characters_name, concepts_name, characters_id, concepts_id, numLikes) VALUES ('2575', 'Marvel Premiere', 'And Men Shall Call Him... Warlock', '31', '<p>Marvel Premiere is a series that introduced some major Marvel Characters, it starred the first appearances of <a href="../../iron-fist/29-1492/" rel="nofollow ">Iron Fist</a>, <a href="../../colleen-wing/29-1494/" rel="nofollow ">Colleen Wing</a>, <a href="../../3-d-man/29-43653/" rel="nofollow ">3-D Man</a>, <a href="../../legion-of-monsters/65-46227/" rel="nofollow ">the Legion of Monsters</a> and <a href="../../stature/29-40516/" rel="nofollow ">Stature</a> to name a few.</p><h4>Collected Editions</h4><ul><li><a href="/annihilation-classic/4050-30933/" data-ref-id="4050-30933">Annihilation Classic</a> (#1)</li><li><a href="https://comicvine.gamespot.com/doctor-strange-epic-collection-a-separate-reality/4050-95006/" data-ref-id="4050-95006">Doctor Strange Epic Collection: A Separate Reality</a> (#3-14)</li><li><a href="https://comicvine.gamespot.com/doctor-strange-what-is-it-that-disturbs-you-stephe/4050-95213/" data-ref-id="4050-95213">Doctor Strange: What Is It That Disturbs You, Stephen?</a> (#7)</li><li><a href="https://comicvine.gamespot.com/marvels-doctor-strange-prelude/4050-94646/" data-ref-id="4050-94646">Marvel''s Doctor Strange Prelude</a> (#14)</li><li><a href="/iron-fist-epic-collection-the-fury-of-iron-fist/4050-83138/" data-ref-id="4050-83138">Iron Fist Epic Collection: The Fury of Iron Fist</a> (#15-25)</li><li><a href="/marvel-universe-by-john-byrne-omnibus-2-volume-2/4000-694138/" data-ref-id="4000-694138">Marvel Universe by John Byrne Omnibus Volume 2</a> (#25)</li><li><a href="https://comicvine.gamespot.com/marvel-horror-lives-again-omnibus/4050-131205/">Marvel Horror Lives Again! Omnibus</a> (#27)</li><li><a href="/werewold-by-night-omnibus/4050-85148/" data-ref-id="4050-85148">Werewolf By Night Omni