INSERT INTO volumes (id, name, firstIssue, publisher, description, startYear, numIssues, image, characters_name, concepts_name, characters_id, concepts_id, numLikes) VALUES ('2576', 'Marvel Team-Up', 'Have Yourself a Sandman Little Christmas!', '31', '<p>A series that connected the Marvel Universe for years to come. It features mainly Spider-Man teaming up with other heroes. This series had a <a href="https://www.comicvine.com/marvel-team-up-annual/4050-2863/">Marvel Team-Up Annual</a> series as well.</p><h4>Collected Editions</h4><ul><li><a href="/spider-man-saga-of-the-sandman/4050-27204/" data-ref-id="4050-27204">Spider-Man: Saga of the Sandman</a> (#1)</li><li><a href="https://comicvine.gamespot.com/morbius-the-living-vampire-omnibus/4050-128226/">Morbius the Living Vampire Omnibus</a> (#3-4)</li><li><a href="https://comicvine.gamespot.com/morbius-preludes-and-nightmares/4050-133630/">Morbius: Preludes and Nightmares</a> (#3-4)</li><li><a href="https://comicvine.gamespot.com/morbius-epic-collection-the-living-vampire/4050-133733/">Morbius Epic Collection: The Living Vampire</a> (#3-4)</li><li><a href="https://comicvine.gamespot.com/x-men-epic-collection-its-always-darkest-before-th/4050-120262/">X-Men Epic Collection: It''s Always Darkest Before the Dawn</a> (#4 &amp; 23)</li><li><a href="https://comicvine.gamespot.com/tigra-the-complete-collection/4050-123417/">Tigra: The Complete Collection</a> (#8 &amp; 67)</li><li><a href="https://comicvine.gamespot.com/spider-maniron-man-marvel-team-up/4050-114422/">Spider-Man/Iron Man: Marvel Team-Up</a> (#9-11, 48-51, 72, 110 &amp; 145)</li><li><a href="/werewold-by-night-omnibus/4050-85148/" data-ref-id="4050-85148">Werewolf By Night Omnibus</a> (#12)</li><li><a href="https://comicvine.gamespot.com/werewolf-by-night-the-complete-collection-1-volume/4000-626305/" data-ref-id="4000-626305">Werewolf By Night: The Complete Collection Volume 1</a> (#12)</li><li><a href="https://comicvine.gamespot.com/marvel-verse-captain-america/4050-129192/">Marvel-Verse: Captain America</a> (#13)</li><li><a href="https://comicvine.gamespot.com/spidermandoctor-strange-the-way-to-dusty-death/4050-102278/" data-ref-id="4050-102278">Spider-Man/Doctor Strange: The Way To Dusty Death</a> (#21, 50-51, 76-77 &amp; 80-81)</li><li><a href="https://comicvine.gamespot.com/marvel-horror-omnibus/4050-121088/">Marvel Horror Omnibus</a> (#24)</li><li><a href="/marvel-masterworks-brother-voodoo-1-volume-1/4000-851632/" data-ref-id="4000-851632">Marvel Masterworks: Brother Voodoo Volume 1</a> (#24)</li><li><a href="/marvel-masterworks-marvel-team-up-4-volume-4/4000-696947/" data-ref-id="4000-696947">Marvel Masterworks: Marvel Team-Up Volume 4</a> (#31-40)</li><li><a href="https://comicvine.gamespot.com/the-son-of-satan-classic/4050-95033/" data-ref-id="4050-95033">The Son of Satan Classic</a> (#32)</li><li><a href="/monster-of-frankenstein/4050-84984/" data-ref-id="4050-84984">Monster of Frankenstein</a> (#36-37)</li><li><a href="https://comicvine.gamespot.com/man-wolf-the-complete-collection/4050-121739/">Man-Wolf: The Complete Collection</a> (#36-37)</li><li><a href="/marvel-masterworks-marvel-team-up-5-volume-5/4000-785731/" data-ref-id="4000-785731">Marvel Masterworks: Marvel Team-Up Volume 5</a> (#41-52)</li><li><a href="https://comicvine.gamespot.com/killraven-epic-collection-warrior-of-the-worlds/4050-139434/">Killraven Epic Collection: Warrior of the Worlds</a> (#45)</li><li><a href="/deathlok-the-demolisher-the-complete-collection/4050-77316/" data-ref-id="4050-77316">Deathlok The Demolisher: The Complete Collection</a> (#46)</li><li><a href="https://comicvine.gamespot.com/marvel-masterworks-marvel-two-in-one-2-volume-2/4000-621669/" data-ref-id="4000-621669">Marvel Masterworks: Marvel Two-In-One vol. 2</a> (#47)</li><li><a href="https://comicvine.gamespot.com/marvel-two-in-one-epic-collection-cry-monster/4050-112694/">Marvel Two-In-One Epic Collection: Cry Monster</a> (#47)</li><li><a href="https://comicvine.