INSERT INTO volumes (id, name, firstIssue, publisher, description, startYear, numIssues, image, characters_name, concepts_name, characters_id, concepts_id, numLikes) VALUES ('2577', 'Marvel Triple Action', 'When Strikes the Silver Surfer! - Enter... Dr. Doom!', '31', '<b><i>Marvel Triple Action</i> </b>was a reprint title from the 1970''s, reprinting older <i>Avengers</i> issues (after the first four issues were devoted to  <i>Fantastic Four</i> reprints).  For us kids who were growing up at the time, older comics were nearly impossible to get (for those of us in  the boondocks, anyway), and <i>MTA</i> provided us with some fantastic Avengers stories that we otherwise wouldn''t have been able to afford. By the time I was reading it, the book was reprinting stories from the era when the Avengers consisted of Captain America, Hawkeye, the Scarlet Witch, and Quicksilver - a weak lineup, it seemed to me, but the stories were fantastic. Don Heck''s art lended itself to dynamic figures, manic action, and fantastic machinery; Roy Thomas was fresh and creative and had a definite vision of super-heroic stories that was a perfect complement to what his mentor Stan Lee had been doing.<br/><br/>  As time wore on, later issues of the <i>Avengers</i> comic were reprinted. I got to read about the introduction of such characters as Ultron - whom I had always been intrigued with since Fantastic Four #150 - and his creation The Vision, a favorite superhero of mine and some schoolmates. Like <i>Marvel Tales</i> with the Spider-man stories and <i>Marvel''s Greatest Comics</i> with <i>Fantastic Four</i> issues, <i>MTA</i> provided kids of the 1970''s with beautiful, full-color reprints of classic Silver Age stories that we''d previously only heard about, and all for the same cover price as our regular comics. Even in this day of deluxe Marvel Masterworks and DC Archives, nothing beat the thrill of being able to go to the local comics dealer and pick up classic stories, month after month. Of course, it would help if I could be twelve years old again.', '1972', '47', '{''icon_url'': ''https://comicvine.gamespot.com/a/uploads/square_avatar/0/4/10881-2577-11997-1-marvel-triple-action.jpg'', ''medium_url'': ''https://comicvine.gamespot.com/a/uploads/scale_medium/0/4/10881-2577-11997-1-marvel-triple-action.jpg'', ''screen_url'': ''https://comicvine.gamespot.com/a/uploads/screen_medium/0/4/10881-2577-11997-1-marvel-triple-action.jpg'', ''screen_large_url'': ''https://comicvine.gamespot.com/a/uploads/screen_kubrick/0/4/10881-2577-11997-1-marvel-triple-action.jpg'', ''small_url'': ''https://comicvine.gamespot.com/a/uploads/scale_small/0/4/10881-2577-11997-1-marvel-triple-action.jpg'', ''super_url'': ''https://comicvine.gamespot.com/a/uploads/scale_large/0/4/10881-2577-11997-1-marvel-triple-action.jpg'', ''thumb_url'': ''https://comicvine.gamespot.com/a/uploads/scale_avatar/0/4/10881-2577-11997-1-marvel-triple-action.jpg'', ''tiny_url'': ''https://comicvine.gamespot.com/a/uploads/square_mini/0/4/10881-2577-11997-1-marvel-triple-action.jpg'', ''original_url'': ''https://comicvine.gamespot.com/a/uploads/original/0/4/10881-2577-11997-1-marvel-triple-action.jpg'', ''image_tags'': ''All Images''}', '[{"id": "Hawkeye"}, {"id": "Captain America"}, {"id": "Hank Pym"}, {"id": "Wasp"}, {"id": "Quicksilver"}, {"id": "Scarlet Witch"}, {"id": "Black Widow"}, {"id": "Hercules"}, {"id": "Iron Man"}, {"id": "Thor"}, {"id": "Mr. Fantastic"}, {"id": "Thing"}, {"id": "Human Torch"}, {"id": "Rick Jones"}, {"id": "Invisible Woman"}, {"id": "Toad"}, {"id": "Black Panther"}, {"id": "Enchantress"}, {"id": "Magneto"}, {"id": "Doctor Doom"}, {"id": "Swordsman"}, {"id": "Atlas"}, {"id": "Black Goliath"}, {"id": "Wyatt Wingfoot"}, {"id": "Executioner"}, {"id": "Silver Surfer"}, {"id": "Mole Man"}, {"id": "Black Knight (Garrett)"}, {"id": "Baron Heinrich Zemo"}, {"id": "Whirlwind"}, {"id": "Kang"}, {"id": "Abe Jenkins"}, {"id": "Iceman"}, {"id": "Black Knight"}, {"id": "Jasper Sitwell"