INSERT INTO volumes (id, name, firstIssue, publisher, description, startYear, numIssues, image, characters_name, concepts_name, characters_id, concepts_id, numLikes) VALUES ('2580', 'Shanna the She-Devil', 'And A Jungle Queen Is Born!', '31', '<p>Shanna the She-Devil''s very first appearance and ongoing series. It was part of Marvel''s plan to break open the market for more female readers, with other series like <a href="/night-nurse/4050-20623/" data-ref-id="4050-20623"> Night Nurse</a>. The series however failed to catch on and lasted only 5 issues. Her story continued into <a href="https://comicvine.gamespot.com/ka-zar/4050-2692/">Ka-Zar Vol.1</a> issues 1 and 2 and in <a href="https://comicvine.gamespot.com/daredevil-109-dying-for-dollars/4000-14260/">Daredevil Vol.1 issue 109</a> and further issues after that. <br />Shanna would later become a mayor player in the <a href="/ka-zar-the-savage/4050-3087/" data-ref-id="4050-3087">Ka-Zar The Savage</a> series and become Ka-Zar''s wife.</p><p>Collected in <a href="/marvel-masterworks-ka-zar-2-volume-2/4000-663576/" data-ref-id="4000-663576">Marvel Masterworks: Ka-Zar Volume 2</a>.</p>', '1972', '5', '{''icon_url'': ''https://comicvine.gamespot.com/a/uploads/square_avatar/8/84205/4033767-shanna1nm9m054.jpg'', ''medium_url'': ''https://comicvine.gamespot.com/a/uploads/scale_medium/8/84205/4033767-shanna1nm9m054.jpg'', ''screen_url'': ''https://comicvine.gamespot.com/a/uploads/screen_medium/8/84205/4033767-shanna1nm9m054.jpg'', ''screen_large_url'': ''https://comicvine.gamespot.com/a/uploads/screen_kubrick/8/84205/4033767-shanna1nm9m054.jpg'', ''small_url'': ''https://comicvine.gamespot.com/a/uploads/scale_small/8/84205/4033767-shanna1nm9m054.jpg'', ''super_url'': ''https://comicvine.gamespot.com/a/uploads/scale_large/8/84205/4033767-shanna1nm9m054.jpg'', ''thumb_url'': ''https://comicvine.gamespot.com/a/uploads/scale_avatar/8/84205/4033767-shanna1nm9m054.jpg'', ''tiny_url'': ''https://comicvine.gamespot.com/a/uploads/square_mini/8/84205/4033767-shanna1nm9m054.jpg'', ''original_url'': ''https://comicvine.gamespot.com/a/uploads/original/8/84205/4033767-shanna1nm9m054.jpg'', ''image_tags'': ''All Images''}', '[{"id": "Shanna"}, {"id": "Professor X"}, {"id": "Mandrill"}, {"id": "Fred Duncan"}, {"id": "Nekra"}]', 'NaN', '[{"id": 4579}, {"id": 1505}, {"id": 6829}, {"id": 13808}, {"id": 13896}]', 'NaN', '0');
INSERT INTO volumes (id, name, firstIssue, publisher, description, startYear, numIssues, image, characters_name, concepts_name, characters_id, concepts_id, numLikes) VALUES ('2583', 'Warlock', 'Day of the Prophet', '31', '<p>Continues from <a href="/marvel-premiere/4050-2575/" data-ref-id="4050-2575">Marvel Premier</a> issue 2. <a href="//www.comicvine.com/adam-warlock/4005-6805/" data-ref-id="4005-6805">Adam Warlock</a> stars in his first own ongoing series. The series lasted until issue 8, after which it was on a hiatus for 2 years. After that, the series resumed with issue 9 (hence that issue 9 says it''s a "premier issue") and lasted until issue 15. Issue #9 is the first issue after the reviving of the series and was the continued story from <a href="../../strange-tales/49-2643/" rel="nofollow ">Strange Tales</a> #181.</p><p>Although a short series, it has been critically acclaimed for the ground breaking work <a href="//www.comicvine.com/jim-starlin/4040-7922/" data-ref-id="4040-7922">Jim Starlin</a> did in these comics.</p><h4>Collected Editions</h4><ul><li><a href="/marvel-masterworks-warlock-1-volume-one/4000-394410/" data-ref-id="4000-394410">Marvel Masterworks: Warlock Vol. 1</a> (#1-8)</li><li><a href="/essential-warlock-1-volume-1/4000-352254/" data-ref-id="4000-352254">Essential Warlock</a> (#1-15) *Black and white*</li><li><a href="/avengers-avengers-vs-thanos/4050-57667/" data-ref-id="4050-57667">Avengers vs Thanos</a> (#9-11)</li><li><a href="/guardians-of-the-galaxy-solo-classic-omnibus/4050-85759/" data-ref-id="4050-85759">Guardians of the Galaxy Solo Classic Omnibus</a> (#9-11)</li><li><a href="/marvel-masterworks-warlock-2-volume-two/4000-233678/" data-ref-id="4000-233678">Marvel Masterworks: Warlock Vol. 2</a> (#9-15)</li><li><a href="https://www.comicvine.com/warlock-by-jim-starlin-1-tpb/4000-444317/" data-ref-id="4000-444317">Warlock By Jim Starlin: The Complete Collection vol. 1</a> (#9-15)</li><li><a href="https://comicvine.gamespot.com/gamora-guardian-of-the-galaxy/4050-94272/" data-ref-id="4050-94272">Gamora: Guardian of the Galaxy</a> (#9-11 &amp; 15)</li><li><a href="https://comicvine.gamespot.com/the-thanos-wars-infinity-origin/4050-118000/">The Thanos Wars: Infinity Origin</a> (#9-15)</li><li><a href="https://comicvine.gamespot.com/marvel-tales-thanos/4050-118253/">Marvel Tales: Thanos</a> (#10)</li><li><a href="/thanos-vs-hulk/4050-82251/" data-ref-id="4050-82251">Thanos vs. Hulk</a> (#12)</li><li><a href="https://comicvine.gamespot.com/drax-guardian-of-the-galaxy/4050-93657/" data-ref-id="4050-93657">Drax: Guardian of the Galaxy</a> (#15)</li></ul><h4>Reprints</h4><ul><li><a href="/fantasy-masterpieces/4050-3003/" data-ref-id="4050-3003">Fantasy Masterpieces Vol 2</a> (1979)</li><li><a href="/warlock/4050-3156/" data-ref-id="4050-3156">Warlock</a> (1982)</li></ul>', '1972', '15', '{''icon_url'': ''https://comicvine.gamespot.com/a/uploads/square_avatar/11/117763/2618088-power_of_warlock01.jpg'', ''medium_url'': ''https://comicvine.gamespot.com/a/uploads/scale_medium/11/117763/2618088-power_of_warlock01.jpg'', ''screen_url'': ''https://comicvine.gamespot.com/a/uploads/screen_medium/11/117763/2618088-power_of_warlock01.jpg'', ''screen_large_url'': ''https://comicvine.gamespot.com/a/uploads/screen_kubrick/11/117763/2618088-power_of_warlock01.jpg'', ''small_url'': ''https://comicvine.gamespot.com/a/uploads/scale_small/11/117763/2618088-power_of_warlock01.jpg'', ''super_url'': ''https://comicvine.gamespot.com/a/uploads/scale_large/11/117763/2618088-power_of_warlock01.jpg'', ''thumb_url'': ''https://comicvine.gamespot.com/a/uploads/scale_avatar/11/117763/2618088-power_of_warlock01.jpg'', ''tiny_url'': ''https://comicvine.gamespot.com/a/uploads/square_mini/11/117763/2618088-power_of_warlock01.jpg'', ''original_url'': ''https://comicvine.gamespot.com/a/uploads/original/11/117763/2618088-power_of_warlock01.jpg'', ''image_tags'': ''All Images''}', '[{"id": "Adam Warlock"}, {"id": "Jason Grey"}, {"id": "Man-Beast"}, {"id": "Ellie Roberts"}, {"id": "David Carter"}, {"id": "Astrella"}, {"id": "High Evolutionary"}, {"id": "Pip the Troll"}, {"id": "Eddie Roberts"}, {"id": "Thanos"}, {"id": "Gamora"}, {"id": "Colonel Barney Roberts"}, {"id": "Doctor Doom"}, {"id": "In-Betweener"}, {"id": "Magus"}, {"id": "Matriarch"}, {"id": "Triax"}, {"id": "Tom Vocson"}, {"id": "Drax the Destroyer"}, {"id": "Starfox"}, {"id": "Khobra"}, {"id": "Nathan Carter"}, {"id": "Mr. Fantastic"}, {"id": "Star-Thief"}, {"id": "General Egeus"}, {"id": "Haukk"}, {"id": "Mama Alpha"}, {"id": "Captain Autolycus"}, {"id": "Heater Delight"}, {"id": "Captain America"}, {"id": "Constable Trueheart"}, {"id": "Ancient Traveller"}, {"id": "Thor"}, {"id": "Captain Marvel"}, {"id": "Black Panther"}, {"id": "Vision"}, {"id": "Thing"}, {"id": "Human Torch"}, {"id": "Rhino"}, {"id": "Invisible Woman"}, {"id": "Hulk"}, {"id": "Lamilm Gor"}, {"id": "Mantis"}, {"id": "Swordsman"}, {"id": "Recorder"}, {"id": "Death"}, {"id": "Mentor"}, {"id": "Kray-Tor"}, {"id": "Marr Gar"}]', 'NaN', '[{"id": 6805}, {"id": 36839}, {"id": 14524}, {"id": 37424}, {"id": 37423}, {"id": 36840}, {"id": 13346}, {"id": 13782}, {"id": 37389}, {"id": 7607}, {"id": 6806}, {"id": 37390}, {"id": 1468}, {"id": 13354}, {"id": 14619}, {"id": 14622}, {"id": 27627}, {"id": 35626}, {"id": 6807}, {"id": 7257}, {"id": 36929}, {"id": 37391}, {"id": 2151}, {"id": 77674}, {"id": 92295}, {"id": 37312}, {"id": 35778}, {"id": 52164}, {"id": 57207}, {"id": 1442}, {"id": 35494}, {"id": 35493}, {"id": 2268}, {"id": 1472}, {"id": 1477}, {"id": 1504}, {"id": 2114}, {"id": 2120}, {"id": 2126}, {"id": 2190}, {"id": 2267}, {"id": 35492}, {"id": 3324}, {"id": 3795}, {"id": 12344}, {"id": 12620}, {"id": 14522}, {"id": 14623}, {"id": 35491}]', 'NaN', '0');
INSERT INTO volumes (id, name, firstIssue, publisher, description, startYear, numIssues, image, characters_name, concepts_name, characters_id, concepts_id, numLikes) VALUES ('2584', 'Werewolf by Night', 'Eye of the Beholder!', '31', '<p>After enjoying a successful three issue stint in <a href="/marvel-spotlight/4050-2516/" data-ref-id="4050-2516"> Marvel Spotlight </a>(Vol. 1), Marvel awarded the Werewolf his own series, <b>Werewolf By Night</b>, in 1972. The series depicted the trials of Jack Russell who inherited the curse of the <a href="/werewolf-by-night/4005-4984/" data-ref-id="4005-4984"> Werewolf</a> on his eighteenth birthday. He frequently confronted menaces who wanted the man-beast for one nefarious purpose or another. His supporting cast included his devoted sister Lissa, who feared her approaching eighteenth birthday and possibly succumbing to the curse herself; Jack''s step-father Philip whom the siblings suspected murdered their mother, and Buck Cowan, the reporter who became Jack''s best friend and confidante. Other characters introduced in the series include the <a href="/the-hangman/4005-68262/" data-ref-id="4005-68262"> Hangman</a>, <a href="/topaz/4005-16079/" data-ref-id="4005-16079"> Topaz</a> (currently a member of the Witches), and most significantly, <a href="/moon-knight/4005-1493/" data-ref-id="4005-1493"> Moon Knight</a>.</p><p>The series was at its artistic peak in its first two years with decent writing by <a href="/gerry-conway/4040-40871/" data-ref-id="4040-40871"> Gerry Conway</a>, <a href="/len-wein/4040-41457/" data-ref-id="4040-41457"> Len Wein</a> and <a href="/marv-wolfman/4040-41478/" data-ref-id="4040-41478"> Marv Wolfman</a> and excellent art by <a href="/mike-ploog/4040-26572/" data-ref-id="4040-26572"> Mike Ploog</a>, <a href="/tom-sutton/4040-4016/" data-ref-id="4040-4016"> Tom Sutton</a> and <a href="/gil-kane/4040-1764/" data-ref-id="4040-1764"> Gil Kane</a>, developing a style that was referred to in the letters pages as "California Gothic". Then the book took a severe drop in quality, with inconsistent stories by <a href="/doug-moench/4040-42016/" data-ref-id="4040-42016"> Doug Moench</a> and pedestrian art by <a href="/don-perlin/4040-1539/" data-ref-id="4040-1539"> Don Perlin</a>. In 1976, the Marvel monster boom of the mid-70s went bust and the series was nearly canceled, but a leveling off in sales kept it in publication, albeit demoted to bi-monthly status. Feeling restricted by the fact that a werewolf can appear for only three nights out of a month, Moench and Perlin made changes to the Werewolf character. They put Jack in full control of the Werewolf, giving him the abilities to think, speak and transform at will. It appeared they were grooming him for a career as a super-hero as they completely phased-out the California Gothic style. The success of the experiment proved inconclusive, as the series was canceled with the 43rd issue, leaving a developing subplot with the abduction of Jack''s friend Buck Cowan unresolved.</p><p>The Werewolf also starred in the companion series <a href="/giant-size-werewolf/4050-2689/" data-ref-id="4050-2689"> <b>GIANT-SIZE WEREWOLF</b></a>.</p><p>A second volume of <a href="/werewolf-by-night/4050-18541/" data-ref-id="4050-18541"> <b>WEREWOLF BY NIGHT</b></a> was published is 1998, lasing six issues.</p><h4>Collected Editions</h4><ul><li><a href="/werewold-by-night-omnibus/4050-85148/" data-ref-id="4050-85148">Werewolf By Night Omnibus</a> (#1-43)</li><li><a href="https://comicvine.gamespot.com/werewolf-by-night-the-complete-collection-1-volume/4000-626305/" data-ref-id="4000-626305">Werewolf By Night: The Complete Collection Volume 1</a> (#1-15)</li><li><a href="https://comicvine.gamespot.com/avengersdoctor-strange-rise-of-the-darkhold/4050-114044/">Avengers/Doctor Strange: Rise of the Darkhold</a> (#1, 3 &amp; 15)</li><li><a href="https://comicvine.gamespot.com/the-tomb-of-dracula-the-complete-collection-2-volu/4000-687022/" data-ref-id="4000-687022">The Tomb of Dracula: The Complete Collection Volume 2</a> (#15)</li><li><a href="https://comicvine.gamespot.com/werewolf-by-night-in-the-blood/4050-125395/">Werewolf by Night: In the Blood</a> (#15)</li><li><a href="/werewolf-by-night-the-complete-collection-2-volume/4000-656721/" data-ref-id="4000-656721">Werewolf By Night: The Complete Collection Volume 2</a> (#16-30)</li><li><a href="/moon-knight-epic-collection-bad-moon-rising/4050-77333/" data-ref-id="4050-77333">Moon Knight Epic Collection: Bad Moon Rising</a> (#32-33)</li><li><a href="/moon-knight-omnibus-1-volume-1/4000-824088/" data-ref-id="4000-824088">Moon Knight Omnibus Volume 1</a> (#32-33)</li><li><a href="https://comicvine.gamespot.com/marvel-horror-omnibus/4050-121088/">Marvel Horror Omnibus</a> (#39-41)</li><li><a href="/marvel-masterworks-brother-voodoo-1-volume-1/4000-851632/" data-ref-id="4000-851632">Marvel Masterworks: Brother Voodoo Volume 1</a> (#39-41)</li></ul><h4>Non-U.S. Collected Editions</h4><ul><li><a href="https://comicvine.gamespot.com/100-max-hombe-lobo/4050-41720/" data-ref-id="4050-41720">100% MAX: Hombe Lobo</a> (#15) (Spanish)</li><li><a href="https://comicvine.gamespot.com/coleccionable-marvel-heroes-65-caballero-luna-1-cu/4000-612301/">Coleccionable Marvel Héroes - Caballero Luna 1: Cuenta atrás hacia la oscuridad</a> (#32-33) (Spanish)</li></ul>', '1972', '43', '{''icon_url'': ''https://comicvine.gamespot.com/a/uploads/square_avatar/0/4/11278-2584-12500-1-werewolf-by-night.jpg'', ''medium_url'': ''https://comicvine.gamespot.com/a/uploads/scale_medium/0/4/11278-2584-12500-1-werewolf-by-night.jpg'', ''screen_url'': ''https://comicvine.gamespot.com/a/uploads/screen_medium/0/4/11278-2584-12500-1-werewolf-by-night.jpg'', ''screen_large_url'': ''https://comicvine.gamespot.com/a/uploads/screen_kubrick/0/4/11278-2584-12500-1-werewolf-by-night.jpg'', ''small_url'': ''https://comicvine.gamespot.com/a/uploads/scale_small/0/4/11278-2584-12500-1-werewolf-by-night.jpg'', ''supe