INSERT INTO volumes (id, name, firstIssue, publisher, description, startYear, numIssues, image, characters_name, concepts_name, characters_id, concepts_id, numLikes) VALUES ('2632', 'Crypt of Shadows', 'Midnight On Black Mountain', '31', '<p>What nameless evil lurks in...the Crypt of Shadows!! A Marvel Comics horror series, with new and reprinted short stories full of horrifying events. It lasted for 21 issues.</p>', '1973', '21', '{''icon_url'': ''https://comicvine.gamespot.com/a/uploads/square_avatar/0/4/59031-2632-92026-1-crypt-of-shadows.jpg'', ''medium_url'': ''https://comicvine.gamespot.com/a/uploads/scale_medium/0/4/59031-2632-92026-1-crypt-of-shadows.jpg'', ''screen_url'': ''https://comicvine.gamespot.com/a/uploads/screen_medium/0/4/59031-2632-92026-1-crypt-of-shadows.jpg'', ''screen_large_url'': ''https://comicvine.gamespot.com/a/uploads/screen_kubrick/0/4/59031-2632-92026-1-crypt-of-shadows.jpg'', ''small_url'': ''https://comicvine.gamespot.com/a/uploads/scale_small/0/4/59031-2632-92026-1-crypt-of-shadows.jpg'', ''super_url'': ''https://comicvine.gamespot.com/a/uploads/scale_large/0/4/59031-2632-92026-1-crypt-of-shadows.jpg'', ''thumb_url'': ''https://comicvine.gamespot.com/a/uploads/scale_avatar/0/4/59031-2632-92026-1-crypt-of-shadows.jpg'', ''tiny_url'': ''https://comicvine.gamespot.com/a/uploads/square_mini/0/4/59031-2632-92026-1-crypt-of-shadows.jpg'', ''original_url'': ''https://comicvine.gamespot.com/a/uploads/original/0/4/59031-2632-92026-1-crypt-of-shadows.jpg'', ''image_tags'': ''All Images''}', '[{"id": "HYDRA Agent"}]', 'NaN', '[{"id": 168834}]', 'NaN', '0');
INSERT INTO volumes (id, name, firstIssue, publisher, description, startYear, numIssues, image, characters_name, concepts_name, characters_id, concepts_id, numLikes) VALUES ('2636', 'Ghost Rider', 'A Woman Possessed!', '31', '<p><a href="/ghost-rider-blaze/4005-6108/" data-ref-id="4005-6108">Ghost Rider</a> (Johnny Blaze) received his own ongoing series after his debut in <a href="/marvel-spotlight/4050-2516/" data-ref-id="4050-2516">Marvel Spotlight</a>. This volume bearing the title Ghost Rider lasted for ten years and 81 issues.</p><h3>Writers</h3><ul><li><a href="/gary-friedrich/4040-43812/" data-ref-id="4040-43812">Gary Friedrich</a> #1-4, 6, 10(reprint of <a href="/marvel-spotlight-5-origin-of-the-ghost-rider/4000-12422/" data-ref-id="4000-12422">Marvel Spotlight #5</a>)</li><li><a href="/marv-wolfman/4040-41478/" data-ref-id="4040-41478">Marv Wolfman</a> #5, 20</li><li><a href="/doug-moench/4040-42016/" data-ref-id="4040-42016">Doug Moench</a> #5</li><li><a href="/tony-isabella/4040-42209/" data-ref-id="4040-42209">Tony Isabella</a> #6-9, 11-15, 17-19</li><li><a href="/frank-robbins/4040-34476/" data-ref-id="4040-34476">Frank Robbins</a> #12</li><li><a href="/bill-mantlo/4040-42478/" data-ref-id="4040-42478">Bill Mantlo</a> #16</li><li><a href="/gerry-conway/4040-40871/" data-ref-id="4040-40871">Gerry Conway</a> #21-23</li><li><a href="/don-glut/4040-57469/" data-ref-id="4040-57469">Don Glut</a> #22</li><li><a href="/jim-shooter/4040-40450/" data-ref-id="4040-40450">Jim Shooter</a> #23-27</li><li><a href="/roger-mckenzie/4040-44822/" data-ref-id="4040-44822">Roger McKenzie</a> #28-34</li><li><a href="/don-perlin/4040-1539/" data-ref-id="4040-1539">Don Perlin</a> #32-33</li><li><a href="/jim-starlin/4040-7922/" data-ref-id="4040-7922">Jim Starlin</a> #35</li><li><a href="/michael-fleisher/4040-44657/" data-ref-id="4040-44657">Michael Fleisher</a> #36-66</li><li><a href="/jm-dematteis/4040-41043/" data-ref-id="4040-41043">J.M. DeMatteis</a> #67, 71, 74-81</li><li><a href="/roger-stern/4040-41502/" data-ref-id="4040-41502">Roger Stern</a> #68-70, 72-73</li></ul><h4>Collected Editions</h4><ul><li><a href="https://comicvine.gamespot.com/the-son-of-satan-classic/4050-95033/" data-ref-id="4050-95033">The Son of Satan Classic</a> (#1-2)</li><li><a href="/essential-ghost-rider-1-volume-1/4000-153492/" data-ref-id="4000-153492">Essential Ghost Rider #1 - Volume 1</a> (#1-20)</li><li><a href="/marvel-masterworks-ghost-rider-1-volume-1/4000-721798/" data-ref-id="4000-721798">Marvel Masterworks: Ghost Rider Volume 1</a> (#1-5)</li><li><a href="https://comicvine.gamespot.com/hellstrom-evil-origins/4050-129473/">Hellstrom: Evil Origins</a> (#1-2)</li><li><a href="/marvel-masterworks-ghost-rider-2-volume-2/4000-821522/" data-ref-id="4000-821522">Marvel Masterworks: Ghost Rider Volume 2</a> (#6-20)</li><li><a href="/marvel-universe-by-john-byrne-omnibus-2-volume-2/4000-694138/" data-ref-id="4000-694138">Marvel Universe by John Byrne Omnibus Volume 2</a> (#20)</li><li><a href="https://comicvine.gamespot.com/essential-ghost-rider-2-volume-2/4000-153726/" data-ref-id="4000-153726">Essential Ghost Rider #2 - Volume 2</a> (#21-50)</li><li><a href="/marvel-masterworks-ghost-rider-3-volume-3/4000-891875/" data-ref-id="4000-891875">Marvel Masterworks: Ghost Rider Volume 3</a> (#21-35)</li><li><a href="/ghost-racers/4050-87545/" data-ref-id="4050-87545">Ghost Racers</a> (#35)</li><li><a href="/essential-ghost-rider-3-volume-3/4000-186481/" data-ref-id="4000-186481">Essential Ghost Rider #3 - Volume 3</a> (#51-65)</li><li><a href="/essential-ghost-rider-4-volume-4/4000-239679/" data-ref-id="4000-239679">Essential Ghost Rider #4 - Volume 4</a> (#66-81)</li></ul>', '1973', '81', '{''icon_url'': ''https://comicvine.gamespot.com/a/uploads/square_avatar/0/4/12128-2636-13577-1-ghost-rider.jpg'', ''medium_url'': ''https://comicvine.gamespot.com/a/uploads/scale_medium/0/4/12128-2636-13577-1-ghost-rider.jpg'', ''screen_url'': ''https://comicvine.gamespot.