INSERT INTO volumes (id, name, firstIssue, publisher, description, startYear, numIssues, image, characters_name, concepts_name, characters_id, concepts_id, numLikes) VALUES ('2639', 'Marvel Double Feature', NULL, '31', '<p>Marvel Double Feature was a reprint title, originally reprinting issues of Tales of Suspense and giving Captain America lead billing on the cover. The final two issues dropped Iron Man in favour of reprinting a story from Captain America that featured Black Panther.</p>', '1973', '21', '{''icon_url'': ''https://comicvine.gamespot.com/a/uploads/square_avatar/0/4/12394-2639-13889-1-marvel-double-featur.jpg'', ''medium_url'': ''https://comicvine.gamespot.com/a/uploads/scale_medium/0/4/12394-2639-13889-1-marvel-double-featur.jpg'', ''screen_url'': ''https://comicvine.gamespot.com/a/uploads/screen_medium/0/4/12394-2639-13889-1-marvel-double-featur.jpg'', ''screen_large_url'': ''https://comicvine.gamespot.com/a/uploads/screen_kubrick/0/4/12394-2639-13889-1-marvel-double-featur.jpg'', ''small_url'': ''https://comicvine.gamespot.com/a/uploads/scale_small/0/4/12394-2639-13889-1-marvel-double-featur.jpg'', ''super_url'': ''https://comicvine.gamespot.com/a/uploads/scale_large/0/4/12394-2639-13889-1-marvel-double-featur.jpg'', ''thumb_url'': ''https://comicvine.gamespot.com/a/uploads/scale_avatar/0/4/12394-2639-13889-1-marvel-double-featur.jpg'', ''tiny_url'': ''https://comicvine.gamespot.com/a/uploads/square_mini/0/4/12394-2639-13889-1-marvel-double-featur.jpg'', ''original_url'': ''https://comicvine.gamespot.com/a/uploads/original/0/4/12394-2639-13889-1-marvel-double-featur.jpg'', ''image_tags'': ''All Images''}', '[{"id": "Captain America"}, {"id": "Iron Man"}, {"id": "Jasper Sitwell"}, {"id": "Red Skull"}, {"id": "Happy Hogan"}, {"id": "Pepper Potts"}, {"id": "Madame Masque"}, {"id": "Nick Fury"}, {"id": "Sharon Carter"}, {"id": "Whiplash (Scarlotti)"}, {"id": "Jarvis"}, {"id": "Hank Pym"}, {"id": "Senator Harrington Byrd"}, {"id": "Wasp"}, {"id": "Titani