INSERT INTO volumes (id, name, firstIssue, publisher, description, startYear, numIssues, image, characters_name, concepts_name, characters_id, concepts_id, numLikes) VALUES ('2642', 'SHIELD', 'When the Unliving Strike!', '31', '<p>This short-run volume features <a href="/nick-fury/4005-3202/" data-ref-id="4005-3202"> Nick Fury</a> and his <a href="/shield/4060-3775/" data-ref-id="4060-3775"> S.H.I.E.L.D.</a> agents in stories reprinted from <a href="/strange-tales/4050-18066/" data-ref-id="4050-18066">Strange Tales</a>. </p><p><strong>Note</strong>: Volume named per the indicia.</p>', '1973', '5', '{''icon_url'': ''https://comicvine.gamespot.com/a/uploads/square_avatar/0/4/11630-2642-12935-1-shield-nick-fury-an.jpg'', ''medium_url'': ''https://comicvine.gamespot.com/a/uploads/scale_medium/0/4/11630-2642-12935-1-shield-nick-fury-an.jpg'', ''screen_url'': ''https://comicvine.gamespot.com/a/uploads/screen_medium/0/4/11630-2642-12935-1-shield-nick-fury-an.jpg'', ''screen_large_url'': ''https://comicvine.gamespot.com/a/uploads/screen_kubrick/0/4/11630-2642-12935-1-shield-nick-fury-an.jpg'', ''small_url'': ''https://comicvine.gamespot.com/a/uploads/scale_small/0/4/11630-2642-12935-1-shield-nick-fury-an.jpg'', ''super_url'': ''https://comicvine.gamespot.com/a/uploads/scale_large/0/4/11630-2642-12935-1-shield-nick-fury-an.jpg'', ''thumb_url'': ''https://comicvine.gamespot.com/a/uploads/scale_avatar/0/4/11630-2642-12935-1-shield-nick-fury-an.jpg'', ''tiny_url'': ''https://comicvine.gamespot.com/a/uploads/square_mini/0/4/11630-2642-12935-1-shield-nick-fury-an.jpg'', ''original_url'': ''https://comicvine.gamespot.com/a/uploads/original/0/4/11630-2642-12935-1-shield-nick-fury-an.jpg'', ''image_tags'': ''All Images''}', '[{"id": "Nick Fury"}, {"id": "Dum Dum Dugan"}, {"id": "Jasper Sitwell"}, {"id": "Gabriel Jones"}, {"id": "Rebel Ralston"}, {"id": "Percy Pinkerton"}, {"id": "Izzy Cohen"}, {"id": "Dino Manelli"}, {"id": "Supreme Hydra"}, {"id": "Laura Brown"}, {"id": "Count Bornag Royale"}, {"id": "Anton Trojak"}, {"id": "Dreadnought"}, {"id": "Linda Donaldson"}]', 'NaN', '[{"id": 3202}, {"id": 3526}, {"id": 7529}, {"id": 13836}, {"id": 14196}, {"id": 14197}, {"id": 14198}, {"id": 14199}, {"id": 16040}, {"id": 13838}, {"id": 38629}, {"id": 14566}, {"id": 19941}, {"id": 37198}]', 'NaN', '0');
INSERT INTO volumes (id, name, firstIssue, publisher, description, startYear, numIssues, image, characters_name, concepts_name, characters_id, concepts_id, numLikes) VALUES ('2643', 'Strange Tales', 'Brother Voodoo', '31', '<p>This series is a continuation of the <a href="/strange-tales/4050-18066/" data-ref-id="4050-18066">Strange Tales</a> series that ended in 1968 with issue 168. That series'' name was transformed into <a href="/doctor-strange/4050-2403/" data-ref-id="4050-2403">Doctor Strange</a> with issue 169 while the Nick Fury stories moved to a new title, <a href="/nick-fury-agent-of-shield/4050-2410/" data-ref-id="4050-2410">Nick Fury, Agent of SHIELD</a>.</p><p>Strangely enough, a few years later, this series came to light with a new issue 169. This comic-series is mostly known for introducing Brother Voodoo and Golem to the Marvel Universe, as well as the beginning of Jim Starlin''s run on Warlock. After Strange Tales 181, Warlock''s series continues in number 9 of <a href="../../warlock/49-2583/" rel="nofollow ">Warlock''s own</a> (revived) series.</p><h4>Collected Editions</h4><ul><li><a href="https://www.comicvine.com/warlock-by-jim-starlin-1-tpb/4000-444317/" data-ref-id="4000-444317">Warlock By Jim Starlin: The Complete Collection vol. 1</a> (#178-181)</li><li><a href="https://comicvine.gamespot.com/marvels-guardians-of-the-galaxy-prelude-1-tpb/4000-458964/" data-ref-id="4000-458964">Marvel''s Guardians of the Galaxy Prelude Volume 1</a> (#181)</li></ul>', '1973', '20', '{''icon_url'': ''https://comicvine.gamespot.com/a/uploads/square_avatar/6/67663/3754591-169.jpg'', ''medium_url'': ''https://comicvine.gamespot.com/a/uploads/scale_medium/6/67663/3754591-169.jpg'', ''screen_url'': ''https://comicvine.gamespot.com/a/uploads/screen_medium/6/67663/3754591-169.jpg'', ''screen_large_url'': ''https://comicvine.gamespot.com/a/uploads/screen_kubrick/6/67663/3754591-169.jpg'', ''small_url'': ''https://comicvine.gamespot.com/a/uploads/scale_small/6/67663/3754591-169.jpg'', ''super_url'': ''https://comicvine.gamespot.com/a/uploads/scale_large/6/67663/3754591-169.jpg'', ''thumb_url'': ''https://comicvine.gamespot.com/a/uploads/scale_avatar/6/67663/3754591-169.jpg'', ''tiny_url'': ''https://comicvine.gamespot.com/a/uploads/square_mini/6/67663/3754591-169.jpg'', ''original_url'': ''https://comicvine.gamespot.com/a/uploads/original/6/67663/3754591-169.jpg'', ''image_tags'': ''All Images''}', '[{"id": "Doctor Strange"}, {"id": "Daniel Drumm"}, {"id": "Doctor Voodoo"}, {"id": "Baron Mordo"}, {"id": "Matriarch"}, {"id": "Adam Warlock"}, {"id": "The Golem"}, {"id": "Dormammu"}, {"id": "Magus"}, {"id": "Bambu"}, {"id": "Pip the Troll"}, {"id": "Damballah"}, {"id": "Kray-Tor"}, {"id": "Kaballa"}, {"id": "Gamora"}, {"id": "Thor"}, {"id": "Loralee Tate"}, {"id": "Desmond Drew"}, {"id": "Papa Jambo"}, {"id": "David Carter"}, {"id": "Torr"}, {"id": "Eddie Roberts"}, {"id": "Khobra"}, {"id": "Ellie Roberts"}, {"id": "Maris Morlak"}, {"id": "Captain Autolycus"}, {"id": "Madness Monster"}, {"id": "Saudia Yamal"}, {"id": "Jason Grey"}, {"id": "Shinsky"}, {"id": "Carlo Zota"}, {"id": "Mama Limbo"}, {"id": "Triax"}, {"id": "Sphinxor"}, {"id": "Man-Beast"}, {"id": "High Evolutionary"}, {"id": "Recorder"}, {"id": "Loki"}, {"id": "Hulk"}, {"id": "Clea"}, {"id": "Doctor Doom"}]', '[{"id": "Alternate Reality"}]', '[{"id": 1456}, {"id": 28756}, {"id": 10280}, {"id": 2213}, {"id": 14622}, {"id": 6805}, {"id": 37860}, {"id": 2205}, {"id": 14619}, {"id": 28867}, {"id": 13782}, {"id": 23320}, {"id": 14623}, {"id": 47166}, {"id": 6806}, {"id": 2268}, {"id": 60673}, {"id": 90065}, {"id": 28755}, {"id": 37423}, {"id": 39583}, {"id": 37389}, {"id": 36929}, {"id": 37424}, {"id": 24401}, {"id": 52164}, {"id": 52165}, {"id": 91552}, {"id": 36839}, {"id": 30974}, {"id": 30973}, {"id": 28869}, {"id": 27627}, {"id": 14625}, {"id": 14524}, {"id": 13346}, {"id": 12344}, {"id": 4324}, {"id": 2267}, {"id": 2216}, {"id": 1468}]', '[{"id": 40617}]', '0');
INSERT INTO volumes (id, name, firstIssue, publisher, description, startYear, numIssues, image, characters_name, concepts_name, characters_id, concepts_id, numLikes) VALUES ('2668', 'The Superman Family', 'Death Bites with Fangs of Stone / The Gift-Wrapped Doom', '10', '<p><em><b>The Superman Family</b></em> was a DC Comics comic book series which ran from 1974 to 1982 featuring primarily stories starring the supporting characters in the Superman comics. The term is often used to refer to the extended cast of characters (especially super-powered ones) of comics books associated with Superman.</p><p>The title was an amalgamation of the titles <em><a href="/supermans-girl-friend-lois-lane/4050-19245/" data-ref-id="4050-19245">Superman''s Girl Friend, Lois Lane</a></em> and <em><a href="/supermans-pal-jimmy-olsen/4050-19172/" data-ref-id="4050-19172">Superman''s Pal Jimmy Olsen</a></em> and the first series of <em><a href="/supergirl/4050-2555/" data-ref-id="4050-2555">Supergirl</a></em>, therefore immediately becoming DC''s flagship title with the highest sales for the remainder. The first issue, #164, took its numbering from the Jimmy Olsen title, which had reached issue <a href="/superman-s-pal-jimmy-olsen-163-a-world-that-came-b/4000-134734/" data-ref-id="4000-134734">#163</a> and thus had the most issues published (the Lois Lane series ended at issue <a href="/superman-s-girl-friend-lois-lane-137-the-stolen-su/4000-125593/" data-ref-id="4000-125593">#137</a>, while the newly-launched <em>Supergirl</em> volume 1 series had only made it to <a href="/supergirl-10-death-of-a-prez/4000-14554/" data-ref-id="4000-14554">#10</a>). The three leads rotated new stories in each issue with <a href="/reprinted-material/4015-56278/" data-ref-id="4015-56278">reprints</a> as a backup feature for other the characters (Issues #164-181). <em>The Superman Family</em> started as a 100-page format from issues #164-169. The quantity of pages dropped to 64-pages with issue #170 and dropped to 48-pages with issue #178. In 1976 (<a href="/the-superman-family-182-death-on-ice/4000-17226/" data-ref-id="4000-17226">#182</a>), <em>The Superman Family</em> became the first DC Comics to feature the 80-page Dollar Comics format. The new 80-page format featured all new stories for all the characters. Later the page quantity dropped to 64-pages starting with issue <a href="/the-superman-family-191-the-incredible-shrinking-t/4000-18799/" data-ref-id="4000-18799">#191</a> and finally to 48-pages starting with issue <a href="/the-superman-family-205-magic-over-miami-catch-a-f/4000-20931/" data-ref-id="4000-20931">#205</a>. The series briefly featured a "no ads" and a wraparound cover format from issues #191-196. The series was published on a bi-monthly schedule until 1981, when the series was published on a monthly schedule starting with issue <a href="/the-superman-family-207-look-homeward-argonian-the/4000-21203/" data-ref-id="4000-21203">#207</a>.</p><p>Other featured series in addition to:</p><p>* Lois Lane (166,169,172,175,178,181-222)</p><p>* Supergirl (165,168,171,174,177,180,182-222)</p><p>* Jimmy Olsen (164,167,170,173,176,179,182-222)</p><p>* "Superboy" (182,191-198) — The adventures of the Earth-One Superman as a teenage super-hero. This series continued from <em><a href="/adventure-comics/4050-3105/" data-ref-id="4050-3105">Adventure Comics #458</a></em> and led to the feature leaving the title for its own in 1980, <em><a href="/new-adventures-of-superboy/4050-3035/" data-ref-id="4050-3035">The New Adventures of Superboy</a></em>.</p><p>* "<em>The Private Life of Clark Kent</em>" (195-197, 199-215) — The adventures of Clark Kent in which he used his powers and skills without becoming Superman. This feature had moved over from <em><a href="/superman/4050-773/" data-ref-id="4050-773">Superman</a></em> after <a href="/superman-328-the-attack-of-the-kryptonoid-clark-ke/4000-18875/" data-ref-id="4000-18875">#328</a>.</p><p>* "<em>Mr. and Mrs. Superman</em>" (195-196, 198-222) — The adventures of the <a href="/kal-l/4005-62833/" data-ref-id="4005-62833">Earth-Two Superman</a> and his wife, <a href="/lois-lane/4005-1808/" data-ref-id="4005-1808">Lois</a>. This feature had moved from Superman after <a href="/superman-329-i-have-met-the-enemy-and-it-is-me-sec/4000-18945/" data-ref-id="4000-18945">#329</a>. #200 of this series also had a story that dealt with a married Lois and Clark, but as part of an issue-long <a href="/imaginary-stories/4015-55849/" data-ref-id="4015-55849">Imaginary Story</a> set on Earth-1 at the turn of the millennium.</p><p>* "Krypto" (182-192) — The adventures of Superman''s dog.</p><p>* "<a href="/nightwing-flamebird/4060-56092/" data-ref-id="4060-56092">Nightwing and Flamebird</a>" (182-194) — The adventures of the second Nightwing and Flamebird team of heroes (<a href="/van-zee/4005-31096/" data-ref-id="4005-31096">Van-Zee</a> and <a href="/ak-var/4005-65220/" data-ref-id="4005-65220">Ak-Var</a>) in the <a href="/kandor/4020-41290/" data-ref-id="4020-41290">Bottled City of Kandor</a>.</p><p>* "<em>The Misadventures of Superbaby</em>" (216) — A one-shot story featuring Superbaby.</p><p>DC published several other "Family" titles concurrent with <em>The Superman Family</em>: <em><a href="/batman-family/4050-2727/" data-ref-id="4050-2727">Batman Family</a></em> (1975-78), <em><a href="/super-team-family/4050-2741/" data-ref-id="4050-2741">Super-Team Family</a></em> (1975-1978) and <em><a href="/tarzan-family/4050-2743/" data-ref-id="4050-2743">Tarzan Family</a></em> (1975-76). As a rule, DC''s "Family" titles contained mostly reprints, and featured a higher page count (and higher price) than DC''s normal books. (In 2004, <a href="/marvel/4010-31/" data-ref-id="4010-31">Marvel Comics</a> paid homage to DC''s "Family" titles with <em><a href="/spider-man-family/4050-18459/" data-ref-id="4050-18459">Spider-Man Family</a></em>.)</p><p>In 1982, with issue #222, <em>The Superman Family</em> series was cancelled to make room for the <em><a href="/supergirl-vol-2/4050-3113/" data-ref-id="4050-3113">Daring New Adventures of Supergirl</a></em>, which briefly featured a Lois Lane back-up series. The <a href="/doom-patrol/4060-5701/" data-ref-id="4060-5701">Doom Patrol</a> appeared alongside Supergirl in issues of both series.</p><h4>Collected Editions</h4><ul><li><a href="https://comicvine.gamespot.com/deadman-omnibus/4050-132454/">Deadman Omnibus</a> (#183)</li></ul>', '1974', '59', '{''icon_url'': ''https://comicvine.gamespot.com/a/uploads/square_avatar/0/4/12621-2668-14164-1-superman-family-the.jpg'', ''medium_url'': ''https://comicvine.gamespot.com/a/uploads/scale_medium/0/4/12621-2668-14164-1-superman-family-the.jpg'', ''screen_url'': ''https://comicvine.gamespot.com/a/uploads/screen_medium/0/4/12621-2668-14164-1-superman-family-the.jpg'', ''screen_large_url'': ''https://comicvine.gamespot.com/a/uploads/screen_kubrick/0/4/12621-2668-14164-1-superman-family-the.jpg'', ''small_url'': ''https://comicvine.gamespot.com/a/uploads/scale_small/0/4/12621-2668-14164-1-superman-family-the.jpg'', ''super_url'': ''https://comicvine.gamespot.com/a/uploads/scale_large/0/4/12621-2668-14164-1-superman-family-the.jpg'', ''thumb_url'': ''https://comicvine.gamespot.com/a/uploads/scale_avatar/0/4/12621-2668-14164-1-superman-family-the.jpg'', ''tiny_url'': ''https://comicvine.gamespot.com/a/uploads/square_mini/0/4/12621-2668-14164-1-superman-family-the.jpg'', ''original_url'': ''https://comicvine.gamespot.com/a/uploads/original/0/4/12621-2668-14164-1-superman-family-the.jpg'', ''image_tags'': ''All Images''}', '[{"id": "Jimmy Olsen"}, {"id": "Superman"}, {"id": "Lois Lane"}, {"id": "Supergirl"}, {"id": "Perry White"}, {"id": "Kal-L"}, {"id": "Lana Lang"}, {"id": "Morgan Edge"}, {"id": "Krypto"}, {"id": "Bill Henderson"}, {"id": "Lex Luthor"}, {"id": "Jonathan Kent"}, {"id": "Zor-El"}, {"id": "Lucy Lane"}, {"id": "Steve Lombard"}, {"id": "Van-Zee"}, {"id": "Ak-Var"}, {"id": "Martha Kent