INSERT INTO volumes (id, name, firstIssue, publisher, description, startYear, numIssues, image, characters_name, concepts_name, characters_id, concepts_id, numLikes) VALUES ('2675', 'The Deadly Hands of Kung Fu', 'The Testing of Shang-Chi', '31', '<p>A black and white magazine from Marvel Comics. Coming from the success of the Martial-Arts craze in the early 1970''s in America. It housed the first appearance of such Marvel superheroes such as Jack of Hearts and the White Tiger to name a few.</p><h4>Collected Editions</h4><ul><li><a href="https://comicvine.gamespot.com/deadly-hands-of-kung-fu-omnibus-1-volume-1/4000-557364/" data-ref-id="4000-557364">The Deadly Hands of Kung Fu Omnibus Volume 1</a> (#1-18)</li><li><a href="/deadly-hands-of-kung-fu-out-of-the-past/4050-77630/" data-ref-id="4050-77630">Deadly Hands of Kung Fu: Out Of The Past</a> (#1 and 32-33)</li><li><a href="https://comicvine.gamespot.com/the-deadly-hands-of-kung-fu-omnibus-2-volume-2/4000-600566/" data-ref-id="4000-600566">The Deadly Hands of Kung Fu Omnibus Volume 2</a> (#19-33)</li></ul>', '1974', '33', '{''icon_url'': ''https://comicvine.gamespot.com/a/uploads/square_avatar/0/4/12649-2675-14192-1-deadly-hands-of-kung.jpg'', ''medium_url'': ''https://comicvine.gamespot.com/a/uploads/scale_medium/0/4/12649-2675-14192-1-deadly-hands-of-kung.jpg'', ''screen_url'': ''https://comicvine.gamespot.com/a/uploads/screen_medium/0/4/12649-2675-14192-1-deadly-hands-of-kung.jpg'', ''screen_large_url'': ''https://comicvine.gamespot.com/a/uploads/screen_kubrick/0/4/12649-2675-14192-1-deadly-hands-of-kung.jpg'', ''small_url'': ''https://comicvine.gamespot.com/a/uploads/scale_small/0/4/12649-2675-14192-1-deadly-hands-of-kung.jpg'', ''super_url'': ''https://comicvine.gamespot.com/a/uploads/scale_large/0/4/12649-2675-14192-1-deadly-hands-of-kung.jpg'', ''thumb_url'': ''https://comicvine.gamespot.com/a/uploads/scale_avatar/0/4/12649-2675-14192-1-deadly-hands-of-kung.jpg'', ''tiny_url'': ''https://comicvine.gamespot.c