INSERT INTO volumes (id, name, firstIssue, publisher, description, startYear, numIssues, image, characters_name, concepts_name, characters_id, concepts_id, numLikes) VALUES ('2676', 'Doctor Strange', 'Through an Orb Darkly', '31', '<p>The second ongoing series starring Doctor Strange. After the Doctor''s adventures in <a href="/strange-tales/4050-18066/" data-ref-id="4050-18066"> Strange Tales Vol.1</a>, his continued adventures in<a href="/doctor-strange/4050-2403/" data-ref-id="4050-2403"> Doctor Strange Vol.1 </a>and his spot in issues 3 - 14 of <a href="https://www.comicvine.com/marvel-premiere/4050-2575/">Marvel Premiere</a>, here Steven Strange is once more ready to battle the spiritual threads that threaten Earth!</p><p>The series lasted for 81 issues after which it continued as <a href="/strange-tales/4050-3863/" data-ref-id="4050-3863">Strange Tales Vol.3</a>.</p><h4>Additional Volumes</h4><ul><li><a href="https://comicvine.gamespot.com/doctor-strange/4050-2403/" data-ref-id="4050-2403">Doctor Strange Volume 1</a></li><li>Doctor Strange Volume 2</li><li><a href="https://comicvine.gamespot.com/doctor-strange/4050-85094/" data-ref-id="4050-85094">Doctor Strange Volume 3</a></li><li><a href="https://comicvine.gamespot.com/doctor-strange/4050-111415/" data-ref-id="4050-111415">Doctor Strange Volume 4</a></li><li><a href="https://comicvine.gamespot.com/doctor-strange/4050-148962/" data-ref-id="4050-148962">Doctor Strange Volume 5</a></li></ul><h4>Collected Editions</h4><ul><li>Marvel Masterworks Vol. 5 (#1-9)</li><li><a href="https://comicvine.gamespot.com/doctor-strange-epic-collection-a-separate-reality/4050-95006/" data-ref-id="4050-95006">Doctor Strange Epic Collection: A Separate Reality</a> (#1-5)</li><li><a href="https://comicvine.gamespot.com/doctor-strange-epic-collection-alone-against-etern/4050-133481/">Doctor Strange Epic Collection: Alone Against Eternity</a> (#6-28)</li><li><a href="https://comicvine.gamespot.com/the-tomb-of-dracula-the-complete-collection-4-volu/4000-797288/" data-ref-id="4000-797288">The Tomb of Dracula: The Complete Collection Volume 4</a> (#14)</li><li><a href="https://comicvine.gamespot.com/marvel-masterworks-doctor-strange-7-volume-7/4000-557368/" data-ref-id="4000-557368">Marvel Masterworks: Doctor Strange Volume 7</a> (#23-37)</li><li><a href="https://comicvine.gamespot.com/doctor-strange-what-is-it-that-disturbs-you-stephe/4050-95213/" data-ref-id="4050-95213">Doctor Strange: What Is It That Disturbs You, Stephen?</a> (#34)</li><li><a href="https://comicvine.gamespot.com/marvel-masterworks-doctor-strange-8-volume-8/4000-594966/" data-ref-id="4000-594966">Marvel Masterworks: Doctor Strange Volume 8</a> (#38-45)</li><li><a href="https://comicvine.gamespot.com/marvel-universe-by-chris-claremont-omnibus/4050-103251/" data-ref-id="4050-103251">Marvel Universe by Chris Claremont Omnibus</a> (#38-45)</li><li><a href="/marvel-masterworks-brother-voodoo-1-volume-1/4000-851632/" data-ref-id="4000-851632">Marvel Masterworks: Brother Voodoo Volume 1</a> (#41)</li><li><a href="/marvel-masterworks-doctor-strange-9-volume-9/4000-723125/" data-ref-id="4000-723125">Marvel Masterworks: Doctor Strange Volume 9</a> (#47-57)</li><li><a href="https://comicvine.gamespot.com/marvel-horror-omnibus/4050-121088/">Marvel Horror Omnibus</a> (#48)</li><li><a href="https://comicvine.gamespot.com/marvel-verse-doctor-strange/4050-138455/">Marvel-Verse: Doctor Strange</a> (#55)</li><li><a href="https://comicvine.gamespot.com/doctor-strange-doctor-doom-triumph-and-torment/4050-89079/" data-ref-id="4050-89079">Doctor Strange &amp; Doctor Doom: Triumph &amp; Torment</a> (#57)</li><li><a href="https://comicvine.gamespot.com/avengersdoctor-strange-rise-of-the-darkhold/4050-114044/">Avengers/Doctor Strange: Rise of the Darkhold</a> (#59-62, 67 &amp; 81)</li><li><a href="/doctor-strange-dont-pay-the-ferryman/4050-85095/" data-ref-id="4050-85095">Doctor Strange: Don''t Pay the Ferryman</a> (#75-81)</li><li><a href="https://comicvine.gamespot.com/cloak-and-dagger-agony-and-ecstasy/4050-119528/">Cloak and Dagger: Agony and Ecstasy</a> (#78)</li><li><a href="https://comicvine.gamespot.com/cloak-and-dagger-omnibus/4050-130070/">Cloak and Dagger Omnibus</a> (#78)</li></ul><h4>Non-U.S. Collected Editions</h4><ul><li><a href="https://comicvine.gamespot.com/coleccionable-marvel-heroes-75-doctor-extrano-de-r/4000-612313/">Coleccionable Marvel Héroes - Doctor Extraño de Roger Stern</a> (#46-73) (Spanish)</li><li><a href="https://comicvine.gamespot.com/coleccionable-marvel-heroes-53-secret-wars-ii-quie/4000-612261/">Coleccionable Marvel Héroes - Secret Wars II: ¿Quién es el Todopoderoso?</a> (#74) (Spanish)</li></ul><p>Issues <a href="https://comicvine.gamespot.com/biblioteca-marvel-dr-extrano/4050-41949/" data-ref-id="4050-41949">#15-76</a> have been translated into Spanish.</p>', '1974', '81', '{''icon_url'': ''https://comicvine.gamespot.com/a/uploads/square_avatar/0/4/12773-2676-14334-1-doctor-strange.jpg'', ''medium_url'': ''https://comicvine.gamespot.com/a/uploads/scale_medium/0/4/12773-2676-14334-1-doctor-strange.jpg'', ''screen_url'': ''https://comicvine.gamespot.com/a/uploads/screen_medium/0/4/12773-2676-14334-1-doctor-strange.jpg'', ''screen_large_url'': ''https://comicvine.gamespot.com/a/uploads/screen_kubrick/0/4/12773-2676-14334-1-doctor-strange.jpg'', ''small_url'': ''https://comicvine.gamespot.com/a/uploads/scale_small/0/4/12773-2676-14334-1-doctor-strange.jpg'', ''super_url'': ''https://comicvine.gamespot.com/a/uploads/scale_large/0/4/12773-2676-14334-1-doctor-strange.jpg'', ''thumb_url'': ''https://comicvine.gamespot.com/a/uploads/scale_avatar/0/4/12773-2676-14334-1-doctor-strange.jpg'', ''tiny_url'': ''https://comicvine.gamespot.com/a/uploads/square_mini/0/4/12773-2676-14334-1-doctor-strange.jpg'', ''original_url'': ''https://comicvine.gamespot.com/a/uploads/original/0/4/12773-2676-14334-1-doctor-strange.jpg'', ''image_tags'': ''All Images''}', '[{"id": "Doctor Strange"}, {"id": 