INSERT INTO volumes (id, name, firstIssue, publisher, description, startYear, numIssues, image, characters_name, concepts_name, characters_id, concepts_id, numLikes) VALUES ('2696', 'Marvel Two-in-One', 'Vengeance Of The Molecule Man!', '31', '<p>A series that featured the Fantastic Four''s very own Ben Grimm, better known as the Thing, teaming him up with a multitude of other Marvel Heroes. The series was somewhat of a continuation of Thing''s adventures in <a href="../../marvel-feature/49-2515/" rel="nofollow ">Marvel Feature</a>. After 100 issues of Marvel Two-in-One, the series was replaced by Thing''s own solo series, simply called "<a href="../../the-thing/49-3245/" rel="nofollow ">The Thing</a>".</p><h4>Collected Editions</h4><ul><li><a href="https://www.comicvine.com/marvel-masterworks-marvel-two-in-one-1-volume-1/4000-433434/" data-ref-id="4000-433434">Marvel Masterworks: Marvel Two-In-One vol. 1</a> (#1-10)</li><li><a href="/man-thing-by-steve-gerber-the-complete-collection-/4000-502866/" data-ref-id="4000-502866">Man-Thing by Steve Gerber: The Complete Collection Vol. 1</a> (#1)</li><li><a href="https://comicvine.gamespot.com/marvel-two-in-one-epic-collection-cry-monster/4050-112694/">Marvel Two-In-One Epic Collection: Cry Monster</a> (#1-19)</li><li><a href="https://comicvine.gamespot.com/marvel-masterworks-daredevil-11-volume-11/4000-585084/" data-ref-id="4000-585084">Marvel Masterworks: Daredevil Volume 11</a> (#3)</li><li><a href="/guardians-of-the-galaxy-earth-shall-overcome/4050-30359/" data-ref-id="4050-30359">Guardians of the Galaxy: Earth Shall Overcome</a> (#4-5)</li><li><a href="https://comicvine.gamespot.com/guardians-of-the-galaxy-tomorrows-heroes-omnibus/4050-116248/">Guardians of the Galaxy: Tomorrow''s Heroes Omnibus</a> (#4-5, 61-63 &amp; 69)</li><li><a href="/marvel-masterworks-ghost-rider-2-volume-2/4000-821522/" data-ref-id="4000-821522">Marvel Masterworks: Ghost Rider Volume 2</a> (#8)</li><li><a href="https://comicvine.gamespot.com/black-widow-marvel-team-up/4050-125684/">Black Widow: Marvel Team-Up</a> (#10)</li><li><a href="https://comicvine.gamespot.com/marvel-masterworks-marvel-two-in-one-2-volume-2/4000-621669/" data-ref-id="4000-621669">Marvel Masterworks: Marvel Two-In-One vol. 2</a> (#11-20)</li><li><a href="https://comicvine.gamespot.com/marvel-horror-omnibus/4050-121088/">Marvel Horror Omnibus</a> (#11, 18, 33, 41 &amp; 95)</li><li><a href="https://comicvine.gamespot.com/the-son-of-satan-classic/4050-95033/" data-ref-id="4050-95033">The Son of Satan Classic</a> (#14)</li><li><a href="https://comicvine.gamespot.com/morbius-the-living-vampire-omnibus/4050-128226/">Morbius the Living Vampire Omnibus</a> (#15)</li><li><a href="https://comicvine.gamespot.com/morbius-epic-collection-the-end-of-a-living-vampir/4050-136029/">Morbius Epic Collection: The End Of A Living Vampire</a> (#15)</li><li><a href="https://comicvine.gamespot.com/marvel-masterworks-marvel-team-up-5-volume-5/4000-785731/" data-ref-id="4000-785731">Marvel Masterworks: Marvel Team-Up Volume 5</a> (#17)</li><li><a href="https://comicvine.gamespot.com/doctor-strange-lords-of-fear/4050-107359/" data-ref-id="4050-107359">Doctor Strange: Lords of Fear</a> (#18)</li><li><a href="https://comicvine.gamespot.com/tigra-the-complete-collection/4050-123417/">Tigra: The Complete Collection</a> (#19)</li><li><a href="/marvel-masterworks-marvel-two-in-one-3-volume-3/4000-663577/" data-ref-id="4000-663577">Marvel Masterworks: Marvel Two-In-One vol. 3</a> (#21-36)</li><li><a href="/deathlok-the-demolisher-the-complete-collection/4050-77316/" data-ref-id="4050-77316">Deathlok The Demolisher: The Complete Collection</a> (#27 &amp; 54)</li><li><a href="/marvel-masterworks-spider-woman-1-volume-1/4000-505913/" data-ref-id="4000-505913">Marvel Masterworks: Spider-Woman Volume 1</a> (#29-33)</li><li><a href="/skull-the-slayer/4050-81312/" data-ref-id="4050-81312">Skull The Slayer</a> (#35-36)</li><li><a href="https://comicvine.gamespot.com/marvel-masterworks-marvel-two-in-one-4-volume-4/4000-716964/" data-ref-id="4000-716964">Marvel Masterworks: Marvel Two-In-One Volume 4</a> (#37-46)</li><li><a href="/marvel-masterworks-brother-voodoo-1-volume-1/4000-851632/" data-ref-id="4000-851632">Marvel Masterworks: Brother Voodoo Volume 1</a> (#41)</li><li><a href="/marvel-universe-by-john-byrne-omnibus-2-volume-2/4000-694138/" data-ref-id="4000-694138">Marvel Universe by John Byrne Omnibus Volume 2</a> (#43, 50 &amp; 53-55)</li><li><a href="/marvel-masterworks-marvel-two-in-one-5-volume-5/4000-819153/" data-ref-id="4000-819153">Marvel Masterworks: Marvel Two-In-One Volume 5</a> (#47-60)</li><li><a href="https://comicvine.gamespot.com/marvel-universe-by-frank-miller-omnibus/4050-116073/">Marvel Universe by Frank Miller Omnibus</a> (#51)</li><li><a href="https://comicvine.gamespot.com/captain-marvel-ms-marvel-a-hero-is-born/4050-117049/">Captain Marvel: Ms. Marvel: A Hero Is Born</a> (#51)</li><li><a href="https://comicvine.gamespot.com/ms-marvel-epic-collection-the-woman-who-fell-to-ea/4050-118662/">Ms. Marvel Epic Collection: The Woman Who Fell To Earth</a> (#51)</li><li><a href="/moon-knight-epic-collection-bad-moon-rising/4050-77333/" data-ref-id="4050-77333">Moon Knight Epic Collection: Bad Moon Rising</a> (#52)</li><li><a href="https://comicvine.gamespot.com/moon-knight-omnibus-1-volume-1/4000-824088/" data-ref-id="4000-824088">Moon Knight Omnibus Volume 1</a> (#52)</li><li><a href="https://comicvine.gamespot.com/alpha-flight-by-john-byrne-omnibus/4050-98560/" data-ref-id="4050-98560">Alpha Flight By John Byrne Omnibus</a> (#83-84)</li><li><a href="/spider-man-saga-of-the-sandman/4050-27204/" data-ref-id="4050-27204">Spider-Man: Saga of the Sandman</a> (#86)</li><li><a href="/antman-scott-lang/4050-82479/" data-ref-id="4050-82479">Ant-Man: Scott Lang</a> (#87)</li><li><a href="/marvel-masterworks-the-savage-she-hulk-2-volume-2/4000-708135/" data-ref-id="4000-708135">Marvel Masterworks: The Savage She-Hulk Volume 2</a> (#88)</li></ul><h4>Non-U.S. Collected Editions</h4><ul><li><a href="https://comicvine.gamespot.com/coleccionable-marvel-heroes-62-los-4-fantasticos-d/4000-612270/">Coleccionable Marvel Héroes - Los 4 Fantásticos de John Byrne 4</a> (#50) (Spanish)</li><li><a href="https://comicvine.gamespot.com/coleccionable-marvel-heroes-76-la-cosa-secret-wars/4000-612314/">Coleccionable Marvel Héroes - La Cosa: Secret Wars</a> (#50 &amp; #100) (Spanish)</li><li><a href="https://comicvine.gamespot.com/coleccion-frank-miller-el-universo-marvel-segun-fr/4050-105405/">Colección Frank Miller. El Universo Marvel según Frank Miller</a> (#51) (Spanish)</li></ul><p>Issues <a href="https://comicvine.gamespot.com/biblioteca-marvel-la-cosa/4050-41953/" data-ref-id="4050-41953">#1-20 &amp; #22-100</a> have been translated into Spanish.</p>', '1974', '100', '{''icon_url'': ''https://comicvine.gamespot.com/a/uploads/square_avatar/0/4/12538-2696-14067-1-marvel-two-in-one.jpg'', ''medium_url'': ''https://comicvine.gamespot.com/a/uploads/scale_medium/0/4/12538-2696-14067-1-marvel-two-in-one.jpg'', ''screen_url'': ''https://comicvine.gamespot.com/a/uploads/screen_medium/0/4/12538-2696-14067-1-marvel-two-in-one.jpg'', ''screen_large_url'': ''https://comicvine.gamespot.com/a/uploads/screen_kubrick/0/4/12538-2696-14067-1-marvel-two-in-one.jpg'', ''small_url'': ''https://comicvine.gamespot.com/a/uploads/scale_small/0/4/12538-2696-14067-1-marvel-two-in-one.jpg'', ''super_url'': ''https://comicvine.gamespot.com/a/uploads/scale_large/0/4/12538-2696-14067-1-marvel-two-in-one.jpg'', ''thumb_url'': ''https://comicvine.gamespot.com/a/uploads/scale_avatar/0/4/12538-2696-14067-1-marvel-two-in-one.jpg'', ''tiny_url'': ''https://comicvine.gamespot.com/a/uploads/square_mini/0/4/12538-2696-14067-1-marvel-two-in-one.jpg'', ''original_url'': ''https://comicvine.gamespot.com/a/uploads/original/0/4/12538-2696-14067-1-marvel-two-in-one.jpg'', ''image_tags'': ''All Images''}', '[{"id": "Thing"}, {"id": "Mr. Fantasti