INSERT INTO volumes (id, name, firstIssue, publisher, description, startYear, numIssues, image, characters_name, concepts_name, characters_id, concepts_id, numLikes) VALUES ('2697', 'Master of Kung Fu', 'Lair of the Lost!', '31', '<p>Continued from <a href="/special-marvel-edition/4050-2520/" data-ref-id="4050-2520"> Special Marvel Edition</a> #16. In the 1970''s Kung Fu was discovered in America and it became a craze for many years. Enter Shang-Chi, the Master of Kung Fu! After Shang-Chi made his first appearance in Special Marvel Edition issue 15, the series was renamed after the star with issue 17. This stunning and critically acclaimed series lasted for 125 issues, ending in 1983. The series was accompanied by a <a href="https://www.comicvine.com/master-of-kung-fu-annual/4050-28081/">Master of Kung Fu Annual</a> and 4 special <a href="https://www.comicvine.com/giant-size-master-of-kung-fu/4050-2685/">Giant-Size Master of Kung Fu</a> issues. More then 35 years later the series received an <a href="https://comicvine.gamespot.com/master-of-kung-fu/4050-105963/">issue 126</a> published as a one-shot.</p><h4>Collected Editions</h4><ul><li><a href="https://comicvine.gamespot.com/shang-chi-master-of-kung-fu-omnibus-1-volume-1/4000-533502/" data-ref-id="4000-533502">Shang-Chi Master of Kung-Fu Omnibus Volume 1</a> (#17-37)</li><li><a href="/master-of-kung-fu-epic-collection-weapon-of-the-so/4050-109201/" data-ref-id="4050-109201">Master of Kung Fu Epic Collection: Weapon of the Soul</a> (#17-28)</li><li><a href="https://comicvine.gamespot.com/master-of-kung-fu-epic-collection-fight-without-pi/4050-119860/">Master of Kung Fu Epic Collection: Fight Without Pity</a> (#29-53)</li><li><a href="https://comicvine.gamespot.com/shang-chi-master-of-kung-fu-omnibus-2-volume-2/4000-551546/" data-ref-id="4000-551546">Shang-Chi Master of Kung-Fu Omnibus Volume 2</a> (#38-70)</li><li><a href="https://comicvine.gamespot.com/shang-chi-master-of-kung-fu-omnibus-3-volume-3/4000-583726/" data-ref-id="4000-583726">Shang-Chi Master of Kung-Fu Omnibus Volume 3</a> (#71-101)</li><li><a href="https://comicvine.gamespot.com/shang-chi-master-of-kung-fu-omnibus-4-volume-4/4000-626294/" data-ref-id="4000-626294">Shang-Chi Master of Kung-Fu Omnibus Volume 4</a> (#102-125)</li></ul><p><strong>Note:</strong> Although the title on the cover always had the extra line; "The Hands of Shang-Chi", the indica just states "Master of Kung Fu".</p>', '1974', '109', '{''icon_url'': ''https://comicvine.gamespot.com/a/uploads/square_avatar/0/4/12660-2697-14204-1-master-of-kung-fu.jpg'', ''medium_url'': ''https://comicvine.gamespot.com/a/uploads/scale_medium/0/4/12660-2697-14204-1-master-of-kung-fu.jpg'', ''screen_url'': ''https://comicvine.gamespot.com/a/uploads/screen_medium/0/4/12660-2697-14204-1-master-of-kung-fu.jpg'', ''screen_large_url'': ''https://comicvine.gamespot.com/a/uploads/screen_kubrick/0/4/12660-2697-14204-1-master-of-kung-fu.jpg'', ''small_url'': ''https://comicvine.gamespot.com/a/uploads/scale_small/0/4/12660-2697-14204-1-master-of-kung-fu.jpg'', ''super_url'': ''https://comicvine.gamespot.com/a/uploads/scale_large/0/4/12660-2697-14204-1-master-of-kung-fu.jpg'', ''thumb_url'': ''https://comicvine.gamespot.com/a/uploads/scale_avatar/0/4/12660-2697-14204-1-master-of-kung-fu.jpg'', ''tiny_url'': ''https://comicvine.gamespot.com/a/uploads/square_mini/0/4/12660-2697-14204-1-master-of-kung-fu.jpg'', ''original_url'': ''https://comicvine.gamespot.com/a/uploads/original/0/4/12660-2697-14204-1-master-of-kung-fu.jpg'', ''image_tags'': ''All Images''}', '[{"id": "Shang-Chi"}, {"id": "Black Jack Tarr"}, {"id": "Clive Reston"}, {"id": "Sir Denis Nayland Smith"}, {"id": "Leiko Wu"}, {"id": "Fu Manchu"}, {"id": "Melissa Greville"}, {"id": "Fah Lo Suee"}, {"id": "Juliette"}, {"id": "Cat"}, {"id": "Doctor Petrie"}, {"id": "Zaran"}, {"id": "Mia Lessing"}, {"id": "Pavane"}, {"id": "Shockwave"}, {"id": "Ducharme "}, {"id": "Skull-Crusher"}, {"id": "Brynocki"}, {"id": "Peko"}, 