INSERT INTO volumes (id, name, firstIssue, publisher, description, startYear, numIssues, image, characters_name, concepts_name, characters_id, concepts_id, numLikes) VALUES ('2700', 'Power Man', 'Rich man: Iron Man -- Power Man: Thief!', '31', '<p>This series is continued from <a href="/hero-for-hire/4050-2572/" data-ref-id="4050-2572">Hero for Hire </a>issue 16 when it changed its name to Power Man with issue 17. Luke Cage fights criminals in the mean streets of New York City. See how this former Hero for Hire becomes an icon for the regular people. The series continues as <a href="/power-man-and-iron-fist/4050-2959/" data-ref-id="4050-2959">Power Man &amp; Iron Fist </a>with issue 50 and on.</p><h4>Collected Editions</h4><ul><li><a href="https://comicvine.gamespot.com/marvel-masterworks-luke-cage-power-man-1-volume-2/4000-619633/" data-ref-id="4000-619633">Marvel Masterworks: Luke Cage, Power Man Volume 2</a> (#17-31)</li><li><a href="https://comicvine.gamespot.com/luke-cage-epic-collection-retribution/4050-133628/">Luke Cage Epic Collection: Retribution</a> (#17-23)</li><li><a href="/marvel-masterworks-ant-mangiant-man-3-volume-3/4000-673021/" data-ref-id="4000-673021">Marvel Masterworks: Ant-Man/Giant-Man Volume 3</a> (#24-25)</li><li><a href="/power-man-and-iron-fist-epic-collection-heroes-for/4050-83705/" data-ref-id="4050-83705">Power Man and Iron Fist Epic Collection: Heroes For Hire</a> (#48-49)</li><li><a href="/marvel-universe-by-john-byrne-omnibus-1-hc/4000-523259/" data-ref-id="4000-523259">Marvel Universe by John Byrne Omnibus Volume 1</a> (#48-50)</li></ul>', '1974', '33', '{''icon_url'': ''https://comicvine.gamespot.com/a/uploads/square_avatar/0/4/12541-2700-14070-1-power-man.jpg'', ''medium_url'': ''https://comicvine.gamespot.com/a/uploads/scale_medium/0/4/12541-2700-14070-1-power-man.jpg'', ''screen_url'': ''https://comicvine.gamespot.com/a/uploads/screen_medium/0/4/12541-2700-14070-1-power-man.jpg'', ''screen_large_url'': ''https://comicvine.games