INSERT INTO volumes (id, name, firstIssue, publisher, description, startYear, numIssues, image, characters_name, concepts_name, characters_id, concepts_id, numLikes) VALUES ('2733', 'The Joker', 'The Joker''s Double Jeopardy', '10', '<p>In 1975 the Clown Prince Of Crime became the very first villain to gain his own ongoing series. "The Joker" lasted only 9 issues, focused on the Rollicking Rogue''s various misadventures and criminal endeavors. Each issue saw The Joker face not only heroes but fellow villains as well. Decades later the unpublished tenth issue was finally published as a digital exclusive release.</p><h4>Collected Editions</h4><ul><li><a href="//www.comicvine.com/the-joker-the-clown-prince-of-crime/4050-69566/" data-ref-id="4050-69566">The Joker: The Clown Prince of Crime</a></li><li><a href="https://comicvine.gamespot.com/the-joker-the-bronze-age-omnibus/4050-120647/">The Joker: The Bronze Age Omnibus</a> (#1-10)</li></ul>', '1975', '10', '{''icon_url'': ''https://comicvine.gamespot.com/a/uploads/square_avatar/6/67663/7091420-01.jpg'', ''medium_url'': ''https://comicvine.gamespot.com/a/uploads/scale_medium/6/67663/7091420-01.jpg'', ''screen_url'': ''https://comicvine.gamespot.com/a/uploads/screen_medium/6/67663/7091420-01.jpg'', ''screen_large_url'': ''https://comicvine.gamespot.com/a/uploads/screen_kubrick/6/67663/7091420-01.jpg'', ''small_url'': ''https://comicvine.gamespot.com/a/uploads/scale_small/6/67663/7091420-01.jpg'', ''super_url'': ''https://comicvine.gamespot.com/a/uploads/scale_large/6/67663/7091420-01.jpg'', ''thumb_url'': ''https://comicvine.gamespot.com/a/uploads/scale_avatar/6/67663/7091420-01.jpg'', ''tiny_url'': ''https://comicvine.gamespot.com/a/uploads/square_mini/6/67663/7091420-01.jpg'', ''original_url'': ''https://comicvine.gamespot.com/a/uploads/original/6/67663/7091420-01.jpg'', ''image_tags'': ''All Images''}', '[{"id": "Joker"}, {"id": "Tooth"}, {"id": "Southpaw"}, {"id": "Marvin Fargo"}, {"id": "Benny Khiss"}, {"id": "James Gordon"}, {"id": "Black Canary"}, {"id": "Green Arrow"}, {"id": "Nightmare"}, {"id": "Jack"}, {"id": "Elton John"}, {"id": "The Weeper"}, {"id": "Clive Sigerson"}, {"id": "Ten"}, {"id": "Senor Alvarez"}, {"id": "Sandor Cleeves"}, {"id": "Sandy Saturn"}, {"id": "Lex Luthor"}, {"id": "Ace"}, {"id": "Barry Allen"}, {"id": "Queen"}, {"id": "King"}, {"id": "Hal Jordan"}, {"id": "Creeper"}, {"id": "Two-Face"}, {"id": "Scarecrow"}, {"id": "Wonder Woman"}, {"id": "Batman"}, {"id": "Catwoman"}]', '[{"id": "Digital Comic"}, {"id": "DC Explosion and Implosion"}, {"id": "DC Comics Salutes the Bicentennial"}]', '[{"id": 1702}, {"id": 176322}, {"id": 176321}, {"id": 188753}, {"id": 188752}, {"id": 3727}, {"id": 1689}, {"id": 5936}, {"id": 176323}, {"id": 48110}, {"id": 58764}, {"id": 58945}, {"id": 95227}, {"id": 28701}, {"id": 188750}, {"id": 188751}, {"id": 188767}, {"id": 41952}, {"id": 28702}, {"id": 22804}, {"id": 22284}, {"id": 19126}, {"id": 11202}, {"id": 5713}, {"id": 5555}, {"id": 3726}, {"id": 2048}, {"id": 1699}, {"id": 1698}]', '[{"id": 56085}, {"id": 56163}, {"id": 56229}]', '0');
INSERT INTO volumes (id, name, firstIssue, publisher, description, startYear, numIssues, image, characters_name, concepts_name, characters_id, concepts_id, numLikes) VALUES ('2737', 'Richard Dragon, Kung Fu Fighter', 'Coming of a Dragon', '10', '<p>In the mid 1970''s Kung Fu was popular in TV and films and so DC got on board with this martial arts series. Richard Dragon Kung Fu Fighter lasted a reasonable 18 issues before being beaten by the DC Implosion, which claimed 31 titles in the late 1970''s.</p><p>Collected in <a href="https://comicvine.gamespot.com/richard-dragon-kung-fu-fighter-coming-of-the-drago/4050-133796/">Richard Dragon, Kung-Fu Fighter: Coming of the Dragon!</a>.</p>', '1975', '18', '{''icon_url'': ''https://comicvine.gamespot.com/a/uploads/square_avatar/1/14065/282662-2737-121664-1-richard-dragon-kung.jpg'', ''medium_url'': ''https://comicvine.gamespot.com/a/uploads/scale_medium/1/14065/282662-2737-121664-1-richard-dragon-kung.jpg'', ''screen_url'': ''https://comicvine.gamespot.com/a/uploads/screen_medium/1/14065/282662-2737-121664-1-richard-dragon-kung.jpg'', ''screen_large_url'': ''https://comicvine.gamespot.com/a/uploads/screen_kubrick/1/14065/282662-2737-121664-1-richard-dragon-kung.jpg'', ''small_url'': ''https://comicvine.gamespot.com/a/uploads/scale_small/1/14065/282662-2737-121664-1-richard-dragon-kung.jpg'', ''super_url'': ''https://comicvine.gamespot.com/a/uploads/scale_large/1/14065/282662-2737-121664-1-richard-dragon-kung.jpg'', ''thumb_url'': ''https://comicvine.gamespot.com/a/uploads/scale_avatar/1/14065/282662-2737-121664-1-richard-dragon-kung.jpg'', ''tiny_url'': ''https://comicvine.gamespot.com/a/uploads/square_mini/1/14065/282662-2737-121664-1-richard-dragon-kung.jpg'', ''original_url'': ''https://comicvine.gamespot.com/a/uploads/original/1/14065/282662-2737-121664-1-richard-dragon-kung.jpg'', ''image_tags'': ''All Images''}', '[{"id": "Richard Dragon"}, {"id": "Lady Shiva"}, {"id": "Bronze Tiger"}, {"id": "O-Sensei"}, {"id": "Luke Lewis"}, {"id": "Carolyn Woosan"}, {"id": "Professor Ojo"}, {"id": "Dr. Moon"}, {"id": "Slash"}, {"id": "The Swiss"}, {"id": "Sing"}, {"id": "Madame Sun"}, {"id": "Bruce Lee"}, {"id": "Telegram Sam"}, {"id": "The Preying Mantis"}, {"id": "Guano Cravat"}, {"id": "The Axeman"}, {"id": "Viper"}]', '[{"id": "DC Explosion and Implosion"}, {"id": "DC Comics Salutes the Bicentennial"}]', '[{"id": 2221}, {"id": 2222}, {"id": 23535}, {"id": 33079}, {"id": 35019}, {"id": 36098}, {"id": 62055}, {"id": 35339}, {"id": 35742}, {"id": 36099}, {"id": 35340}, {"id": 35561}, {"id": 35606}, {"id": 35640}, {"id": 35711}, {"id": 35790}, {"id": 35246}, {"id": 16771}]', '[{"id": 56163}, {"id": 56229}]', '0');
