INSERT INTO volumes (id, name, firstIssue, publisher, description, startYear, numIssues, image, characters_name, concepts_name, characters_id, concepts_id, numLikes) VALUES ('2746', 'The Champions', 'The World Still Needs... The Champions!', '31', '<p>A new superhero team for the common man! The short-lived, but legendary superhero team known as the Champions, starring a variety of superheroes such as Hercules, Ghost Rider, Iceman, Angel, Dark Star and the Black Widow! The series lasted for only 17 issues. The round-up to the Champions'' story was in Spectacular Spider-Man<a href="https://www.comicvine.com/the-spectacular-spider-man-17-whatever-happened-to/4000-18429/"> issue 17</a> and <a href="https://www.comicvine.com/the-spectacular-spider-man-18-my-friend-my-foe/4000-18511/">issue 18</a>.</p><h4>Collected Editions</h4><ul><li><a href="/champions-classic-1-volume-one/4000-140344/" data-ref-id="4000-140344">The Champions Classic Vol. 1</a> (#1-11)</li><li><a href="https://comicvine.gamespot.com/marvel-masterworks-the-champions-1-volume-1/4000-516959/" data-ref-id="4000-516959">Marvel Masterworks: The Champions Volume 1</a> (#1-17)</li><li><a href="https://comicvine.gamespot.com/champions-classic-the-complete-collection/4050-111662/">Champions Classic: The Complete Collection</a> (#1-17)</li><li><a href="https://comicvine.gamespot.com/the-champions-no-time-for-losers/4050-95208/" data-ref-id="4050-95208">The Champions: No Time For Losers</a> (#1-3 &amp; 14-15)</li><li><a href="/marvel-universe-by-john-byrne-omnibus-1-hc/4000-523259/" data-ref-id="4000-523259">Marvel Universe by John Byrne Omnibus Volume 1</a> (#11-15)</li><li><a href="/marvel-masterworks-ant-mangiant-man-3-volume-3/4000-673021/" data-ref-id="4000-673021">Marvel Masterworks: Ant-Man/Giant-Man Volume 3</a> (#11-13)</li><li><a href="/champions-classic-2-volume-two/4000-140345/" data-ref-id="4000-140345">The Champions Classic Vol. 2</a> (#12-17)</li><li><a href="/super-villains-unite-the-complete-supervillain-tea/4050-80542/" data-ref-id="4050-80542">Super Villains Unite: The Complete Super-Villain Team-Up</a> (#16)</li><li><a href="/marvel-universe-by-john-byrne-omnibus-2-volume-2/4000-694138/" data-ref-id="4000-694138">Marvel Universe by John Byrne Omnibus Volume 2</a> (#17)</li></ul>', '1975', '17', '{''icon_url'': ''https://comicvine.gamespot.com/a/uploads/square_avatar/8/84205/4018334-tn1.jpg'', ''medium_url'': ''https://comicvine.gamespot.com/a/uploads/scale_medium/8/84205/4018334-tn1.jpg'', ''screen_url'': ''https://comicvine.gamespot.com/a/uploads/screen_medium/8/84205/4018334-tn1.jpg'', ''screen_large_url'': ''https://comicvine.gamespot.com/a/uploads/screen_kubrick/8/84205/4018334-tn1.jpg'', ''small_url'': ''https://comicvine.gamespot.com/a/uploads/scale_small/8/84205/4018334-tn1.jpg'', ''super_url'': ''https://comicvine.gamespot.com/a/uploads/scale_large/8/84205/4018334-tn1.jpg'', ''thumb_url'': ''https://comicvine.gamespot.com/a/uploads/scale_avatar/8/84205/4018334-tn1.jpg'', ''tiny_url'': ''https://comicvine.gamespot.com/a/uploads/square_mini/8/84205/4018334-tn1.jpg'', ''original_url'': ''https://comicvine.gamespot.com/a/uploads/original/8/84205/4018334-tn1.jpg'', ''image_tags'': ''All Images''}', '[{"id": "Iceman"}, {"id": "Angel"}, {"id": "Hercules"}, {"id": "Black Widow"}, {"id": "Ghost Rider (Blaze)"}, {"id": "Zarathos"}, {"id": "Darkstar (Petrovna)"}, {"id": "Ivan Petrovitch"}, {"id": "Commissar"}, {"id": "Yuri Petrovich"}, {"id": "Rampage"}, {"id": "Griffin"}, {"id": "Titanium Man"}, {"id": "Pluto"}, {"id": "Black Goliath"}, {"id": "Aphrodite Ourania"}, {"id": "Emerson Bale"}, {"id": "Hippolyta"}, {"id": "Ares"}, {"id": "Swarm"}, {"id": "Dionysus"}, {"id": "Hulk"}, {"id": "Stilt-Man"}, {"id": "Possessor"}, {"id": "Stranger"}, {"id": "Zeus"}, {"id": "Richard Fenster"}, {"id": "Huntsman of Zeus"}, {"id": "Captain Andreyivich"}, {"id": "Eric the Red"}, {"id": "Athena"}, {"id": "Amos Crawley"}, {"id": "Menoetius"}, {"id": "Old Billy"}, {"id": "Lore