INSERT INTO volumes (id, name, firstIssue, publisher, description, startYear, numIssues, image, characters_name, concepts_name, characters_id, concepts_id, numLikes) VALUES ('2759', 'Giant-Size Marvel Triple Action', 'Never Bug a Giant!', '31', NULL, '1975', '2', '{''icon_url'': ''https://comicvine.gamespot.com/a/uploads/square_avatar/0/4/13543-2759-15182-1-giant-size-marvel-tr.jpg'', ''medium_url'': ''https://comicvine.gamespot.com/a/uploads/scale_medium/0/4/13543-2759-15182-1-giant-size-marvel-tr.jpg'', ''screen_url'': ''https://comicvine.gamespot.com/a/uploads/screen_medium/0/4/13543-2759-15182-1-giant-size-marvel-tr.jpg'', ''screen_large_url'': ''https://comicvine.gamespot.com/a/uploads/screen_kubrick/0/4/13543-2759-15182-1-giant-size-marvel-tr.jpg'', ''small_url'': ''https://comicvine.gamespot.com/a/uploads/scale_small/0/4/13543-2759-15182-1-giant-size-marvel-tr.jpg'', ''super_url'': ''https://comicvine.gamespot.com/a/uploads/scale_large/0/4/13543-2759-15182-1-giant-size-marvel-tr.jpg'', ''thumb_url'': ''https://comicvine.gamespot.com/a/uploads/scale_avatar/0/4/13543-2759-15182-1-giant-size-marvel-tr.jpg'', ''tiny_url'': ''https://comicvine.gamespot.com/a/uploads/square_mini/0/4/13543-2759-15182-1-giant-size-marvel-tr.jpg'', ''original_url'': ''https://comicvine.gamespot.com/a/uploads/original/0/4/13543-2759-15182-1-giant-size-marvel-tr.jpg'', ''image_tags'': ''All Images''}', '[{"id": "Captain America"}, {"id": "Doctor Strange"}, {"id": "Hawkeye"}, {"id": "Wasp"}, {"id": "Hank Pym"}, {"id": "Owl"}, {"id": "Daredevil"}, {"id": "Spider-Man"}, {"id": "Scarlet Witch"}, {"id": "Quicksilver"}, {"id": "Captain Marvel"}, {"id": "Thor"}, {"id": "Nightmare"}, {"id": "Nitro"}, {"id": "Black Widow"}, {"id": "Loki"}]', 'NaN', '[{"id": 1442}, {"id": 1456}, {"id": 1475}, {"id": 1502}, {"id": 2247}, {"id": 13908}, {"id": 24694}, {"id": 1443}, {"id": 1466}, {"id": 1467}, {"id": 1472}, {"id": 2268}, {"id": 2646}, {"id": 3160}, {"id": 3200}, {"id": 4324}]', 'NaN', '0');
INSERT INTO volumes (id, name, firstIssue, publisher, description, startYear, numIssues, image, characters_name, concepts_name, characters_id, concepts_id, numLikes) VALUES ('2761', 'Giant-Size Super-Villain Team-Up', 'Encounter at Land''s End!', '31', '<p>A two-part story showing Dr. Doom''s and Submariner''s struggle to form an alliance to rule the world.</p><p>These where specials to the monthly <a href="/super-villain-team-up/4050-2782/" data-ref-id="4050-2782">Super-Villain Team-Up</a> series.</p><p>Collected in <a href="/super-villains-unite-the-complete-supervillain-tea/4050-80542/" data-ref-id="4050-80542">Super Villains Unite: The Complete Super-Villain Team-Up</a>.</p>', '1975', '2', '{''icon_url'': ''https://comicvine.gamespot.com/a/uploads/square_avatar/6/67663/4427950-01.jpg'', ''medium_url'': ''https://comicvine.gamespot.com/a/uploads/scale_medium/6/67663/4427950-01.jpg'', ''screen_url'': ''https://comicvine.gamespot.com/a/uploads/screen_medium/6/67663/4427950-01.jpg'', ''screen_large_url'': ''https://comicvine.gamespot.com/a/uploads/screen_kubrick/6/67663/4427950-01.jpg'', ''small_url'': ''https://comicvine.gamespot.com/a/uploads/scale_small/6/67663/4427950-01.jpg'', ''super_url'': ''https://comicvine.gamespot.com/a/uploads/scale_large/6/67663/4427950-01.jpg'', ''thumb_url'': ''https://comicvine.gamespot.com/a/uploads/scale_avatar/6/67663/4427950-01.jpg'', ''tiny_url'': ''https://comicvine.gamespot.com/a/uploads/square_mini/6/67663/4427950-01.jpg'', ''original_url'': ''https://comicvine.gamespot.com/a/uploads/original/6/67663/4427950-01.jpg'', ''image_tags'': ''All Images''}', '[{"id": "Doctor Doom"}, {"id": "Namor"}, {"id": "Thing"}, {"id": "Spider-Man"}, {"id": "Human Torch"}, {"id": "Mr. Fantastic"}, {"id": "Invisible Woman"}, {"id": "Lockjaw"}, {"id": "Boris"}, {"id": "Diablo"}, {"id": "Valeria"}, {"id": "Living Brain"}, {"id": "Faceless One"}, {"id": "Doomsman"}, {"id": "Werner von Doom"}]', 'NaN', '[{"id": 1468}, {"id": 1476}, {"id": 2114}, {"id": 1443}, {"id": 2120}, {"id": 2151}, {"id": 2190}, {"id": 3534}, {"id": 8108}, {"id": 10242}, {"id": 18250}, {"id": 30091}, {"id": 34294}, {"id": 37900}, {"id": 47841}]', 'NaN', '0');
INSERT INTO volumes (id, name, firstIssue, publisher, description, startYear, numIssues, image, characters_name, concepts_name, characters_id, concepts_id, numLikes) VALUES ('2763', 'Giant-Size X-Men', 'Deadly Genesis!; Call Him...Cyclops; I, the Iceman; The Female of the Species!', '31', '<p>The series that famously introduced the New X-men team in 1975. It was a companion title to the (Uncanny) X-Men series and featured the first original X-Men-story in 5 years. After issue 1 of this series, the X-Men returned in full force in <a href="https://comicvine.gamespot.com/the-x-men-94-the-doomsmith-scenario/4000-15508/">(Uncanny) X-men issue 94</a>.</p><h4>Collected Editions</h4><ul><li><a href="/giantsize-xmen-40th-anniversary/4050-82296/" data-ref-id="4050-82296">Giant-Size X-Men: 40th Anniversary</a> (#1 &amp; 3-4)</li><li><a href="https://comicvine.gamespot.com/xmen-epic-collection-second-genesis/4050-100394/" data-ref-id="4050-100394">X-Men Epic Collection: Second Genesis</a> (#1)</li><li><a href="https://comicvine.gamespot.com/x-men-we-are-the-x-men/4050-35334/">X-Men: We Are the X-Men</a> (#1)</li><li><a href="https://comicvine.gamespot.com/giant-size-x-men-tribute-to-wein-and-cockrum-galle/4050-137986/">Giant-Size X-Men: Tribute To Wein &amp; Cockrum Gallery Edition</a> (#1)</li><li><a href="https://comicvine.gamespot.com/astonishing-x-men-companion/4050-126608/">Astonishing X-Men Companion</a> (#3-4)</li></ul>', '1975', '4', '{''icon_url'': ''https://comicvine.gamespot.com/a/uploads/square_avatar/0/4/13286-2763-14890-1-giant-size-x-men.jpg'', ''medium_url'': ''https://comicvine.gamespot.com/a/uploads/scale_medium/0/4/13286-2763-14890-1-giant-size-x-men.jpg'', ''screen_url'': ''https://comicvine.gamespot.com/a/uploads/screen_medium/0/4/13286-2763-14890-1-giant-size-x-men.jpg'', ''screen_large_url'': ''https://comicvine.gamespot.com/a/uploads/screen_kubrick/0/4/13286-2763-14890-1-giant-size-x-men.jpg'', ''small_url'': ''https://comicvine.gamespot.com/a/uploads/sc