INSERT INTO volumes (id, name, firstIssue, publisher, description, startYear, numIssues, image, characters_name, concepts_name, characters_id, concepts_id, numLikes) VALUES ('2764', 'The Inhumans', 'Spawn of Alien Heat', '31', '<p>From the pages of the Fantastic Four come the Inhumans in their own series! The most uncanny heroes of all! The race known as the Inhumans star in their first own ongoing series. It was a bi-monthly series that lasted for 12 issues.</p><p>Issue <a href="https://comicvine.gamespot.com/biblioteca-marvel-hulk-27/4000-285416/" data-ref-id="4000-285416">#12</a> has been translated into Spanish.</p>', '1975', '12', '{''icon_url'': ''https://comicvine.gamespot.com/a/uploads/square_avatar/8/84205/3542293-inhumans1nm9m103.jpg'', ''medium_url'': ''https://comicvine.gamespot.com/a/uploads/scale_medium/8/84205/3542293-inhumans1nm9m103.jpg'', ''screen_url'': ''https://comicvine.gamespot.com/a/uploads/screen_medium/8/84205/3542293-inhumans1nm9m103.jpg'', ''screen_large_url'': ''https://comicvine.gamespot.com/a/uploads/screen_kubrick/8/84205/3542293-inhumans1nm9m103.jpg'', ''small_url'': ''https://comicvine.gamespot.com/a/uploads/scale_small/8/84205/3542293-inhumans1nm9m103.jpg'', ''super_url'': ''https://comicvine.gamespot.com/a/uploads/scale_large/8/84205/3542293-inhumans1nm9m103.jpg'', ''thumb_url'': ''https://comicvine.gamespot.com/a/uploads/scale_avatar/8/84205/3542293-inhumans1nm9m103.jpg'', ''tiny_url'': ''https://comicvine.gamespot.com/a/uploads/square_mini/8/84205/3542293-inhumans1nm9m103.jpg'', ''original_url'': ''https://comicvine.gamespot.com/a/uploads/original/8/84205/3542293-inhumans1nm9m103.jpg'', ''image_tags'': ''All Images''}', '[{"id": "Karnak"}, {"id": "Gorgon"}, {"id": "Black Bolt"}, {"id": "Medusa"}, {"id": "Triton"}, {"id": "Lockjaw"}, {"id": "Falzon"}, {"id": "Crystal"}, {"id": "Quicksilver"}, {"id": "Leonus"}, {"id": "Iridia"}, {"id": "Maximus"}, {"id": "Stallior"}, {"id": "Skybreaker"}, {"id": "Arides"}, {"id": "Falcona"}, {"id"