INSERT INTO volumes (id, name, firstIssue, publisher, description, startYear, numIssues, image, characters_name, concepts_name, characters_id, concepts_id, numLikes) VALUES ('2765', 'The Invaders', 'Battle over Britain!', '31', '<p><b>The Invaders Volume 1.</b></p><p>Marvel''s redefinition of the heroes from World War Two! Join Captain America, Namor, Bucky, the original Human Torch, Union Jack and Spitfire among others while they fight the axis of evil, such as the Nazi''s and the Japanese.</p><h4>Collected Editions</h4><ul><li>Invaders Classic Vol. 1 (1-9), Vol. 2 (10-21), Vol. 3 (22-23, 25-34), Vol. 4 (35-41)</li><li><a href="https://www.comicvine.com/the-invaders-classic-the-complete-collection-1-vol/4000-456284/" data-ref-id="4000-456284">The Invaders Classic: The Complete Collection Vol. 1</a> (#1-22)</li><li><a href="https://www.comicvine.com/the-invaders-classic-the-complete-collection-2-vol/4000-472288/" data-ref-id="4000-472288">The Invaders Classic: The Complete Collection Vol. 2</a> (#23-41)</li></ul>', '1975', '41', '{''icon_url'': ''https://comicvine.gamespot.com/a/uploads/square_avatar/11/117763/2697107-invaders01.jpg'', ''medium_url'': ''https://comicvine.gamespot.com/a/uploads/scale_medium/11/117763/2697107-invaders01.jpg'', ''screen_url'': ''https://comicvine.gamespot.com/a/uploads/screen_medium/11/117763/2697107-invaders01.jpg'', ''screen_large_url'': ''https://comicvine.gamespot.com/a/uploads/screen_kubrick/11/117763/2697107-invaders01.jpg'', ''small_url'': ''https://comicvine.gamespot.com/a/uploads/scale_small/11/117763/2697107-invaders01.jpg'', ''super_url'': ''https://comicvine.gamespot.com/a/uploads/scale_large/11/117763/2697107-invaders01.jpg'', ''thumb_url'': ''https://comicvine.gamespot.com/a/uploads/scale_avatar/11/117763/2697107-invaders01.jpg'', ''tiny_url'': ''https://comicvine.gamespot.com/a/uploads/square_mini/11/117763/2697107-invaders01.jpg'', ''original_url'': ''https://comicvine.gamespot.com/a/uploads/original/11/117763/2697107-i