INSERT INTO volumes (id, name, firstIssue, publisher, description, startYear, numIssues, image, characters_name, concepts_name, characters_id, concepts_id, numLikes) VALUES ('2766', 'Iron Fist', 'A Duel of Iron!', '31', '<p>The first volume starring Iron Fist in his own ongoing series. The series is perhaps well known for introducing X-men enemy Sabretooth as well as John Byrne''s first X-men work in issue 15 of this series. The series was canceled after issue 15, but not a few month later, Iron Fist got a starring role in the Power Man series, witch became <a href="../../power-man-and-iron-fist/49-2959/" rel="nofollow "> Power Man and Iron Fist</a> after he joined the cast.</p><h4>Collected Editions</h4><ul><li><a href="/iron-fist-epic-collection-the-fury-of-iron-fist/4050-83138/" data-ref-id="4050-83138">Iron Fist Epic Collection: The Fury of Iron Fist</a></li><li><a href="/marvel-universe-by-john-byrne-omnibus-2-volume-2/4000-694138/" data-ref-id="4000-694138">Marvel Universe by John Byrne Omnibus Volume 2</a></li><li><a href="https://comicvine.gamespot.com/xmen-epic-collection-second-genesis/4050-100394/" data-ref-id="4050-100394">X-Men Epic Collection: Second Genesis</a> (#14-15)</li></ul>', '1975', '15', '{''icon_url'': ''https://comicvine.gamespot.com/a/uploads/square_avatar/0/4/14106-2766-15784-1-iron-fist.jpg'', ''medium_url'': ''https://comicvine.gamespot.com/a/uploads/scale_medium/0/4/14106-2766-15784-1-iron-fist.jpg'', ''screen_url'': ''https://comicvine.gamespot.com/a/uploads/screen_medium/0/4/14106-2766-15784-1-iron-fist.jpg'', ''screen_large_url'': ''https://comicvine.gamespot.com/a/uploads/screen_kubrick/0/4/14106-2766-15784-1-iron-fist.jpg'', ''small_url'': ''https://comicvine.gamespot.com/a/uploads/scale_small/0/4/14106-2766-15784-1-iron-fist.jpg'', ''super_url'': ''https://comicvine.gamespot.com/a/uploads/scale_large/0/4/14106-2766-15784-1-iron-fist.jpg'', ''thumb_url'': ''https://comicvine.gamespot.com/a/uploads/scale_avatar/0/4/14106-2766-15784-1-iron-fist.jpg'', ''tiny_url'': ''https://comicvine.gamespot.com/a/uploads/square_mini/0/4/14106-2766-15784-1-iron-fist.jpg'', ''original_url'': ''https://comicvine.gamespot.com/a/uploads/original/0/4/14106-2766-15784-1-iron-fist.jpg'', ''image_tags'': ''All Images''}', '[{"id": "Iron Fist"}, {"id": "Misty Knight"}, {"id": "Steel Serpent"}, {"id": "Colleen Wing"}, {"id": "Ward Meachum"}, {"id": "Jeryn Hogarth"}, {"id": "Rafael Scarfe"}, {"id": "Alan Cavanaugh"}, {"id": "Master Khan"}, {"id": "Angar the Screamer"}, {"id": "Joy Meachum"}, {"id": "Yu-Ti"}, {"id": "Lei Kung"}, {"id": "Henri Sorel"}, {"id": "Chaka"}, {"id": "Golden Tigers"}, {"id": "Bill Hao"}, {"id": "Boomerang"}, {"id": "Jean Grey"}, {"id": "Wrecker"}, {"id": "Khumbala Bey"}, {"id": "Bulldozer"}, {"id": "Thunderball"}, {"id": "Piledriver"}, {"id": "Lee Wing"}, {"id": "Harold Meachum"}, {"id": "Wendell Rand"}, {"id": "Cyclops"}, {"id": "Heather Rand"}, {"id": "Shou-Lao the Undying"}, {"id": "Hassan"}, {"id": "Michael Kramer"}, {"id": "Daredevil"}, {"id": "John Bushmaster"}, {"id": "Heather Glenn"}, {"id": "Triple-Iron"}, {"id": "Sssesthugar"}, {"id": "Merrin"}, {"id": "Blake Tower"}, {"id": "Captain America"}, {"id": "Spider-Man"}, {"id": "Storm"}, {"id": "Iron Man"}, {"id": "Doctor Strange"}, {"id": "Colossus"}, {"id": "Nightcrawler"}, {"id": "Professor X"}, {"id": "Jarvis"}, {"id": "Thing"}, {"id": "Thor"}, {"id": "Sharyd"}, {"id": "Scimitar"}, {"id": "Puppet Master"}, {"id": "Sabretooth"}, {"id": "Lilandra"}, {"id": "Moira MacTaggert"}, {"id": "Banshee"}, {"id": "Wolverine"}, {"id": "John Byrne"}, {"id": "Mary Jane"}, {"id": "Death Sting"}]', 'NaN', '[{"id": 1492}, {"id": 1491}, {"id": 21195}, {"id": 1494}, {"id": 28163}, {"id": 23834}, {"id": 36086}, {"id": 34091}, {"id": 12603}, {"id": 32260}, {"id": 23380}, {"id": 21916}, {"id": 10306}, {"id": 34141}, {"id": 35462}, {"id": 35463}, {"id": 35553}, {"id": 6299}, {"id": 3552}, {"id": 2252}, {"id": 35605}, {"id": 2254}, {"id": 2253}, {"id": 2251}, {"id": 36071}, {"id": 36421}, {"id": 46642}, {"id": 1459}, {"id": 60347}, {"id": 61344}, {"id": 80584}, {"id": 35864}, {"id": 24694}, {"id": 27473}, {"id": 10365}, {"id": 36392}, {"id": 113844}, {"id": 151953}, {"id": 2467}, {"id": 1442}, {"id": 1443}, {"id": 1444}, {"id": 1455}, {"id": 1456}, {"id": 1460}, {"id": 1461}, {"id": 1505}, {"id": 1781}, {"id": 2114}, {"id": 2268}, {"id": 23382}, {"id": 3429}, {"id": 3799}, {"id": 4563}, {"id": 6144}, {"id": 8304}, {"id": 9708}, {"id": 1440}, {"id": 12642}, {"id": 13380}, {"id": 23379}]', 'NaN', '0');
INSERT INTO volumes (id, name, firstIssue, publisher, description, startYear, numIssues, image, characters_name, concepts_name, characters_id, concepts_id, numLikes) VALUES ('2782', 'Super-Villain Team-Up', 'Slayers From the Sea!', '31', '<p>Most of the series starred Dr. Doom teaming up with Namor, the Sub-Mariner, whom the Latverian monarch had bent to his service with promises of assistance for ailing Atlantean people. Von Doom''s schemes brought him into conflict with several of Namor''s foes, including the Tiger Shark and Attuma, but the Avengers, Circus of Crime, the debut of the Shroud, and the Red Skull also appeared to complicate Von Doom''s megalomaniac plans for world domination. In later issues of the series, Von Doom and Magneto became embroiled in a bitter rivalry that led both into conflict with both the Avengers and the Champions of Los Angeles. The last issues of the series focused on the Red Skull''s efforts to recreate the Cosmic Cube with the help of the original Hate-Monger and Arnim Zola.</p><p>The series had two special <a href="/giant-size-super-villain-team-up/4050-2761/" data-ref-id="4050-2761">Giant-Size Super-Villain Team-Up </a>issues.</p><p>The title has been appropriated by comic book fans Chris Stewart and Rob Pickering for their Tumblr podcast, which they indicate is strictly for parody. <em>Super-Villain Team-Up </em>began in 2012, featuring the original <a href="//www.comicvine.com/porcupine/4005-12610/" data-ref-id="4005-12610">Porcupine</a> and the first <a href="//www.comicvine.com/eel-stryke/4005-10312/" data-ref-id="4005-10312">Eel</a> interviewing low tier Marvel super-villains to pay back the <a href="//www.comicvine.com/tinkerer/4005-3144/" data-ref-id="4005-3144">Tinkerer</a> for services rendered. Stewart and Pickering''s use of two inactive characters is apparently a dig at the frequent resurrections that occur in comics.</p><h4>Collected Editions</h4><ul><li><a href="/super-villains-unite-the-complete-supervillain-tea/4050-80542/" data-ref-id="4050-80542">Super Villains Unite: The Complete Super-Villain Team-Up</a> (#1-14 &amp; #16-17)</li><li><a href="https://comicvine.gamespot.com/marvel-masterworks-avengers-16-volume-16/4000-535357/" data-ref-id="4000-535357">Marvel Masterworks: Avengers Volume 16</a> (#9)</li><li><a href="https://comicvine.gamespot.com/marvel-masterworks-the-champions-1-volume-1/4000-516959/" data-ref-id="4000-516959">Marvel Masterworks: The Champions Volume 1</a> (#14)</li><li><a href="https://comicvine.gamespot.com/champions-classic-the-complete-collection/4050-111662/">Champions Classic: The Complete Collection</a> (#14)</li></ul>', '1975', '17', '{''icon_url'': ''https://comicvine.gamespot.com/a/uploads/square_avatar/0/4/13839-2782-15501-1-super-villain-team-u.jpg'', ''medium_url'': ''https://comicvine.gamespot.com/a/uploads/scale_medium/0/4/13839-2782-15501-1-super-villain-team-u.jpg'', ''screen_url'': ''https://comicvine.gamespot.com/a/uploads/screen_medium/0/4/13839-2782-15501-1-super-villain-team-u.jpg'', ''screen_large_url'': ''https://comicvine.gamespot.com/a/uploads/screen_kubrick/0/4/13839-2782-15501-1-super-villain-team-u.jpg'', ''small_url'': ''https://comicvine.gamespot.com/a/uploads/scale_small/0/4/13839-2782-15501-1-super-villain-team-u.jpg'', ''super_url'': ''https://comicvine.gamespot.com/a/uploads/scale_large/0/4/13839-2782-15501-1-super-villain-team-u.jpg'', ''thumb_url'': ''https://comicvine.gamespot.com/a/uploads/scale_avatar/0/4/13839-2782-15501-1-super-villain-team-u.jpg'', ''tiny_url'': ''https://comicvine.gamespot.com/a/uploads/square_mini/0/4/13839-2782-15501-1-super-villain-team-u.jpg'', ''original_url'': ''https://comicvine.gamespot.com/a/uploads/original/0/4/13839-2782-15501-1-super-villain-team-u.jpg'', ''image_tags'': ''All Images''}', '[{"id": "Doctor Doom"}, {"id": "Namor"}, {"id": "Shroud"}, {"id": "Captain America"}, {"id": "Red Skull"}, {"id": "Attuma"}, {"id": "Dr. Jennings"}, {"id": "Tamara Rahn"}, {"id": "Prince Rudolfo