INSERT INTO volumes (id, name, firstIssue, publisher, description, startYear, numIssues, image, characters_name, concepts_name, characters_id, concepts_id, numLikes) VALUES ('2839', 'Green Lantern', 'The Planet of Doomed Men; Menace of the Giant Puppet!', '10', '<figure data-align="right" data-size="medium" data-img-src="https://static.comicvine.com/uploads/original/14/148518/4187013-1983%20-%20green%20lantern%20house%20ad%20%282%29.jpg" data-ref-id="1300-4187013" data-ratio="1.4911463187325" data-width="1073" data-embed-type="image" style="width: 1073px"><a class="fluid-height" style="padding-bottom:149.1%" href="https://static.comicvine.com/uploads/original/14/148518/4187013-1983%20-%20green%20lantern%20house%20ad%20%282%29.jpg" data-ref-id="1300-4187013"><img alt="Promo by Dave Gibbons" src="https://comicvine.gamespot.com/a/uploads/scale_medium/14/148518/4187013-1983%20-%20green%20lantern%20house%20ad%20%282%29.jpg" srcset="https://comicvine.gamespot.com/a/uploads/original/14/148518/4187013-1983%20-%20green%20lantern%20house%20ad%20%282%29.jpg 1073w, https://comicvine.gamespot.com/a/uploads/scale_super/14/148518/4187013-1983%20-%20green%20lantern%20house%20ad%20%282%29.jpg 960w, https://comicvine.gamespot.com/a/uploads/scale_medium/14/148518/4187013-1983%20-%20green%20lantern%20house%20ad%20%282%29.jpg 643w" sizes="(max-width: 643px) 100vw, 643px" data-width="643"></a><figcaption>Promo by Dave Gibbons</figcaption></figure><p>Preceded by <a href="https://comicvine.gamespot.com/green-lantern/4050-25944/" data-ref-id="4050-25944">Volume 1</a>.</p><p>Continued in <a href="https://comicvine.gamespot.com/the-green-lantern-corps/4050-3600/" data-ref-id="4050-3600">Green Lantern Corps Volume 1</a>.</p><p><ins><a href="/green-lantern/4050-25944/" data-ref-id="4050-25944">Volume 1</a></ins> was centered around <a href="/alan-scott/4005-12663/" data-ref-id="4005-12663">Alan Scott</a>. Although the volumes share the names the Green Lanterns had completely different powers and origins.</p><p><ins>Volume 2</ins> featured <a href="/hal-jordan/4005-11202/" data-ref-id="4005-11202">Hal Jordan</a>. He debuted in Showcase #22 in 1959. This series would include the first appearances of <a href="/sinestro/4005-10448/" data-ref-id="4005-10448">Sinestro</a>, <a href="/guy-gardner/4005-1791/" data-ref-id="4005-1791">Guy Gardner</a>, and <a href="/john-stewart/4005-10451/" data-ref-id="4005-10451">John Stewart</a>. For several years during the middle of this volume''s publication, <a href="/green-arrow/4005-5936/" data-ref-id="4005-5936">Green Arrow</a> would be given a co-starring role and cover credit (issues #76- 122). The series then changed its cover title back to <em>Green Lantern</em>, which lasted up to issue #200. Then the series changed its cover title again to<em> Green Lantern Corps</em>, which lasted five issue before the series became officially<em> <a href="/the-green-lantern-corps/4050-3600/" data-ref-id="4050-3600">Green Lantern Corps</a></em> beginning with issue #206.</p><h4>Writers</h4><ul><li><a href="/john-broome/4040-48152/" data-ref-id="4040-48152">John Broome</a> #1-16, 18-22, 24, 27, 29-31, 39-40, 44-47, 49-55, 59, 66, 69-71, 75, 87-89, 184</li><li><a href="/gardner-fox/4040-41171/" data-ref-id="4040-41171">Gardner Fox</a> #16-17, 21-23, 25-29, 32-38, 41-44, 46, 48, 50, 56-58, 60, 62, 65, 67</li><li>Mike Friedrich #61, 73-74</li><li><a href="/dennis-oneil/4040-40861/" data-ref-id="4040-40861">Dennis O''Neil</a> #63-64, 68, 72, 76-87, 89-100, 102-106, 108-129</li><li><a href="/elliot-s-maggin/4040-42850/" data-ref-id="4040-42850">Elliot S! Maggin</a> #87, 100</li><li>Frank McGinty #101</li><li>Bob Rozakis #107, 130, 159-160</li><li>Cary Burkett #107-110</li><li><a href="/len-wein/4040-41457/" data-ref-id="4040-41457">Len Wein</a> #128, 172-183, 185-186</li><li>Bob Toomey #130-132</li><li>Mike W. Barr #131, 154, 156-165</li><li>Paul Kupperberg #132, 148-149, 151-158, 181, 187</li><li>Jack C. Harris #132, 168-169</li><li><a href="/marv-wolfman/4040-41478/" data-ref-id="4040-41478">Marv Wolfman</a> #133-153</li><li>Laurie Sutton #133-147 (Adam Strange features)</li><li>Roy Thomas #138-139</li><li>Dan Mishkin #152-153</li><li>Gary Cohn #152-153, 170</li><li>Robin Snyder #161, 171</li><li><a href="/kurt-busiek/4040-41741/" data-ref-id="4040-41741">Kurt Busiek</a> #162, 185</li><li>Todd Klein #162-167, 171-172, 179-180, 189-190</li><li><a href="/joey-cavalieri/4040-41787/" data-ref-id="4040-41787">Joey Cavalieri</a> #166-169, 171, 173, 182-183</li><li><a href="/keith-giffen/4040-6536/" data-ref-id="4040-6536">Keith Giffen</a> #171</li><li>Mike Baron #187</li><li><a href="/alan-moore/4040-40382/" data-ref-id="4040-40382">Alan Moore</a> #188 (back-up story)</li><li><a href="/steve-englehart/4040-42211/" data-ref-id="4040-42211">Steve Englehart</a> #188-205</li></ul><h2>Collected Editions</h2><h3>The Silver Age</h3><p>Actual collection</p><table data-max-width="true"><thead><tr><th scope="col">TP</th><th scope="col">Issues</th><th scope="col">Omnibus</th><th scope="col">Issues</th></tr></thead><tbody><tr><td><a href="https://comicvine.gamespot.com/green-lantern-the-silver-age-1-volume-one/4000-552137/" data-ref-id="4000-552137">Vol. 1</a></td><td>1-9</td><td><a href="https://comicvine.gamespot.com/green-lantern-the-silver-age-omnibus-1-volume-1/4000-582499/" data-ref-id="4000-582499">Vol. 1</a></td><td>1-35</td></tr><tr><td><a href="https://comicvine.gamespot.com/green-lantern-the-silver-age-2-volume-two/4000-636344/" data-ref-id="4000-636344">Vol. 2</a></td><td>10-22</td><td> </td><td> </td></tr><tr><td><a href="/green-lantern-the-silver-age-3-volume-three/4000-666782/" data-ref-id="4000-666782">Vol. 3</a></td><td>23-35</td><td> </td><td> </td></tr><tr><td><a href="/green-lantern-the-silver-age-4-volume-four/4000-720046/" data-ref-id="4000-720046">Vol. 4</a></td><td>36-48</td><td><a href="/green-lantern-the-silver-age-omnibus-2-volume-2/4000-664265/" data-ref-id="4000-664265">Vol. 2</a></td><