INSERT INTO volumes (id, name, firstIssue, publisher, description, startYear, numIssues, image, characters_name, concepts_name, characters_id, concepts_id, numLikes) VALUES ('2860', 'The Incredible Hulk Annual', 'A Refuge Divided!', '31', '<p>Although there were twenty numbered annuals, from 1997-1994, five more annuals and 1 team-up with <a href="/x-man/4005-15051/" data-ref-id="4005-15051">X-Man</a> were released, with unique titles;</p><ul><li><a href="//www.comicvine.com/the-incredible-hulk-annual-97/4050-60432/" data-ref-id="4050-60432">The Incredible Hulk ''97</a></li><li><a href="//www.comicvine.com/the-incredible-hulk-and-sub-mariner-annual-98/4050-60434/" data-ref-id="4050-60434">Hulk / Sub-Mariner ''98</a></li><li><a href="/x-man-hulk-annual-98/4050-28192/" data-ref-id="4050-28192">X-Man / Hulk ''98</a> (<a href="/x-man-annual-96/4050-18050/" data-ref-id="4050-18050">X-Man Annual</a>)</li><li><a href="//www.comicvine.com/hulk-annual-1999/4050-58522/" data-ref-id="4050-58522">Hulk 1999</a></li><li><a href="//www.comicvine.com/the-incredible-hulk-annual-2000/4050-60435/" data-ref-id="4050-60435">Hulk 2000</a></li><li><a href="/incredible-hulk-annual-2001/4050-39930/" data-ref-id="4050-39930">Incredible Hulk 2001</a></li></ul><h4>Collected Editions</h4><ul><li><a href="https://comicvine.gamespot.com/inhumans-beware-the-inhumans/4050-107505/" data-ref-id="4050-107505">Inhumans: Beware the Inhumans</a> (#1)</li><li><a href="https://comicvine.gamespot.com/incredible-hulk-epic-collection-the-leader-lives/4050-114890/">Incredible Hulk Epic Collection: The Leader Lives</a> (#1)</li><li><a href="/guardians-of-the-galaxy-solo-classic-omnibus/4050-85759/" data-ref-id="4050-85759">Guardians of the Galaxy Solo Classic Omnibus</a> (#5)</li><li><a href="/marvel-masterworks-the-incredible-hulk-13-volume-1/4000-718774/" data-ref-id="4000-718774">Marvel Masterworks: The Incredible Hulk Volume 13</a> (#6)</li><li><a href="https://www.comicvine.com/xmen-vs-hulk/4050-73770/" da