INSERT INTO volumes (id, name, firstIssue, publisher, description, startYear, numIssues, image, characters_name, concepts_name, characters_id, concepts_id, numLikes) VALUES ('2863', 'Marvel Team-Up Annual', 'The Lords of Light and Darkness!', '31', '<p>Annuals to the first Marvel Team-Up series. These special double-sized issues brought some of the greates heroes together. Many years later, one single team up was published in 1997, and in 1998 most of the Annuals produced by Marvel were Team-Ups;</p><ul><li><a href="/daredevildeadpool-annual-97/4050-26448/" data-ref-id="4050-26448">Daredevil / Deadpool ''97</a></li><li><a href="//www.comicvine.com/silver-surfer-thor-annual-98/4050-39906/" data-ref-id="4050-39906">Silver Surfer / Thor ''98</a></li><li><a href="//www.comicvine.com/captain-america-98/4050-60452/" data-ref-id="4050-60452">Captain America / Citizen V ''98</a></li><li><a href="//www.comicvine.com/cable-machine-man-annual-98/4050-18365/" data-ref-id="4050-18365">Cable / Machine Man ''98</a></li><li><a href="/deadpooldeath-annual-98/4050-18606/" data-ref-id="4050-18606">Deadpool / Death ''98</a></li><li><a href="/heroes-for-hire-quicksilver-annual-98/4050-19807/" data-ref-id="4050-19807">Heroes for Hire / Quicksilver ''98</a></li><li><a href="/alpha-flight-inhumans-annual-98/4050-25658/" data-ref-id="4050-25658">Alpha Flight / Inhumans ''98</a></li><li><a href="/machine-manbastion-annual-98/4050-26009/" data-ref-id="4050-26009">Machine Man / Bastion ''98</a></li><li><a href="//www.comicvine.com/x-mendr-doom-annual-98/4050-26316/" data-ref-id="4050-26316">X-Men / Dr. Doom ''98</a></li><li><a href="/x-man-hulk-annual-98/4050-28192/" data-ref-id="4050-28192">X-Man / Hulk ''98</a></li><li><a href="//www.comicvine.com/avengers-squadron-supreme-annual-98/4050-30632/" data-ref-id="4050-30632">Avengers / Squadron Supreme ''98</a></li><li><a href="//www.comicvine.com/x-force-champions-annual-98/4050-34173/" data-ref-id="4050-34173">X-Force / Champions ''98</a></li><li><a href="/peter-parker-spider-man-elektra-annual-98/4050-39918/" data-ref-id="4050-39918">Peter Parker: Spider-Man / Elektra ''98</a></li><li><a href="//www.comicvine.com/the-incredible-hulk-and-sub-mariner-annual-98/4050-60434/" data-ref-id="4050-60434">The Incredible Hulk / Sub-Mariner ''98</a></li><li><a href="//www.comicvine.com/generation-x-annual-98/4050-60445/" data-ref-id="4050-60445">Generation X / Dracula ''98</a></li><li><a href="//www.comicvine.com/uncanny-x-men-fantastic-four-annual-98/4050-30468/" data-ref-id="4050-30468">Uncanny X-Men / Fantastic Four ''98</a></li><li><a href="//www.comicvine.com/iron-man-captain-america-annual-98/4050-30391/" data-ref-id="4050-30391">Iron Man / Captain America ''98</a></li></ul><h4>Collected Editions</h4><ul><li><a href="https://comicvine.gamespot.com/xmen-epic-collection-second-genesis/4050-100394/" data-ref-id="4050-100394">X-Men Epic Collection: Second Genesis</a> (#1)</li><li><a href="https://comicvine.gamespot.com/luke-cage-avenger/4050-92377/" data-ref-id="4050-92377">Luke Cage: Avenger</a> (#4)</li><li><a href="https://comicvine.gamespot.com/marvel-universe-by-frank-miller-omnibus/4050-116073/">Marvel Universe by Frank Miller Omnibus</a> (#4)</li><li><a href="https://comicvine.gamespot.com/moon-knight-omnibus-1-volume-1/4000-824088/" data-ref-id="4000-824088">Moon Knight Omnibus Volume 1</a> (#4)</li><li><a href="https://comicvine.gamespot.com/cloak-and-dagger-shadows-and-light/4050-98729/" data-ref-id="4050-98729">Cloak and Dagger: Shadows and Light</a> (#6)</li><li><a href="https://comicvine.gamespot.com/new-mutants-epic-collection-renewal/4050-99448/" data-ref-id="4050-99448">New Mutants Epic Collection: Renewal</a> (#6)</li><li><a href="https://comicvine.gamespot.com/cloak-and-dagger-omnibus/4050-130070/">Cloak and Dagger Omnibus</a> (#6)</li><li><a href="/the-amazing-spider-man-the-complete-alien-costume-/4000-461312/" data-ref-id="4000-461312">The Amazing Spider-Man: The Complete Alien Costume Saga Book 1</a> (#7)</li></ul><h4>Non-U.S. Collected Editions</h4><ul><li><a href="https://comicvine.gamespot.com/coleccion-frank-miller-el-universo-marvel-segun-fr/4050-105405/">Colección Frank Miller. El Universo Marvel según Frank Miller</a> (#4) (Spanish)</li><li><a href="https://comicvine.gamespot.com/coleccionable-marvel-heroes-6-spiderman-integral-f/4000-612211/" data-ref-id="4000-612211">Coleccionable Marvel Héroes: Spiderman: Integral Frank Miller </a>(#4) (Spanish)</li></ul><p>Translated into <a href="https://comicvine.gamespot.com/spiderman-marvel-team-up/4050-43280/" data-ref-id="4050-43280">Spanish</a>.</p>', '1976', '7', '{''icon_url'': ''https://comicvine.gamespot.com/a/uploads/square_avatar/11/117763/2432227-marvelteam_upannual1.jpg'', ''medium_url'': ''https://comicvine.gamespot.com/a/uploads/scale_medium/11/117763/2432227-marvelteam_upannual1.jpg'', ''screen_url'': ''https://comicvine.gamespot.com/a/uploads/screen_medium/11/117763/2432227-marvelteam_upannual1.jpg'', ''screen_large_url'': ''https://comicvine.gamespot.com/a/uploads/screen_kubrick/11/117763/2432227-marvelteam_upannual1.jpg'', ''small_url'': ''https://comicvine.gamespot.com/a/uploads/scale_small/11/117763/2432227-marvelteam_upannual1.jpg'', ''super_url'': ''https://comicvine.gamespot.com/a/uploads/scale_large/11/117763/2432227-marvelteam_upannual1.jpg'', ''thumb_url'': ''https://comicvine.gamespot.com/a/uploads/scale_avatar/11/117763/2432227-marvelteam_upannual1.jpg'', ''tiny_url'': ''https://comicvine.gamespot.com/a/uploads/square_mini/11/117763/2432227-marvelteam_upannual1.jpg'', ''original_url'': ''https://comicvine.gamespot.com/a/uploads/original/11/117763/2432227-marvelteam_upannual1.jpg'', ''image_tags'': ''All Images''}', '[{"id": "Spider-Man"}, {"id": "Mr. Fantastic"}, {"id": "Robbie Robertson"}, {"id": "Aunt May"}, {"id": "Hulk"}, {"id": "Iron Fist"}, {"id": "Crimson Dynamo (Bukharin)"}, {"id": "Luke Cage"}, {"id": "Indiana Jones"}, {"id": "Marrina"}, {"id": "Black Mamba"}, {"id": "N