INSERT INTO volumes (id, name, firstIssue, publisher, description, startYear, numIssues, image, characters_name, concepts_name, characters_id, concepts_id, numLikes) VALUES ('2865', 'Marvel Two-in-One Annual', 'Their Name Is Legion!', '31', '<p>Annual series to the Thing''s starring title, <a href="/marvel-two-in-one/4050-2696/" data-ref-id="4050-2696">Marvel Two-in-One</a>.</p><h4>Collected Editions</h4><ul><li><a href="https://comicvine.gamespot.com/marvel-masterworks-marvel-two-in-one-2-volume-2/4000-621669/" data-ref-id="4000-621669">Marvel Masterworks: Marvel Two-In-One vol. 2</a> (#1)</li><li><a href="/guardians-of-the-galaxy-solo-classic-omnibus/4050-85759/" data-ref-id="4050-85759">Guardians of the Galaxy Solo Classic Omnibus</a> (#2)</li><li><a href="https://comicvine.gamespot.com/gamora-guardian-of-the-galaxy/4050-94272/" data-ref-id="4050-94272">Gamora: Guardian of the Galaxy</a> (#2)</li><li><a href="https://comicvine.gamespot.com/marvel-masterworks-avengers-17-volume-17/4000-613795/" data-ref-id="4000-613795">Marvel Masterworks: Avengers Volume 17</a> (#2)</li><li><a href="https://comicvine.gamespot.com/the-thanos-wars-infinity-origin/4050-118000/">The Thanos Wars: Infinity Origin</a> (#2)</li><li><a href="https://comicvine.gamespot.com/marvel-masterworks-marvel-two-in-one-4-volume-4/4000-716964/" data-ref-id="4000-716964">Marvel Masterworks: Marvel Two-In-One Volume 4</a> (#2-3)</li><li><a href="/marvel-masterworks-marvel-two-in-one-5-volume-5/4000-819153/" data-ref-id="4000-819153">Marvel Masterworks: Marvel Two-In-One Volume 5</a> (#4)</li></ul><p>Translated into <a href="https://comicvine.gamespot.com/biblioteca-marvel-la-cosa/4050-41953/" data-ref-id="4050-41953">Spanish</a>.</p>', '1976', '7', '{''icon_url'': ''https://comicvine.gamespot.com/a/uploads/square_avatar/0/4/14228-2865-15916-1-marvel-two-in-one-an.jpg'', ''medium_url'': ''https://comicvine.gamespot.com/a/uploads/scale_medium/0/4/14228-2865-15916-1-marvel-two-in-one-an.jpg'', ''screen_ur