INSERT INTO volumes (id, name, firstIssue, publisher, description, startYear, numIssues, image, characters_name, concepts_name, characters_id, concepts_id, numLikes) VALUES ('2870', 'The Spectacular Spider-Man', 'Twice Stings the Tarantula!', '31', '<p>The second monthly Spider-Man series and the second most popular volume next to the Amazing Spider-Man that started back in the 1970''s. The cover-title started out as "<em>Peter Parker: The Spectacular Spider-Man</em>" (<a href="https://comicvine.gamespot.com/peter-parker-the-spectacular-spider-man/4050-139754/" data-ref-id="4050-139754">and became the indicia title for a few years mid-run</a>), but the "Peter Parker" part was dropped with issue 134. The comic lasted until 1998 for a total of 263 issues. A second volume named <em><a href="/spectacular-spider-man/4050-11069/" data-ref-id="4050-11069">Spectacular Spider-Man</a></em> started in 2003.</p><p>To see the annuals associated with this title <em><a href="/the-spectacular-spider-man-annual/4050-3012/" data-ref-id="4050-3012">The Spectacular Spider-Man Annual</a></em>.</p><h4>Collected Editions</h4><ul><li><a href="https://comicvine.gamespot.com/marvel-masterworks-the-spectacular-spider-man-1-vo/4000-606630/" data-ref-id="4000-606630">Marvel Masterworks: The Spectacular Spider-Man Volume 1</a> (#1-15)</li><li><a href="https://comicvine.gamespot.com/amazing-spider-man-epic-collection-the-goblin-live/4050-119744/">Amazing Spider-Man Epic Collection: The Goblin Lives</a> (#1-2)</li><li><a href="https://comicvine.gamespot.com/morbius-the-living-vampire-omnibus/4050-128226/">Morbius the Living Vampire Omnibus</a> (#6-8 &amp; 38)</li><li><a href="https://comicvine.gamespot.com/morbius-epic-collection-the-end-of-a-living-vampir/4050-136029/">Morbius Epic Collection: The End Of A Living Vampire</a> (#6-8 &amp; 38)</li><li><a href="https://comicvine.gamespot.com/marvel-masterworks-the-champions-1-volume-1/4000-516959/" data-ref-id="4000-516959">Marvel Masterworks: The Champions Volume 1</a> (#17-18)</li><li><a href="https://comicvine.gamespot.com/champions-classic-the-complete-collection/4050-111662/">Champions Classic: The Complete Collection</a> (#17-18)</li><li><a href="/moon-knight-epic-collection-bad-moon-rising/4050-77333/" data-ref-id="4050-77333">Moon Knight Epic Collection: Bad Moon Rising</a> (#22-23)</li><li><a href="https://comicvine.gamespot.com/moon-knight-omnibus-1-volume-1/4000-824088/" data-ref-id="4000-824088">Moon Knight Omnibus Volume 1</a> (#22-23)</li><li><a href="https://comicvine.gamespot.com/spider-man-the-original-clone-saga/4050-41275/">Spider-Man: The Original Clone Saga</a> (#25-31, 149 &amp; 162-163)</li><li><a href="https://comicvine.gamespot.com/marvel-universe-by-frank-miller-omnibus/4050-116073/">Marvel Universe by Frank Miller Omnibus</a> (#27-28)</li><li><a href="/marvel-masterworks-the-spectacular-spider-man-3-vo/4000-772344/" data-ref-id="4000-772344">Marvel Masterworks: The Spectacular Spider-Man Volume 3</a> (#32-42)</li><li><a href="https://comicvine.gamespot.com/fantastic-fourspider-man-classic/4050-41406/">Fantastic Four/Spider-Man Classic</a> (#42)</li><li><a href="https://comicvine.gamespot.com/marvel-masterworks-the-spectacular-spider-man-4-vo/4000-907536/" data-ref-id="4000-907536">Marvel Masterworks: The Spectacular Spider-Man Volume 4</a> (#43-55)</li><li><a href="https://comicvine.gamespot.com/spider-man-by-john-byrne-omnibus/4050-121104/">Spider-Man By John Byrne Omnibus</a> (#58)</li><li><a href="https://comicvine.gamespot.com/cloak-and-dagger-shadows-and-light/4050-98729/" data-ref-id="4050-98729">Cloak and Dagger: Shadows and Light</a> (#64, 69-70, 81-82 &amp; 94-96)</li><li><a href="https://comicvine.gamespot.com/cloak-and-dagger-omnibus/4050-130070/">Cloak and Dagger Omnibus</a> (#64, 69-70, 81-82 &amp; 94-96)</li><li><a href="https://comicvine.gamespot.com/the-punisher-back-to-the-war-omnibus/4050-104072/" data-ref-id="4050-104072">The Punisher: Back To the War Omnibus</a> (#