INSERT INTO volumes (id, name, firstIssue, publisher, description, startYear, numIssues, image, characters_name, concepts_name, characters_id, concepts_id, numLikes) VALUES ('2873', 'Super Heroes Album', NULL, '2378', '<p>Title changed from <a href="/super-heroes/4050-28253/" data-ref-id="4050-28253"> Super Heroes</a> to Super Heroes Album starting with issue #3.</p>', '1976', '17', '{''icon_url'': ''https://comicvine.gamespot.com/a/uploads/square_avatar/0/4/42426-2873-48346-1-super-heroes-album.jpg'', ''medium_url'': ''https://comicvine.gamespot.com/a/uploads/scale_medium/0/4/42426-2873-48346-1-super-heroes-album.jpg'', ''screen_url'': ''https://comicvine.gamespot.com/a/uploads/screen_medium/0/4/42426-2873-48346-1-super-heroes-album.jpg'', ''screen_large_url'': ''https://comicvine.gamespot.com/a/uploads/screen_kubrick/0/4/42426-2873-48346-1-super-heroes-album.jpg'', ''small_url'': ''https://comicvine.gamespot.com/a/uploads/scale_small/0/4/42426-2873-48346-1-super-heroes-album.jpg'', ''super_url'': ''https://comicvine.gamespot.com/a/uploads/scale_large/0/4/42426-2873-48346-1-super-heroes-album.jpg'', ''thumb_url'': ''https://comicvine.gamespot.com/a/uploads/scale_avatar/0/4/42426-2873-48346-1-super-heroes-album.jpg'', ''tiny_url'': ''https://comicvine.gamespot.com/a/uploads/square_mini/0/4/42426-2873-48346-1-super-heroes-album.jpg'', ''original_url'': ''https://comicvine.gamespot.com/a/uploads/original/0/4/42426-2873-48346-1-super-heroes-album.jpg'', ''image_tags'': ''All Images''}', '[{"id": "Superman"}, {"id": "Hal Jordan"}, {"id": "Green Arrow"}, {"id": "Batman"}, {"id": "Saturn Girl"}, {"id": "Brainiac 5"}, {"id": "Wonder Woman"}, {"id": "Karate Kid"}, {"id": "Black Canary"}, {"id": "Hawkwoman"}, {"id": "Chameleon Boy"}, {"id": "Aquaman"}, {"id": "Phantom Girl"}, {"id": "Katar Hol"}, {"id": "Red Tornado"}, {"id": "Sun Boy"}, {"id": "Colossal Boy"}, {"id": "Ultra Boy"}, {"id": "Sensor Girl"}, {"id": "Barry Allen"}, {"id": "Mon-El"}, {"id": "Shrinking Violet"}, {"