INSERT INTO volumes (id, name, firstIssue, publisher, description, startYear, numIssues, image, characters_name, concepts_name, characters_id, concepts_id, numLikes) VALUES ('2884', 'Black Lightning', 'Black Lightning', '10', '<figure data-align="right" data-size="small" data-img-src="https://static.comicvine.com/uploads/original/14/148518/2959667-black%20lightnng%20ad.jpg" data-ref-id="1300-2959667" data-ratio="1.4752136752137" data-width="585" data-embed-type="image" style="width: 585px"><a class="fluid-height" style="padding-bottom:147.5%" href="https://static.comicvine.com/uploads/original/14/148518/2959667-black%20lightnng%20ad.jpg" data-ref-id="1300-2959667"><img alt="No Caption Provided" src="https://comicvine.gamespot.com/a/uploads/scale_small/14/148518/2959667-black%20lightnng%20ad.jpg" srcset="https://comicvine.gamespot.com/a/uploads/original/14/148518/2959667-black%20lightnng%20ad.jpg 585w, https://comicvine.gamespot.com/a/uploads/scale_small/14/148518/2959667-black%20lightnng%20ad.jpg 433w" sizes="(max-width: 433px) 100vw, 433px" data-width="433"></a></figure><p>Black Lighting was the creation of writer Tony Isabella and artist Trevor Von Eeden. Originally DC planned to have their first ever black headlining character be "The Black Bomber", a black hero who was secretly a white racist. Thankfully, the project fell through when the editor left and writer Tony Isabella was able to introduce his Black Lightning character that he had been working on and the project was handed over to him.</p><p>Isabella handed over to book to Denny O''Neil after the 10th issue, but the book was canceled after #11. Black Lightning next went on to become a back-up feature in <em>Detective Comics</em>.</p><p>Note: This series was implemented as part of the <a href="/dc-explosion-and-implosion/4015-56163/" data-ref-id="4015-56163">DC Explosion,</a> but was subsequently cancelled in what became known as the DC Implosion.</p><p>Collected in <a href="/black-lightning-1-volume-1/4000-523220/" data-ref-id="4000-523220">Black Lightning Volume 1</a>.</p>', '1977', '11', '{''icon_url'': ''https://comicvine.gamespot.com/a/uploads/square_avatar/0/4/15528-2884-17309-1-black-lightning.jpg'', ''medium_url'': ''https://comicvine.gamespot.com/a/uploads/scale_medium/0/4/15528-2884-17309-1-black-lightning.jpg'', ''screen_url'': ''https://comicvine.gamespot.com/a/uploads/screen_medium/0/4/15528-2884-17309-1-black-lightning.jpg'', ''screen_large_url'': ''https://comicvine.gamespot.com/a/uploads/screen_kubrick/0/4/15528-2884-17309-1-black-lightning.jpg'', ''small_url'': ''https://comicvine.gamespot.com/a/uploads/scale_small/0/4/15528-2884-17309-1-black-lightning.jpg'', ''super_url'': ''https://comicvine.gamespot.com/a/uploads/scale_large/0/4/15528-2884-17309-1-black-lightning.jpg'', ''thumb_url'': ''https://comicvine.gamespot.com/a/uploads/scale_avatar/0/4/15528-2884-17309-1-black-lightning.jpg'', ''tiny_url'': ''https://comicvine.gamespot.com/a/uploads/square_mini/0/4/15528-2884-17309-1-black-lightning.jpg'', ''original_url'': ''https://comicvine.gamespot.com/a/uploads/original/0/4/15528-2884-17309-1-black-lightning.jpg'', ''image_tags'': ''All Images''}', '[{"id": "Black Lightning"}, {"id": "Bill Henderson"}, {"id": "Whale"}, {"id": "Peter Gambi"}, {"id": "Lynn Stewart"}, {"id": "Two-Bits"}, {"id": "Macnair Chapin"}, {"id": "Superman"}, {"id": "Jimmy Olsen"}, {"id": "Meltdown"}, {"id": "Jim Corrigan"}, {"id": "Syonide"}, {"id": "Earl Clifford"}, {"id": "Joey Toledo"}, {"id": "Aquaman"}, {"id": "Batman"}, {"id": "Barbara Hannah"}, {"id": "Alvin Pierce"}, {"id": "Green Arrow"}, {"id": "Langford Terrill"}, {"id": "Merlyn"}, {"id": "Talia al Ghul"}, {"id": "Trickster (Jesse)"}]', '[{"id": "DC Explosion and Implosion"}]', '[{"id": 10994}, {"id": 12930}, {"id": 34795}, {"id": 71654}, {"id": 51579}, {"id": 190977}, {"id": 71655}, {"id": 1807}, {"id": 3213}, {"id": 32123}, {"id": 106511}, {"id": 47260}, {"id": 71656}, {"id": 71653}, {"id": 2357}, {"id": 1699}, {"id": 170570}, {"id": 118365}, {"id": 5936}, {"id": 47131}, {"id": 2532}, {"id": 4917}, {"id": 10460}]', '[{"id": 56163}]', '0');
INSERT INTO volumes (id, name, firstIssue, publisher, description, startYear, numIssues, image, characters_name, concepts_name, characters_id, concepts_id, numLikes) VALUES ('2886', 'DC Special Series', '5-Star Super-Hero Spectacular', '10', '<p>Launched as part of the <a href="/dc-explosion-and-implosion/4015-56163/" data-ref-id="4015-56163">DC Explosion</a>, <i>DC Special Series</i> was anthology that focused on a different character every month. It would survive the following Implosion, lasting until the 1981 #27 - <i>Batman vs. The Incredible Hulk</i> - a <a href="/crossover/4015-55803/" data-ref-id="4015-55803">crossover</a> between <a href="/dc-comics/4010-10/" data-ref-id="4010-10">DC</a> &amp; <a href="/marvel/4010-31/" data-ref-id="4010-31">Marvel</a>.</p><h4>Collected Editions</h4><ul><li><a href="/justice-league-of-america-the-bronze-age-omnibus-3/4000-867809/" data-ref-id="4000-867809">Justice League of America: The Bronze Age Omnibus Volume 3</a> (#6)</li><li><a href="https://comicvine.gamespot.com/deadman-omnibus/4050-132454/">Deadman Omnibus</a> (#8)</li><li><a href="https://comicvine.gamespot.com/new-gods-by-gerry-conway/4050-126349/">New Gods by Gerry Conway</a> (#10)</li><li><a href="https://comicvine.gamespot.com/batman-arkham-ras-al-ghul/4050-117730/">Batman Arkham: Ra''s Al Ghul</a> (#15)</li><li><a href="https://comicvine.gamespot.com/batman-tales-of-the-demon/4050-125639/">Batman: Tales of the Demon</a> (#15)</li><li><a href="/batman-a-celebration-of-75-years/4050-75707/" data-ref-id="4050-75707">Batman: A Celebration of 75 Years</a> (#21)</li></ul>', '1977', '27', '{''icon_url'': ''https://comicvine.gamespot.com/a/uploads/square_avatar/0/4/15261-2886-17013-1-dc-special-series.jpg'', ''medium_url'': ''https://comicvine.gamespot.com/a/uploads/scale_medium/0/4/15261-2886-17013-1-dc-special-series.jpg'', ''screen_url'': ''https://comicvine.gamespot.com/a/uploads/screen_medium/0/4/15261-2886-17013-1-dc-special-series.jpg'', ''screen_large_url'': '