INSERT INTO volumes (id, name, firstIssue, publisher, description, startYear, numIssues, image, characters_name, concepts_name, characters_id, concepts_id, numLikes) VALUES ('2896', 'Black Panther', 'King Solomon''s Frog!', '31', '<p>After the Black Panther''s stint in <a href="/jungle-action/4050-2574/" data-ref-id="4050-2574"> Jungle Action</a>, the African hero stars in his very own magazine, drawn and written by the legendary Jack Kirby!</p><h4>Collected Edition</h4><ul><li><a href="/black-panther-by-jack-kirby-volume-one/4000-294017/" data-ref-id="4000-294017"> Black Panther by Jack Kirby Vol. 1</a> (#1-7)</li><li><a href="/essential-black-panther/4050-49774/" data-ref-id="4050-49774">Essential Black Panther</a> (#1-10)</li><li><a href="https://comicvine.gamespot.com/marvel-masterworks-black-panther-2-volume-2/4000-556473/" data-ref-id="4000-556473">Marvel Masterworks: Black Panther Volume 2</a> (#1-15)</li><li><a href="https://comicvine.gamespot.com/black-panther-epic-collection-revenge-of-the-black/4050-117199/">Black Panther Epic Collection: Revenge of the Black Panther</a> (#1-15)</li><li><a href="https://comicvine.gamespot.com/kirby-returns/4050-120559/">Kirby Returns!</a> (#1-3)</li><li><a href="/black-panther-by-jack-kirby-volume-two/4000-294018/" data-ref-id="4000-294018">Black Panther by Jack Kirby Vol. 2</a> (#8-13)</li><li><a href="https://comicvine.gamespot.com/marvel-verse-black-panther/4050-124689/">Marvel-Verse: Black Panther</a> (#14-15)</li></ul>', '1977', '15', '{''icon_url'': ''https://comicvine.gamespot.com/a/uploads/square_avatar/0/4/15334-2896-17091-1-black-panther.jpg'', ''medium_url'': ''https://comicvine.gamespot.com/a/uploads/scale_medium/0/4/15334-2896-17091-1-black-panther.jpg'', ''screen_url'': ''https://comicvine.gamespot.com/a/uploads/screen_medium/0/4/15334-2896-17091-1-black-panther.jpg'', ''screen_large_url'': ''https://comicvine.gamespot.com/a/uploads/screen_kubrick/0/4/15334-2896-17091-1-black-panther.jpg'', ''small_url'': ''