INSERT INTO volumes (id, name, firstIssue, publisher, description, startYear, numIssues, image, characters_name, concepts_name, characters_id, concepts_id, numLikes) VALUES ('2901', 'Godzilla', 'The Coming!', '31', '<p>Marvel Comics got the rights to publish comics of the famed Godzilla monster. Resulting in this series, where the famous monster is set firmly into the Marvel Universe and interacts with the Avengers, among others.</p><h4>Collected Editions</h4><ul><li><a href="/essential-godzilla/4050-36892/" data-ref-id="4050-36892">Essential Godzilla</a> (#1-24)</li></ul>', '1977', '24', '{''icon_url'': ''https://comicvine.gamespot.com/a/uploads/square_avatar/0/4/15869-2901-17681-1-godzilla.jpg'', ''medium_url'': ''https://comicvine.gamespot.com/a/uploads/scale_medium/0/4/15869-2901-17681-1-godzilla.jpg'', ''screen_url'': ''https://comicvine.gamespot.com/a/uploads/screen_medium/0/4/15869-2901-17681-1-godzilla.jpg'', ''screen_large_url'': ''https://comicvine.gamespot.com/a/uploads/screen_kubrick/0/4/15869-2901-17681-1-godzilla.jpg'', ''small_url'': ''https://comicvine.gamespot.com/a/uploads/scale_small/0/4/15869-2901-17681-1-godzilla.jpg'', ''super_url'': ''https://comicvine.gamespot.com/a/uploads/scale_large/0/4/15869-2901-17681-1-godzilla.jpg'', ''thumb_url'': ''https://comicvine.gamespot.com/a/uploads/scale_avatar/0/4/15869-2901-17681-1-godzilla.jpg'', ''tiny_url'': ''https://comicvine.gamespot.com/a/uploads/square_mini/0/4/15869-2901-17681-1-godzilla.jpg'', ''original_url'': ''https://comicvine.gamespot.com/a/uploads/original/0/4/15869-2901-17681-1-godzilla.jpg'', ''image_tags'': ''All Images''}', '[{"id": "Godzilla"}, {"id": "Gabriel Jones"}, {"id": "Dum Dum Dugan"}, {"id": "Rob Takiguchi"}, {"id": "Jimmy Woo"}, {"id": "Tamara Hashioka"}, {"id": "Dr. Takiguchi"}, {"id": "Hugh Howards"}, {"id": "Red Ronin"}, {"id": "Gladstone Hawkins"}, {"id": "Mr. Fantastic"}, {"id": "Human Torch"}, {"id": "Thing"}, {"id": "Invisible Woman"}, {"id": "Hank Pym"}, {"id": "Krollar