INSERT INTO volumes (id, name, firstIssue, publisher, description, startYear, numIssues, image, characters_name, concepts_name, characters_id, concepts_id, numLikes) VALUES ('2905', 'Iron Man Annual', 'What Price Victory?; Disaster!; When Fall The Mighty!; The Power of Iron Man!', '31', '<p>This series accompanies <a href="/iron-man/4050-2407/" data-ref-id="4050-2407">Iron Man vol. 1</a> and <a href="/iron-man/4050-6504/" data-ref-id="4050-6504">Iron Man vol. 3</a>. Published for fifteen issues until 1994. It resumed in 1998 with unique titles;</p><ul><li><a href="//www.comicvine.com/iron-man-captain-america-annual-98/4050-30391/" data-ref-id="4050-30391">Iron Man / Captain America ''98</a></li><li><a href="//www.comicvine.com/iron-man-annual-99/4050-60457/" data-ref-id="4050-60457">Iron Man 1999</a></li><li><a href="//www.comicvine.com/iron-man-annual-2000/4050-60459/" data-ref-id="4050-60459">Iron Man 2000</a></li><li><a href="//www.comicvine.com/iron-man-annual-2001/4050-60460/" data-ref-id="4050-60460">Iron Man 2001</a></li></ul><h4>Collected Editions</h4><ul><li><a href="/man-thing-by-steve-gerber-the-complete-collection-/4000-845175/" data-ref-id="4000-845175">Man-Thing by Steve Gerber: The Complete Collection Vol. 3</a> (#3)</li><li><a href="https://comicvine.gamespot.com/marvel-masterworks-the-champions-1-volume-1/4000-516959/" data-ref-id="4000-516959">Marvel Masterworks: The Champions Volume 1</a> (#4)</li><li><a href="https://comicvine.gamespot.com/champions-classic-the-complete-collection/4050-111662/">Champions Classic: The Complete Collection</a> (#4)</li><li><a href="https://comicvine.gamespot.com/marvel-verse-black-panther/4050-124689/">Marvel-Verse: Black Panther</a> (#5)</li><li><a href="https://comicvine.gamespot.com/iron-man-epic-collection-duel-of-iron/4050-89265/" data-ref-id="4050-89265">Iron Man Epic Collection: Duel of Iron</a> (#6-7)</li><li><a href="https://comicvine.gamespot.com/eternals-the-dreaming-celestial-saga/4050-133206/">Eternals: