INSERT INTO volumes (id, name, firstIssue, publisher, description, startYear, numIssues, image, characters_name, concepts_name, characters_id, concepts_id, numLikes) VALUES ('2909', 'Marvel Comics Super Special', NULL, '31', '<p>In 1977 <a href="/marvel/4010-31/" data-ref-id="4010-31">Marvel</a> began publishing a full-color magazine series devoted to concepts thought to be deserving of special treatment, such as <a href="/kiss/4060-45153/" data-ref-id="4060-45153"> Kiss</a>'' first comics appearance as headliners, new stories of Conan, <a href="/starlord/4005-10957/" data-ref-id="4005-10957"> Star-Lord</a> and <a href="https://comicvine.gamespot.com/weirdworld/4020-61290/" data-ref-id="4020-61290">Weirdworld</a>, and occasional movie adaptations. With issue #14 however, the magazine became an irregularly published vehicle for comics versions of new films. The series lasted 41 issues.</p><h4>Collected Editions</h4><ul><li><a href="https://comicvine.gamespot.com/the-savage-sword-of-conan-the-original-marvel-year/4000-726224/" data-ref-id="4000-726224">Savage Sword of Conan: The Original Marvel Years Omnibus Volume 2</a> (#2)</li><li><a href="https://comicvine.gamespot.com/the-savage-sword-of-conan-the-original-marvel-year/4000-775032/" data-ref-id="4000-775032">Savage Sword of Conan: The Original Marvel Years Omnibus Volume 3</a> (#9)</li><li><a href="https://comicvine.gamespot.com/muppet-babies-omnibus/4050-104803/" data-ref-id="4050-104803">Muppet Babies Omnibus</a> (#32)</li></ul>', '1977', '41', '{''icon_url'': ''https://comicvine.gamespot.com/a/uploads/square_avatar/0/4/15258-2909-17010-1-marvel-comics-super-.jpg'', ''medium_url'': ''https://comicvine.gamespot.com/a/uploads/scale_medium/0/4/15258-2909-17010-1-marvel-comics-super-.jpg'', ''screen_url'': ''https://comicvine.gamespot.com/a/uploads/screen_medium/0/4/15258-2909-17010-1-marvel-comics-super-.jpg'', ''screen_large_url'': ''https://comicvine.gamespot.com/a/uploads/screen_kubrick/0/4/15258-2909-17010-1-ma