INSERT INTO volumes (id, name, firstIssue, publisher, description, startYear, numIssues, image, characters_name, concepts_name, characters_id, concepts_id, numLikes) VALUES ('2910', 'Ms. Marvel', 'This Woman, This Warrior!', '31', '<p>Ms. Marvel''s first ongoing series. It follows the adventures of <a href="/carol-danvers/4005-21561/" data-ref-id="4005-21561">Carol Danvers</a> after she gained superpowers and became a superhero. With issue 20, she changed costumes into the one that was most famous during the 2000''s. The series was cancelled with issue 23 in the middle of a story-line. Years later however, <a href="/marvel-super-heroes/4050-4404/" data-ref-id="4050-4404"> Marvel Super-Heroes</a> issue 10 and 11 printed the (already finished) stories intended for issues 24 and 25 and its covers. This included the first appearance (supposedly) of the X-Man <a href="/rogue/4005-1446/" data-ref-id="4005-1446">Rogue</a>.</p><figure data-ref-id="1300-4429427" data-img-src="https://static.comicvine.com/uploads/original/11121/111219164/4429427-mms25.jpg" data-size="small" data-align="right" data-ratio="1.6641025641026" data-width="780" data-embed-type="image" style="width: 780px"><a class="fluid-height" style="padding-bottom:166.4%" href="https://static.comicvine.com/uploads/original/11121/111219164/4429427-mms25.jpg" data-ref-id="1300-4429427"><img alt="Ms. Marvel 25" src="https://comicvine.gamespot.com/a/uploads/scale_small/11121/111219164/4429427-mms25.jpg" srcset="https://comicvine.gamespot.com/a/uploads/original/11121/111219164/4429427-mms25.jpg 780w, https://comicvine.gamespot.com/a/uploads/scale_medium/11121/111219164/4429427-mms25.jpg 576w, https://comicvine.gamespot.com/a/uploads/scale_small/11121/111219164/4429427-mms25.jpg 384w" sizes="(max-width: 384px) 100vw, 384px" data-width="384"></a><figcaption>Ms. Marvel 25</figcaption></figure><figure data-align="left" data-img-src="https://static.comicvine.com/uploads/original/10/109227/2861926-msmarvelvol124.jpg" data-r