INSERT INTO volumes (id, name, firstIssue, publisher, description, startYear, numIssues, image, characters_name, concepts_name, characters_id, concepts_id, numLikes) VALUES ('2911', 'Rampaging Hulk', 'The Krylorian Conspiracy', '31', '<p><b>THE RAMPAGING HULK</b> was a black-and-white comic magazine Marvel produced with the intent that the stories presented within would bridge the gap between the sixth and final issue the the Hulk''s first series, and his later serial in <b>TALES TO ASTONISH</b>. However, so many inconsistencies were apparent in the stories that they were later written off as a fictional entertainment produced by the alien Bereet.</p><p>With issue #10, the magazine was re-titled, "<b>HULK!</b>", and presented color tales somewhat closer in scope to the then-popular "Incredible Hulk" TV series.</p><p>Continues into <a href="/hulk/4050-2954/" data-ref-id="4050-2954"> Hulk!</a> #10</p><h4>Collected Editions</h4><ul><li>Reprinted in <a href="/essential-rampaging-hulk-1-volume-one/4000-473268/" data-ref-id="4000-473268">Essential Rampaging Hulk #1 - Volume One</a></li></ul>', '1977', '9', '{''icon_url'': ''https://comicvine.gamespot.com/a/uploads/square_avatar/0/4/15359-2911-17116-1-rampaging-hulk.jpg'', ''medium_url'': ''https://comicvine.gamespot.com/a/uploads/scale_medium/0/4/15359-2911-17116-1-rampaging-hulk.jpg'', ''screen_url'': ''https://comicvine.gamespot.com/a/uploads/screen_medium/0/4/15359-2911-17116-1-rampaging-hulk.jpg'', ''screen_large_url'': ''https://comicvine.gamespot.com/a/uploads/screen_kubrick/0/4/15359-2911-17116-1-rampaging-hulk.jpg'', ''small_url'': ''https://comicvine.gamespot.com/a/uploads/scale_small/0/4/15359-2911-17116-1-rampaging-hulk.jpg'', ''super_url'': ''https://comicvine.gamespot.com/a/uploads/scale_large/0/4/15359-2911-17116-1-rampaging-hulk.jpg'', ''thumb_url'': ''https://comicvine.gamespot.com/a/uploads/scale_avatar/0/4/15359-2911-17116-1-rampaging-hulk.jpg'', ''tiny_url'': ''https://comicvine.gamespot.com/a/uploads/s