INSERT INTO volumes (id, name, firstIssue, publisher, description, startYear, numIssues, image, characters_name, concepts_name, characters_id, concepts_id, numLikes) VALUES ('2914', 'Star Wars', 'Star Wars', '31', '<p>A long time ago...</p><p>The original Star Wars comic book series, published by Marvel Comics from 1977-1986. The series started as an official adaption, but build on the legacy after the original film''s ending.</p><h4>Star Wars Annuals</h4><ul><li><a href="/star-wars-annual-1-the-long-hunt/4000-19083/" data-ref-id="4000-19083">Star Wars Annual #1</a></li><li><a href="/star-wars-annual-2-shadeshine/4000-21789/" data-ref-id="4000-21789">Star Wars Annual #2</a></li><li><a href="/star-wars-annual-3-the-apprentice/4000-22721/" data-ref-id="4000-22721">Star Wars Annual #3</a></li></ul><h4>Trade Paperback Collections</h4><ul><li><a href="/classic-star-wars-a-long-time-ago-doomworld/4000-307855/" data-ref-id="4000-307855">Classic Star Wars: A Long Time Ago... volume 1</a> (#1-20)</li><li><a href="/journey-to-star-wars-the-force-awakens-shattered-e/4050-86107/" data-ref-id="4050-86107">Journey to Star Wars: The Force Awakens - Shattered Empire</a> (#1)</li><li><a href="https://comicvine.gamespot.com/star-wars-legends-epic-collection-the-original-mar/4000-555541/" data-ref-id="4000-555541">Star Wars Legends Epic Collection: The Original Marvel Years Volume 1</a> (#1-23)</li><li><a href="https://comicvine.gamespot.com/star-wars-the-original-trilogy-the-movie-adaptatio/4050-124292/">Star Wars: The Original Trilogy: The Movie Adaptations</a> (#1-6 &amp; 39-44)</li><li><a href="https://comicvine.gamespot.com/star-wars-legends-forever-crimson/4050-124457/">Star Wars Legends: Forever Crimson</a> (#16, 27, 29, 50 &amp; 108)</li><li><a href="/classic-star-wars-a-long-time-ago-dark-encounters/4000-307856/" data-ref-id="4000-307856">Classic Star Wars: A Long Time Ago... volume 2</a> (#21-38)</li><li><a href="https://comicvine.gamespot.com/star-wars-legends-epic-collection-the-original-mar/4000-608258/" data-ref-id="4000-608258">Star Wars Legends Epic Collection: The Original Marvel Years Volume 2</a> (#24-38)</li><li><a href="/classic-star-wars-a-long-time-ago-resurrection-of-evil/4000-307857/" data-ref-id="4000-307857">Classic Star Wars: A Long Time Ago... volume 3</a> (#39-53)</li><li><a href="/star-wars-legends-epic-collection-the-original-mar/4000-677297/" data-ref-id="4000-677297">Star Wars Legends Epic Collection: The Original Marvel Years Volume 3</a> (#39-55)</li><li><a href="/classic-star-wars-a-long-time-ago-screams-in-the-void/4000-307858/" data-ref-id="4000-307858">Classic Star Wars: A Long Time Ago... volume 4</a> (#54-67)</li><li><a href="/star-wars-legends-epic-collection-the-original-mar/4000-715320/" data-ref-id="4000-715320">Star Wars Legends Epic Collection: The Original Marvel Years Volume 4</a> (#56-73)</li><li><a href="/classic-star-wars-a-long-time-ago-fools-bounty/4000-307859/" data-ref-id="4000-307859">Classic Star Wars: A Long Time Ago... volume 5</a> (#68-81)</li><li><a href="/star-wars-legends-epic-collection-the-original-mar/4000-878330/" data-ref-id="4000-878330">Star Wars Legends Epic Collection: The Original Marvel Years Volume 5</a> (#74-88)</li><li><a href="/classic-star-wars-a-long-time-ago-wookie-world/4000-307860/" data-ref-id="4000-307860">Classic Star Wars: A Long Time Ago... volume 6</a> (#82-95)</li><li><a href="/classic-star-wars-a-long-time-ago-far-far-away/4000-307861/" data-ref-id="4000-307861">Classic Star Wars: A Long Time Ago... volume 7</a> (#96-107)</li></ul><h4>Omnibus Trade Paperback Collections</h4><ul><li><a href="/star-wars-omnibus-a-long-time-ago-star-wars-omnibus-a-long-time-ago-volume-1/4000-249857/" data-ref-id="4000-249857">Star Wars Omnibus: A Long Time Ago volume 1</a> (#1-27)</li><li><a href="/star-wars-omnibus-a-long-time-ago-star-wars-omnibus-a-long-time-ago-volume-2/4000-266311/" data-ref-id="4000-266311">Star Wars Omnibus: A Long Time Ago volume 2</a> (#28-49)</li>