INSERT INTO volumes (id, name, firstIssue, publisher, description, startYear, numIssues, image, characters_name, concepts_name, characters_id, concepts_id, numLikes) VALUES ('2918', 'What If?', 'What if Spider-Man joined the Fantastic Four?', '31', '<p><em>What If?</em> is a series that shows what would have happened if things had turned out differently during many of the famous Marvel stories. Of note is issues #4 and #9 of this volume are considered canon.</p><p>Continued in <a href="/what-if/4050-4249/" data-ref-id="4050-4249">What If...?</a> Vol. 2 (1989)</p><h4>Collected Editions</h4><ul><li><a href="/what-if-classic-1-volume-1/4000-175521/" data-ref-id="4000-175521">What If? Classic #1</a> (#1-6)</li><li><a href="/what-if-classic-the-complete-collection-1-vol-1/4000-697649/" data-ref-id="4000-697649">What If? Classic: The Complete Collection Vol. 1</a> (#1-12)</li><li><a href="/what-if-the-original-marvel-series-omnibus-1-volum/4000-883326/" data-ref-id="4000-883326">What If?: The Original Marvel Series Omnibus Volume 1</a> (#1-15 &amp; 17-22)</li><li><a href="https://comicvine.gamespot.com/captain-america-the-legacy-of-captain-america/4050-40166/">Captain America: The Legacy of Captain America</a> (#4)</li><li><a href="/what-if-classic-2-volume-2/4000-175572/" data-ref-id="4000-175572">What If? Classic #2</a> (#7-12)</li><li><a href="/agents-of-atlas-the-complete-collection-1-vol-1/4000-668768/" data-ref-id="4000-668768">Agents of Atlas: The Complete Collection Vol. 1</a> (#9)</li><li><a href="/kingsize-kirby/4050-83141/" data-ref-id="4050-83141">King-Size Kirby</a> (#11)</li><li><a href="/what-if-classic-the-complete-collection-2-vol-2/4000-725270/" data-ref-id="4000-725270">What If? Classic: The Complete Collection Vol. 2</a> (#13-15 &amp; 17-23)</li><li><a href="/conan-the-barbarian-the-original-marvel-years-omni/4000-803673/" data-ref-id="4000-803673">Conan the Barbarian: The Original Marvel Years Omnibus Volume 4</a> (#13)</li><li><a href="/what-if-classic-3-volume-3/4000-175593/" data-ref-id="4000-175593">What If? Classic #3</a> (#14-15, #17-20)</li><li><a href="https://comicvine.gamespot.com/shang-chi-master-of-kung-fu-omnibus-3-volume-3/4000-583726/" data-ref-id="4000-583726">Shang-Chi Master of Kung-Fu Omnibus Volume 3</a> (#16)</li><li><a href="https://comicvine.gamespot.com/marvel-masterworks-doctor-strange-8-volume-8/4000-594966/" data-ref-id="4000-594966">Marvel Masterworks: Doctor Strange Volume 8</a> (#18)</li><li><a href="/what-if-classic-4-volume-4/4000-175729/" data-ref-id="4000-175729">What If? Classic #4</a> (#21-26)</li><li><a href="https://comicvine.gamespot.com/hulk-heart-of-the-atom/4050-50267/" data-ref-id="4050-50267">Hulk: Heart of the Atom</a> (#23)</li><li><a href="/what-if-classic-the-complete-collection-3-vol-3/4000-735592/" data-ref-id="4000-735592">What If? Classic: The Complete Collection Vol. 3</a> (#24-35)</li><li><a href="/what-if-classic-5-volume-5/4000-185211/" data-ref-id="4000-185211">What If? Classic #5</a> (#27-32)</li><li><a href="/what-if-classic-6-volume-6/4000-192526/" data-ref-id="4000-192526">What If? Classic #6</a> (#33-38)</li><li><a href="/what-if-classic-the-complete-collection-4-vol-4/4000-755773/" data-ref-id="4000-755773">What If? Classic: The Complete Collection Vol. 4</a> (#36-47)</li><li><a href="/conan-the-barbarian-the-original-marvel-years-omni/4000-832905/" data-ref-id="4000-832905">Conan the Barbarian: The Original Marvel Years Omnibus Volume 5</a> (#39)</li><li><a href="/marvel-masterworks-the-fantastic-four-22-volume-22/4000-791981/" data-ref-id="4000-791981">Marvel Masterworks: The Fantastic Four Volume 22</a> (#36)</li><li><a href="/what-if-classic-7-volume-7/4000-261667/" data-ref-id="4000-261667">What If? Classic #7</a> (#40-42, #44-47, and material from #43)</li><li><a href="https://comicvine.gamespot.com/thor-vs-hulk/4050-104825/" data-ref-id="4050-104825">Thor vs. Hulk</a> (#45)</li></ul><h4>Non-U.S. Collected Editions</h4><ul><li><a href="https://