INSERT INTO volumes (id, name, firstIssue, publisher, description, startYear, numIssues, image, characters_name, concepts_name, characters_id, concepts_id, numLikes) VALUES ('2943', 'DC Comics Presents', 'Chase to the End of Time!', '10', '<p>Since the late 1960s Batman has been teaming up with various characters in <em><a href="https://comicvine.gamespot.com/the-brave-and-the-bold/4050-1683/" data-ref-id="4050-1683">The Brave and the Bold</a></em>. It wasn''t until 1978 that DC Comic''s flagship character Superman was given his own team up book.<em> DC Comics Presents</em> ran for 97 issues with 4 annuals featuring Superman in team up adventures with characters from across the DC Universe. For a brief time it also featured a <a href="https://comicvine.gamespot.com/back-up-story/4015-57009/" data-ref-id="4015-57009">backup</a> series called "<em>Whatever Happened To</em>" which would highlight a Golden Age character that hasn''t been seen for many years. Though this title was abruptly ended with the <a href="/reboot/4015-56620/" data-ref-id="4015-56620">rebooting</a> of Superman, the concept of the Superman team-ups continued briefly in <a href="https://comicvine.gamespot.com/action-comics/4050-18005/" data-ref-id="4050-18005"><em>Action Comics</em></a> from issues 584-600.</p><h4>Related Issues</h4><ul><li><a href="https://comicvine.gamespot.com/dc-comics-presents-annual/4050-3114/">DC Comics Presents Annual</a> (#1-4)</li></ul><h4>Collected Editions</h4><ul><li><a href="https://www.comicvine.com/showcase-presents-dc-comics-presents-superman-team/4000-315276/" data-ref-id="4000-315276">Showcase Presents: DC Comics Presents - Superman Team-Ups vol. 1</a> (#1-26)</li><li><a href="/adventures-of-superman-jose-luis-garcia-lopez-1-vo/4000-395904/" data-ref-id="4000-395904">Adventures of Superman: José Luis García-López Volume 1</a> (#1-4, 17)</li><li><a href="https://comicvine.gamespot.com/supermans-greatest-team-ups/4050-135226/">Superman''s Greatest Team-Ups</a> (#5, 9-10, 12, 14, 19, 28, 30, 35, 38-39, 45, 50, 58, 63, 67, 71 &amp; 97)</li><li><a href="https://comicvine.gamespot.com/swamp-thing-the-bronze-age-2-volume-two/4000-732690/" data-ref-id="4000-732690">Swamp Thing: The Bronze Age Volume Two</a> (#8)</li><li><a href="https://comicvine.gamespot.com/mister-miracle-by-steve-englehart-and-steve-gerber/4050-125642/">Mister Miracle by Steve Englehart and Steve Gerber</a> (#12)</li><li><a href="/black-lightning-2-volume-two/4000-656676/" data-ref-id="4000-656676">Black Lightning Volume 2</a> (#16)</li><li><a href="/justice-league-of-america-the-bronze-age-omnibus-3/4000-867809/" data-ref-id="4000-867809">Justice League of America: The Bronze Age Omnibus Volume 3</a> (#17)</li><li><a href="https://www.comicvine.com/new-teen-titans-1-volume-one/4000-465827/" data-ref-id="4000-465827">New Teen Titans Volume One</a> (#26)</li><li><a href="https://www.comicvine.com/showcase-presents-dc-comics-presents-superman-team/4000-419963/" data-ref-id="4000-419963">Showcase Presents: DC Comics Presents - Superman Team-Ups vol. 2</a> (#27-50 &amp; <a href="/dc-comics-presents-annual-1-crisis-on-three-earths/4000-21776/" data-ref-id="4000-21776">Annual #1</a>)</li><li><a href="//www.comicvine.com/superman-vs-mongul/4050-70058/" data-ref-id="4050-70058">Superman vs. Mongul</a> (#27-28, 36 and 43)</li><li><a href="https://comicvine.gamespot.com/robin-the-bronze-age-omnibus/4050-127130/">Robin: The Bronze Age Omnibus</a> (#31 &amp; 58)</li><li><a href="https://comicvine.gamespot.com/superman-vs-shazam/4050-134487/">Superman vs. Shazam!</a> (#33-34 &amp; 49)</li><li><a href="https://comicvine.gamespot.com/the-joker-the-bronze-age-omnibus/4050-120647/">The Joker: The Bronze Age Omnibus</a> (#41 &amp; 72)</li><li><a href="https://comicvine.gamespot.com/the-doom-patrol-the-bronze-age-omnibus/4050-122961/">The Doom Patrol: The Bronze Age Omnibus</a> (#52)</li><li><a href="https://comicvine.gamespot.com/adventures-of-superman-by-george-perez/4050-126873/">Adventures of Superman by George Perez</a> (#61)</li><li><a href="/crisis-on-infinite-earths-companion-deluxe-edition/4000-691351/" data-ref-id="4000-691351">Crisis On Infinite Earths Companion Deluxe Edition Volume 1</a> (#78)</li><li><a href="/batman-and-the-outsiders-3-volume-3/4000-705406/" data-ref-id="4000-705406">Batman and the Outsiders Volume 3</a> (#83)</li><li><a href="/jack-kirby-omnibus-2-volume-2/4000-400381/" data-ref-id="4000-400381">Jack Kirby Omnibus vol. 2</a> (#84)</li><li><a href="/dc-universe-the-stories-of-alan-moore-1-the-storie/4000-119422/" data-ref-id="4000-119422">DC Universe: The Stories of Alan Moore </a>and<a href="/across-the-universe-the-dc-universe-stories-of-ala/4000-136829/" data-ref-id="4000-136829"> Across the Universe: The DC uinverse Stories of Alan Moore</a> (#85)</li><li><a href="/crisis-on-infinite-earths-companion-deluxe-edition/4000-708088/" data-ref-id="4000-708088">Crisis On Infinite Earths Companion Deluxe Edition Volume 2</a> (#86)</li><li><a href="https://comicvine.gamespot.com/deadman-omnibus/4050-132454/">Deadman Omnibus</a> (#94)</li></ul>', '1978', '97', '{''icon_url'': ''https://comicvine.gamespot.com/a/uploads/square_avatar/0/4/16713-2943-18623-1-dc-comics-presents.jpg'', ''medium_url'': ''https://comicvine.gamespot.com/a/uploads/scale_medium/0/4/16713-2943-18623-1-dc-comics-presents.jpg'', ''screen_url'': ''https://comicvine.gamespot.com/a/uploads/screen_medium/0/4/16713-2943-18623-1-dc-comics-presents.jpg'', ''screen_large_url'': ''https://comicvine.gamespot.com/a/uploads/screen_kubrick/0/4/16713-2943-18623-1-dc-comics-presents.jpg'', ''small_url'': ''https://comicvine.gamespot.com/a/uploads/scale_small/0/4/16713-2943-18623-1-dc-comics-presents.jpg'', ''super_url'': ''https://comicvine.gamespot.com/a/uploads/scale_large/0/4/16713-2943-18623-1-dc-comics-presents.jpg'', ''thumb_url'': ''https://comicvine.gamespot.com/a/uploads/scale_avatar/0/4/16713-2943-18623-1-dc-comics-presents.jpg'', ''tiny_url'': ''https