INSERT INTO volumes (id, name, firstIssue, publisher, description, startYear, numIssues, image, characters_name, concepts_name, characters_id, concepts_id, numLikes) VALUES ('2954', 'Hulk!', NULL, '31', '<p>Continues from <a href="/rampaging-hulk/4050-2911/" data-ref-id="4050-2911"> Rampaging Hulk</a> #9.</p><h4>Collected Editions</h4><ul><li>Reprinted in <a href="/essential-rampaging-hulk-1-volume-one/4000-473268/" data-ref-id="4000-473268">Essential Rampaging Hulk #1 - Volume One</a> (#10-15)</li><li><p>Reprinted in <a href="/essential-rampaging-hulk-2-volume-two/4000-473276/" data-ref-id="4000-473276">Essential Rampaging Hulk #2 - Volume Two</a> (#16-27)</p></li></ul><h4>Non-U.S. Collected Editions</h4><ul><li><a href="https://comicvine.gamespot.com/coleccionable-marvel-heroes-65-caballero-luna-1-cu/4000-612301/">Coleccionable Marvel Héroes - Caballero Luna 1: Cuenta atrás hacia la oscuridad</a> (#11-15, #17-18 &amp; #20) (Spanish)</li></ul>', '1978', '18', '{''icon_url'': ''https://comicvine.gamespot.com/a/uploads/square_avatar/0/4/16818-2954-18735-1-hulk.jpg'', ''medium_url'': ''https://comicvine.gamespot.com/a/uploads/scale_medium/0/4/16818-2954-18735-1-hulk.jpg'', ''screen_url'': ''https://comicvine.gamespot.com/a/uploads/screen_medium/0/4/16818-2954-18735-1-hulk.jpg'', ''screen_large_url'': ''https://comicvine.gamespot.com/a/uploads/screen_kubrick/0/4/16818-2954-18735-1-hulk.jpg'', ''small_url'': ''https://comicvine.gamespot.com/a/uploads/scale_small/0/4/16818-2954-18735-1-hulk.jpg'', ''super_url'': ''https://comicvine.gamespot.com/a/uploads/scale_large/0/4/16818-2954-18735-1-hulk.jpg'', ''thumb_url'': ''https://comicvine.gamespot.com/a/uploads/scale_avatar/0/4/16818-2954-18735-1-hulk.jpg'', ''tiny_url'': ''https://comicvine.gamespot.com/a/uploads/square_mini/0/4/16818-2954-18735-1-hulk.jpg'', ''original_url'': ''https://comicvine.gamespot.com/a/uploads/original/0/4/16818-2954-18735-1-hulk.jpg'', ''image_tags'': ''All Images''}', '[{"id": "Hulk"}, {"id": "Moon Knight"}, {"id": "Marlene Alraune"}, {"id": "Dominic Fortune"}, {"id": "Frenchie"}, {"id": "Gena Landers"}, {"id": "Randall Spector"}, {"id": "Crawley"}, {"id": "Feldstadt"}, {"id": "Baron von Strucker"}, {"id": "Louie Kelt"}]', '[{"id": "Homage Covers"}]', '[{"id": 2267}, {"id": 1493}, {"id": 33191}, {"id": 28466}, {"id": 27829}, {"id": 10282}, {"id": 27828}, {"id": 34561}, {"id": 62295}, {"id": 4662}, {"id": 66210}]', '[{"id": 43734}]', '0');
INSERT INTO volumes (id, name, firstIssue, publisher, description, startYear, numIssues, image, characters_name, concepts_name, characters_id, concepts_id, numLikes) VALUES ('2956', 'Machine Man', 'Machine Man', '31', '<p>Spinning out of the comic-book adaptions of <a href="../../2001-a-space-odyssey/49-2854/" rel="nofollow "> 2001: A Space Odyssey</a>. After Marvel lost the license to publish the series, they brought their own creation, Machine Man, to the Marvel Universe and gave him his own series.</p><p>The first (and longest) series is known for it''s classic Jack Kirby art. The series lasted untill issue 9, but was revived some months later with issue 10 and a new creative team. The series is famous for introducing villain Jack O'' Lantern, as well as the second appearance of Alpha Flight.</p><p>After this series ended with issue 19, Machine Man returned with a <a href="../49-3350/" rel="nofollow "> Machine Man mini-series</a> in 1984 and returned with an ongoing series called <a href="../../x-51/49-11868/" rel="nofollow "> X-51</a>, starring the Machine Man.</p><h4>Collected Editions</h4><ul><li><a href="https://comicvine.gamespot.com/kirby-returns/4050-120559/">Kirby Returns!</a> (#1-6)</li><li><a href="https://comicvine.gamespot.com/alpha-flight-by-john-byrne-omnibus/4050-98560/" data-ref-id="4050-98560">Alpha Flight By John Byrne Omnibus</a> (#18)</li><li><a href="https://comicvine.gamespot.com/machine-man-by-kirby-ditko-the-complete-collection/4050-92563/" data-ref-id="4050-92563">Machine Man by Kirby &amp; Ditko: The Complete Collection</a></li></ul>', '1978', '19', '{''icon_url'': ''https://comicvine.gamespot.com/a/uploads/square_avatar/0/4/16532-2956-18419-1-machine-man.jpg'', ''medium_url'': ''https://comicvine.gamespot.com/a/uploads/scale_medium/0/4/16532-2956-18419-1-machine-man.jpg'', ''screen_url'': ''https://comicvine.gamespot.com/a/uploads/screen_medium/0/4/16532-2956-18419-1-machine-man.jpg'', ''screen_large_url'': ''https://comicvine.gamespot.