INSERT INTO volumes (id, name, firstIssue, publisher, description, startYear, numIssues, image, characters_name, concepts_name, characters_id, concepts_id, numLikes) VALUES ('2957', 'Nova', 'Heavy Mettle', '31', '<p>Richard Rider is back for all-new adventures as Nova, the Human Rocket! While Nova is not hanging out with the New Warriors, he has his hands full in his own life. The series lasted for a total of 18 issues.</p><p> </p>', '1994', '18', '{''icon_url'': ''https://comicvine.gamespot.com/a/uploads/square_avatar/0/77/328692-2957-18970-2-man-called-nova-the.jpg'', ''medium_url'': ''https://comicvine.gamespot.com/a/uploads/scale_medium/0/77/328692-2957-18970-2-man-called-nova-the.jpg'', ''screen_url'': ''https://comicvine.gamespot.com/a/uploads/screen_medium/0/77/328692-2957-18970-2-man-called-nova-the.jpg'', ''screen_large_url'': ''https://comicvine.gamespot.com/a/uploads/screen_kubrick/0/77/328692-2957-18970-2-man-called-nova-the.jpg'', ''small_url'': ''https://comicvine.gamespot.com/a/uploads/scale_small/0/77/328692-2957-18970-2-man-called-nova-the.jpg'', ''super_url'': ''https://comicvine.gamespot.com/a/uploads/scale_large/0/77/328692-2957-18970-2-man-called-nova-the.jpg'', ''thumb_url'': ''https://comicvine.gamespot.com/a/uploads/scale_avatar/0/77/328692-2957-18970-2-man-called-nova-the.jpg'', ''tiny_url'': ''https://comicvine.gamespot.com/a/uploads/square_mini/0/77/328692-2957-18970-2-man-called-nova-the.jpg'', ''original_url'': ''https://comicvine.gamespot.com/a/uploads/original/0/77/328692-2957-18970-2-man-called-nova-the.jpg'', ''image_tags'': ''All Images''}', '[{"id": "Nova"}, {"id": "Namorita"}, {"id": "Robbie Rider"}, {"id": "Night Thrasher"}, {"id": "Thera"}, {"id": "Firestar"}, {"id": "Bernie Dillon"}, {"id": "Adora"}, {"id": "Maxov"}, {"id": "The Planner"}, {"id": "Condor"}, {"id": "Warhead"}, {"id": "Sphinx"}, {"id": "Laura Dunham"}, {"id": "Speedball"}, {"id": "Diamondhead"}, {"id": "Caps Cooper"}, {"id": "Nick Fury"}, {"id": "Justice"}, {"id"