INSERT INTO volumes (id, name, firstIssue, publisher, description, startYear, numIssues, image, characters_name, concepts_name, characters_id, concepts_id, numLikes) VALUES ('2959', 'Power Man and Iron Fist', 'Freedom!', '31', '<p>The long running team-up comic starring Luke Cage and Iron Fist as they fight the thugs from the mean streets of America. It is continued from <a href="/power-man/4050-2700/" data-ref-id="4050-2700"> Power Man</a> #49 and lasted until issue 125.</p><h4>Collected Editions</h4><ul><li><a href="/power-man-and-iron-fist-epic-collection-heroes-for/4050-83705/" data-ref-id="4050-83705">Power Man and Iron Fist Epic Collection: Heroes For Hire</a> (#50-70)</li><li><a href="https://comicvine.gamespot.com/power-man-and-iron-fist-epic-collection-revenge/4050-94655/" data-ref-id="4050-94655">Power Man And Iron Fist Epic Collection: Revenge!</a> (#71-72 &amp; 74-89)</li><li><a href="https://comicvine.gamespot.com/power-man-and-iron-fist-epic-collection-doombringe/4050-122992/">Power Man and Iron Fist Epic Collection: Doombringer</a> (#90-107)</li></ul><h4>Non-U.S. Collected Editions</h4><ul><li><a href="https://comicvine.gamespot.com/coleccionable-marvel-heroes-53-secret-wars-ii-quie/4000-612261/">Coleccionable Marvel Héroes - Secret Wars II: ¿Quién es el Todopoderoso?</a> (#121) (Spanish)</li></ul>', '1978', '76', '{''icon_url'': ''https://comicvine.gamespot.com/a/uploads/square_avatar/0/4/16539-2959-18426-1-power-man-and-iron-f.jpg'', ''medium_url'': ''https://comicvine.gamespot.com/a/uploads/scale_medium/0/4/16539-2959-18426-1-power-man-and-iron-f.jpg'', ''screen_url'': ''https://comicvine.gamespot.com/a/uploads/screen_medium/0/4/16539-2959-18426-1-power-man-and-iron-f.jpg'', ''screen_large_url'': ''https://comicvine.gamespot.com/a/uploads/screen_kubrick/0/4/16539-2959-18426-1-power-man-and-iron-f.jpg'', ''small_url'': ''https://comicvine.gamespot.com/a/uploads/scale_small/0/4/16539-2959-18426-1-power-man-and-iron-f.jpg'', ''super_url'': ''https://c