INSERT INTO volumes (id, name, firstIssue, publisher, description, startYear, numIssues, image, characters_name, concepts_name, characters_id, concepts_id, numLikes) VALUES ('2960', 'Spider-Woman', '... A Future Uncertain', '31', '<p><strong>To know her...is to fear her!</strong></p><p>After her debut in <a href="https://www.comicvine.com/marvel-spotlight-32-dark-destiny/4000-17194/">Marvel Spotlight issue 32</a>, the mysterious and eerie Spider-Woman stars in her very own ongoing series. The first ongoing series of Spider-woman started in 1978 and lasted until 1983 with a total of 50 issues.</p><h4>Collected Editions</h4><ul><li><a href="/marvel-masterworks-spider-woman-1-volume-1/4000-505913/" data-ref-id="4000-505913">Marvel Masterworks: Spider-Woman Volume 1</a> (#1-8)</li><li><a href="https://comicvine.gamespot.com/spider-man-spider-verse-spider-women/4050-130410/">Spider-Man: Spider-Verse - Spider-Women</a> (#1 &amp; 20)</li></ul>', '1978', '50', '{''icon_url'': ''https://comicvine.gamespot.com/a/uploads/square_avatar/6/67663/3755103-01.jpg'', ''medium_url'': ''https://comicvine.gamespot.com/a/uploads/scale_medium/6/67663/3755103-01.jpg'', ''screen_url'': ''https://comicvine.gamespot.com/a/uploads/screen_medium/6/67663/3755103-01.jpg'', ''screen_large_url'': ''https://comicvine.gamespot.com/a/uploads/screen_kubrick/6/67663/3755103-01.jpg'', ''small_url'': ''https://comicvine.gamespot.com/a/uploads/scale_small/6/67663/3755103-01.jpg'', ''super_url'': ''https://comicvine.gamespot.com/a/uploads/scale_large/6/67663/3755103-01.jpg'', ''thumb_url'': ''https://comicvine.gamespot.com/a/uploads/scale_avatar/6/67663/3755103-01.jpg'', ''tiny_url'': ''https://comicvine.gamespot.com/a/uploads/square_mini/6/67663/3755103-01.jpg'', ''original_url'': ''https://comicvine.gamespot.com/a/uploads/original/6/67663/3755103-01.jpg'', ''image_tags'': ''All Images''}', '[{"id": "Spider-Woman"}, {"id": "Lindsay McCabe"}, {"id": "Jerry Hunt"}, {"id": "Scotty McDowell"}, {"id": "Charles 