INSERT INTO volumes (id, name, firstIssue, publisher, description, startYear, numIssues, image, characters_name, concepts_name, characters_id, concepts_id, numLikes) VALUES ('2989', 'The Best of DC', 'Superman', '10', '<p><em>The Best of DC</em> Blue Ribbon Digest is just that: <a href="https://comicvine.gamespot.com/reprinted-material/4015-56278/" data-ref-id="4015-56278">reprinting</a> the best storylines from <a href="//www.comicvine.com/batman/4005-1699/" data-ref-id="4005-1699">Batman</a>, <a href="//www.comicvine.com/superman/4005-1807/" data-ref-id="4005-1807">Superman</a>, <a href="//www.comicvine.com/worlds-finest-comics/4050-18006/" data-ref-id="4050-18006">World''s Finest Comics</a>, <a href="/superboy/4050-19154/" data-ref-id="4050-19154">Superboy</a>, <a href="//www.comicvine.com/green-lantern/4015-41148/" data-ref-id="4015-41148">Green Lantern</a>, The Flash <a href="//www.comicvine.com/barry-allen/4005-22804/" data-ref-id="4005-22804">Barry Allen</a> and featuring the Secret Origin of Super-Villains, the <a href="/justice-society-of-america/4060-27589/" data-ref-id="4060-27589">Justice Society of America</a>, <a href="//www.comicvine.com/legion-of-super-heroes/4060-19241/" data-ref-id="4060-19241">Legion of Super-Heroes</a>, <a href="//www.comicvine.com/teen-titans/4060-19081/" data-ref-id="4060-19081">Teen Titans</a> and other characters.</p><p>The digests, similar to <a href="//www.comicvine.com/archie-comics/4010-101/" data-ref-id="4010-101">Archie Comics</a> digests, were published at a time before graphic novels and trade paperbacks, when publishers like <a href="//www.comicvine.com/dc-comics/4010-10/" data-ref-id="4010-10">DC Comics</a> and <a href="//www.comicvine.com/marvel/4010-31/" data-ref-id="4010-31">Marvel</a> reprinted material in comic book pages. DC''s 100 Page Comics featured 10 - 12 pages of original stories and the rest were reprint material. Case in point <em><a href="/the-best-of-dc-9-batman/4000-20935/" data-ref-id="4000-20935">The Best of DC #9</a></em>, collecting the <em><a href="/detective-comics/4050-18058/" data-ref-id="4050-18058">Detective Comics</a></em> "<em><a href="//www.comicvine.com/bat-murderer/4045-57688/" data-ref-id="4045-57688">Bat Murderer</a></em>" storyline. Each segment is roughly 12-pages long. Combining that with a 1969 reprint from <em><a href="//www.comicvine.com/batman/4050-796/" data-ref-id="4050-796">Batman</a></em>, and a layout of the <a href="/wayne-foundation-building/4020-58159/" data-ref-id="4020-58159">Wayne Foundation Building</a>, what you have is a 100 page digest for under a dollar!</p><p>After 71 issues, the series ended in 1986.</p>', '1979', '71', '{''icon_url'': ''https://comicvine.gamespot.com/a/uploads/square_avatar/0/4/17662-2989-19747-1-best-of-dc-the.jpg'', ''medium_url'': ''https://comicvine.gamespot.com/a/uploads/scale_medium/0/4/17662-2989-19747-1-best-of-dc-the.jpg'', ''screen_url'': ''https://comicvine.gamespot.com/a/uploads/screen_medium/0/4/17662-2989-19747-1-best-of-dc-the.jpg'', ''screen_large_url'': ''https://comicvine.gamespot.com/a/uploads/screen_kubrick/0/4/17662-2989-19747-1-best-of-dc-the.jpg'', ''small_url'': ''https://comicvine.gamespot.com/a/uploads/scale_small/0/4/17662-2989-19747-1-best-of-dc-the.jpg'', ''super_url'': ''https://comicvine.gamespot.com/a/uploads/scale_large/0/4/17662-2989-19747-1-best-of-dc-the.jpg'', ''thumb_url'': ''https://comicvine.gamespot.com/a/uploads/scale_avatar/0/4/17662-2989-19747-1-best-of-dc-the.jpg'', ''tiny_url'': ''https://comicvine.gamespot.com/a/uploads/square_mini/0/4/17662-2989-19747-1-best-of-dc-the.jpg'', ''original_url'': ''https://comicvine.gamespot.com/a/uploads/original/0/4/17662-2989-19747-1-best-of-dc-the.jpg'', ''image_tags'': ''All Images''}', '[{"id": "Superman"}, {"id": "Batman"}, {"id": "Lois Lane"}, {"id": "Dick Grayson"}, {"id": "Jimmy Olsen"}, {"id": "Green Arrow"}, {"id": "Perry White"}, {"id": "Supergirl"}, {"id": "Aquaman"}, {"id": "James Gordon"}, {"id": "Barry Allen