INSERT INTO volumes (id, name, firstIssue, publisher, description, startYear, numIssues, image, characters_name, concepts_name, characters_id, concepts_id, numLikes) VALUES ('3002', 'Battlestar Galactica', 'Battlestar Galactica', '31', NULL, '1979', '23', '{''icon_url'': ''https://comicvine.gamespot.com/a/uploads/square_avatar/8/84205/4085418-bg1nm92m084.jpg'', ''medium_url'': ''https://comicvine.gamespot.com/a/uploads/scale_medium/8/84205/4085418-bg1nm92m084.jpg'', ''screen_url'': ''https://comicvine.gamespot.com/a/uploads/screen_medium/8/84205/4085418-bg1nm92m084.jpg'', ''screen_large_url'': ''https://comicvine.gamespot.com/a/uploads/screen_kubrick/8/84205/4085418-bg1nm92m084.jpg'', ''small_url'': ''https://comicvine.gamespot.com/a/uploads/scale_small/8/84205/4085418-bg1nm92m084.jpg'', ''super_url'': ''https://comicvine.gamespot.com/a/uploads/scale_large/8/84205/4085418-bg1nm92m084.jpg'', ''thumb_url'': ''https://comicvine.gamespot.com/a/uploads/scale_avatar/8/84205/4085418-bg1nm92m084.jpg'', ''tiny_url'': ''https://comicvine.gamespot.com/a/uploads/square_mini/8/84205/4085418-bg1nm92m084.jpg'', ''original_url'': ''https://comicvine.gamespot.com/a/uploads/original/8/84205/4085418-bg1nm92m084.jpg'', ''image_tags'': ''All Images''}', '[{"id": "Commander Adama"}, {"id": "Apollo"}, {"id": "Colonel Tigh"}, {"id": "Cassiopeia"}, {"id": "Boxey"}, {"id": "Jolly"}, {"id": "Lucifer"}, {"id": "Imperious Leader"}, {"id": "Baltar"}, {"id": "Dr. Wilker"}, {"id": "Zak Adama"}]', '[{"id": "Battlestar Galactica"}]', '[{"id": 8167}, {"id": 8169}, {"id": 8168}, {"id": 8193}, {"id": 8194}, {"id": 8175}, {"id": 8181}, {"id": 8192}, {"id": 8179}, {"id": 8195}, {"id": 44270}]', '[{"id": 58492}]', '0');
INSERT INTO volumes (id, name, firstIssue, publisher, description, startYear, numIssues, image, characters_name, concepts_name, characters_id, concepts_id, numLikes) VALUES ('3003', 'Fantasy Masterpieces', 'The Origin of the Silver Surfer!', '31', '<p>Fantasy Masterpieces Volume 2 are reprints of <a data-ref-id="4050-2411" href="/the-silver-surfer/4050-2411/" slug="the-silver-surfer"> Silver Surfer Volume 1</a> #1-14. The first eleven issues are not complete reprints. Issues #1-7 are missing four pages each and issues #8-11 are missing two. Issues #12-14 are complete. These reprints are presented by <a data-ref-id="4040-40467" href="/stan-lee/4040-40467/" slug="stan-lee"> Stan Lee</a> and <a data-ref-id="4040-3800" href="/john-buscema/4040-3800/" slug="john-buscema"> John Buscema</a>. <br/><br/>Beginning at issue #8, the volume reprints <a data-ref-id="4005-6805" href="/adam-warlock/4005-6805/" slug="adam-warlock"> Adam Warlock</a> stories from <a data-ref-id="4050-18066" href="/strange-tales/4050-18066/" slug="strange-tales"> Strange Tales</a> and <a data-ref-id="4050-2583" href="/warlock/4050-2583/" slug="warlock"> Warlock</a>.<br/><br/>Complete reproductions can be found in the <a data-ref-id="4050-3851" href="/marvel-masterworks/4050-3851/" slug="marvel-masterworks"> Marvel Masterworks</a> hardcovers or in the <a data-ref-id="4050-26431" href="/essential-silver-surfer/4050-26431/" slug="essential-silver-surfer"> Essential Silver Surfer</a> TPB.<br/></p>', '1979', '14', '{''icon_url'': ''https://comicvine.gamespot.com/a/uploads/square_avatar/0/4/50784-3003-66593-1-fantasy-masterpieces.jpg'', ''medium_url'': ''https://comicvine.gamespot.com/a/uploads/scale_medium/0/4/50784-3003-66593-1-fantasy-masterpieces.jpg'', ''screen_url'': ''https://comicvine.gamespot.com/a/uploads/screen_medium/0/4/50784-3003-66593-1-fantasy-masterpieces.jpg'', ''screen_large_url'': ''https://comicvine.gamespot.com/a/uploads/screen_kubrick/0/4/50784-3003-66593-1-fantasy-masterpieces.jpg'', 