INSERT INTO volumes (id, name, firstIssue, publisher, description, startYear, numIssues, image, characters_name, concepts_name, characters_id, concepts_id, numLikes) VALUES ('3004', 'Fun and Games Magazine', NULL, '31', '<p>Marvel''s very own puzzle magazine. "All you need is a pencil".  It featured Marvel heroes in puzzles.  The only original character introduced was Cross Wordo.</p>', '1979', '13', '{''icon_url'': ''https://comicvine.gamespot.com/a/uploads/square_avatar/0/4/50798-3004-66607-1-fun-and-games-magazi.jpg'', ''medium_url'': ''https://comicvine.gamespot.com/a/uploads/scale_medium/0/4/50798-3004-66607-1-fun-and-games-magazi.jpg'', ''screen_url'': ''https://comicvine.gamespot.com/a/uploads/screen_medium/0/4/50798-3004-66607-1-fun-and-games-magazi.jpg'', ''screen_large_url'': ''https://comicvine.gamespot.com/a/uploads/screen_kubrick/0/4/50798-3004-66607-1-fun-and-games-magazi.jpg'', ''small_url'': ''https://comicvine.gamespot.com/a/uploads/scale_small/0/4/50798-3004-66607-1-fun-and-games-magazi.jpg'', ''super_url'': ''https://comicvine.gamespot.com/a/uploads/scale_large/0/4/50798-3004-66607-1-fun-and-games-magazi.jpg'', ''thumb_url'': ''https://comicvine.gamespot.com/a/uploads/scale_avatar/0/4/50798-3004-66607-1-fun-and-games-magazi.jpg'', ''tiny_url'': ''https://comicvine.gamespot.com/a/uploads/square_mini/0/4/50798-3004-66607-1-fun-and-games-magazi.jpg'', ''original_url'': ''https://comicvine.gamespot.com/a/uploads/original/0/4/50798-3004-66607-1-fun-and-games-magazi.jpg'', ''image_tags'': ''All Images''}', '[{"id": "Spider-Man"}, {"id": "Hulk"}, {"id": "Captain America"}, {"id": "Daredevil"}, {"id": "Iron Man"}, {"id": "Thor"}, {"id": "Human Torch"}, {"id": "Thing"}, {"id": "Vision"}, {"id": "Spider-Woman"}, {"id": "Wolverine"}, {"id": "Black Panther"}, {"id": "Nova"}, {"id": "Sam Wilson"}, {"id": "Cross Wordo"}, {"id": "Jack of Hearts"}, {"id": "Silver Surfer"}, {"id": "Invisible Woman"}, {"id": "Mr. Fantastic"}, {"id": "Namor"}, {"id": "Doctor Doom"},