INSERT INTO volumes (id, name, firstIssue, publisher, description, startYear, numIssues, image, characters_name, concepts_name, characters_id, concepts_id, numLikes) VALUES ('3007', 'Marvel Spotlight', 'The Saturn Storm!', '31', '<p>The short lived second incarnation of the Marvel Spotlight series. Issue #8 features one of the last (if not THE last) appearances of <a href="/captain-marvel/4005-1472/" data-ref-id="4005-1472">Captain Marvel</a> before his death in <a href="/marvel-graphic-novel/4050-3144/" data-ref-id="4050-3144">Marvel Graphic Novel</a> #1: <a href="/marvel-graphic-novel-the-death-of-captain-marvel/4000-21782/" data-ref-id="4000-21782">The Death of Captain Marvel</a>. Issue #12 was supposed to put the spotlight back on Captain Marvel but the series was instead cancelled.</p><h4>Collected Editions</h4><ul><li><a href="/guardians-of-the-galaxy-solo-classic-omnibus/4050-85759/" data-ref-id="4050-85759">Guardians of the Galaxy Solo Classic Omnibus</a> (#1-2 &amp; 6-7)</li><li><a href="https://comicvine.gamespot.com/drax-guardian-of-the-galaxy/4050-93657/" data-ref-id="4050-93657">Drax: Guardian of the Galaxy</a> (#1-2)</li><li><a href="https://comicvine.gamespot.com/marvel-masterworks-captain-marvel-6-volume-6/4000-529659/" data-ref-id="4000-529659">Marvel Masterworks: Captain Marvel Vol. 6</a> (#1-4 &amp; 8)</li><li><a href="/captain-marvel-the-death-of-captain-marvel/4050-34102/" data-ref-id="4050-34102">Captain Marvel: The Death of Captain Marvel</a> (#1-2)</li><li><a href="https://comicvine.gamespot.com/decades-marvel-in-the-70s-legion-of-monsters/4050-118241/">Decades: Marvel In The ''70s - Legion of Monsters</a> (#2 &amp; 5)</li><li><a href="/annihilation-classic/4050-30933/" data-ref-id="4050-30933">Annihilation Classic</a> (#6)</li><li><a href="/starlord-tears-for-heaven/4050-72794/" data-ref-id="4050-72794">Star-Lord: Tears For Heaven</a> (#6-7)</li><li><a href="https://comicvine.gamespot.com/captain-universe-power-unimaginable/4050-25914/">Captain Universe: Power Unimaginable</a> (#9-11)</li></ul>', '1979', '11', '{''icon_url'': ''https://comicvine.gamespot.com/a/uploads/square_avatar/0/4/17571-3007-19647-1-marvel-spotlight.jpg'', ''medium_url'': ''https://comicvine.gamespot.com/a/uploads/scale_medium/0/4/17571-3007-19647-1-marvel-spotlight.jpg'', ''screen_url'': ''https://comicvine.gamespot.com/a/uploads/screen_medium/0/4/17571-3007-19647-1-marvel-spotlight.jpg'', ''screen_large_url'': ''https://comicvine.gamespot.com/a/uploads/screen_kubrick/0/4/17571-3007-19647-1-marvel-spotlight.jpg'', ''small_url'': ''https://comicvine.gamespot.com/a/uploads/scale_small/0/4/17571-3007-19647-1-marvel-spotlight.jpg'', ''super_url'': ''https://comicvine.gamespot.com/a/uploads/scale_large/0/4/17571-3007-19647-1-marvel-spotlight.jpg'', ''thumb_url'': ''https://comicvine.gamespot.com/a/uploads/scale_avatar/0/4/17571-3007-19647-1-marvel-spotlight.jpg'', ''tiny_url'': ''https://comicvine.gamespot.com/a/uploads/square_mini/0/4/17571-3007-19647-1-marvel-spotlight.jpg'', ''original_url'': ''https://comicvine.gamespot.com/a/uploads/original/0/4/17571-3007-19647-1-marvel-spotlight.jpg'', ''image_tags'': ''All Images''}', '[{"id": "Captain Marvel"}, {"id": "Rick Jones"}, {"id": "Captain Universe"}, {"id": "ISAAC"}, {"id": "Mentor"}, {"id": "Elysius"}, {"id": "Starfox"}, {"id": "Master of the Sun"}, {"id": "Meredith Quill"}, {"id": "J''son of Spartax"}, {"id": "Ship"}, {"id": "Dionysus of Titan"}, {"id": "Chaos, Deity of Space"}, {"id": "Lord Gaea"}, {"id": "Stellarax"}, {"id": "Star-Lord"}, {"id": "Drax the Destroyer"}, {"id": "Mister E"}, {"id": "Spider-Man"}, {"id": "Guido Carboni"}, {"id": "Monty Walsh"}, {"id": "Kyras Shakati"}, {"id": "Storm"}, {"id": "Rruothk''ar"}, {"id": "Cyclops"}, {"id": "Nemesis"}, {"id": "Clare Dodgson"}, {"id": "Ann Dodgson-Stanford"}, {"id": "Colossus"}, {"id": "Nightcrawler"}, {"id": "Beast"}, {"id": "Una"}, {"id": "Steve Coffin"}, {"id": "Iceman"}, {"id": "Dragon-Lord"}, {"id": "J. Jonah Jameson"}, {"id": "Vindar"}, {"id": "Sylvana"}, {"id": "Ray Coffin"}, {"id": "Medusa"}, {"id": "Black Bolt"}, {"id": "Gorgon"}, {"id": "Eon"}, {"id": "Triton"}, {"id": "Karnak"}, {"id": "Yon-Rogg"}, {"id": "Banshee"}]', 'NaN', '[{"id": 1472}, {"id": 2248}, {"id": 27193}, {"id": 22002}, {"id": 14522}, {"id": 7990}, {"id": 7257}, {"id": 103797}, {"id": 81549}, {"id": 81150}, {"id": 63898}, {"id": 62906}, {"id": 62905}, {"id": 58345}, {"id": 34213}, {"id": 10957}, {"id": 6807}, {"id": 58998}, {"id": 1443}, {"id": 83448}, {"id": 83442}, {"id": 81550}, {"id": 1444}, {"id": 81548}, {"id": 1459}, {"id": 77297}, {"id": 77287}, {"id": 77286}, {"id": 1460}, {"id": 1461}, {"id": 1462}, {"id": 60450}, {"id": 59127}, {"id": 1464}, {"id": 37247}, {"id": 1487}, {"id": 33756}, {"id": 32499}, {"id": 28038}, {"id": 4327}, {"id": 4329}, {"id": 4330}, {"id": 13348}, {"id": 11428}, {"id": 10975}, {"id": 6094}, {"id": 9708}]', 'NaN', '0');
INSERT INTO volumes (id, name, firstIssue, publisher, description, startYear, numIssues, image, characters_name, concepts_name, characters_id, concepts_id, numLikes) VALUES ('3008', 'Micronauts', 'Homeworld', '31', '<p data-right-indent="0" data-left-indent="0"><b>The Micronauts Volume 1</b></p><p data-right-indent="0" data-left-indent="0">The Micronauts series was created by Marvel Comics in a deal with Mego Toys to produce a series of adventures based off their Micronauts toy line. The Mego toys were in fact mostly reproductions of an earlier long running series of Japanese toys called Microman.</p><p data-right-indent="0" data-left-indent="0">The comic''s inaugural creators were Bill Mantlo and Michael Golden, and they presented The Micronauts as a team of adventurers, exploring a subatomic universe called the Microverse. The series ends with issue #59 and was later revamped as <a href="../../micronauts-the-new-voyages/49-3353/" rel="nofollow "> Micronauts: The New Voyages</a>.</p>', '1979', '59', '{''icon_url'': ''https://comicvine.gamespot.com/a/uploads/square_avatar/8/84205/4351486-mn1nm92m013.jpg'', ''medium_url'': ''https://comicvine.gamespot.com/a/uploads/scale_medium/8/84205/4351486-mn1nm92m013.jpg'', ''screen_url'': ''https://comicvine.gamespot.com/a/uploads/screen_medium/8/84205/4351486-mn1nm92m013.jpg'', ''screen_large_url'': ''https://comicvine.gamespot.com/a/uploads/screen_kubrick/8/84205/4351486-mn1nm92m013.jpg'', ''small_url'': ''https://comicvine.gamespot.com/a/uploads/scale_small/8/84205/4351486-mn1nm92m013.jpg'', ''super_url'': ''https://comicvine.gamespot.com/a/uploads/scale_large/8/84205/4351486-mn1nm92m013.jpg'', ''thumb_url'': ''https://comicvine.gamespot.com/a/uploads/scale_avatar/8/84205/4351486-mn1nm92m013.jpg'', ''tiny_url'': ''https://comicvine.gamespot.com/a/uploads/square_mini/8/84205/4351486-mn1nm92m013.jpg'', ''original_url'': ''https://comicvine.gamespot.com/a/uploads/original/8/84205/4351486-mn1nm92m013.jpg'', ''image_tags'': ''All