INSERT INTO volumes (id, name, firstIssue, publisher, description, startYear, numIssues, image, characters_name, concepts_name, characters_id, concepts_id, numLikes) VALUES ('3010', 'Rom', 'Arrival!', '31', '<p>The first (and only) volume of Rom. Although Rom was a Marvel character, and fully integrated into the Marvel Universe, the Hasbro toy company owned the rights to the character (since it was a comic published after a toy they made). The series ended with issue 75, after which Marvel lost the rights to publish Rom. Rom has a devoted fan-base who tries to convince Marvel to buy the rights back to publish a new Rom series. A sequel to this series, the mini-series <a href="../../spaceknights/49-25951/" rel="nofollow ">Spaceknights</a>, was published in 2000.</p>', '1979', '75', '{''icon_url'': ''https://comicvine.gamespot.com/a/uploads/square_avatar/0/4/17893-3010-19997-1-rom.jpg'', ''medium_url'': ''https://comicvine.gamespot.com/a/uploads/scale_medium/0/4/17893-3010-19997-1-rom.jpg'', ''screen_url'': ''https://comicvine.gamespot.com/a/uploads/screen_medium/0/4/17893-3010-19997-1-rom.jpg'', ''screen_large_url'': ''https://comicvine.gamespot.com/a/uploads/screen_kubrick/0/4/17893-3010-19997-1-rom.jpg'', ''small_url'': ''https://comicvine.gamespot.com/a/uploads/scale_small/0/4/17893-3010-19997-1-rom.jpg'', ''super_url'': ''https://comicvine.gamespot.com/a/uploads/scale_large/0/4/17893-3010-19997-1-rom.jpg'', ''thumb_url'': ''https://comicvine.gamespot.com/a/uploads/scale_avatar/0/4/17893-3010-19997-1-rom.jpg'', ''tiny_url'': ''https://comicvine.gamespot.com/a/uploads/square_mini/0/4/17893-3010-19997-1-rom.jpg'', ''original_url'': ''https://comicvine.gamespot.com/a/uploads/original/0/4/17893-3010-19997-1-rom.jpg'', ''image_tags'': ''All Images''}', '[{"id": "Rom"}, {"id": "Brandy Clark"}, {"id": "Starshine"}, {"id": "Torpedo"}, {"id": "Rick Jones"}, {"id": "General Locklin"}, {"id": "Cindy Adams"}, {"id": "Firefall"}, {"id": "Doctor Dredd"}, {"id": "Forge"}, {"id":