INSERT INTO volumes (id, name, firstIssue, publisher, description, startYear, numIssues, image, characters_name, concepts_name, characters_id, concepts_id, numLikes) VALUES ('3011', 'Shogun Warriors', 'Raydeen!', '31', '<p>Inspired by the toy-line of Shogun Warriors licensed by Mattel. Marvel brought these warriors into the Marvel Universe and even had them joined up with the Fantastic Four..</p>', '1979', '20', '{''icon_url'': ''https://comicvine.gamespot.com/a/uploads/square_avatar/0/4/66844-3011-99841-1-shogun-warriors.jpg'', ''medium_url'': ''https://comicvine.gamespot.com/a/uploads/scale_medium/0/4/66844-3011-99841-1-shogun-warriors.jpg'', ''screen_url'': ''https://comicvine.gamespot.com/a/uploads/screen_medium/0/4/66844-3011-99841-1-shogun-warriors.jpg'', ''screen_large_url'': ''https://comicvine.gamespot.com/a/uploads/screen_kubrick/0/4/66844-3011-99841-1-shogun-warriors.jpg'', ''small_url'': ''https://comicvine.gamespot.com/a/uploads/scale_small/0/4/66844-3011-99841-1-shogun-warriors.jpg'', ''super_url'': ''https://comicvine.gamespot.com/a/uploads/scale_large/0/4/66844-3011-99841-1-shogun-warriors.jpg'', ''thumb_url'': ''https://comicvine.gamespot.com/a/uploads/scale_avatar/0/4/66844-3011-99841-1-shogun-warriors.jpg'', ''tiny_url'': ''https://comicvine.gamespot.com/a/uploads/square_mini/0/4/66844-3011-99841-1-shogun-warriors.jpg'', ''original_url'': ''https://comicvine.gamespot.com/a/uploads/original/0/4/66844-3011-99841-1-shogun-warriors.jpg'', ''image_tags'': ''All Images''}', '[{"id": "Ilongo Savage"}, {"id": "Genji Odashu"}, {"id": "Richard Carson"}, {"id": "Dangard Ace"}, {"id": "Combatra"}, {"id": "Raydeen"}, {"id": "Doctor Tambura"}, {"id": "Deena James"}, {"id": "Doctor Demonicus"}, {"id": "Lord Maur-Kon"}, {"id": "Hand of Five"}, {"id": "Starchild Monster"}, {"id": "Mech-Monster"}, {"id": "Magar"}, {"id": "Rok-Korr"}, {"id": "Invisible Woman"}, {"id": "Mr. Fantastic"}, {"id": "Human Torch"}, {"id": "Thing"}, {"id": "Basque"}, {"id": "Sherna"}, {"id"