INSERT INTO volumes (id, name, firstIssue, publisher, description, startYear, numIssues, image, characters_name, concepts_name, characters_id, concepts_id, numLikes) VALUES ('3012', 'The Spectacular Spider-Man Annual', 'And Men Shall Call Him Octopus!', '31', '<p>Annual series to the <a href="/the-spectacular-spider-man/4050-2870/" data-ref-id="4050-2870">Spectacular Spider-man</a> series. It lasted from 1979 until 1994.</p><h4>Collected Editions</h4><ul><li><a href="https://comicvine.gamespot.com/marvel-masterworks-the-amazing-spider-man-19-volum/4000-601796/" data-ref-id="4000-601796">Marvel Masterworks: The Amazing Spider-Man Vol. 19</a> (#1)</li><li><a href="https://comicvine.gamespot.com/marvel-masterworks-the-spectacular-spider-man-3-vo/4000-772344/" data-ref-id="4000-772344">Marvel Masterworks: The Spectacular Spider-Man Volume 3</a> (#1)</li><li><a href="https://comicvine.gamespot.com/marvel-masterworks-the-spectacular-spider-man-4-vo/4000-907536/" data-ref-id="4000-907536">Marvel Masterworks: The Spectacular Spider-Man Volume 4</a> (#2)</li><li><a href="/the-amazing-spider-man-the-complete-alien-costume-/4000-486880/" data-ref-id="4000-486880">The Amazing Spider-Man: The Complete Alien Costume Saga Book 2</a> (#4)</li><li><a href="https://comicvine.gamespot.com/spider-man-the-original-clone-saga/4050-41275/">Spider-Man: The Original Clone Saga</a> (#8)</li><li><a href="/amazing-spiderman-epic-collection-round-robin/4050-80960/" data-ref-id="4050-80960">Amazing Spider-Man Epic Collection: Round Robin</a> (#11)</li><li><a href="https://comicvine.gamespot.com/spider-man-vibranium-vendetta/4050-126605/">Spider-Man: Vibranium Vendetta</a> (#11 (Main Story))</li><li><a href="https://comicvine.gamespot.com/spider-man-the-new-warriors-the-hero-killers/4050-46628/" data-ref-id="4050-46628">Spider-Man &amp; the New Warriors: The Hero Killers</a> (#12)</li></ul><h4>Non-U.S. Collected Editions</h4><ul><li><a href="https://comicvine.gamespot.com/coleccionable-marvel-heroes-74-peter-parker-el-esp/4000-612311/">Coleccionable Marvel Héroes - Peter Parker, El Espectacular Spiderman: Punto de ruptura</a> (#4-5) (Spanish)</li><li><a href="https://comicvine.gamespot.com/coleccionable-marvel-heroes-80-peter-parker-el-esp/4000-612318/">Coleccionable Marvel Héroes - Peter Parker, El Espectacular Spiderman: La Caza de la Araña</a> (#6) (Spanish)</li><li><a href="https://comicvine.gamespot.com/coleccionable-marvel-heroes-58-el-asombroso-spider/4000-612266/">Coleccionable Marvel Héroes - El Asombroso Spiderman: La identidad del Duende</a> (#7) (Spanish)</li></ul>', '1979', '14', '{''icon_url'': ''https://comicvine.gamespot.com/a/uploads/square_avatar/11/117763/2430746-spectacularspider_manannual01.jpg'', ''medium_url'': ''https://comicvine.gamespot.com/a/uploads/scale_medium/11/117763/2430746-spectacularspider_manannual01.jpg'', ''screen_url'': ''https://comicvine.gamespot.com/a/uploads/screen_medium/11/117763/2430746-spectacularspider_manannual01.jpg'', ''screen_large_url'': ''https://comicvine.gamespot.com/a/uploads/screen_kubrick/11/117763/2430746-spectacularspider_manannual01.jpg'', ''small_url'': ''https://comicvine.gamespot.com/a/uploads/scale_small/11/117763/2430746-spectacularspider_manannual01.jpg'', ''super_url'': ''https://comicvine.gamespot.com/a/uploads/scale_large/11/117763/2430746-spectacularspider_manannual01.jpg'', ''thumb_url'': ''https://comicvine.gamespot.com/a/uploads/scale_avatar/11/117763/2430746-spectacularspider_manannual01.jpg'', ''tiny_url'': ''https://comicvine.gamespot.com/a/uploads/square_mini/11/117763/2430746-spectacularspider_manannual01.jpg'', ''original_url'': ''https://comicvine.gamespot.com/a/uploads/original/11/117763/2430746-spectacularspider_manannual01.jpg'', ''image_tags'': ''All Images''}', '[{"id": "Spider-Man"}, {"id": "Mary Jane"}, {"id": "Aunt May"}, {"id": "J. Jonah Jameson"}, {"id": "Hobie Brown"}, {"id": "Harry Osborn"}, {"id": "Flash Thompson"}, {"id": "Jean DeWolff"}, {"id": "Joy Mercado"}, {