INSERT INTO volumes (id, name, firstIssue, publisher, description, startYear, numIssues, image, characters_name, concepts_name, characters_id, concepts_id, numLikes) VALUES ('3033', 'The Legion of Super-Heroes', 'Psycho War', '10', '<p>Starring: <a href="/legion-of-super-heroes/4060-19241/" data-ref-id="4060-19241">The Legion of Super-Heroes</a>.</p><p>Continued from: <em><a href="/superboy-and-the-legion-of-super-heroes/4050-2894/" data-ref-id="4050-2894">Superboy and the Legion of Super-Heroes</a></em> (231-258).</p><p>Continued in: <em><a href="/tales-of-the-legion-of-super-heroes/4050-20776/" data-ref-id="4050-20776">Tales of the Legion of Super-Heroes</a></em> (314-354).</p><p>Annuals: <a href="/legion-of-super-heroes-annual/4050-3116/" data-ref-id="4050-3116"><em>Legion of Super-Heroes Annual</em></a> (1-3).</p><p>After a decade of playing second fiddle to Superboy in "<em>Superboy and the Legion of Super-Heroes</em>", the Legion finally made a grab for the title''s marquee when the boy of steel left the 30th Century. In this seminal issue, penned by Gerry Conway and drawn by Joe Staton, Superboy was confronted with a vision of the death of his adoptive parents when he battled with the misguided Rejis Thomak. As he set off for Smallville, Saturn Girl used her telepathic powers to insure that Superboy would stay in the past and therefore never have to confront a similar vision about his parents'' fate when he returned to the future.</p><h4>Collected Editions</h4><ul><li><a href="/legion-of-super-heroes-before-the-darkness-1-volum/4000-827114/" data-ref-id="4000-827114">Legion of Super-Heroes: Before the Darkness Volume One</a> (#260-271)</li><li><a href="/legion-of-super-heroes-the-curse-the-deluxe-editio/4050-76859/" data-ref-id="4050-76859">Legion of Super-Heroes: The Curse - The Deluxe Edition</a> (#297-313)</li><li><a href="https://comicvine.gamespot.com/dc-through-the-80s-the-experiments/4050-137001/">DC Through the 80''s: The Experiments</a> (#298)</li></