INSERT INTO volumes (id, name, firstIssue, publisher, description, startYear, numIssues, image, characters_name, concepts_name, characters_id, concepts_id, numLikes) VALUES ('3049', 'Epic Illustrated', 'The Answer; Homespun; Aware; For the next 60 seconds; Metamorphosis Odyssey, Chapter I: Aknaton; Lullabye of Bedlam; Elfspire; History of Human Absurdity Part 1; The Victor; Shakti; Convert; Heads; Metamorphosis Odyssey, Chapter II: Za!; Metamorphosis Ody', '31', '<p>Epic was a Marvel Comics magazine that featured groundbreaking artwork and stories that focused on a market for more mature readers. According to the Marvel Bullpen Bulletins from October 1979, the comic was originally supposed to be named "Odyssey", but was renamed after Marvel found out a comic with that name was already being published by another publisher. It was then renamed Epic instead. The series would become a huge success and was even followed by it''s own Epic imprint some months later. Many of the individual stories contained within have since been published in trade format among many different publishers.</p><h4>Collected Editions</h4><ul><li><em><a href="/dreadstar/4050-51175/" data-ref-id="4050-51175">Dreadstar</a> </em>Vol 1:<em> <a href="/dreadstar-1-the-metamorphosis-odyssey/4000-350328/" data-ref-id="4000-350328">Metamorphosis Odyssey</a> </em>(#1-9. <a href="/slg-publishing/4010-383/" data-ref-id="4010-383">SLG</a>, 2000) Vol. 2:<em><a href="/dreadstar-2-the-price/4000-350517/" data-ref-id="4000-350517"> The Price</a> </em>(#15. <a href="/slg-publishing/4010-383/" data-ref-id="4010-383">SLG</a> 2000)</li><li><a href="/shiny-beasts/4050-34709/" data-ref-id="4050-34709"><em>Shiny Beasts </em></a>(#2, #4-6, #8, #19, #25, #28-29, #34. <a href="/king-hell/4010-469/" data-ref-id="4010-469">King Hell</a>, 2007)</li><li><a href="https://comicvine.gamespot.com/weirdworld-the-dragonmaster-of-klarn/4050-120142/">Weirdworld: The Dragonmaster of Klarn</a> (#9 &amp; 11-13)</li><li><a href="/dr-watchstop-adventures-in-time-and-space/4050-49321/" data-ref-id="4050-49321"><em>Dr. Watchstop: Adventures in Time and Space</em></a> (#10,#14,#17,#21,#29, #33-34. <a href="/eclipse/4010-285/" data-ref-id="4010-285">Eclipse</a>, 1989)</li><li><em>At Home With Ricky Geary</em> (#16, #18, #26, #30. <a href="/fantagraphics/4010-309/" data-ref-id="4010-309">Fantagraphics</a>, 1985)</li><li><a href="/generation-zero/4050-78531/" data-ref-id="4050-78531"><em>Generation Zero</em></a> (#17-24. <a href="/dc-comics/4010-10/" data-ref-id="4010-10">DC Comics</a>, 1991)</li><li><em><a href="/fantastic-four-by-john-byrne-omnibus/4050-43976/" data-ref-id="4050-43976">Fantastic Four by John Byrne Omnibus</a>: <a href="/fantastic-four-by-john-byrne-omnibus-2-volume-2/4000-435863/" data-ref-id="4000-435863">Volume 2</a></em> (#26-34. <a href="/marvel/4010-31/" data-ref-id="4010-31">Marvel</a>, 2013)</li><li><em>Cobalt-60</em> (#27-31. <a href="/starblaze-graphics/4010-3411/" data-ref-id="4010-3411">Starblaze</a>, 1988)</li><li><a href="/marvel-graphic-novel-2-elric-the-dreaming-city/4000-21788/" data-ref-id="4000-21788">Marvel Graphic Novel #2 - Elric: The Dreaming City</a> (#3-4. <a href="/marvel/4010-31/" data-ref-id="4010-31">Marvel</a>, 1982)</li><li><a href="/the-michael-moorcock-library-3-elric-the-dreaming-/4000-539300/" data-ref-id="4000-539300">The Michael Moorcock Library #3 - Elric: The Dreaming City</a> (#3-4. <a href="/titan-comics/4010-4212/" data-ref-id="4010-4212">Titan Comics</a>, 2016)</li><li><a href="/elric-the-weird-of-the-white-wolf/4050-3708/" data-ref-id="4050-3708">Elric: The Weird of the White Wolf #2-3</a> (#14, <a href="/first/4010-324/" data-ref-id="4010-324">First</a>, 1986)</li><li><a href="/elric-the-weird-of-the-white-wolf/4050-38442/" data-ref-id="4050-38442">Elric: The Weird of the White Wolf</a> (#14, <a href="/first/4010-324/" data-ref-id="4010-324">First</a>, 1990)</li><li><a href="/the-michael-moorcock-library-4-elric-the-weird-of-/4000-566778/" dat