INSERT INTO volumes (id, name, firstIssue, publisher, description, startYear, numIssues, image, characters_name, concepts_name, characters_id, concepts_id, numLikes) VALUES ('3052', 'Moon Knight', 'The Macabre Moon Knight', '31', '<p>Moon Knight''s first on-going series. It sets up much of his rogues gallery and delves deeper into Marc Spector and his different personas.</p><p>Continues in the <a href="/moon-knight-fist-of-khonshu/4050-3492/" data-ref-id="4050-3492">Moon Knight: Fist of Khonshu</a> mini-series.</p><h4>Collected Editions</h4><ul><li><a href="/moon-knight-epic-collection-bad-moon-rising/4050-77333/" data-ref-id="4050-77333">Moon Knight Epic Collection: Bad Moon Rising</a> (#1-4)</li><li><a href="https://comicvine.gamespot.com/moon-knight-omnibus-1-volume-1/4000-824088/" data-ref-id="4000-824088">Moon Knight Omnibus Volume 1</a> (#1-20)</li><li><a href="https://comicvine.gamespot.com/moon-knight-reincarnations/4050-101627/" data-ref-id="4050-101627">Moon Knight: Reincarnations</a> (#2)</li><li><a href="/moon-knight-epic-collection-shadows-of-the-moon/4050-85440/" data-ref-id="4050-85440">Moon Knight Epic Collection: Shadows of the Moon</a> (#5-23)</li><li><a href="/marvel-masterworks-brother-voodoo-1-volume-1/4000-851632/" data-ref-id="4000-851632">Marvel Masterworks: Brother Voodoo Volume 1</a> (#21)</li><li><a href="https://comicvine.gamespot.com/moon-knight-epic-collection-final-rest/4050-116075/">Moon Knight Epic Collection: Final Rest</a> (#24-38)</li><li><a href="https://comicvine.gamespot.com/moon-knight-omnibus-2-volume-2/4000-941422/" data-ref-id="4000-941422">Moon Knight Omnibus Volume 2</a> (#21-38)</li></ul><h4>Non-U.S. Collected Editions</h4><ul><li><a href="https://comicvine.gamespot.com/coleccionable-marvel-heroes-65-caballero-luna-1-cu/4000-612301/">Coleccionable Marvel Héroes - Caballero Luna 1: Cuenta atrás hacia la oscuridad</a> (#1-15) (Spanish)</li><li><a href="https://comicvine.gamespot.com/coleccionable-marvel-heroes-71-caballero