INSERT INTO volumes (id, name, firstIssue, publisher, description, startYear, numIssues, image, characters_name, concepts_name, characters_id, concepts_id, numLikes) VALUES ('3053', 'The Savage She-Hulk', 'The She-Hulk Lives', '31', '<p>The series that introduced She-Hulk! It started out as just a female version of the angry-mad Hulk. In later series, She-Hulk got a grip on her mind.</p><h4>Writers</h4><ul><li><a href="/stan-lee/4040-40467/" data-ref-id="4040-40467">Stan Lee</a> (#1)</li><li><a href="/david-anthony-kraft/4040-42922/" data-ref-id="4040-42922">David Anthony Kraft</a> (#2-25)</li></ul><h4>Related Issues:</h4><ul><li><a href="https://comicvine.gamespot.com/savage-she-hulk-no-1-facsimile-edition/4050-150837/">Savage She-Hulk No. 1 Facsimile Edition</a> (reprints #1)</li></ul><h4>Collected Editions</h4><ul><li><a href="/essential-savage-she-hulk/4050-56871/" data-ref-id="4050-56871">The Essential Savage She-Hulk</a></li><li><a href="/the-savage-she-hulk-omnibus/4050-148450/" data-ref-id="4050-148450">The Savage She-Hulk Omnibus</a></li><li><a href="https://comicvine.gamespot.com/marvel-masterworks-the-savage-she-hulk-1-volume-1/4000-612044/" data-ref-id="4000-612044">Marvel Masterworks: The Savage She-Hulk Volume 1</a> (#1-14)</li><li><a href="https://comicvine.gamespot.com/marvel-verse-she-hulk/4050-137620/">Marvel-Verse: She-Hulk</a> (#1)</li><li><a href="https://comicvine.gamespot.com/morbius-the-living-vampire-omnibus/4050-128226/">Morbius the Living Vampire Omnibus</a> (#9-12)</li><li><a href="https://comicvine.gamespot.com/morbius-epic-collection-the-end-of-a-living-vampir/4050-136029/">Morbius Epic Collection: The End Of A Living Vampire</a> (#9-12)</li><li><a href="https://comicvine.gamespot.com/man-wolf-the-complete-collection/4050-121739/">Man-Wolf: The Complete Collection</a> (#13-14)</li><li><a href="/marvel-masterworks-the-savage-she-hulk-2-volume-2/4000-708135/" data-ref-id="4000-708135">Marvel Masterworks: The Savage She-Hulk Volume 2</a> (#15-25)</li></ul>', '1980', '25', '{''icon_url'': ''https://comicvine.gamespot.com/a/uploads/square_avatar/0/4/18037-3053-20177-1-savage-she-hulk-the.jpg'', ''medium_url'': ''https://comicvine.gamespot.com/a/uploads/scale_medium/0/4/18037-3053-20177-1-savage-she-hulk-the.jpg'', ''screen_url'': ''https://comicvine.gamespot.com/a/uploads/screen_medium/0/4/18037-3053-20177-1-savage-she-hulk-the.jpg'', ''screen_large_url'': ''https://comicvine.gamespot.com/a/uploads/screen_kubrick/0/4/18037-3053-20177-1-savage-she-hulk-the.jpg'', ''small_url'': ''https://comicvine.gamespot.com/a/uploads/scale_small/0/4/18037-3053-20177-1-savage-she-hulk-the.jpg'', ''super_url'': ''https://comicvine.gamespot.com/a/uploads/scale_large/0/4/18037-3053-20177-1-savage-she-hulk-the.jpg'', ''thumb_url'': ''https://comicvine.gamespot.com/a/uploads/scale_avatar/0/4/18037-3053-20177-1-savage-she-hulk-the.jpg'', ''tiny_url'': ''https://comicvine.gamespot.com/a/uploads/square_mini/0/4/18037-3053-20177-1-savage-she-hulk-the.jpg'', ''original_url'': ''https://comicvine.gamespot.com/a/uploads/original/0/4/18037-3053-20177-1-savage-she-hulk-the.jpg'', ''image_tags'': ''All Images''}', '[{"id": "She-Hulk"}, {"id": "Dr. Daniel Ridge"}, {"id": "Morris Walters"}, {"id": "Buck Bukowski"}, {"id": "Richard Rory"}, {"id": "Ralphie Hutchins"}, {"id": "Beverly Cross"}, {"id": "Doc"}, {"id": "Lou Monkton"}, {"id": "Shade"}, {"id": "Mrs. Jonathan Ridge"}, {"id": "Nicholas Trask"}, {"id": "Morbius"}, {"id": "Dr. Jonathan Ridge"}, {"id": "Hellcat"}, {"id": "Garth Of Mournhelm"}, {"id": "John Jameson"}, {"id": "Hulk"}, {"id": "Lambert"}, {"id": "Gorjoon"}, {"id": "The Word"}, {"id": "Ultima"}, {"id": "Professor Slaughter"}, {"id": "Purple Ogres Of La Hacienda"}, {"id": "Valkyrie"}, {"id": "Man-Thing"}, {"id": "Angelo"}, {"id": "Sagittarius (LMD)"}, {"id": "Aquarius (LMD)"}, {"id": "Taurus (LMD)"}, {"id": "Gemini (LMD)"}, {"id": "Jill Stevens"}, {"id": "Libra (LMD)"}, {"id": "Elaine Ann Walters"}, {"id": "She-Droid"}, {"id": "Microwave"}, {"id": "F A Schist"}, {"id": "Dahlia"}, {"id": "Igor Drenkov"}, {"id": "Jimmy Carter"}, {"id": "Grappler"}, {"id": "Behemoth"}, {"id": "Jake Fury"}, {"id": "Nighthawk"}, {"id": "Nick Fury"}, {"id": "Rick Jones"}, {"id": "Iron Man"}]', '[{"id": "Homage Covers"}]', '[{"id": 1449}, {"id": 12616}, {"id": 12614}, {"id": 69549}, {"id": 12634}, {"id": 69550}, {"id": 69551}, {"id": 69546}, {"id": 32948}, {"id": 69547}, {"id": 33917}, {"id": 69545}, {"id": 6722}, {"id": 28516}, {"id": 3316}, {"id": 80354}, {"id": 4456}, {"id": 2267}, {"id": 33460}, {"id": 33461}, {"id": 33645}, {"id": 33646}, {"id": 33788}, {"id": 33789}, {"id": 6809}, {"id": 4988}, {"id": 178946}, {"id": 87554}, {"id": 87563}, {"id": 87560}, {"id": 87555}, {"id": 69552}, {"id": 87564}, {"id": 80352}, {"id": 81143}, {"id": 69548}, {"id": 36578}, {"id": 33414}, {"id": 27723}, {"id": 21941}, {"id": 14452}, {"id": 12626}, {"id": 5076}, {"id": 4832}, {"id": 3202}, {"id": 2248}, {"id": 1455}]', '[{"id": 43734}]', '0');
INSERT INTO volumes (id, name, firstIssue, publisher, description, startYear, numIssues, image, characters_name, concepts_name, characters_id, concepts_id, numLikes) VALUES ('3070', 'All-Star Squadron', 'The World on Fire!', '10', '<p>"Come with us now to Earth-Two, and the awesome origin of the <a href="/all-star-squadron/4060-41753/" data-ref-id="4060-41753">All-Star Squadron</a>!"</p><p><a href="/roy-thomas/4040-42067/" data-ref-id="4040-42067">Roy Thomas</a>, <a href="/rich-buckler/4040-14053/" data-ref-id="4040-14053">Rich Buckler</a>, <a href="/jerry-ordway/4040-2908/" data-ref-id="4040-2908">Jerry Ordway</a> (credited here as <em>Jeremiah Ordway</em>!) along with editor <a href="/len-wein/4040-41457/" data-ref-id="4040-41457">Len Wein</a>, letterer <a href="/john-costanza/4040-9421/" data-ref-id="4040-9421">John Costanza</a> and colorist <a href="/carl-gafford/4040-7825/" data-ref-id="4040-7825">Carl Gafford</a> begin the wartime adventures of the Golden-Age heroes of the DC Universe. Writer <strong>Roy Thomas</strong> is no stranger to <a href="https://comicvine.gamespot.com/world-war-ii/4015-56025/" data-ref-id="4015-56025">World War II</a>, or wartime comic book super-heroes having come off Marvel''s WWII super-team, <a href="/invaders/4060-25865/" data-ref-id="4060-25865">The Invaders</a>.</p><p>The world of <a href="https://comicvine.gamespot.com/earth-2/4015-56462/" data-ref-id="4015-56462">Earth-2</a> was at war. In a dimension not unlike that of the Justice League on Earth-1, the greatest heroes of the 1940s had banded together to form the Justice Society of America, but even that wasn''t enough to battle the Axis powers plaguing their society. So, at the behest of President Franklin D. Roosevelt, a new, larger team was created to help unite the war torn country. The massive All-Star Squadron was formed, setting up their headquarters in the <a href="/perisphere-and-trylon/4020-56251/" data-ref-id="4020-56251">Perisphere</a> at the heart of New York''s World''s Fair.</p><p>The creative team of writer Roy Thomas and artist Rich Buckler on "All-Star Squadron" offered readers a nostalgic glimpse back in time, albeit through the slightly distorted lens of Earth-2''s history. In this popular series that ran for 67 issues, readers were treated not only to the adventures of the more familiar Justice Society, but also to every other mystery man of the time and dozens of minor heroes from DC''s Golden Age, including the speedster Johnny Quick, the patriotic Liberty Belle, power houses Robotman and Commander Steel, and the 1940s versions of Batman and Robin.</p><p>With Thomas''comprehensive knowledge of the heroes and history of World War II era Americana, the All-Star Squadron was a certifiable hit, even if the Earth-2 shattering events of DC''s tumultuous "<a href="/crisis-on-infinite-earths/4050-3441/" data-ref-id="4050-3441"><em>Crisis on Infinite Earths</em></a>" <a href="/mini-series/4015-56281/" data-ref-id="4015-56281">maxi-series</a> of the mid-1980s took a toll on the book''s continuity.</p><p>Click here for the annuals of the <a href="/all-star-squadron-annual/4050-3106/" data-ref-id="4050-3106">All-Star Squadron</a>.</p><h4>Collected Editions</h4><ul><li><a href="/crisis-on-infinite-earths-companion-deluxe-edition/4000-691351/" data-ref-id="4000-691351">Crisis On Infinite Earths Companion Deluxe Edition Volume 1</a> (#50-60)</li></ul><h4>Non-U.S. Collected Editions</h4><ul><li><a href="https://comicvine.gamespot.com/justice-league-of-america-crisis-6-band-6-1981-198/4000-667900/">Justice League of America: Crisis - Band 6: 1981-1982</a> (#14-15) (German)</li></ul>', '1981', '67', '{''icon_url'': ''https://comicvine.gamespot.com/a/uploads/square_avatar/0/4/19233-3070-21477-1-all-star-squadron.jpg'', ''medium_url'': ''https://comicvine.gamespot.com/a/uploads/scale_medium/0/4/19233-3070-21477-1-all-star-squadron.jpg'', ''screen_url'': ''https://comicvine.gamespot.com/a/uploads/screen_medium/0/4/19233-3070-21477-1-