INSERT INTO volumes (id, name, firstIssue, publisher, description, startYear, numIssues, image, characters_name, concepts_name, characters_id, concepts_id, numLikes) VALUES ('3082', 'Bizarre Adventures', 'I Got the Yo-Yo... You Got the String', '31', '<p>Continues from <a href="/marvel-preview/4050-2774/" data-ref-id="4050-2774">Marvel Preview</a> #24</p><p>With issue #25, Marvel''s black-and-white showcase magazine <b>MARVEL PREVIEW</b> was re-titled <b>BIZARRE ADVENTURES</b>. Content remained more or less the same, with themes changing every issue. The series continued to feature stories starring new and established Marvel Universe characters (some left over from other canceled series), new stand-alone stories, and adaptions of prose fiction. The final issue, #34, was published in a color comic book format, rather than as a black-and-white magazine.</p><h4>Collected Editions</h4><ul><li><a href="https://comicvine.gamespot.com/black-widow-epic-collection-the-coldest-war/4050-130989/">Black Widow Epic Collection: The Coldest War</a> (#25)</li></ul><h4>Non-U.S. Collected Editions</h4><ul><li><a href="https://comicvine.gamespot.com/coleccion-frank-miller-el-universo-marvel-segun-fr/4050-105405/">Colección Frank Miller. El Universo Marvel según Frank Miller</a> (#28 &amp; #31) (Spanish)</li></ul>', '1981', '10', '{''icon_url'': ''https://comicvine.gamespot.com/a/uploads/square_avatar/0/4/18881-3082-21102-1-bizarre-adventures.jpg'', ''medium_url'': ''https://comicvine.gamespot.com/a/uploads/scale_medium/0/4/18881-3082-21102-1-bizarre-adventures.jpg'', ''screen_url'': ''https://comicvine.gamespot.com/a/uploads/screen_medium/0/4/18881-3082-21102-1-bizarre-adventures.jpg'', ''screen_large_url'': ''https://comicvine.gamespot.com/a/uploads/screen_kubrick/0/4/18881-3082-21102-1-bizarre-adventures.jpg'', ''small_url'': ''https://comicvine.gamespot.com/a/uploads/scale_small/0/4/18881-3082-21102-1-bizarre-adventures.jpg'', ''super_url'': ''https://comicvine.gamespot.com/a/upload