INSERT INTO volumes (id, name, firstIssue, publisher, description, startYear, numIssues, image, characters_name, concepts_name, characters_id, concepts_id, numLikes) VALUES ('3083', 'Dazzler', 'So Bright This Star', '31', '<p>Published from the early to mid 80''s, ''Dazzler'' was an attempt on Marvel Comics'' part to draw a female audience by putting a title on the stands that was half superhero action and part soap opera. Or, at least, that''s what the series was like for most of its first two years. Towards the end of its second year it took a turn towards being more soap opera than superhero book. In the series'' final 5 issues it made a return to superheroics, with Dazzler''s well-known blue costume making it''s first appearance in issue 38.</p><p>Issue 1 of Dazzler was the first ever "Direct Market Only" comic, giving the book a large hype at the time, since a lot of readers whom bought their comics at newsstands, did not manage to get a copy. There was also a graphic novel published named <a href="https://www.comicvine.com/marvel-graphic-novel-12-dazzler-the-movie/4000-108265/">Marvel Graphic Novel issue 12: Dazzler the Movie</a>, set between issues 34 and 35 of this series. Years later, a special <a href="https://comicvine.gamespot.com/dazzler/4050-33347/">Dazzler</a> one-shot was published, which was an aftermath of the Necrosha-X crossover as well as a special homage to this original series.</p><h4>Collected Editions</h4><ul><li><a href="/marvel-masterworks-dazzler-1-volume-1/4000-742426/" data-ref-id="4000-742426">Marvel Masterworks: Dazzler Volume 1</a> (#1-13)</li><li><a href="/marvel-masterworks-dazzler-2-volume-2/4000-839820/" data-ref-id="4000-839820">Marvel Masterworks: Dazzler Volume 2</a> (#14-25)</li></ul><h4>Non-U.S. Collected Editions</h4><ul><li><a href="https://comicvine.gamespot.com/coleccionable-marvel-heroes-53-secret-wars-ii-quie/4000-612261/">Coleccionable Marvel Héroes - Secret Wars II: ¿Quién es el Todopoderoso?</a> (#40) (Spanish)</li>