INSERT INTO volumes (id, name, firstIssue, publisher, description, startYear, numIssues, image, characters_name, concepts_name, characters_id, concepts_id, numLikes) VALUES ('3087', 'Ka-Zar the Savage', 'A New Dawn...A New World!', '31', '<p>Ka-Zar''s second and most critically acclaimed own ongoing comic-book series. This time, the title is officialy named "Ka-Zar the Savage" instead of just Ka-Zar. The series started out in 1981, not 4 years after the first ongoing <a href="../../ka-zar/49-2692/" rel="nofollow "> Ka-Zar</a> series ended, and lasted for 34 issues.</p><h4>Collected Editions</h4><ul><li><a href="https://comicvine.gamespot.com/kazar-savage-dawn/4050-98060/" data-ref-id="4050-98060">Ka-Zar: Savage Dawn</a> (#1-5)</li><li><a href="https://comicvine.gamespot.com/ka-zar-the-savage-omnibus/4050-136161/">Ka-Zar the Savage Omnibus</a> (#1-34)</li></ul>', '1981', '34', '{''icon_url'': ''https://comicvine.gamespot.com/a/uploads/square_avatar/0/4/18955-3087-21180-1-ka-zar-the-savage.jpg'', ''medium_url'': ''https://comicvine.gamespot.com/a/uploads/scale_medium/0/4/18955-3087-21180-1-ka-zar-the-savage.jpg'', ''screen_url'': ''https://comicvine.gamespot.com/a/uploads/screen_medium/0/4/18955-3087-21180-1-ka-zar-the-savage.jpg'', ''screen_large_url'': ''https://comicvine.gamespot.com/a/uploads/screen_kubrick/0/4/18955-3087-21180-1-ka-zar-the-savage.jpg'', ''small_url'': ''https://comicvine.gamespot.com/a/uploads/scale_small/0/4/18955-3087-21180-1-ka-zar-the-savage.jpg'', ''super_url'': ''https://comicvine.gamespot.com/a/uploads/scale_large/0/4/18955-3087-21180-1-ka-zar-the-savage.jpg'', ''thumb_url'': ''https://comicvine.gamespot.com/a/uploads/scale_avatar/0/4/18955-3087-21180-1-ka-zar-the-savage.jpg'', ''tiny_url'': ''https://comicvine.gamespot.com/a/uploads/square_mini/0/4/18955-3087-21180-1-ka-zar-the-savage.jpg'', ''original_url'': ''https://comicvine.gamespot.com/a/uploads/original/0/4/18955-3087-21180-1-ka-zar-the-savage.jpg'', ''image_tags'': ''All Images''}