INSERT INTO volumes (id, name, firstIssue, publisher, description, startYear, numIssues, image, characters_name, concepts_name, characters_id, concepts_id, numLikes) VALUES ('3088', 'Marvel Super-Heroes', NULL, '2812', '<p>In 1979 <a href="/marvel-uk/4010-2812/" data-ref-id="4010-2812">Marvel UK''s</a> then-longest running weekly title, <a href="/marvel-comic/4050-47378/" data-ref-id="4050-47378">Marvel Comic</a> (originally titled <a href="/the-mighty-world-of-marvel/4050-33875/" data-ref-id="4050-33875">Mighty World of Marvel</a>) came to an end with #352, cover dated 25th July, and was merged into Spider-Man Comic (the second longest running Marvel UK title), while at the same time being relaunched as the monthly title Marvel Super-Heroes, which continued Marvel Comics numbering. In May 1983''s #397, Marvel Super-Heroes was cancelled and merged into The Daredevils.</p><p>Issue''s <a href="https://comicvine.gamespot.com/best-of-marvel-capitan-britania/4050-41906/" data-ref-id="4050-41906">#387-388</a> have been translated into Spanish.</p>', '1979', '45', '{''icon_url'': ''https://comicvine.gamespot.com/a/uploads/square_avatar/0/77/1564078-uk_msh_353.jpg'', ''medium_url'': ''https://comicvine.gamespot.com/a/uploads/scale_medium/0/77/1564078-uk_msh_353.jpg'', ''screen_url'': ''https://comicvine.gamespot.com/a/uploads/screen_medium/0/77/1564078-uk_msh_353.jpg'', ''screen_large_url'': ''https://comicvine.gamespot.com/a/uploads/screen_kubrick/0/77/1564078-uk_msh_353.jpg'', ''small_url'': ''https://comicvine.gamespot.com/a/uploads/scale_small/0/77/1564078-uk_msh_353.jpg'', ''super_url'': ''https://comicvine.gamespot.com/a/uploads/scale_large/0/77/1564078-uk_msh_353.jpg'', ''thumb_url'': ''https://comicvine.gamespot.com/a/uploads/scale_avatar/0/77/1564078-uk_msh_353.jpg'', ''tiny_url'': ''https://comicvine.gamespot.com/a/uploads/square_mini/0/77/1564078-uk_msh_353.jpg'', ''original_url'': ''https://comicvine.gamespot.com/a/uploads/original/0/77/1564078-uk_msh_353.jpg'',