INSERT INTO volumes (id, name, firstIssue, publisher, description, startYear, numIssues, image, characters_name, concepts_name, characters_id, concepts_id, numLikes) VALUES ('3092', 'The Uncanny X-Men', 'Mind Out of Time!', '31', '<p>This is a continuation of <a href="/stan-lee/4040-40467/" data-ref-id="4040-40467">Stan Lee''s</a> and <a href="/jack-kirby/4040-5614/" data-ref-id="4040-5614">Jack Kirby''s</a> original <a href="/x-men/4050-2133/" data-ref-id="4050-2133">The X-Men</a> (Vol. 1). Beginning with issue #114 the descriptive "Uncanny" was added to the cover treatment but it wasn''t until issue #142 that the volume''s official name, via the indicia, was permanently changed to <i>Uncanny X-Men.</i></p><p>The title has had many creative influences over the years, but <a href="/chris-claremont/4040-40468/" data-ref-id="4040-40468"> Chris Claremont</a> was probably the force that drove the title through many of its historic changes, truly bringing it from "the world''s strangest teens" into their new status as a team of mutants fighting in a "world that fears and hates them." During his legendary 15 year run, he gave us characters and stories such as Phoenix/Dark Phoenix, the Hellfire Club, the New Mutants, X-Factor, the Mutant Massacre, Inferno and Jubilee and numerous other historic heroes and events. This epic run ended after editorial disputes in 1991.</p><p>For the Uncanny X-Men Post-<a href="/schism/4045-56404/" data-ref-id="4045-56404">Schism</a>, see <a href="/uncanny-x-men/4050-43785/" data-ref-id="4050-43785"> Uncanny X-Men (Vol. 2)</a>.</p><h4>Writers</h4><h4>Pencillers</h4><ul><li>John Romita, Jr #175–185, 187–197, 199–200, 202–203, 206–211, 287, 300–302, 304, 306–311 (TOT 43)</li><li>John Byrne #108–109, 111–143 (TOT 35)</li><li>Marc Silvestri #218, 220-222, 224-227, 229-230, 232-234, 236, 238-244, 246-247, 249-251, 253-255, 259-261, 273 (TOT 33)</li><li>Greg Land #500–503, 508–511, 515–521, 530–534, 540–544 (TOT 25)</li><li>Joe Madureira #312–313, 316–317, 325–326, 328–330, 332, 334–338, 340–343, 345–348, 350 (TOT 24)</li><li>Salvador Larroca #338, #387–392, #437–443, #487–491 (TOT 19)</li><li>Billy Tan #338, 387–392, 437–443, 487–491 (TOT 19)</li><li>Jim Lee #248, 256–258, 267–277 (TOT 15)</li><li>Alan Davis #213, 215, 444–447, 450–451, 455–459, 462–463 (TOT 15)</li><li>Whilce Portacio #281–286, 289–290, 526–529 (TOT 12)</li></ul><h4>Collected Editions</h4><ul><li>Issues #142-143 are collected in <a href="/x-men-days-of-future-past/4050-34959/" data-ref-id="4050-34959"> X-Men: Days of the Future Past</a></li><li><a href="https://comicvine.gamespot.com/uncanny-x-men-omnibus-3-volume-3/4000-516096/" data-ref-id="4000-516096">Uncanny X-Men Omnibus Volume 3</a> (#154-175)</li><li><a href="https://comicvine.gamespot.com/x-men-starjammers-by-dave-cockrum/4050-122501/">X-Men: Starjammers by Dave Cockrum</a> (#154-158 &amp; 161-167)</li><li><a href="https://comicvine.gamespot.com/captain-marvel-vs-rogue/4050-136150/">Captain Marvel vs. Rogue</a> (#158, 171 &amp; 269)</li><li><a href="https://comicvine.gamespot.com/captain-marvel-the-many-lives-of-carol-danvers/4050-129471/">Captain Marvel: The Many Lives of Carol Danvers</a> (#164)</li><li><a href="https://comicvine.gamespot.com/new-mutants-epic-collection-renewal/4050-99448/" data-ref-id="4050-99448">New Mutants Epic Collection: Renewal</a> (#167)</li><li>Issues #168-176 are collected in <a href="/uncanny-x-men-from-the-ashes/4050-30242/" data-ref-id="4050-30242"> From the Ashes</a></li><li><a href="https://comicvine.gamespot.com/x-men-we-are-the-x-men/4050-35334/">X-Men: We Are the X-Men</a> (#171, 200, 213, 267 &amp; 287)</li><li><a href="https://comicvine.gamespot.com/decades-marvel-in-the-80s-awesome-evolutions/4050-118846/">Decades: Marvel In The ''80s: Awesome Evolutions</a> (#173)</li><li><a href="https://comicvine.gamespot.com/marvel-masterworks-the-uncanny-x-men-10-volume-10/4000-580758/" data-ref-id="4000-580758">Marvel Masterworks: The Uncanny X-Men Volum