INSERT INTO volumes (id, name, firstIssue, publisher, description, startYear, numIssues, image, characters_name, concepts_name, characters_id, concepts_id, numLikes) VALUES ('3105', 'Adventure Comics', 'Fang Gow of China', '10', '<p>Issues 12-31 are indexed in <a href="/new-adventure-comics/4050-18546/" data-ref-id="4050-18546">New Adventure Comics</a>. The series was relaunched decades after its conclusion, with <a href="/adventure-comics/4050-25643/" data-ref-id="4050-25643">Adventure Comics</a> a series featuring the age-old technique of dual-numbering so that although it began it''s own numbering of the series, it also displays the numbering on the cover as if the series were still ongoing from this series started back in ''35.</p><h3>Collected Editions</h3><ul><li><a href="/all-star-comics-archives-volume-1/4000-299160/" data-ref-id="4000-299160">JSA All Stars Archives Vol. 1</a> (#48-52)</li><li><a href="/the-adventures-of-superboy/4050-35819/" data-ref-id="4050-35819">The Adventures of Superboy Vol. 1</a> (#103-121, <a href="/more-fun-comics/4050-19320/" data-ref-id="4050-19320">More Fun Comics</a> #101-107)</li><li><a href="https://comicvine.gamespot.com/green-arrow-the-golden-age-omnibus-1-volume-1/4000-649704/" data-ref-id="4000-649704">Green Arrow: The Golden Age Omnibus Volume 1</a> (#103-117)</li><li><a href="/showcase-presents-green-arrow/4050-38845/" data-ref-id="4050-38845">Showcase Presents: Green Arrow </a>(#250-266, 268-269)</li><li><a href="/aquaman-archives/4050-23395/" data-ref-id="4050-23395">Aquaman Archives Vol. 1</a> (#260-280, 282)</li><li><a href="https://comicvine.gamespot.com/superman-tales-from-the-phantom-zone/4050-43665/">Superman: Tales from the Phantom Zone</a> (#283 &amp; 300)</li><li><a href="/the-legion-of-super-heroes-archives-volume-two/4000-140324/" data-ref-id="4000-140324">Legion of Super-Heroes Archives Vol. 2</a> (#306-317)</li><li><a href="/the-legion-of-super-heroes-archives-volume-three/4000-46448/" data-ref-id="4000-46448">Legion of Super-Heroes Archives Vol. 3</a> (#318-328)</li><li><a href="https://comicvine.gamespot.com/the-legion-of-super-heroes-archives-5-volume-5/4000-46450/" data-ref-id="4000-46450">Legion of Super-Heroes Archives Vol. 4</a> (#329-339)</li><li><a href="/the-legion-of-super-heroes-archives-5-volume-5/4000-46450/" data-ref-id="4000-46450">Legion of Super-Heroes Archives Vol. 5</a> (#340-349)</li><li><a href="/the-legion-of-super-heroes-archives-volume-six/4000-48146/" data-ref-id="4000-48146">Legion of Super-Heroes Archives Vol. 6</a> (#350-358)</li><li><a href="/the-legion-of-super-heroes-archives-volume-seven/4000-48147/" data-ref-id="4000-48147">Legion of Super-Heroes Archives Vol. 7</a> (#359-367)</li><li><a href="/the-legion-of-super-heroes-archives-volume-eight/4000-48148/" data-ref-id="4000-48148">Legion of Super-Heroes Archives Vol. 8</a> (#368-376)</li><li><a href="/the-legion-of-super-heroes-archives-volume-nine/4000-48149/" data-ref-id="4000-48149">Legion of Super-Heroes Archives Vol. 9</a> (#377-380)</li><li><a href="/aquaman-death-of-a-prince/4050-41218/" data-ref-id="4050-41218">Aquaman: Death of a Prince</a> (#435-437, 441-466)</li><li><a href="https://comicvine.gamespot.com/new-gods-by-gerry-conway/4050-126349/">New Gods by Gerry Conway</a> (#459-460)</li><li><a href="https://comicvine.gamespot.com/deadman-omnibus/4050-132454/">Deadman Omnibus</a> (#459-466)</li></ul><h3>Non-U.S. Collected Editions</h3><ul><li><a href="https://comicvine.gamespot.com/aquaman-anthologie/4050-116277/">Aquaman Anthologie</a> (#174, #260 #269, #444, #452 &amp; #475) (German)</li></ul>', '1938', '472', '{''icon_url'': ''https://comicvine.gamespot.com/a/uploads/square_avatar/0/3125/220967-3105-116357-1-adventure-comics.jpg'', ''medium_url'': ''https://comicvine.gamespot.com/a/uploads/scale_medium/0/3125/220967-3105-116357-1-adventure-comics.jpg'', ''screen_url'': ''https://comicvine.gamespot.com/a/uploads/screen_medium/0/3125/220967-3105-116357-1-adventure-comics.j