INSERT INTO volumes (id, name, firstIssue, publisher, description, startYear, numIssues, image, characters_name, concepts_name, characters_id, concepts_id, numLikes) VALUES ('3109', 'Batman Annual', '1,001 Secrets Of Batman And Robin', '10', '<p>The first <a href="/batman/4050-796/" data-ref-id="4050-796">Batman</a> annual was released in 1961. Originally, despite the name annual, the series often released two comics per calendar year. The first 7 annuals were reprints of select stories from the late 50''s and early 60''s and contained no new stories. There is an 18 year gap between the release of Batman annual 7 and 8.</p><h4>Writers</h4><ul><li>Mike W. Barr #8-9</li><li>Doug Moench #10, 17-21</li><li>Alan Moore #11</li><li>Max Allan Collins #11</li><li>Mike Baron #12</li><li>Robert Greenberger #12</li><li>Christopher Priest #13</li><li>Kevin Dooley #13</li><li>Andrew Helfer #14</li><li>Alan Grant #15-16</li><li>John Wagner #16</li><li>Devin Grayson #22</li><li>Chuck Dixon #23</li><li>John Ostrander #24</li><li>Judd Winick #25</li><li>Jim Starlin #25</li><li>Peter Milligan #26</li><li>Fabian Nicieza #27</li><li>Derek Fridolfs #27</li><li>Dustin Nguyen #27</li><li>Mandy McMurray #27</li><li>David Hine #28</li><li>Paul Tobin #28</li><li>Kyle Higgins #28</li></ul><h4>Collected Editions</h4><ul><li><a href="/batman-second-chances/4050-83297/" data-ref-id="4050-83297">Batman: Second Chances</a> (#11)</li><li><a href="/legends-of-the-dark-knight-norm-breyfogle-1-volume/4000-495783/" data-ref-id="4000-495783">Legends of the Dark Knight: Norm Breyfogle Volume 1</a> (#11-12)</li><li><a href="/batman-the-caped-crusader-1-volume-1/4000-679967/" data-ref-id="4000-679967">Batman: The Caped Crusader Volume 1</a> (#12)</li><li><a href="/batman-the-caped-crusader-2-volume-2/4000-700637/" data-ref-id="4000-700637">Batman: The Caped Crusader Volume 2</a> (#13)</li><li><a href="/batman-the-caped-crusader-3-volume-3/4000-719301/" data-ref-id="4000-719301">Batman: The Caped Crusader Volume 3</a> (#14)</li><li><a href="https://comicvine.gamespot.com/batman-the-caped-crusader-4-volume-4/4000-763258/" data-ref-id="4000-763258">Batman: The Caped Crusader Volume 4</a> (#15)</li><li><a href="/tales-of-the-batman-jh-williams-iii/4050-75714/" data-ref-id="4050-75714">Tales of the Batman: J.H. Williams III</a> (#21)</li><li><a href="https://comicvine.gamespot.com/batman-arkham-ras-al-ghul/4050-117730/">Batman Arkham: Ra''s Al Ghul</a> (#26)</li></ul>', '1961', '28', '{''icon_url'': ''https://comicvine.gamespot.com/a/uploads/square_avatar/1/19859/846090-88302_20071006024323_large.jpg'', ''medium_url'': ''https://comicvine.gamespot.com/a/uploads/scale_medium/1/19859/846090-88302_20071006024323_large.jpg'', ''screen_url'': ''https://comicvine.gamespot.com/a/uploads/screen_medium/1/19859/846090-88302_20071006024323_large.jpg'', ''screen_large_url'': ''https://comicvine.gamespot.com/a/uploads/screen_kubrick/1/19859/846090-88302_20071006024323_large.jpg'', ''small_url'': ''https://comicvine.gamespot.com/a/uploads/scale_small/1/19859/846090-88302_20071006024323_large.jpg'', ''super_url'': ''https://comicvine.gamespot.com/a/uploads/scale_large/1/19859/846090-88302_20071006024323_large.jpg'', ''thumb_url'': ''https://comicvine.gamespot.com/a/uploads/scale_avatar/1/19859/846090-88302_20071006024323_large.jpg'', ''tiny_url'': ''https://comicvine.gamespot.com/a/uploads/square_mini/1/19859/846090-88302_20071006024323_large.jpg'', ''original_url'': ''https://comicvine.gamespot.com/a/uploads/original/1/19859/846090-88302_20071006024323_large.jpg'', ''image_tags'': ''All Images''}', '[{"id": "Batman"}, {"id": "James Gordon"}, {"id": "Alfred Pennyworth"}, {"id": "Dick Grayson"}, {"id": "Joker"}, {"id": "Two-Face"}, {"id": "Jason Todd"}, {"id": "Penguin"}, {"id": "Barbara Gordon"}, {"id": "Harvey Bullock"}, {"id": "Vicki Vale"}, {"id": "Thomas Wayne"}, {"id": "Scarecrow"}, {"id": "Talia al Ghul"}, {"id": "Joe Chill"}, {"id": "Ra''s al Ghul"}, {"id": "Catwoman"}, {"id": "Ma