INSERT INTO volumes (id, name, firstIssue, publisher, description, startYear, numIssues, image, characters_name, concepts_name, characters_id, concepts_id, numLikes) VALUES ('3125', 'Tales of the New Teen Titans', 'Cyborg', '10', '<p><b>Tales of the New Teen Titans</b></p><p><i>A four-issue miniseries starring</i> <a href="/cyborg/4005-2388/" data-ref-id="4005-2388">Cyborg</a>, <a href="/raven/4005-3584/" data-ref-id="4005-3584">Raven</a>, <a href="/beast-boy/4005-3586/" data-ref-id="4005-3586">Changeling</a>, <i>and</i> <a href="/starfire/4005-2389/" data-ref-id="4005-2389">Starfire</a></p><h4>Collected Editions</h4><ul><li><a href="https://comicvine.gamespot.com/the-new-teen-titans-archives-3-volume-3/4000-273555/" data-ref-id="4000-273555">The New Teen Titans Archives Vol. 3</a></li><li><a href="/new-teen-titans-3-volume-three/4000-500274/" data-ref-id="4000-500274">New Teen Titans Volume Three</a></li><li><a href="/the-new-teen-titans-omnibus/4050-43537/" data-ref-id="4050-43537">The New Teen Titans Omnibus</a> Vol. 2</li></ul>', '1982', '4', '{''icon_url'': ''https://comicvine.gamespot.com/a/uploads/square_avatar/0/4/19908-3125-22213-1-tales-of-the-new-tee.jpg'', ''medium_url'': ''https://comicvine.gamespot.com/a/uploads/scale_medium/0/4/19908-3125-22213-1-tales-of-the-new-tee.jpg'', ''screen_url'': ''https://comicvine.gamespot.com/a/uploads/screen_medium/0/4/19908-3125-22213-1-tales-of-the-new-tee.jpg'', ''screen_large_url'': ''https://comicvine.gamespot.com/a/uploads/screen_kubrick/0/4/19908-3125-22213-1-tales-of-the-new-tee.jpg'', ''small_url'': ''https://comicvine.gamespot.com/a/uploads/scale_small/0/4/19908-3125-22213-1-tales-of-the-new-tee.jpg'', ''super_url'': ''https://comicvine.gamespot.com/a/uploads/scale_large/0/4/19908-3125-22213-1-tales-of-the-new-tee.jpg'', ''thumb_url'': ''https://comicvine.gamespot.com/a/uploads/scale_avatar/0/4/19908-3125-22213-1-tales-of-the-new-tee.jpg'', ''tiny_url'': ''https://comicvine.gamespot.com/a/uploads/square_mini/0/4/19908-3125-22213-1-tales-of-the-new-tee.jpg'', ''original_url'': ''https://comicvine.gamespot.com/a/uploads/original/0/4/19908-3125-22213-1-tales-of-the-new-tee.jpg'', ''image_tags'': ''All Images''}', '[{"id": "Cyborg"}, {"id": "Wally West"}, {"id": "Donna Troy"}, {"id": "Beast Boy"}, {"id": "Raven"}, {"id": "Starfire"}, {"id": "Dick Grayson"}, {"id": "Herald"}, {"id": "Marcy Reynolds"}, {"id": "Luand''r"}, {"id": "Myand''r"}, {"id": "Elinore Stone"}, {"id": "Azar"}, {"id": "Ron Evers"}, {"id": "Tempest"}, {"id": "Primus"}, {"id": "Kalista"}, {"id": "Darkfire"}, {"id": "Marie Logan"}, {"id": "Mark Logan"}, {"id": "Nicholas Galtry"}, {"id": "The Chief"}, {"id": "Bumblebee"}, {"id": "Gnarrk"}, {"id": "Silas Stone"}, {"id": "Mento"}, {"id": "Golden Eagle"}, {"id": "Lilith Clay"}, {"id": "Arella"}, {"id": "Blackfire"}, {"id": "Trigon"}, {"id": "Elasti-Girl"}, {"id": "Negative Man"}, {"id": "Robotman"}, {"id": "Roy Harper"}]', '[{"id": "Robin"}]', '[{"id": 2388}, {"id": 23879}, {"id": 4913}, {"id": 3586}, {"id": 3584}, {"id": 2389}, {"id": 1691}, {"id": 35124}, {"id": 176030}, {"id": 101811}, {"id": 101810}, {"id": 72987}, {"id": 66583}, {"id": 62837}, {"id": 55866}, {"id": 54060}, {"id": 54024}, {"id": 46976}, {"id": 38460}, {"id": 38459}, {"id": 38420}, {"id": 35126}, {"id": 3576}, {"id": 35014}, {"id": 27660}, {"id": 14647}, {"id": 12530}, {"id": 12525}, {"id": 12523}, {"id": 12502}, {"id": 5310}, {"id": 4088}, {"id": 4087}, {"id": 4079}, {"id": 3404}]', '[{"id": 56363}]', '0');
INSERT INTO volumes (id, name, firstIssue, publisher, description, startYear, numIssues, image, characters_name, concepts_name, characters_id, concepts_id, numLikes) VALUES ('3138', 'G.I. Joe: A Real American Hero', 'Operation: Lady Doomsday; ...Hot Potato!', '31', '<p><a href="//www.comicvine.com/gi-joe/4060-12206/" data-ref-id="4060-12206">G.I. Joe</a>, the legendary <a href="//www.comicvine.com/marvel/4010-31/" data-ref-id="4010-31">Marvel</a> series based on the cartoon and action figures-line. It featured many of the most popular G.I.Joe characters and even introduced <a href="/snake-eyes/4050-40244/" data-ref-id="4050-40244">Snake Eyes</a>.</p><p>The series lasted for 155 issues until Marvel lost the rights to publish the series in 1995.</p><p>The series had a concluding re-print special in 1995, simply called <a href="/gi-joe-special/4050-32923/" data-ref-id="4050-32923">G.I. Joe: Special</a>, making that the last G.I. Joe comic to be published by Marvel Comics.</p><p>In 2010, the G.I. Joe series was continued by <a href="//www.comicvine.com/idw-publishing/4010-1190/" data-ref-id="4010-1190">IDW Publishing</a> as <a href="/gi-joe-a-real-american-hero/4050-32910/" data-ref-id="4050-32910">G.I. Joe: A Real American Hero</a>, continuing the numbering and the storyline of this original series. IDW''s series ignored <a href="//www.comicvine.com/image/4010-513/" data-ref-id="4010-513">Image</a>''s <a href="/gi-joe-a-real-american-hero/4050-9112/" data-ref-id="4050-9112">G.I. Joe: A Real American Hero</a> and <a href="//www.comicvine.com/devils-due/4010-1863/" data-ref-id="4010-1863">Devil''s Due</a>''s <a href="/gi-joe-a-real-american-hero/4050-11071/" data-ref-id="4050-11071">G.I. Joe: A Real American Hero</a>.</p><p>Whether the G.I. Joe comics published by various publishers in between the cap from 1995 till 2010 are ''in continuity'' remains to be seen.</p><h4><strong>Writers</strong></h4><ul><li><a href="https://comicvine.gamespot.com/larry-hama/4040-12272/" data-ref-id="4040-12272">Larry Hama</a> #1-7, 10-19, 21-118, 120-142, 144-152, 155 <strong>(TOT 148)</strong></li><li><a href="https://comicvine.gamespot.com/herb-trimpe/4040-3439/" data-ref-id="4040-3439">Herb Trimpe</a> #8, 119,</li><li><a href="https://comicvine.gamespot.com/steven-grant/4040-41567/" data-ref-id="4040-41567">Steven Grant</a> #9</li><li><a href="https://comicvine.gamespot.com/eric-fern/4040-56536/" data-ref-id="4040-56536">Eric Fein </a>#143</li><li><a href="https://comicvine.gamespot.com/peter-quinones/4040-42502/" data-ref-id="4040-42502">Peter Quionones</a> #153,</li></ul><p><strong>Pencillers</strong></p><ul><li><a href="https://comicvine.gamespot.com/herb-trimpe/4040-3439/" data-ref-id="4040-3439">Herb Trimpe</a> #1, 3, 4, 6-8, 99, 119</li><li><a href="https://comicvine.gamespot.com/don-perlin/4040-1539/" data-ref-id="4040-1539">Don Perlin</a> #2, 5</li><li><a href="https://comicvine.gamespot.com/mike-vosburg/4040-5595/" data-ref-id="4040-5595">Mike Vosburg</a> #9-19, 22, 23</li><li><a href="https://comicvine.gamespot.com/geof-isherwood/4040-11627/" data-ref-id="4040-11627">Geoff Isherwood</a> #20, 97</li><li><a href="https://comicvine.gamespot.com/larry-hama/4040-12272/" data-ref-id="4040-12272">Larry Hama</a> #21, 26,</li><li><a href="https://comicvine.gamespot.com/russ-heath/4040-6102/" data-ref-id="4040-6102">Russ Heath</a> #24</li><li><a href="https://comicvine.gamespot.com/frank-springer/4040-30117/" data-ref-id="4040-30117">Frank Springer</a> #25, 27, 29, 30, 32, 33, 37</li><li><a href="https://comicvine.gamespot.com/marie-severin/4040-3492/" data-ref-id="4040-3492">Marie Severin</a> #28</li><li><a href="https://comicvine.gamespot.com/gi-joe-a-real-american-hero-31-all-fall-down/4000-76185/" data-ref-id="4000-76185">Rod Whigham</a> #31, 34-36, 38-58, 78, 116-118</li><li><a href="https://comicvine.gamespot.com/ron-wagner/4040-6586/" data-ref-id="4040-6586">Ron Wagner</a> #59, 63-68, 70-74, 76, 80, 83</li><li><a href="https://comicvine.gam