INSERT INTO volumes (id, name, firstIssue, publisher, description, startYear, numIssues, image, characters_name, concepts_name, characters_id, concepts_id, numLikes) VALUES ('3139', 'Hercules', 'What Fools These Immortals Be!', '31', '<p>Hercules'' first solo series and, along with Wolverine, one of the first Marvel mini-series! The series proved so popular that a second mini-series named <a href="/hercules/4050-3344/" data-ref-id="4050-3344">Hercules Prince of Power Vol.2</a> was started a few months later.</p><p><strong>Note:</strong> this is not Earth 616''s Hercules, but rather Earth 829''s Hercules.</p><p>Collected in <a href="https://comicvine.gamespot.com/hercules-prince-of-power/4050-43093/">Hercules: Prince of Power</a>.</p>', '1982', '4', '{''icon_url'': ''https://comicvine.gamespot.com/a/uploads/square_avatar/0/4/20115-3139-22444-1-hercules.jpg'', ''medium_url'': ''https://comicvine.gamespot.com/a/uploads/scale_medium/0/4/20115-3139-22444-1-hercules.jpg'', ''screen_url'': ''https://comicvine.gamespot.com/a/uploads/screen_medium/0/4/20115-3139-22444-1-hercules.jpg'', ''screen_large_url'': ''https://comicvine.gamespot.com/a/uploads/screen_kubrick/0/4/20115-3139-22444-1-hercules.jpg'', ''small_url'': ''https://comicvine.gamespot.com/a/uploads/scale_small/0/4/20115-3139-22444-1-hercules.jpg'', ''super_url'': ''https://comicvine.gamespot.com/a/uploads/scale_large/0/4/20115-3139-22444-1-hercules.jpg'', ''thumb_url'': ''https://comicvine.gamespot.com/a/uploads/scale_avatar/0/4/20115-3139-22444-1-hercules.jpg'', ''tiny_url'': ''https://comicvine.gamespot.com/a/uploads/square_mini/0/4/20115-3139-22444-1-hercules.jpg'', ''original_url'': ''https://comicvine.gamespot.com/a/uploads/original/0/4/20115-3139-22444-1-hercules.jpg'', ''image_tags'': ''All Images''}', '[{"id": "Hercules"}, {"id": "Recorder"}, {"id": "Galactus"}, {"id": "Zeus"}, {"id": "Ronhon"}, {"id": "Frankie Raye"}, {"id": "Layana Sweetwater"}, {"id": "Apollo"}]', '[{"id": "Alternate Reality"}]', '[{"id