INSERT INTO volumes (id, name, firstIssue, publisher, description, startYear, numIssues, image, characters_name, concepts_name, characters_id, concepts_id, numLikes) VALUES ('3143', 'Marvel Fanfare', 'Pin Up; Fast Descent Into Hell; Editori-Al; Snow', '31', '<p>In this series, mostly characters with no own comicbook-series starred in stories with high quality art by the top artists of the industry. It was printed on high quality paper as well. Although the series lasted for 10 years, it only had 60 issues published. Some 4 and a half years later, <a href="https://www.comicvine.com/marvel-fanfare/4050-25660/">Marvel Fanfare Vol.2 </a>was started.</p><h4>Collected Editions</h4><ul><li><a href="https://comicvine.gamespot.com/marvel-fanfare-strange-tales/4050-32702/">Marvel Fanfare: Strange Tales</a> (#1-7)</li><li><a href="/marvel-masterworks-the-fantastic-four-22-volume-22/4000-791981/" data-ref-id="4000-791981">Marvel Masterworks: The Fantastic Four Volume 22</a> (#2)</li><li><a href="https://comicvine.gamespot.com/black-widow-epic-collection-the-coldest-war/4050-130989/">Black Widow Epic Collection: The Coldest War</a> (#10-13)</li><li><a href="https://comicvine.gamespot.com/thor-the-warriors-three/4050-43096/">Thor: The Warriors Three</a> (#13 &amp; 34-37)</li><li><a href="https://comicvine.gamespot.com/marvel-universe-by-frank-miller-omnibus/4050-116073/">Marvel Universe by Frank Miller Omnibus</a> (#18)</li><li><a href="https://comicvine.gamespot.com/cloak-and-dagger-shadows-and-light/4050-98729/" data-ref-id="4050-98729">Cloak and Dagger: Shadows and Light</a> (#19)</li><li><a href="https://comicvine.gamespot.com/cloak-and-dagger-omnibus/4050-130070/">Cloak and Dagger Omnibus</a> (#19)</li><li><a href="https://comicvine.gamespot.com/iron-man-epic-collection-return-of-the-ghost/4050-117588/">Iron Man Epic Collection: Return of the Ghost</a> (#22-23 &amp; 44)</li><li><a href="https://comicvine.gamespot.com/captain-universe-power-unimaginable/4050-25914/">Captain Universe: Power Unimaginable</a> (#25)</li><li><a href="https://comicvine.gamespot.com/captain-america-scourge-of-the-underworld/4050-39209/">Captain America: Scourge of the Underworld</a> (#29)</li></ul><h4>Non-U.S. Collected Editions</h4><ul><li><a href="https://comicvine.gamespot.com/coleccionable-marvel-heroes-75-doctor-extrano-de-r/4000-612313/">Coleccionable Marvel Héroes - Doctor Extraño de Roger Stern</a> (#6) (Spanish)</li><li><a href="https://comicvine.gamespot.com/coleccionable-marvel-heroes-22-viuda-negra-red-de-/4000-612227/">Coleccionable Marvel Héroes - Viuda Negra: Red de intrigas</a> (#10-13) (Spanish)</li><li><a href="https://comicvine.gamespot.com/coleccion-frank-miller-el-universo-marvel-segun-fr/4050-105405/">Colección Frank Miller. El Universo Marvel según Frank Miller</a> (#18) (Spanish)</li><li><a href="https://comicvine.gamespot.com/coleccionable-marvel-heroes-74-peter-parker-el-esp/4000-612311/">Coleccionable Marvel Héroes - Peter Parker, El Espectacular Spiderman: Punto de ruptura</a> (#47) (Spanish)</li></ul><p>Issues <a href="https://comicvine.gamespot.com/biblioteca-marvel-la-cosa-16/4000-285483/" data-ref-id="4000-285483">#15</a> &amp; <a href="https://comicvine.gamespot.com/biblioteca-marvel-la-cosa-16/4000-285483/" data-ref-id="4000-285483">#20-21</a> have been translated into Spanish.</p>', '1982', '60', '{''icon_url'': ''https://comicvine.gamespot.com/a/uploads/square_avatar/0/4/19728-3143-22013-1-marvel-fanfare.jpg'', ''medium_url'': ''https://comicvine.gamespot.com/a/uploads/scale_medium/0/4/19728-3143-22013-1-marvel-fanfare.jpg'', ''screen_url'': ''https://comicvine.gamespot.com/a/uploads/screen_medium/0/4/19728-3143-22013-1-marvel-fanfare.jpg'', ''screen_large_url'': ''https://comicvine.gamespot.com/a/uploads/screen_kubrick/0/4/19728-3143-22013-1-marvel-fanfare.jpg'', ''small_url'': ''https://comicvine.gamespot.com/a/uploads/scale_small/0/4/19728-3143-22013-1-marvel-fanfare.jpg'', ''super_url'': ''https://comicvine.gamespot.com/