INSERT INTO volumes (id, name, firstIssue, publisher, description, startYear, numIssues, image, characters_name, concepts_name, characters_id, concepts_id, numLikes) VALUES ('3144', 'Marvel Graphic Novel', 'Dreadstar', '31', '<p>Marvel Graphic Novels (MGN) was a volume of graphic novel trade paperbacks in an over-sized magazine format that was published from 1982 to 1993, often filled with big stories and introductions of new characters and teams, such as the <a href="/new-mutants/4060-15971/" data-ref-id="4060-15971">New Mutants</a> or <a href="/futurians/4060-43541/" data-ref-id="4060-43541">Futurians</a>. Unfortunately they fell to the wayside in the early ''90s, when the prestige format came around.</p><p>Only the first 20 issues were cataloged as Marvel Graphic Novel #1, #2, #3, etc. After these 20 issues, Marvel continued the volume for another 18 graphic novels officially. <a href="/the-overstreet-comic-book-price-guide/4050-65397/" data-ref-id="4050-65397">The Overstreet Comic Book Price Guide</a> began to label them #21-38 as part of the volume, but the titles in the indicia were shown unnumbered, as what the cover stated.</p><p>General listing for the graphic novels that were published after issue #38 from 1988-1993 (adding up to 76 published graphic novels in total):</p><ul><li>39 - <a href="/the-inhumans/4050-37821/" data-ref-id="4050-37821">The Inhumans</a></li><li>40 - <a href="/punisher-assassins-guild/4050-30703/" data-ref-id="4050-30703">The Punisher: Assassin''s Guild</a></li><li>41 - <a href="/who-framed-roger-rabbit/4050-33739/" data-ref-id="4050-33739">Who Framed Roger Rabbit?</a></li><li>42 - <a href="/conan-of-the-isles/4050-37820/" data-ref-id="4050-37820">Conan of the Isles: Red Shadows and Black Kraken!</a></li><li>43 - <a href="/the-dreamwalker/4050-33738/" data-ref-id="4050-33738">The Dreamwalker</a></li><li>44 - <a href="/ax/4050-33731/" data-ref-id="4050-33731">Ax</a></li><li>45 -<a href="/arena/4050-22563/" data-ref-id="4050-22563"> Arena</a></li><li>46 - <a href="/spider-man-parallel-lives/4050-27473/" data-ref-id="4050-27473">Spider-Man: Parallel Lives</a></li><li>47 - <a href="/kull-the-vale-of-shadow/4050-33733/" data-ref-id="4050-33733">Kull: The Vale of Shadow</a></li><li>48 -<a href="/a-sailors-story-book-2/4050-33726/" data-ref-id="4050-33726"> A Sailor''s Story: Book Two - Winds, Dreams, and Dragons</a></li><li>49 - <a href="/doctor-strange-doctor-doom-triumph-and-torment/4050-23227/" data-ref-id="4050-23227">Doctor Strange &amp; Doctor Doom: Triumph and Torment</a></li><li>50 -<a href="/wolverinenick-furythe-scorpio-connection/4050-25998/" data-ref-id="4050-25998"> Wolverine &amp; Nick Fury: The Scorpio Connection</a></li><li>51 -<a href="/the-punisher-intruder/4050-25459/" data-ref-id="4050-25459"> Punisher: Intruder</a></li><li>52 - <a href="/neuromancer/4050-33734/" data-ref-id="4050-33734">Neuromancer: The Graphic Novel</a></li><li>53 - <a href="/conan-the-barbarian-the-skull-of-set/4050-33760/" data-ref-id="4050-33760">Conan: The Skull of Set</a></li><li>54 -<a href="/roger-rabbit-the-resurrection-of-doom/4050-33737/" data-ref-id="4050-33737"> Roger Rabbit: The Resurrection of Doom</a></li><li>55 - <a href="/squadron-supreme-death-of-a-universe/4050-27684/" data-ref-id="4050-27684">Squadron Supreme: Death of a Universe</a></li><li>56 -<a href="/power-pack-cloak-and-dagger-shelter-from-the-storm/4050-33732/" data-ref-id="4050-33732"> Cloak &amp; Dagger and Power Pack: Shelter from the Storm</a></li><li>57 -<a href="/rick-mason-the-agent/4050-33735/" data-ref-id="4050-33735"> Rick Mason: The Agent</a></li><li>58 -<a href="/silver-surfer-the-enslavers/4050-27374/" data-ref-id="4050-27374"> Silver Surfer: The Enslavers</a></li><li>59 -<a href="/conan-the-barbarian-the-horn-of-azoth/4050-30316/" data-ref-id="4050-30316"> Conan the Barbarian: The Horn of Azoth</a></li><li>60 -<a href="/rio-rides-again/4050-33758/" data-ref-id="4050-33758"> Rio Rides Again</a></li><li>61 -<a href="/black-widow-coldest-war/4050-25458/" data-ref-id="4050-25458"> Black Widow: The Coldest War</a></li><li>62 -<a href="/ka-zar-guns-of-the-savage-land/4050-20442/" data-ref-id="4050-20442"> Ka-Zar: Guns of the Savage Land</a></li><li>63 - <a href="/spider-man-spirits-of-the-earth/4050-37819/" data-ref-id="4050-37819">Spider-Man: Spirits of the Earth</a></li><li>64 -<a href="/punisher-kingdom-gone/4050-30714/" data-ref-id="4050-30714"> Punisher: Kingdom Gone</a></li><li>65 - <a href="/wolverine-bloodlust/4050-23816/" data-ref-id="4050-23816">Wolverine: Bloodlust</a></li><li>66 -<a href="/excalibur-weird-war-3/4050-32120/" data-ref-id="4050-32120"> Excalibur: Weird War III</a></li><li>67 -<a href="/wolverine-bloody-choices/4050-32212/" data-ref-id="4050-32212"> Wolverine: Bloody Choices</a></li><li>68 - <a href="/avengers-deathtrap-the-vault/4050-20893/" data-ref-id="4050-20893">Avengers: Death Trap - The Vault</a></li><li>69 - <a href="/conan-the-rogue/4050-33759/" data-ref-id="4050-33759">Conan the Rogue</a></li><li>70 - <a href="/punisher-blood-on-the-moors/4050-27751/" data-ref-id="4050-27751">Punisher: Blood on the Moors</a></li><li>71 -<a href="/the-silver-surfer-homecoming/4050-26865/" data-ref-id="4050-26865"> Silver Surfer: Homecoming</a></li><li>72 - <a href="/spider-man-fear-itself/4050-33873/" data-ref-id="4050-33873">Spider-Man: Fear Itself</a></li><li>73 - <a href="/conan-the-ravagers-out-of-time/4050-35148/" data-ref-id="4050-35148">Conan: The Ravagers Out of Time</a></li><li>74 -<a href="/punisherblack-widow-spinning-doomsdays-web/4050-20443/" data-ref-id="4050-20443"> Punisher &amp; Black Widow: Spinning Doomsday''s Web</a></li><li>75 -<a href="/daredevil-black-widow-abattoir/4050-31673/" data-ref-id="4050-31673"> Daredevil &amp; Black Widow: Abattoir</a></li><li>76 - <a href="https://comicvine.gamespot.com/night-raven-the-collected-stories/4050-20341/">Night Raven: The Collected Stories</a></li></ul><h4>Collected Editions</h4><ul><li><a href="https://comicvi