INSERT INTO volumes (id, name, firstIssue, publisher, description, startYear, numIssues, image, characters_name, concepts_name, characters_id, concepts_id, numLikes) VALUES ('3147', 'Marvel Super Hero Contest of Champions', 'A Gathering of Heroes', '31', '<p>History in the making! The first ever Marvel Comics Crossover mini-series! The heroes of earth are abducted and forced to fight each-other by the <a href="/grandmaster/4005-32735/" data-ref-id="4005-32735"> Grandmaster</a> and <a href="/death/4005-12620/" data-ref-id="4005-12620"> Death</a>. The series seemed to have laid the groundwork for the <a href="/marvel-super-heroes-secret-wars/4050-3352/" data-ref-id="4050-3352"> Marvel Super Heroes Secret Wars</a> mini-series that would start some years later since there is much resemblance to the two series (both featuring stories in which heroes are taken away from their homes and driven to fight one another by an entity). Years later, a second volume named <a href="/contest-of-champions-ii/4050-6353/" data-ref-id="4050-6353"> Contest of Champions II</a> was published.</p><h4>Collected Editions</h4><ul><li><a href="/avengers-the-contest/4050-34101/" data-ref-id="4050-34101">Avengers: The Contest</a></li><li><a href="/marvel-super-hero-contest-of-champions/4050-85118/" data-ref-id="4050-85118">Marvel Super Hero Contest of Champions</a></li></ul>', '1982', '3', '{''icon_url'': ''https://comicvine.gamespot.com/a/uploads/square_avatar/0/4/19929-3147-22234-1-marvel-super-hero-co.jpg'', ''medium_url'': ''https://comicvine.gamespot.com/a/uploads/scale_medium/0/4/19929-3147-22234-1-marvel-super-hero-co.jpg'', ''screen_url'': ''https://comicvine.gamespot.com/a/uploads/screen_medium/0/4/19929-3147-22234-1-marvel-super-hero-co.jpg'', ''screen_large_url'': ''https://comicvine.gamespot.com/a/uploads/screen_kubrick/0/4/19929-3147-22234-1-marvel-super-hero-co.jpg'', ''small_url'': ''https://comicvine.gamespot.com/a/uploads/scale_small/0/4/19929-3147-22234-1-marvel-super-hero-co.jpg