INSERT INTO volumes (id, name, firstIssue, publisher, description, startYear, numIssues, image, characters_name, concepts_name, characters_id, concepts_id, numLikes) VALUES ('3157', 'Wolverine', 'I''m Wolverine', '31', '<p>He is the best at what he does, and here he is in his first own mini-series!</p><p>By the creative minds of Chris Claremont and Frank Miller comes a four-issue miniseries, starring <a href="/wolverine/4005-1440/" data-ref-id="4005-1440">Wolverine</a> in his first solo series!</p><h4>Collected Editions</h4><ul><li><a href="https://comicvine.gamespot.com/marvel-universe-by-frank-miller-omnibus/4050-116073/">Marvel Universe by Frank Miller Omnibus</a></li><li><a href="https://comicvine.gamespot.com/uncanny-x-men-omnibus-3-volume-3/4000-516096/" data-ref-id="4000-516096">Uncanny X-Men Omnibus Volume 3</a></li><li><a href="https://www.comicvine.com/wolverine-1-chris-claremont-frank-miller/4000-184081/" data-ref-id="4000-184081">Wolverine Volume 1</a> (#1-4), (Uncanny X-Men #172-173)</li></ul><h4>Non-U.S. Collected Editions</h4><ul><li><a href="/best-of-marvel-essentials-lobezno-honor/4050-41923/" data-ref-id="4050-41923">Best of Marvel Essentials: Lobezno: Honor</a> (Spanish)</li><li><a href="https://comicvine.gamespot.com/coleccion-frank-miller-lobezno-honor/4050-103302/" data-ref-id="4050-103302">Colección Frank Miller. Lobezno: Honor</a> (Spanish)</li></ul>', '1982', '4', '{''icon_url'': ''https://comicvine.gamespot.com/a/uploads/square_avatar/11161/111615891/9300027-3983472080-30841.jpg'', ''medium_url'': ''https://comicvine.gamespot.com/a/uploads/scale_medium/11161/111615891/9300027-3983472080-30841.jpg'', ''screen_url'': ''https://comicvine.gamespot.com/a/uploads/screen_medium/11161/111615891/9300027-3983472080-30841.jpg'', ''screen_large_url'': ''https://comicvine.gamespot.com/a/uploads/screen_kubrick/11161/111615891/9300027-3983472080-30841.jpg'', ''small_url'': ''https://comicvine.gamespot.com/a/uploads/scale_small/11161/111615891/9300027-3983472080-30841.jpg'', ''super_url'': ''https://comicvine.gamespot.com/a/uploads/scale_large/11161/111615891/9300027-3983472080-30841.jpg'', ''thumb_url'': ''https://comicvine.gamespot.com/a/uploads/scale_avatar/11161/111615891/9300027-3983472080-30841.jpg'', ''tiny_url'': ''https://comicvine.gamespot.com/a/uploads/square_mini/11161/111615891/9300027-3983472080-30841.jpg'', ''original_url'': ''https://comicvine.gamespot.com/a/uploads/original/11161/111615891/9300027-3983472080-30841.jpg'', ''image_tags'': ''All Images''}', '[{"id": "Wolverine"}, {"id": "Mariko Yashida"}, {"id": "Yukio"}, {"id": "Lord Shingen"}, {"id": "Noburu Hideki"}, {"id": "Asano Kimura"}, {"id": "Katsuyori"}, {"id": "Takahashi"}]', '[{"id": "Eagle Awards"}, {"id": "Homage Covers"}]', '[{"id": 1440}, {"id": 3196}, {"id": 9843}, {"id": 15694}, {"id": 32595}, {"id": 32641}, {"id": 32594}, {"id": 168969}]', '[{"id": 56081}, {"id": 43734}]', '0');
INSERT INTO volumes (id, name, firstIssue, publisher, description, startYear, numIssues, image, characters_name, concepts_name, characters_id, concepts_id, numLikes) VALUES ('3194', 'Batman and the Outsiders', 'Preview', '10', '<p>Continued in: <a href="/outsiders-1985/4050-3455/" data-ref-id="4050-3455">Outsiders (Volume 1)</a>.</p><p>Batman had never been what anyone would call a natural team player. True, he had been Robin''s mentor since early in his career, but he''d often had trouble meshing with those he considered equals in the JLA. So, when his long time team mates in the Justice League refused to enter the country of Markovia to help Batman rescue Bruce Wayne''s longtime employee Lucius Fox, Batman abruptly quit the League and set out for the small European country on his own. Batman soon discovered Fox had been kidnapped by Baron Bedlam, a rebel who had already killed the king of Markovia. As he tries to find where Fox is located, Batman enlists the aid of his long time friend, Black Lightning in order to infiltrate a camp of rebel insurgents in the country. However, soon the samurai assassin Katana appeared and killed the rebel general and Batman''s plans took a different turn. Before long he encountered the mysterious energy projecting Halo, the gravity powered prince of Markovia now calling himself Geo-Force, and his old associate and master of the periodic table of the elements, Metamorpho, who all opposed the forces of Baron Bedlam, and a new plan formed in Batman''s mind. After successfully overthrowing Bedlam''s reign of terror, and saving Fox, Batman requested that the team return to Gotham with him and work under his leadership. Batman now had his own league of heroes, only his team would now operate outside the law.</p><p>Popular from its inception, Batman and the Outsiders (Outsiders) ran for a total of 46 issues, and spun off into a deluxe format Baxter title, The Outsiders in 1985. An interesting blend of old and new characters, the team''s roster continued to grow over the years, gaining members such as Looker, Windfall and the Atomic Knight and facing villains like Eclipso, Kobra and Maxie Zeus.</p><h4>Collected Editions</h4><ul><li><a href="/showcase-presents-batman-and-the-outsiders/4050-34908/" data-ref-id="4050-34908">Showcase Presents: Batman and the Outsiders</a> (#1-19)</li><li><a href="https://comicvine.gamespot.com/batman-and-the-outsiders-1-volume-1/4000-581519/" data-ref-id="4000-581519">Batman and the Outsiders Volume 1</a> (#1-12)</li><li><a href="https://comicvine.gamespot.com/new-teen-titans-6-volume-six/4000-580725/" data-ref-id="4000-580725">New Teen Titans Volume Six</a> (#5)</li><li><a href="https://comicvine.gamespot.com/tales-of-the-batman-marv-wolfman-1-volume-1/4000-743303/" data-ref-id="4000-743303">Tales of the Batman: Marv Wolfman Volume 1</a> (#5)</li><li><a href="https://comicvine.gamespot.com/batman-and-the-outsiders-2-volume-2/4000-659974/" data-ref-id="4000-659974">Batman and the Outsiders Volume 2</a> (#13-23)</li><li><a href="/batman-and-the-outsiders-3-volume-3/4000-705406/" data-ref-id="4000-705406">Batman and the Outsiders Volume 3</a> (#24-32)</li></ul>', '1983', '33', '{''icon_url'': ''https://comicvine.gamespot.com/a/uploads/square_avatar/6/67663/2755085-01.jpg'', ''medium_url'': ''https://comicvine.gamespot.com/a/uploads/scale_medium/6/67663/2755085-01.jpg'', ''screen_url'': ''https://comicvine.gamespot.com/a/uploads/screen_medium/6/67663/2755085-01.jpg'', ''screen_large_url'': ''https://comicvine.gamespot.com/a/uploads/screen_kubrick/6/67663/2755085-01.jpg'', ''small_url'': ''https://comicvine.gamespot.com/a/uploads/scale_small/6/67663/2755085-01.jpg'', ''super_url'': ''https://comicvine.gamespot.com/a/uploads/scale_large/6/67663/2755085-01.jpg'', ''thumb_url'': ''https://comicvine.gamespot.com/a/uploads/scale_avatar/6/67663/2755085-01.jpg'', ''tiny_url'': ''https://comicvine.gamespot.com/a/uploads/square_mini/6/67663/2755085-01.jpg'', ''original_url'': ''https