INSERT INTO volumes (id, name, firstIssue, publisher, description, startYear, numIssues, image, characters_name, concepts_name, characters_id, concepts_id, numLikes) VALUES ('3217', 'Alpha Flight', 'Tundra!', '31', '<p>Spinning out of the pages of Uncanny X-men, this is the first comic volume of Canada''s own premiere superhero team. Witness the rebirth of the team of superheroes. It lasted from 1983 until 1994 for a total of 130 issues. Two special Annual issues were released: <a href="/alpha-flight-annual/4050-3623/" data-ref-id="4050-3623">Alpha Flight Annual</a>.</p><h4>Collected Editions</h4><ul><li><a href="/alpha-flight-classic-1-volume-one/4000-140343/" data-ref-id="4000-140343"> Alpha Flight Classic Volume One</a> (#1-8)</li><li><a href="https://comicvine.gamespot.com/alpha-flight-by-john-byrne-omnibus/4050-98560/" data-ref-id="4050-98560">Alpha Flight By John Byrne Omnibus</a> (#1-29)</li><li><a href="/alpha-flight-classic-volume-two/4000-293647/" data-ref-id="4000-293647"> Alpha Flight Classic Volume Two</a> (#9-19)</li><li><a href="https://comicvine.gamespot.com/alpha-flight-classic-3-volume-3/4000-550693/" data-ref-id="4000-550693">Alpha Flight Classic Volume Three</a> (#20-29)</li><li><a href="https://comicvine.gamespot.com/avengers-epic-collection-under-siege/4050-90398/" data-ref-id="4050-90398">Avengers Epic Collection: Under Siege</a> (#39)</li><li><a href="https://comicvine.gamespot.com/acts-of-vengeance-spider-man-and-the-x-men/4050-136147/">Acts of Vengeance: Spider-Man &amp; The X-Men</a> (#79-80)</li><li><a href="https://comicvine.gamespot.com/marvel-comics-the-world-outside-your-window/4050-119858/">Marvel Comics: The World Outside Your Window</a> (#106)</li><li><a href="https://comicvine.gamespot.com/the-infinity-war-omnibus/4050-118131/">The Infinity War Omnibus</a> (#110-112)</li><li><a href="https://comicvine.gamespot.com/the-infinity-crusade-omnibus/4050-133099/">The Infinity Crusade Omnibus</a> (#124-125 &amp; 127)</li></ul><h4>Non-U.S. Collected Editions</h4><ul><li><a href="https://comicvine.gamespot.com/coleccionable-marvel-heroes-56-alpha-flight-de-joh/4000-612264/">Coleccionable Marvel Héroes - Alpha Flight de John Byrne</a> (#1-29) (Spanish)</li><li><a href="https://comicvine.gamespot.com/coleccionable-marvel-heroes-60-los-4-fantasticos-d/4000-612268/" data-ref-id="4000-612268">Coleccionable Marvel Héroes - Los 4 Fantásticos de John Byrne 2</a> (#4) (Spanish)</li><li><a href="https://comicvine.gamespot.com/coleccionable-marvel-heroes-51-el-increible-hulk-l/4000-612259/">Coleccionable Marvel Héroes - El Increíble Hulk: La Encrucijada</a> (#29) (Spanish)</li></ul><p>The series'' second volume started after a three year break: <a href="/alpha-flight/4050-11291/" data-ref-id="4050-11291">Alpha Flight</a> (1997).</p>', '1983', '130', '{''icon_url'': ''https://comicvine.gamespot.com/a/uploads/square_avatar/0/4/20946-3217-23361-1-alpha-flight.jpg'', ''medium_url'': ''https://comicvine.gamespot.com/a/uploads/scale_medium/0/4/20946-3217-23361-1-alpha-flight.jpg'', ''screen_url'': ''https://comicvine.gamespot.com/a/uploads/screen_medium/0/4/20946-3217-23361-1-alpha-flight.jpg'', ''screen_large_url'': ''https://comicvine.gamespot.com/a/uploads/screen_kubrick/0/4/20946-3217-23361-1-alpha-flight.jpg'', ''small_url'': ''https://comicvine.gamespot.com/a/uploads/scale_small/0/4/20946-3217-23361-1-alpha-flight.jpg'', ''super_url'': ''https://comicvine.gamespot.com/a/uploads/scale_large/0/4/20946-3217-23361-1-alpha-flight.jpg'', ''thumb_url'': ''https://comicvine.gamespot.com/a/uploads/scale_avatar/0/4/20946-3217-23361-1-alpha-flight.jpg'', ''tiny_url'': ''https://comicvine.gamespot.com/a/uploads/square_mini/0/4/20946-3217-23361-1-alpha-flight.jpg'', ''original_url'': ''https://comicvine.gamespot.com/a/uploads/original/0/4/20946-3217-23361-1-alpha-flight.jpg'', ''image_tags'': ''All Images''}', '[{"id": "Heather McNeil Hudson"}, {"id": "Sasquatch"}, {"id": "Puck"}, {"id": "Aurora"}, {"id": "Northstar"}, {"id"