INSERT INTO volumes (id, name, firstIssue, publisher, description, startYear, numIssues, image, characters_name, concepts_name, characters_id, concepts_id, numLikes) VALUES ('3223', 'The Falcon', 'Winners and Losers', '31', '<p>Sam "Snap" Wilson soars into his own series. ''Falcon'' reveals Sam Wilson as a mutant, which is retconed out years later, leading to an encounter with a Sentinel.</p><p>Collected in <a href="/avengers-falcon/4050-72196/" data-ref-id="4050-72196">Avengers: Falcon</a>.</p>', '1983', '4', '{''icon_url'': ''https://comicvine.gamespot.com/a/uploads/square_avatar/0/4/21188-3223-23624-1-falcon.jpg'', ''medium_url'': ''https://comicvine.gamespot.com/a/uploads/scale_medium/0/4/21188-3223-23624-1-falcon.jpg'', ''screen_url'': ''https://comicvine.gamespot.com/a/uploads/screen_medium/0/4/21188-3223-23624-1-falcon.jpg'', ''screen_large_url'': ''https://comicvine.gamespot.com/a/uploads/screen_kubrick/0/4/21188-3223-23624-1-falcon.jpg'', ''small_url'': ''https://comicvine.gamespot.com/a/uploads/scale_small/0/4/21188-3223-23624-1-falcon.jpg'', ''super_url'': ''https://comicvine.gamespot.com/a/uploads/scale_large/0/4/21188-3223-23624-1-falcon.jpg'', ''thumb_url'': ''https://comicvine.gamespot.com/a/uploads/scale_avatar/0/4/21188-3223-23624-1-falcon.jpg'', ''tiny_url'': ''https://comicvine.gamespot.com/a/uploads/square_mini/0/4/21188-3223-23624-1-falcon.jpg'', ''original_url'': ''https://comicvine.gamespot.com/a/uploads/original/0/4/21188-3223-23624-1-falcon.jpg'', ''image_tags'': ''All Images''}', '[{"id": "Sam Wilson"}, {"id": "Sergeant Tork"}, {"id": "Redwing"}, {"id": "Captain America"}, {"id": "Electro"}, {"id": "Ronald Reagan"}, {"id": "Cyclops"}, {"id": "Nemesis"}]', 'NaN', '[{"id": 1451}, {"id": 15660}, {"id": 59930}, {"id": 1442}, {"id": 3228}, {"id": 30220}, {"id": 1459}, {"id": 67956}]', 'NaN', '0');
INSERT INTO volumes (id, name, firstIssue, publisher, description, startYear, numIssues, image, characters_name, concepts_name, characters_id, concepts_id, numLikes) VALUES ('3225', 'Hawkeye', 'Listen to the Mockingbird', '31', '<p>The original mini-series starring <a href="/hawkeye/4005-1475/" data-ref-id="4005-1475"> Hawkeye</a> and introducing <a href="/mockingbird/4005-2497/" data-ref-id="4005-2497"> Mockingbird</a>.</p><h4>Collected Editions</h4><ul><li><a href="/avengers-hawkeye/4050-28608/" data-ref-id="4050-28608">Avengers: Hawkeye</a></li><li><a href="https://comicvine.gamespot.com/mockingbird-bobbi-morse-agent-of-shield/4050-92762/" data-ref-id="4050-92762">Mockingbird: Bobbi Morse, Agent of S.H.I.E.L.D.</a></li><li><a href="https://comicvine.gamespot.com/marvel-verse-hawkeye/4050-139914/">Marvel-Verse: Hawkeye</a> (#1)</li></ul>', '1983', '4', '{''icon_url'': ''https://comicvine.gamespot.com/a/uploads/square_avatar/11128/111287063/7415565-hawkeye%20v1983%20%231%20-%20listen%20to%20the%20mockingbird%20%281983_9_1%29%20-%20page%201.jpg'', ''medium_url'': ''https://comicvine.gamespot.com/a/uploads/scale_medium/11128/111287063/7415565-hawkeye%20v1983%20%231%20-%20listen%20to%20the%20mockingbird%20%281983_9_1%29%20-%20page%201.jpg'', ''screen_url'': ''https://comicvine.gamespot.com/a/uploads/screen_medium/11128/111287063/7415565-hawkeye%20v1983%20%231%20-%20listen%20to%20the%20mockingbird%20%281983_9_1%29%20-%20page%201.jpg'', ''screen_large_url'': ''https://comicvine.gamespot.com/a/uploads/screen_kubrick/11128/111287063/7415565-hawkeye%20v1983%20%231%20-%20listen%20to%20the%20mockingbird%20%281983_9_1%29%20-%20page%201.jpg'', ''small_url'': ''https://comicvine.gamespot.com/a/uploads/scale_small/11128/111287063/7415565-hawkeye%20v1983%20%231%20-%20listen%20to%20the%20mockingbird%20%281983_9_1%29%20-%20page%201.jpg'', ''super_url'': ''https://comicvine.gamespot.com/a/uploads/scale_large/11128/111287063/7415565-hawkeye%20v1983%20%231%20-%20listen%20to%20the%20mo