INSERT INTO volumes (id, name, firstIssue, publisher, description, startYear, numIssues, image, characters_name, concepts_name, characters_id, concepts_id, numLikes) VALUES ('3230', 'Magik (Storm and Illyana Limited Series)', 'Little Girl Lost', '31', '<p>Magik: Storm And Illyana tells the tale of <a href="/illyana-rasputin/4005-8303/" data-ref-id="4005-8303">Illyana Rasputin</a>, the younger sister of X-Man <a href="/colossus/4005-1460/" data-ref-id="4005-1460">Colossus</a>, her quest to escape from the demon sorcerer <a href="/belasco/4005-10947/" data-ref-id="4005-10947">Belasco</a> from the interdimensional pocket realm known as <a href="/limbo/4020-42990/" data-ref-id="4020-42990">Limbo</a>, and the manifestation of her mutant teleportation ability.</p><h4>Collected Editions</h4><ul><li><a href="/x-men-magik-storm-and-illyana/4050-29783/" data-ref-id="4050-29783">X-Men: Magik: Storm and Illyana</a></li><li><a href="//www.comicvine.com/x-men-magik-storm-illyana/4050-66837/" data-ref-id="4050-66837">X-Men: Magik - Storm &amp; Illyana</a></li><li><a href="https://comicvine.gamespot.com/uncanny-x-men-omnibus-3-volume-3/4000-516096/" data-ref-id="4000-516096">Uncanny X-Men Omnibus Volume 3</a></li><li><a href="https://comicvine.gamespot.com/marvel-masterworks-the-uncanny-x-men-10-volume-10/4000-580758/" data-ref-id="4000-580758">Marvel Masterworks: The Uncanny X-Men Volume 10</a></li><li><a href="https://comicvine.gamespot.com/new-mutants-epic-collection-renewal/4050-99448/" data-ref-id="4050-99448">New Mutants Epic Collection: Renewal</a></li><li><a href="https://comicvine.gamespot.com/new-mutants-omnibus-1/4000-821559/" data-ref-id="4000-821559">New Mutants Omnibus Vol. 1</a></li></ul><p><b>Note:</b> Indicia titled as "Magik (Storm and Illyana Limited Series)"</p>', '1983', '4', '{''icon_url'': ''https://comicvine.gamespot.com/a/uploads/square_avatar/0/4/21289-3230-23731-1-magik.jpg'', ''medium_url'': ''https://comicvine.gamespot.com/a/uploads/scale_medium/0/4/21289-3230-23731-1-magik.jpg'', ''screen_url'': ''https://comicvine.gamespot.com/a/uploads/screen_medium/0/4/21289-3230-23731-1-magik.jpg'', ''screen_large_url'': ''https://comicvine.gamespot.com/a/uploads/screen_kubrick/0/4/21289-3230-23731-1-magik.jpg'', ''small_url'': ''https://comicvine.gamespot.com/a/uploads/scale_small/0/4/21289-3230-23731-1-magik.jpg'', ''super_url'': ''https://comicvine.gamespot.com/a/uploads/scale_large/0/4/21289-3230-23731-1-magik.jpg'', ''thumb_url'': ''https://comicvine.gamespot.com/a/uploads/scale_avatar/0/4/21289-3230-23731-1-magik.jpg'', ''tiny_url'': ''https://comicvine.gamespot.com/a/uploads/square_mini/0/4/21289-3230-23731-1-magik.jpg'', ''original_url'': ''https://comicvine.gamespot.com/a/uploads/original/0/4/21289-3230-23731-1-magik.jpg'', ''image_tags'': ''All Images''}', '[{"id": "Storm"}, {"id": "Belasco"}, {"id": "S''ym"}, {"id": "Kitty Pryde"}, {"id": "Magik"}, {"id": "Colossus"}, {"id": "Nightcrawler"}, {"id": "Wolverine"}, {"id": "Wolfsbane"}, {"id": "Sunspot"}, {"id": "Cannonball"}, {"id": "Moonstar"}, {"id": "Shanna"}, {"id": "Magma"}, {"id": "Ka-Zar"}, {"id": "Nikolai Rasputin"}, {"id": "Alexandra Rasputina"}]', 'NaN', '[{"id": 1444}, {"id": 10947}, {"id": 10291}, {"id": 3548}, {"id": 8303}, {"id": 1460}, {"id": 1461}, {"id": 1440}, {"id": 4557}, {"id": 4644}, {"id": 1496}, {"id": 1463}, {"id": 4579}, {"id": 4558}, {"id": 3558}, {"id": 27139}, {"id": 27140}]', 'NaN', '0');
INSERT INTO volumes (id, name, firstIssue, publisher, description, startYear, numIssues, image, characters_name, concepts_name, characters_id, concepts_id, numLikes) VALUES ('3232', 'The Mighty World of Marvel', NULL, '2812', '<p>Prior to 1972 US <a href="/marvel/4010-31/" data-ref-id="4010-31">Marvel</a> comics had been reprinted in the UK by a variety of licensees, including <a href="/alan-class-comics/4010-3207/" data-ref-id="4010-3207">Alan Class</a> and <a href="/odhams-press/4010-2495/" data-ref-id="4010-2495">Odhams</a>. In 1972 however, this reprinting was brought in-house with the formation of <a href="/marvel-uk/4010-2812/" data-ref-id="4010-2812">Marvel UK</a>, whose first title was <a href="/the-mighty-world-of-marvel/4050-33875/" data-ref-id="4050-33875">Mighty World of Marvel</a>. In 1979, after a couple of title changes, usually as a result of absorbing other, failing Marvel UK titles, it became the monthly title <a href="/marvel-super-heroes/4050-3088/" data-ref-id="4050-3088">Marvel Super-Heroes</a>, which finally ended in May 1983 with #397. In July 1983 Mighty World of Marvel was revived as a full colour monthly, picking up Marvel Super-Heroes'' final leading strip, the <a href="/chris-claremont/4040-40468/" data-ref-id="4040-40468">Claremont</a>-<a href="/john-byrne/4040-1770/" data-ref-id="4040-1770">Byrne</a> era <a href="/x-men/4060-3173/" data-ref-id="4060-3173">X-Men</a>, where it had left off, at the start of the later-to-be-classic <a href="/days-of-future-past/4045-44425/" data-ref-id="4045-44425">Days of Future Past</a> story-line, alongside the US mini-series <a href="/vision-and-the-scarlet-witch/4050-3155/" data-ref-id="4050-3155">Vision and Scarlet Witch</a>. With the latter concluding in #4, the fifth issue began reprinting Chris Claremont and <a href="/frank-miller/4040-7082/" data-ref-id="4040-7082">Frank Miller''s</a> <a href="/wolverine/4050-3157/" data-ref-id="4050-3157">Wolverine</a> mini-series. The seventh issue saw Mighty World of Marvel absorb <a href="/the-daredevils/4050-22944/" data-ref-id="4050-22944">The Daredevils</a>, causing the X-Men''s departure and bringing in <a href="/alan-moore/4040-40382/" data-ref-id="4040-40382">Alan Moore</a> and <a href="/alan-davis/4040-2348/" data-ref-id="4040-2348">Alan Davis''</a> <a href="/captain-britain/4005-7477/" data-ref-id="4005-7477">Captain Britain</a> and <a href="/night-raven/4005-47365/" data-ref-id="4005-47365">Night Raven</a> (the latter text stories, rather than a comic strip), both of which had previously graced the pages of Marvel Super-Heroes. Falling sales saw the title drop some of the colour pages a few issues later, and in #13 Moore completed his run on Captain Britain, with Alan Davis and <a href="/steve-craddock/4040-56862/" data-ref-id="4040-56862">Steve Craddock</a> taking over writing duties. Issue #16 saw the final instalment of Captain Britain before he departed to star in his <a href="/captain-britain/4050-19753/" data-ref-id="4050-19753">own title</a>. Though the next issue was the last, it saw the start of reprinting another US mini-series, <a href="/magik-storm-and-illyana/4050-3230/" data-ref-id="4050-3230">Magik</a>, which then transferred, along with the Night Raven text stories, to Marvel UK''s <a href="/savage-sword-of-conan/4050-47760/" data-ref-id="4050-47760">Savage Sword of Conan</a> monthly.</p><p>Issue''s #7-13 have been translated into <a href="https://comicvine.gamespot.com/best-of-marvel-capitan-britania/4050-41906/" data-ref-id="4050-41906">Spanish</a>.</p>', '1983', '17', '{''icon_url'': ''https://comicvine.gamespot.com/a/uploads/square_avatar/0/9116/1582260-1.jpg'', ''medium_url'': ''https://comicvine.gamespot.com/a/uploads/scale_medium/0/9116/1582260-1.jpg'', ''screen_url'': ''https://comicvine.gamespot.com/a/uploads/screen_medium/0/9116/1582260-1.jpg'', ''screen_large_url'': ''https://comicvine.gamespot.com/a/uploads/screen_kubrick/0/9116/1582260-1.jpg'', ''small_url'': ''https://comicvine.gamespot.com/a/uploads/scale_small/0/9116/1582260-1.jpg'', ''super_url'': ''https://comicvine.gamespot.com/a/uploads/scale_large/0/9116/1582260-1.jpg'', ''thumb_url'': ''https://comicvine.gamespot.com/a/uploads/scale_avatar/0/9116/1582260-1.jpg'', ''tiny_url'': ''https://comicvine.gamespot.com/a/uploads/square_mini/0/9116/1582260-1.jpg'', ''original_url'': ''https://comicvine.gamespot.com/a/uploads/original/0/9116/1582260-1.jpg'', ''image_tags'': ''All Images''}', '[{"id": "Night Raven"}, {"id": "Captain Britain"}, {"id": "Betsy Braddock"}, {"id": "Mad Jim Jaspers"}, {"id": "Meggan"}, {"id": "Saturnyne"}, {"id": "Wolverine"}, {"id": "Captain U.K."}, {"id": "Dagger"}, {"id": "Roma"}, {"id": "Alison Double"}, {"id": "The Fury"}, {"id": "Yi Yang"}, {"id": "Cloak"}, {"id": "Bioship"}, {"id": "Fireflyte"}, {"id": "Tweedle-Dope"}, {"id": "Merlyn"}, {"id": "Huntarr"}, {"id": "The Jester"}, {"id": "Red Queen"}, {"id": "Arcturus Rann"}, {"id": "Marionette"}, {"id": "Baron Karza"}, {"id": "Bug"}, {"id": "Sunspot"}, {"id": "Kaptain Briton"}, {"id": "Kitty Pryde"}, {"id": "The Executioner"}, {"id": "The Knave"}, {"id": "Moonstar"}, {"id": "Nightcrawler"}, {"id": "Colossus"}, {"id": "Storm"}, {"id": "DeGrayde"}, {"id": "Tom Lennox"}, {"id": "Acroyear"}, {"id": "Father Delgado"}, {"id": "Cannonball"}, {"id": "Professor X"}, {"id": "Courtney Ross"}, {"id": "Wolfsbane"}, {"id": "Magik"}, {"id": "Mayhem"}, {"id": "The Entity"}, {"id": "Angela Cleaver"}, {"id": "Vortigern"}, {"id": "Black Knight"}, {"id": "Lockheed"}, {"id": "Prince Shaitan"}, {"id": "Cilicia"}, {"id": "Biotron"}, {"id": "Jackdaw"}, {"id": "Magma"}, {"id": "Slaymaster"}, {"id": "Dai Thomas"}, {"id": "King Arthur"}, {"id": "Vixen"}, {"id": "Lord Mandragon"}, {"id": "Kommandant Englander"}, {"id": "Captain Empire"}, {"id": "Captain Angleterre"}, {"id": "Captain Commonwealth"}, {"id": "Captain Airstrip One"}, {"id": "Captain Albion"}, {"id": "Captain England"}, {"id": "Victoria Bentley"}]', '[{"id": "Homage Covers"}]', '[{