INSERT INTO volumes (id, name, firstIssue, publisher, description, startYear, numIssues, image, characters_name, concepts_name, characters_id, concepts_id, numLikes) VALUES ('3234', 'The New Mutants', 'Initiation !', '31', '<p>After their first adventure in <a href="/marvel-graphic-novel-the-new-mutants-renewal/4000-21793/" data-ref-id="4000-21793">Marvel Graphic Novel #4</a>, the newest generation of mutants takes center stage in their first ongoing series! See Cannonball, Sunspot, Mirage, Wolfsbane, Magma, Cypher, Warlock, Karma and Magik in their quest for mastering their mutant-powers and growing up in a world that hates and fears them. The series lasted for 100 issues, after which it was continued in <a href="/x-force/4050-4604/" data-ref-id="4050-4604">X-Force</a>.</p><h4>Additional Volumes</h4><ul><li>New Mutants Vol. 1 (1983)</li><li><a href="/new-mutants/4050-18351/" data-ref-id="4050-18351">New Mutants Vol. 2</a> (2003)</li><li><a href="/new-mutants/4050-26327/" data-ref-id="4050-26327">New Mutants Vol. 3</a> (2009)</li><li><a href="/new-mutants/4050-122666/" data-ref-id="4050-122666">New Mutants Vol. 4</a> (2020)</li><li><a href="/new-mutants-lethal-legion/4050-148780/" data-ref-id="4050-148780">New Mutants: Lethal Legion</a> (2023)</li></ul><h4>Collected Editions</h4><ul><li><a href="/new-mutants-classic-volume-1/4000-153497/" data-ref-id="4000-153497">New Mutants Classic: Vol. 1</a> (#1-7)</li><li><a href="https://comicvine.gamespot.com/new-mutants-epic-collection-renewal/4050-99448/" data-ref-id="4050-99448">New Mutants Epic Collection: Renewal</a> (#1-12)</li><li><a href="https://comicvine.gamespot.com/new-mutants-omnibus-1/4000-821559/" data-ref-id="4000-821559">New Mutants Omnibus Vol. 1</a> (#1-34)</li><li><a href="/new-mutants-classic-volume-2/4000-153645/" data-ref-id="4000-153645">New Mutants Classic: Vol. 2</a> (#8-17)</li><li><a href="https://comicvine.gamespot.com/new-mutants-epic-collection-the-demon-bear-saga/4050-120134/">New Mutants Epic 