INSERT INTO volumes (id, name, firstIssue, publisher, description, startYear, numIssues, image, characters_name, concepts_name, characters_id, concepts_id, numLikes) VALUES ('3245', 'The Thing', 'Lifelines', '31', '<p>Thing''s first solo series. This series is somewhat of a continuation of <a href="/marvel-two-in-one/49-2696/">Marvel Two-In-One</a>, a series witch starred the Thing and teamed him up with many other Marvel heroes and anti-heroes. This series started right after Marvel Two-in-One ended. It stars the Thing on earth and from issue 10 and on he is seen on the planet of the Beyonder where he stayed after the events of the Secret Wars. Later the Thing returns to earth and started a wrestling career. The series lasted for 36 issues in total.</p><h4>Collected Editions</h4><ul><li><a href="https://comicvine.gamespot.com/taskmaster-anything-you-can-do/4050-125196/">Taskmaster: Anything You Can Do...</a> (#26)</li></ul><h4>Non-U.S. Collected Editions</h4><ul><li><a href="https://comicvine.gamespot.com/coleccionable-marvel-heroes-76-la-cosa-secret-wars/4000-612314/">Coleccionable Marvel Héroes - La Cosa: Secret Wars</a> (#1-23) (Spanish)</li><li><a href="https://comicvine.gamespot.com/coleccionable-marvel-heroes-60-los-4-fantasticos-d/4000-612268/" data-ref-id="4000-612268">Coleccionable Marvel Héroes - Los 4 Fantásticos de John Byrne 2</a> (#2 &amp; #10) (Spanish)</li><li><a href="https://comicvine.gamespot.com/coleccionable-marvel-heroes-62-los-4-fantasticos-d/4000-612270/">Coleccionable Marvel Héroes - Los 4 Fantásticos de John Byrne 4</a> (#7) (Spanish)</li><li><a href="https://comicvine.gamespot.com/coleccionable-marvel-heroes-61-los-4-fantasticos-d/4000-612269/">Coleccionable Marvel Héroes - Los 4 Fantásticos de John Byrne 3</a> (#19) (Spanish)</li><li><a href="https://comicvine.gamespot.com/coleccionable-marvel-heroes-53-secret-wars-ii-quie/4000-612261/">Coleccionable Marvel Héroes - Secret Wars II: ¿Quién es el Todopoderoso?</a> (#30) (Spanish)</li></ul>', '1983', '36', '{''icon_url'': ''https://comicvine.gamespot.com/a/uploads/square_avatar/0/4/20897-3245-23305-1-thing-the.jpg'', ''medium_url'': ''https://comicvine.gamespot.com/a/uploads/scale_medium/0/4/20897-3245-23305-1-thing-the.jpg'', ''screen_url'': ''https://comicvine.gamespot.com/a/uploads/screen_medium/0/4/20897-3245-23305-1-thing-the.jpg'', ''screen_large_url'': ''https://comicvine.gamespot.com/a/uploads/screen_kubrick/0/4/20897-3245-23305-1-thing-the.jpg'', ''small_url'': ''https://comicvine.gamespot.com/a/uploads/scale_small/0/4/20897-3245-23305-1-thing-the.jpg'', ''super_url'': ''https://comicvine.gamespot.com/a/uploads/scale_large/0/4/20897-3245-23305-1-thing-the.jpg'', ''thumb_url'': ''https://comicvine.gamespot.com/a/uploads/scale_avatar/0/4/20897-3245-23305-1-thing-the.jpg'', ''tiny_url'': ''https://comicvine.gamespot.com/a/uploads/square_mini/0/4/20897-3245-23305-1-thing-the.jpg'', ''original_url'': ''https://comicvine.gamespot.com/a/uploads/original/0/4/20897-3245-23305-1-thing-the.jpg'', ''image_tags'': ''All Images''}', '[{"id": "Thing"}, {"id": "Tarianna"}, {"id": "Demolition Man"}, {"id": "Alicia Masters"}, {"id": "Sharon Ventura"}, {"id": "Llrrllllnnllyyrrl"}, {"id": "Mr. Fantastic"}, {"id": "Justice"}, {"id": "Ed Garner"}, {"id": "Human Torch"}, {"id": "She-Hulk"}, {"id": "Invisible Woman"}, {"id": "Doctor Doom"}, {"id": "The Takers"}, {"id": "Puppet Master"}, {"id": "Ultron"}, {"id": "Franklin Richards"}, {"id": "Poundcakes"}, {"id": "Honcho"}, {"id": "Scourge"}, {"id": "Cowboy"}, {"id": "Black Marauder"}, {"id": "Battleaxe"}, {"id": "Georgianna Sue Castleberry"}, {"id": "Wolf"}, {"id": "Hanrak Of Leenn"}, {"id": "Wrench"}, {"id": "R.U. Reddy"}, {"id": "Spider-Man"}, {"id": "Wonder Man"}, {"id": "Jarvis"}, {"id": "Auntie Freeze"}, {"id": "Magilla"}, {"id": "Lockjaw"}, {"id": "Jacob Grimm"}, {"id": "Vavavoom"}, {"id": "Sergius O''Hoolihan"}, {"id": "Lucas Jackson"}, {"id": "Daniel Grimm Jr."}, {"id": "Mangler"}, {"id": "Capriole"}, {"id": 