INSERT INTO volumes (id, name, firstIssue, publisher, description, startYear, numIssues, image, characters_name, concepts_name, characters_id, concepts_id, numLikes) VALUES ('3247', 'X-Men Classics Starring the X-Men', NULL, '31', '<p>Reprints of issues 57-63 with an overall introduction by John Byrne and new coloring. Each issue begins with a "story thus far" recap, and issue 2 has a newly-created first page. Each issue ends with a gallery of the original covers. Issue 1 has a bonus cover of Neal Adams''s original artwork submission for the cover of issue 56 (as well as the actual issue cover). The only other change is the final panel at the close of issue 3, which adds some artwork to the bottom of the original panel with the words "The End" instead of the preview for issue 64.</p>', '1983', '3', '{''icon_url'': ''https://comicvine.gamespot.com/a/uploads/square_avatar/0/4/21303-3247-23745-1-x-men-classics-starr.jpg'', ''medium_url'': ''https://comicvine.gamespot.com/a/uploads/scale_medium/0/4/21303-3247-23745-1-x-men-classics-starr.jpg'', ''screen_url'': ''https://comicvine.gamespot.com/a/uploads/screen_medium/0/4/21303-3247-23745-1-x-men-classics-starr.jpg'', ''screen_large_url'': ''https://comicvine.gamespot.com/a/uploads/screen_kubrick/0/4/21303-3247-23745-1-x-men-classics-starr.jpg'', ''small_url'': ''https://comicvine.gamespot.com/a/uploads/scale_small/0/4/21303-3247-23745-1-x-men-classics-starr.jpg'', ''super_url'': ''https://comicvine.gamespot.com/a/uploads/scale_large/0/4/21303-3247-23745-1-x-men-classics-starr.jpg'', ''thumb_url'': ''https://comicvine.gamespot.com/a/uploads/scale_avatar/0/4/21303-3247-23745-1-x-men-classics-starr.jpg'', ''tiny_url'': ''https://comicvine.gamespot.com/a/uploads/square_mini/0/4/21303-3247-23745-1-x-men-classics-starr.jpg'', ''original_url'': ''https://comicvine.gamespot.com/a/uploads/original/0/4/21303-3247-23745-1-x-men-classics-starr.jpg'', ''image_tags'': ''All Images''}', '[{"id": "Cyclops"}, {"id": "Beast"}, {"id": "Ice