INSERT INTO volumes (id, name, firstIssue, publisher, description, startYear, numIssues, image, characters_name, concepts_name, characters_id, concepts_id, numLikes) VALUES ('3307', 'Blue Devil', 'How to Trap a Devil', '10', '<p>At the request of editor <a href="/dave-manak/4040-2411/" data-ref-id="4040-2411">Dave Manak</a>, <a href="/blue-devil/4005-4845/" data-ref-id="4005-4845">Blue Devil</a> was created by <a href="/gary-cohn/4040-45877/" data-ref-id="4040-45877">Gary Cohn</a> and <a href="/dan-mishkin/4040-44266/" data-ref-id="4040-44266">Dan Mishkin</a> for the express purpose of giving <a href="/steve-ditko/4040-4026/" data-ref-id="4040-4026">Steve Ditko</a> a project he could sink his teeth into. They tailor-made Blue Devil, using elements of characters that Ditko was famous for. When Ditko reviewed it, he responded that it was not his kind of stuff at all. So <a href="/paris-cullins/4040-7864/" data-ref-id="4040-7864">Paris Cullins</a> was brought in as artist, and the Blue Devil title was born.</p><p><strong>This title has one annual:</strong></p><ul><li><a href="/blue-devil-annual-1-the-day-all-hell-broke-loose/4000-176003/" data-ref-id="4000-176003">Blue Devil Annual #1</a>.</li></ul>', '1984', '31', '{''icon_url'': ''https://comicvine.gamespot.com/a/uploads/square_avatar/0/4/21828-3307-24356-1-blue-devil.jpg'', ''medium_url'': ''https://comicvine.gamespot.com/a/uploads/scale_medium/0/4/21828-3307-24356-1-blue-devil.jpg'', ''screen_url'': ''https://comicvine.gamespot.com/a/uploads/screen_medium/0/4/21828-3307-24356-1-blue-devil.jpg'', ''screen_large_url'': ''https://comicvine.gamespot.com/a/uploads/screen_kubrick/0/4/21828-3307-24356-1-blue-devil.jpg'', ''small_url'': ''https://comicvine.gamespot.com/a/uploads/scale_small/0/4/21828-3307-24356-1-blue-devil.jpg'', ''super_url'': ''https://comicvine.gamespot.com/a/uploads/scale_large/0/4/21828-3307-24356-1-blue-devil.jpg'', ''thumb_url'': ''https://comicvine.gamespot.com/a/uploads/scale_avatar/0/4/21828-3307-24356-1-blue-devil.jpg'', ''tiny_url'': ''https://comicvine.gamespot.com/a/uploads/square_mini/0/4/21828-3307-24356-1-blue-devil.jpg'', ''original_url'': ''https://comicvine.gamespot.com/a/uploads/original/0/4/21828-3307-24356-1-blue-devil.jpg'', ''image_tags'': ''All Images''}', '[{"id": "Blue Devil"}, {"id": "Marlene Bloomberg"}, {"id": "Kid Devil"}, {"id": "Sharon Scott"}, {"id": "Wayne Tarrant"}, {"id": "Norm Paxton"}, {"id": "Trickster (Jesse)"}, {"id": "Jock Verner"}, {"id": "Rojek"}, {"id": "Smitty"}, {"id": "Vanquisher"}, {"id": "Bolt"}, {"id": "Cain"}, {"id": "Shockwave"}, {"id": "John Stewart"}, {"id": "Nebiros"}, {"id": "Dr. Jenet Klyburn"}, {"id": "Zatanna"}, {"id": "Superman"}, {"id": "Etrigan"}, {"id": "Abel"}, {"id": "Metallo"}, {"id": "Elongated Man"}, {"id": "Captain Cold"}, {"id": "Professor Martin Stein"}, {"id": "Etta Candy"}, {"id": "Mary Frances Cassidy"}, {"id": "Athena"}, {"id": "Fisherman"}, {"id": "Mindboggler"}, {"id": "Lucifer"}, {"id": "Rynoc"}, {"id": "Shlagen"}, {"id": "Godfrey Goose"}, {"id": "Zirral"}, {"id": "Jack Edison"}, {"id": "Hyena (Day)"}, {"id": "Jason Todd"}, {"id": "Toyman (Schott)"}, {"id": "Wonder Woman"}, {"id": "Firestorm"}, {"id": "Gorilla Grodd"}, {"id": "Golden Glider"}, {"id": "Jimmy Olsen"}, {"id": "Multiplex"}, {"id": "Doc"}, {"id": "Slipknot"}, {"id": "Alfred Pennyworth"}, {"id": "The Monitor"}, {"id": "Heat Wave"}, {"id": "Weather Wizard"}, {"id": "Pied Piper"}, {"id": "Vibe"}, {"id": "Madame Xanadu"}, {"id": "Harbinger"}, {"id": "Bob Hope"}, {"id": "Solovar"}, {"id": "Captain Boomerang"}]', '[{"id": "Alternate Reality"}, {"id": "Green Lantern"}, {"id": "Homage Covers"}, {"id": "Fourth Wall"}]', '[{"id": 4845}, {"id": 56746}, {"id": 40528}, {"id": 92690}, {"id": 92688}, {"id": 92689}, {"id": 10460}, {"id": 97607}, {"id": 182831}, {"id": 182830}, {"id": 130321}, {"id": 5932}, {"id": 9646}, {"id": 28846}, {"id": 10451}, {"id": 22020}, {"id": 30761}, {"id": 5691}, {"id": 1807}, {"id": 7367}, {"id": 9806}, {"id":