INSERT INTO volumes (id, name, firstIssue, publisher, description, startYear, numIssues, image, characters_name, concepts_name, characters_id, concepts_id, numLikes) VALUES ('3308', 'Infinity, Inc.', 'Generations', '10', '<p><em>Infinity, Inc.</em> ran for 53 issues and told the adventures of the children / nephews and nieces of the original <a href="https://comicvine.gamespot.com/justice-society-of-america/4060-27589/" data-ref-id="4060-27589">Justice Society of America</a> members.</p><p>On the other dimensional world of <a href="https://comicvine.gamespot.com/earth-2/4015-56462/" data-ref-id="4015-56462">Earth-2</a>, the heroes of the Justice Society of America were gathered together for a rare Christmas Eve meeting when a group of brash young costumed heroes burst through their doors demanding membership in the prestigious team. A collection of the sons and daughters of some of the Society''s members, the youths nevertheless failed to impress their mentors. Following their rejection by the majority of the Justice Society, the teens decided to band together and form Infinity Inc, a new generation of Earth-2''s crime fighters. The group even gained the support of Justice Society member Star Spangled Kid who sympathized with Infinity Inc''s situation so much that he joined their ranks.</p><p>Written by DC''s Golden Age guru Roy Thomas and drawn by Jerry Ordway, "Infinity Inc" was released in DC''s new deluxe format on bright Baxter paper. With the team facing threats like the Ultra-Humanite, Brainwave, Solomon Grundy and even manipulated versions of the Justice Society themselves, Infinity Inc proved so popular that the title prevailed even after Earth-2 was destroyed during 1985''s "<em><a href="/crisis-on-infinite-earths/4050-3441/" data-ref-id="4050-3441">Crisis on Infinite Earths</a></em>."</p><p> </p><p>Annuals filed under <em><a href="/infinity-inc-annual/4050-3448/" data-ref-id="4050-3448">Infinity, Inc. Annual</a></em>.</p><p>Special filed under <em><a href="/infinity-inc-special/4050-23217/" data-ref-id="4050-23217">Infinity, Inc. Special</a></em>.</p><h4> </h4><h4>Collected Editions</h4><ul><li><a href="/infinity-inc-the-generations-saga-1-volume-one/4000-424814/" data-ref-id="4000-424814">Infinity, Inc.: The Generations Saga #1 - Volume One</a> (#1-4)</li><li><a href="https://comicvine.gamespot.com/dc-through-the-80s-the-experiments/4050-137001/">DC Through the 80''s: The Experiments</a> (#14)</li><li><a href="/crisis-on-infinite-earths-companion-deluxe-edition/4000-708088/" data-ref-id="4000-708088">Crisis On Infinite Earths Companion Deluxe Edition Volume 2</a> (#18-25)</li><li><a href="https://comicvine.gamespot.com/justice-league-the-detroit-era-omnibus/4050-106681/" data-ref-id="4050-106681">Justice League: The Detroit Era Omnibus</a> (#19)</li><li><a href="/the-new-teen-titans-omnibus-5-volume-5/4000-826309/" data-ref-id="4000-826309">The New Teen Titans Omnibus Volume 5</a> (#45)</li></ul><h4>Non-U.S. Collected Editions</h4><ul><li><a href="https://comicvine.gamespot.com/justice-league-of-america-crisis-7-band-7-1983-198/4000-667901/">Justice League of America: Crisis #7 - Band 7: 1983-1985</a> (#19) (German)</li></ul>', '1984', '53', '{''icon_url'': ''https://comicvine.gamespot.com/a/uploads/square_avatar/0/4/21564-3308-24054-1-infinity-inc-.jpg'', ''medium_url'': ''https://comicvine.gamespot.com/a/uploads/scale_medium/0/4/21564-3308-24054-1-infinity-inc-.jpg'', ''screen_url'': ''https://comicvine.gamespot.com/a/uploads/screen_medium/0/4/21564-3308-24054-1-infinity-inc-.jpg'', ''screen_large_url'': ''https://comicvine.gamespot.com/a/uploads/screen_kubrick/0/4/21564-3308-24054-1-infinity-inc-.jpg'', ''small_url'': ''https://comicvine.gamespot.com/a/uploads/scale_small/0/4/21564-3308-24054-1-infinity-inc-.jpg'', ''super_url'': ''https://comicvine.gamespot.com/a/uploads/scale_large/0/4/21564-3308-24054-1-infinity-inc-.jpg'', ''thumb_url'': ''https://comicvine.gamespot.com/a/uploads/scale_avatar/0/4/21564-3308-