INSERT INTO volumes (id, name, firstIssue, publisher, description, startYear, numIssues, image, characters_name, concepts_name, characters_id, concepts_id, numLikes) VALUES ('3310', 'Legion of Super-Heroes', 'Here a Villain, There a Villain...', '10', '<p>Starring: <a href="/legion-of-super-heroes/4060-19241/" data-ref-id="4060-19241">The Legion of Super-Heroes</a>.</p><p>Runs in tandem with: <em><a href="/tales-of-the-legion-of-super-heroes/4050-20776/" data-ref-id="4050-20776">Tales of the Legion of Super-Heroes</a></em> (reprinted issues 326-354).</p><p>Annuals: <a href="/legion-of-super-heroes-annual/4050-3451/" data-ref-id="4050-3451"><em>Legion of Super-Heroes Annual</em></a>.</p><p>The Legion of Super Heroes had been around since the late 1950''s but the legendary teens from the future had never starred in their own all - new first issue. The Legion had instead bounced around the pages of <a href="/adventure-comics/4050-3105/" data-ref-id="4050-3105"><em>Adventure Comics</em></a> and <a href="/superboy/4050-19154/" data-ref-id="4050-19154"><em>Superboy</em></a>, finally taking over the latter series'' title in 1973, a year in which they also starred in a four issue series featuring <a href="/reprinted-material/4015-56278/" data-ref-id="4015-56278">reprinted</a> Legion tales from <em>Adventure Comics</em>. However. the team had never been treated to the prestige and sales potential of a traditional debut issue. So as DC began to toy with the idea of relaunching some of their more popular titles using high quality Baxter paper, the Legion of Super Heroes was an obvious choice. Utilizing the talents of writer Paul Levitz and artist Keith Giffen, fan favourite creators ever since their fabled 1982 epic, "<a href="/great-darkness-saga/4045-40773/" data-ref-id="4045-40773"><em>The Great Darkness Saga</em></a>," the Legion was off and running with their own new title with a major new storyline. The debut issue and story arc introduced a newly united Legion of Super-Villains, a concept that had been building since the LSH was born and a battle royal between the two Legions ensued. The Baxter series ran for sixty three issues until its next relaunch and remains the high point of the Legion''s career in the eyes of many fans.</p><h4>Collected Editions</h4><ul><li><a href="/superman-the-man-of-steel-2-vol-2/4000-826311/" data-ref-id="4000-826311">Superman: The Man of Steel Vol. 2</a> (#37-38)</li></ul>', '1984', '63', '{''icon_url'': ''https://comicvine.gamespot.com/a/uploads/square_avatar/6/68065/7701746-0aa.jpg'', ''medium_url'': ''https://comicvine.gamespot.com/a/uploads/scale_medium/6/68065/7701746-0aa.jpg'', ''screen_url'': ''https://comicvine.gamespot.com/a/uploads/screen_medium/6/68065/7701746-0aa.jpg'', ''screen_large_url'': ''https://comicvine.gamespot.com/a/uploads/screen_kubrick/6/68065/7701746-0aa.jpg'', ''small_url'': ''https://comicvine.gamespot.com/a/uploads/scale_small/6/68065/7701746-0aa.jpg'', ''super_url'': ''https://comicvine.gamespot.com/a/uploads/scale_large/6/68065/7701746-0aa.jpg'', ''thumb_url'': ''https://comicvine.gamespot.com/a/uploads/scale_avatar/6/68065/7701746-0aa.jpg'', ''tiny_url'': ''https://comicvine.gamespot.com/a/uploads/square_mini/6/68065/7701746-0aa.jpg'', ''original_url'': ''https://comicvine.gamespot.com/a/uploads/original/6/68065/7701746-0aa.jpg'', ''image_tags'': ''All Images''}', '[{"id": "Element Lad"}, {"id": "Dream Girl"}, {"id": "Ultra Boy"}, {"id": "Wildfire"}, {"id": "Lightning Lass"}, {"id": "Sun Boy"}, {"id": "Timber Wolf"}, {"id": "Mon-El"}, {"id": "Blok"}, {"id": "Shrinking Violet"}, {"id": "Brainiac 5"}, {"id": "Polar Boy"}, {"id": "Tellus"}, {"id": "Phantom Girl"}, {"id": "Chameleon Boy"}, {"id": "Colossal Boy"}, {"id": "Shadow Lass"}, {"id": "Dawnstar"}, {"id": "Jacques Foccart"}, {"id": "Sensor Girl"}, {"id": "White Witch"}, {"id": "Magnetic Kid"}, {"id": "Saturn Girl"}, {"id": "Thom Kallor"}, {"id": "Quislet"}, {"id": "Shvaughn Erin"}, {"id": "Computo"}, {"id": "Lightnin