INSERT INTO volumes (id, name, firstIssue, publisher, description, startYear, numIssues, image, characters_name, concepts_name, characters_id, concepts_id, numLikes) VALUES ('3340', 'Elektra Saga', 'Book One: The Wall', '31', '<p>Elektra. The first woman ever loved by the Daredevil, the man without fear. Her touch was warmth. Her simile was light. Then, her father was murdered., and a soft heart became as stone,. She left this country, driven by rage and grief, to study the many arts of killing with an order of ninja called The Hand -- until she betrayed them. Forced into exile, she came back to the land known as America; now as an assassin-for-hire. And for her crimes, thes tragic, haunted woman is hunted by the one man she has ever cared for, remembered through years of loneliness and denial -- Daredevil. When Elektra confronts her last love, only death can follow.</p>', '1984', '4', '{''icon_url'': ''https://comicvine.gamespot.com/a/uploads/square_avatar/0/4/21502-3340-23975-1-elektra-saga-the.jpg'', ''medium_url'': ''https://comicvine.gamespot.com/a/uploads/scale_medium/0/4/21502-3340-23975-1-elektra-saga-the.jpg'', ''screen_url'': ''https://comicvine.gamespot.com/a/uploads/screen_medium/0/4/21502-3340-23975-1-elektra-saga-the.jpg'', ''screen_large_url'': ''https://comicvine.gamespot.com/a/uploads/screen_kubrick/0/4/21502-3340-23975-1-elektra-saga-the.jpg'', ''small_url'': ''https://comicvine.gamespot.com/a/uploads/scale_small/0/4/21502-3340-23975-1-elektra-saga-the.jpg'', ''super_url'': ''https://comicvine.gamespot.com/a/uploads/scale_large/0/4/21502-3340-23975-1-elektra-saga-the.jpg'', ''thumb_url'': ''https://comicvine.gamespot.com/a/uploads/scale_avatar/0/4/21502-3340-23975-1-elektra-saga-the.jpg'', ''tiny_url'': ''https://comicvine.gamespot.com/a/uploads/square_mini/0/4/21502-3340-23975-1-elektra-saga-the.jpg'', ''original_url'': ''https://comicvine.gamespot.com/a/uploads/original/0/4/21502-3340-23975-1-elektra-saga-the.jpg'', ''image_tags'': ''All Images''